INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1987_main_q17', 'math1_1987_main_q17', 1987, 17, 9, 17, '九、【解】 $\overline{\mathbf{A}} = \begin{bmatrix} 1 & 1 & 1 & 1 \\ 0 & 1 & 2 & 2 \\ 0 & -1 & a - 3 & -2 \\ 3 & 2 & 1 & a \end{bmatrix} \rightarrow \begin{bmatrix} 1 & 1 & 1 & 1 \\ 0 & 1 & 2 & 2 \\ 0 & -1 & a - 3 & -2 \\ 0 & -1 & -2 & a - 3 \end{bmatrix} \rightarrow \begin{bmatrix} 0 \\ 1 \\ 1 \\ b \\ -1 \end{bmatrix}$

$$
\rightarrow \left(\begin{array}{c c c c c c}1&1&1&1&0\\0&1&2&2&1\\0&0&a - 1&0&b + 1\\0&0&0&a - 1&0\end{array}\right),
$$

当 $a \neq 1, b$ 为任意常数时，方程组有唯一解；

当 $a = 1, b \neq -1$ 时，方程组无解；

当 $a = 1, b = -1$ 时，方程组有无数个解，将 $a, b$ 代入后得出

$\overline{\mathbf{A}} \rightarrow \begin{bmatrix} 1 & 0 & -1 & -1 \\ 0 & 1 & 2 & 2 \\ 0 & 0 & 0 & 0 \\ 0 & 0 & 0 & 0 \end{bmatrix}$ , 得方程组的通解为

$$
\pmb {X} = k _ {1} \left[ \begin{array}{c} {{1}} \\ {{- 2}} \\ {{1}} \\ {{0}} \end{array} \right] + k _ {2} \left[ \begin{array}{c} {{1}} \\ {{- 2}} \\ {{0}} \\ {{1}} \end{array} \right] + \left[ \begin{array}{c} {{- 1}} \\ {{1}} \\ {{0}} \\ {{0}} \end{array} \right] (k _ {1}, k _ {2} \text {为 任 意 常 数}).
$$

# 十、填空题', 'E:\数学自用\数据资料\真题\按年份整理\1987\解析\1987年解析.md', 'ok', 'sequential_year_index', 0.115, '1987:17', 6, 0.128);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1987_main_q18', 'math1', 1987, '真题', 'main', 18, '# 十、填空题（本题共3小题，每小题2分，共6分）

（1）假设在一次试验中，事件 $A$ 发生的概率为 $p$ ，现进行 $n$ 次独立试验，则 $A$ 至少发生一次的概率为 ，而事件 $A$ 至多发生一次的概率为', 'E:\数学自用\数据资料\真题\按年份整理\1987\按题拆分\真题\第18题\题目.md', '1987\按题拆分\真题\第18题\题目.md', 0, 'ok', '1987 真题 第18题 # 十、填空题（本题共3小题，每小题2分，共6分）

（1）假设在一次试验中，事件 $a$ 发生的概率为 $p$ ，现进行 $n$ 次独立试验，则 $a$ 至少发生一次的概率为 ，而事件 $a$ 至多发生一次的概率为');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1987_main_q18', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1987_main_q18', 'math1_1987_main_q18', 1987, 18, 1, 18, '(1)【答案】 $1 - (1 - p)^n$ ， $[1 + (n - 1)p](1 - p)^{n - 1}$ .

【解】设 $n$ 次试验中 $A$ 发生的次数为 $X$ ，显然 $X\sim B(n,p)$

则 $P\{X \geqslant 1\} = 1 - P\{X = 0\} = 1 - C_n^0 p^0 (1 - p)^n = 1 - (1 - p)^n$

$$
\begin{array}{l} P \{X \leqslant 1 \} = P \{X = 0 \} + P \{X = 1 \} = C _ {n} ^ {0} p ^ {0} (1 - p) ^ {n} + C _ {n} ^ {1} p (1 - p) ^ {n - 1} \\ = (1 - p) ^ {n - 1} [ 1 + (n - 1) p ]. \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\1987\解析\1987年解析.md', 'manual_check', 'sequential_year_index', 0.066, '1987:18', 1, 0.066);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1987_main_q19', 'math1', 1987, '真题', 'main', 19, '# 十、填空题（本题共3小题，每小题2分，共6分）

（2）三个箱子，第一个箱子中有4个黑球1个白球，第二个箱子中有3个黑球3个白球，第三个箱子中有3个黑球5个白球.现随机地取一个箱子，再从这个箱子中取出1个球，这个球为白球的概率等于 .已知取出的球是白球，此球属于第二个箱子的概率为', 'E:\数学自用\数据资料\真题\按年份整理\1987\按题拆分\真题\第19题\题目.md', '1987\按题拆分\真题\第19题\题目.md', 0, 'ok', '1987 真题 第19题 # 十、填空题（本题共3小题，每小题2分，共6分）

（2）三个箱子，第一个箱子中有4个黑球1个白球，第二个箱子中有3个黑球3个白球，第三个箱子中有3个黑球5个白球.现随机地取一个箱子，再从这个箱子中取出1个球，这个球为白球的概率等于 .已知取出的球是白球，此球属于第二个箱子的概率为');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1987_main_q19', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1987_main_q19', 'math1_1987_main_q19', 1987, 19, 2, 19, '(2)【答案】 $\frac{53}{120}, \frac{20}{53}$ .

【解】记 $A_{i} = \{$ 取的是第 $i$ 个箱子 $\}$ $(i = 1,2,3)$ ， $B = \{$ 从箱子中取出的是白球 $\}$ ，则

$$
P \left(A _ {1}\right) = P \left(A _ {2}\right) = P \left(A _ {3}\right) = \frac {1}{3}, P \left(B \mid A _ {1}\right) = \frac {1}{5}, P \left(B \mid A _ {2}\right) = \frac {3}{6} = \frac {1}{2}, P \left(B \mid A _ {3}\right) = \frac {5}{8}.
$$

① 由全概率公式知： $P(B) = P(A_{1})P(B\mid A_{1}) + P(A_{2})P(B\mid A_{2}) + P(A_{3})P(B\mid A_{3})$

$$
= \frac {1}{3} \times \frac {1}{5} + \frac {1}{3} \times \frac {1}{2} + \frac {1}{3} \times \frac {5}{8} = \frac {5 3}{1 2 0}.
$$

$$
\text {②} P \left(A _ {2} \mid B\right) = \frac {P \left(A _ {2} B\right)}{P (B)} = \frac {P \left(A _ {2}\right) P \left(B \mid A _ {2}\right)}{P (B)} = \frac {\frac {1}{3} \times \frac {1}{2}}{\frac {5 3}{1 2 0}} = \frac {2 0}{5 3};
$$', 'E:\数学自用\数据资料\真题\按年份整理\1987\解析\1987年解析.md', 'manual_check', 'sequential_year_index', 0.063, '1987:19', 2, 0.063);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1987_main_q20', 'math1', 1987, '真题', 'main', 20, '# 十、填空题（本题共3小题，每小题2分，共6分）

（3）已知连续型随机变量 $X$ 的概率密度为 $f(x) = \frac{1}{\sqrt{\pi}}\mathrm{e}^{-x^2 +2x - 1}$ ，则 $X$ 的数学期望为________， $X$ 的方差为________.', 'E:\数学自用\数据资料\真题\按年份整理\1987\按题拆分\真题\第20题\题目.md', '1987\按题拆分\真题\第20题\题目.md', 0, 'ok', '1987 真题 第20题 # 十、填空题（本题共3小题，每小题2分，共6分）

（3）已知连续型随机变量 $x$ 的概率密度为 $f(x) = \frac{1}{\sqrt{\pi}}\mathrm{e}^{-x^2 +2x - 1}$ ，则 $x$ 的数学期望为________， $x$ 的方差为________.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1987_main_q20', 'tag_连续');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1987_main_q20', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1987_main_q20', 'math1_1987_main_q20', 1987, 20, 3, 20, '(3)【答案】1， $\frac{1}{2}$ .

【解】 方法一

由 $f(x) = \frac{1}{\sqrt{\pi}}\mathrm{e}^{-x^2 +2x - 1} = \frac{1}{\sqrt{2\pi}\cdot\frac{1}{\sqrt{2}}}\mathrm{e}^{-\frac{(x - 1)^2}{2\left(\frac{1}{\sqrt{2}}\right)^2}},$ 得 $X\sim N\left(1,\frac{1}{2}\right)$

故 $E(X) = 1$ ， $D(X) = \frac{1}{2}$

方法二

$$
\begin{array}{l} E (X) = \int_ {- \infty} ^ {+ \infty} x f (x) d x = \frac {1}{\sqrt {\pi}} \int_ {- \infty} ^ {+ \infty} x e ^ {- (x - 1) ^ {2}} d x \\ = \frac {1}{\sqrt {\pi}} \int_ {- \infty} ^ {+ \infty} [ 1 + (x - 1) ] e ^ {- (x - 1) ^ {2}} d (x - 1) = \frac {1}{\sqrt {\pi}} \int_ {- \infty} ^ {+ \infty} (1 + x) e ^ {- x ^ {2}} d x \\ = \frac {2}{\sqrt {\pi}} \int_ {0} ^ {+ \infty} e ^ {- x ^ {2}} d x \xlongequal {x ^ {2} = t} \frac {2}{\sqrt {\pi}} \int_ {0} ^ {+ \infty} \frac {1}{2 \sqrt {t}} e ^ {- t} d t = \frac {1}{\sqrt {\pi}} \int_ {0} ^ {+ \infty} t ^ {- \frac {1}{2}} e ^ {- t} d t = \frac {1}{\sqrt {\pi}} \Gamma \left(\frac {1}{2}\right) = 1. \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\1987\解析\1987年解析.md', 'ok', 'sequential_year_index', 0.127, '1987:20', 11, 0.145);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1987_main_q21', 'math1', 1987, '真题', 'main', 21, '# 十一、（本题满分6分）

设随机变量 $X, Y$ 相互独立，其概率密度函数分别为

$$
f _ {X} (x) = \left\{ \begin{array}{l l} 1, & 0 <   x <   1, \\ 0, & \text {其 他}, \end{array} \right. f _ {Y} (y) = \left\{ \begin{array}{l l} \mathrm {e} ^ {- y}, & y > 0, \\ 0, & y \leqslant 0, \end{array} \right.
$$

求随机变量 $Z = 2X + Y$ 的概率密度函数 $f_{Z}(z)$', 'E:\数学自用\数据资料\真题\按年份整理\1987\按题拆分\真题\第21题\题目.md', '1987\按题拆分\真题\第21题\题目.md', 0, 'ok', '1987 真题 第21题 # 十一、（本题满分6分）

设随机变量 $x, y$ 相互独立，其概率密度函数分别为

$$
f _ {x} (x) = \left\{ \begin{array}{l l} 1, & 0 <   x <   1, \\ 0, & \text {其 他}, \end{array} \right. f _ {y} (y) = \left\{ \begin{array}{l l} \mathrm {e} ^ {- y}, & y > 0, \\ 0, & y \leqslant 0, \end{array} \right.
$$

求随机变量 $z = 2x + y$ 的概率密度函数 $f_{z}(z)$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1987_main_q21', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1987_main_q21', 'math1_1987_main_q21', 1987, 21, 11, 21, '# 十一、【解】因为随机变量 $X, Y$ 相互独立，所以 $(X, Y)$ 的联合概率密度为

$$
f (x, y) = f _ {X} (x) f _ {Y} (y) = \left\{ \begin{array}{l l} \mathrm {e} ^ {- y}, & 0 <   x <   1, y > 0, \\ 0, & \text {其 他}. \end{array} \right.
$$

则 $F_{Z}(z) = P\{Z \leqslant z\} = P\{2X + Y \leqslant z\} = \iint_{2x + y \leqslant z} f(x, y) \, \mathrm{d}x \, \mathrm{d}y,$

当 $z < 0$ 时， $F_{Z}(z) = 0$

当 $0 \leqslant z < 2$ 时， $F_{Z}(z) = \int_{0}^{\frac{z}{2}} \mathrm{d}x \int_{0}^{z - 2x} \mathrm{e}^{-y} \mathrm{d}y = \int_{0}^{\frac{z}{2}} (1 - \mathrm{e}^{2x - z}) \mathrm{d}x = \frac{z}{2} - \frac{1}{2} + \frac{1}{2} \mathrm{e}^{-z}$ ;

当 $z \geqslant 2$ 时， $F_Z(z) = \int_0^1 \mathrm{d}x \int_0^{z - 2x} \mathrm{e}^{-y} \, \mathrm{d}y = \int_0^1 (1 - \mathrm{e}^{2x - z}) \, \mathrm{d}x = 1 - \frac{1}{2} (\mathrm{e}^2 - 1) \mathrm{e}^{-z}$ ，

故 $f_{Z}(z) = \left\{ \begin{array}{ll}0, & z <   0,\\ \frac{1}{2} (1 - \mathrm{e}^{-z}), & 0\leqslant z\leqslant 2,\\ \frac{1}{2}\mathrm{e}^{-z}(\mathrm{e}^{2} - 1), & z > 2. \end{array} \right.$', 'E:\数学自用\数据资料\真题\按年份整理\1987\解析\1987年解析.md', 'ok', 'sequential_year_index', 0.425, '1987:21', 11, 0.425);
