INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1988_main_q01', 'math1_1988_main_q01', 1988, 1, 1, 1, '(1)【解】 由 $\lim_{n\to \infty}\left|\frac{a_{n + 1}}{a_n}\right| = \lim_{n\to \infty}\frac{1}{(n + 1)\cdot 3^{n + 1}}\Bigg{/}\frac{1}{n\cdot 3^n} = \frac{1}{3}$ ，得收敛半径 $R = 3$

当 $x - 3 = -3$ ，即 $x = 0$ 时， $\sum_{n = 1}^{\infty}\frac{(-1)^n}{n}$ 收敛；

当 $x - 3 = 3$ ，即 $x = 6$ 时， $\sum_{n = 1}^{\infty}\frac{1}{n}$ 发散，

故级数 $\sum_{n=1}^{\infty} \frac{(x-3)^n}{n \cdot 3^n}$ 的收敛域为 $[0,6)$ .', 'E:\数学自用\数据资料\真题\按年份整理\1988\解析\1988年解析.md', 'ok', 'sequential_year_index', 0.375, '1988:1', 1, 0.375);
