INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1988_main_q07', 'math1', 1988, '真题', 'main', 7, '# 二、填空题（本题共4小题，每小题3分，满分12分）

（4）设4阶矩阵 $A = (\alpha, \gamma_2, \gamma_3, \gamma_4), B = (\beta, \gamma_2, \gamma_3, \gamma_4)$ ，其中 $\alpha, \beta, \gamma_2, \gamma_3, \gamma_4$ 都是4维列向量，且 $|\mathbf{A}| = 4, |\mathbf{B}| = 1$ ，则 $|\mathbf{A} + \mathbf{B}| =$ ______.', 'E:\数学自用\数据资料\真题\按年份整理\1988\按题拆分\真题\第07题\题目.md', '1988\按题拆分\真题\第07题\题目.md', 0, 'ok', '1988 真题 第7题 # 二、填空题（本题共4小题，每小题3分，满分12分）

（4）设4阶矩阵 $a = (\alpha, \gamma_2, \gamma_3, \gamma_4), b = (\beta, \gamma_2, \gamma_3, \gamma_4)$ ，其中 $\alpha, \beta, \gamma_2, \gamma_3, \gamma_4$ 都是4维列向量，且 $|\mathbf{a}| = 4, |\mathbf{b}| = 1$ ，则 $|\mathbf{a} + \mathbf{b}| =$ ______.');
