INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1988_main_q09', 'math1_1988_main_q09', 1988, 9, 2, 9, '（2）【答案】（A）.

【解】将 $x = x_0$ 代入 $y'''' - 2y'' + 4y = 0$ ，得 $f''''(x_0) - 2f''(x_0) + 4f(x_0) = 0$

从而 $f^{\prime \prime}(x_0) = -4f(x_0) < 0$ ，由极值判别法得 $x = x_{0}$ 为 $f(x)$ 的极大值点，应选(A).', 'E:\数学自用\数据资料\真题\按年份整理\1988\解析\1988年解析.md', 'ok', 'sequential_year_index', 0.099, '1988:9', 2, 0.099);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1988_main_q10', 'math1', 1988, '真题', 'main', 10, '# 三、选择题(本题共5小题，每小题3分，满分15分）

(3) 设空间区域 $\Omega_{1}: x^{2} + y^{2} + z^{2} \leqslant R^{2} (z \geqslant 0)$ ; $\Omega_{2}: x^{2} + y^{2} + z^{2} \leqslant R^{2} (x \geqslant 0, y \geqslant 0, z \geqslant 0)$ , 则（ ）.

(A) $\iiint_{\Omega_1} x \, \mathrm{d}v = 4 \iiint_{\Omega_2} x \, \mathrm{d}v$

(B) $\iiint_{\Omega_1} y \, \mathrm{d}v = 4 \iiint_{\Omega_2} y \, \mathrm{d}v$

(C) $\iiint_{\Omega_1} z \, \mathrm{d}v = 4 \iiint_{\Omega_2} z \, \mathrm{d}v$

(D) $\iiint_{\Omega_1} xyz \, \mathrm{d}v = 4 \iiint_{\Omega_2} xyz \, \mathrm{d}v$', 'E:\数学自用\数据资料\真题\按年份整理\1988\按题拆分\真题\第10题\题目.md', '1988\按题拆分\真题\第10题\题目.md', 0, 'ok', '1988 真题 第10题 # 三、选择题(本题共5小题，每小题3分，满分15分）

(3) 设空间区域 $\omega_{1}: x^{2} + y^{2} + z^{2} \leqslant r^{2} (z \geqslant 0)$ ; $\omega_{2}: x^{2} + y^{2} + z^{2} \leqslant r^{2} (x \geqslant 0, y \geqslant 0, z \geqslant 0)$ , 则（ ）.

(a) $\iiint_{\omega_1} x \, \mathrm{d}v = 4 \iiint_{\omega_2} x \, \mathrm{d}v$

(b) $\iiint_{\omega_1} y \, \mathrm{d}v = 4 \iiint_{\omega_2} y \, \mathrm{d}v$

(c) $\iiint_{\omega_1} z \, \mathrm{d}v = 4 \iiint_{\omega_2} z \, \mathrm{d}v$

(d) $\iiint_{\omega_1} xyz \, \mathrm{d}v = 4 \iiint_{\omega_2} xyz \, \mathrm{d}v$');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1988_main_q10', 'math1_1988_main_q10', 1988, 10, 3, 10, '(3)【答案】 (C).

【解】 由奇偶性得

$\iiint_{\Omega_1}x\mathrm{d}v = \iiint_{\Omega_1}y\mathrm{d}v = 0,\quad \iiint_{\Omega_1}z\mathrm{d}v = 4\iiint_{\Omega_2}z\mathrm{d}v,\quad \iiint_{\Omega_1}xyz\mathrm{d}v = 0$ 显然选(C).', 'E:\数学自用\数据资料\真题\按年份整理\1988\解析\1988年解析.md', 'ok', 'sequential_year_index', 0.173, '1988:10', 3, 0.173);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1988_main_q11', 'math1', 1988, '真题', 'main', 11, '# 三、选择题(本题共5小题，每小题3分，满分15分）

(4) 若级数 $\sum_{n=0}^{\infty} a_n (x - 1)^n$ 在 $x = -1$ 处收敛, 则该级数在 $x = 2$ 处（ ）.

（A）条件收敛

（B）绝对收敛

（C）发散

（D）收敛性不确定', 'E:\数学自用\数据资料\真题\按年份整理\1988\按题拆分\真题\第11题\题目.md', '1988\按题拆分\真题\第11题\题目.md', 0, 'ok', '1988 真题 第11题 # 三、选择题(本题共5小题，每小题3分，满分15分）

(4) 若级数 $\sum_{n=0}^{\infty} a_n (x - 1)^n$ 在 $x = -1$ 处收敛, 则该级数在 $x = 2$ 处（ ）.

（a）条件收敛

（b）绝对收敛

