INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1989_main_q11', 'math1_1989_main_q11', 1989, 11, 1, 11, '(1)【解】 $\frac{\partial z}{\partial x} = 2f'' + g_1'' + yg_2''$ , $\frac{\partial^2z}{\partial x\partial y} = -2f'''' + xg_{12}'''' + g_2'' + xyg_{22}''''.$', 'E:\数学自用\数据资料\真题\按年份整理\1989\解析\1989年解析.md', 'manual_check', 'sequential_year_index', 0.078, '1989:11', 1, 0.078);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1989_main_q12', 'math1', 1989, '真题', 'main', 12, '# 三、(本题共3小题，每小题5分，满分15分)

（2）设曲线积分 $\int_{C} xy^{2} \, \mathrm{d}x + \varphi(x) y \, \mathrm{d}y$ 与路径无关，其中 $\varphi(x)$ 具有连续的导数，且 $\varphi(0) = 0$ 计算 $\int_{(0,0)}^{(1,1)} xy^{2} \, \mathrm{d}x + \varphi(x) y \, \mathrm{d}y$ 的值.', 'E:\数学自用\数据资料\真题\按年份整理\1989\按题拆分\真题\第12题\题目.md', '1989\按题拆分\真题\第12题\题目.md', 0, 'ok', '1989 真题 第12题 # 三、(本题共3小题，每小题5分，满分15分)

（2）设曲线积分 $\int_{c} xy^{2} \, \mathrm{d}x + \varphi(x) y \, \mathrm{d}y$ 与路径无关，其中 $\varphi(x)$ 具有连续的导数，且 $\varphi(0) = 0$ 计算 $\int_{(0,0)}^{(1,1)} xy^{2} \, \mathrm{d}x + \varphi(x) y \, \mathrm{d}y$ 的值.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1989_main_q12', 'tag_连续');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1989_main_q12', 'tag_导数');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1989_main_q12', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1989_main_q12', 'math1_1989_main_q12', 1989, 12, 2, 12, '(2)【解】 方法一 $P = xy^{2}$ ， $Q = \varphi (x)y$

因为曲线积分与路径无关，所以 $\frac{\partial Q}{\partial x} = \frac{\partial P}{\partial y}$ 即 $\varphi^{\prime}(x) = 2x$

解得 $\varphi (x) = x^{2} + C$ ，由 $\varphi (0) = 0$ 得 $C = 0$ ，故 $\varphi (x) = x^2$

$$
\int_ {(0, 0)} ^ {(1, 1)} x y ^ {2} \mathrm {d} x + \varphi (x) y \mathrm {d} y = \int_ {(0, 0)} ^ {(1, 1)} x y ^ {2} \mathrm {d} x + x ^ {2} y \mathrm {d} y = \int_ {0} ^ {1} 0 \mathrm {d} x + \int_ {0} ^ {1} y \mathrm {d} y = \frac {1}{2}.
$$

方法二 $P = xy^{2},Q = \varphi (x)y,$

由 $\frac{\partial Q}{\partial x} = \frac{\partial P}{\partial y}$ 得 $\varphi^{\prime}(x) = 2x$

解得 $\varphi (x) = x^{2} + C$ ，由 $\varphi (0) = 0$ 得 $C = 0$ ，故 $\varphi (x) = x^2$

$$
\int_ {(0, 0)} ^ {(1, 1)} x y ^ {2} \mathrm {d} x + \varphi (x) y \mathrm {d} y = \int_ {(0, 0)} ^ {(1, 1)} x y ^ {2} \mathrm {d} x + x ^ {2} y \mathrm {d} y = \int_ {(0, 0)} ^ {(1, 1)} \mathrm {d} \left(\frac {1}{2} x ^ {2} y ^ {2}\right) = \frac {1}{2} x ^ {2} y ^ {2} \Bigg | _ {(0, 0)} ^ {(1, 1)} = \frac {1}{2}.
$$', 'E:\数学自用\数据资料\真题\按年份整理\1989\解析\1989年解析.md', 'ok', 'sequential_year_index', 0.271, '1989:12', 2, 0.271);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1989_main_q13', 'math1', 1989, '真题', 'main', 13, '# 三、(本题共3小题，每小题5分，满分15分)

(3) 计算三重积分 $\iiint_{\Omega} (x + z) \, \mathrm{d}v$ ，其中 $\Omega$ 是由 $z = \sqrt{x^2 + y^2}$ 与 $z = \sqrt{1 - x^2 - y^2}$ 所围成的区域.', 'E:\数学自用\数据资料\真题\按年份整理\1989\按题拆分\真题\第13题\题目.md', '1989\按题拆分\真题\第13题\题目.md', 0, 'ok', '1989 真题 第13题 # 三、(本题共3小题，每小题5分，满分15分)

(3) 计算三重积分 $\iiint_{\omega} (x + z) \, \mathrm{d}v$ ，其中 $\omega$ 是由 $z = \sqrt{x^2 + y^2}$ 与 $z = \sqrt{1 - x^2 - y^2}$ 所围成的区域.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1989_main_q13', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1989_main_q13', 'math1_1989_main_q13', 1989, 13, 3, 13, '（3）【解】 方法一

由 $\sqrt{x^2 + y^2} = \sqrt{1 - x^2 - y^2}$ 得 $\Omega$ 在 $xOy$ 平面上的投影区域为 $D: x^2 + y^2 \leqslant \frac{1}{2}$ ,

由对称性得 $\iiint_{\Omega} x \, \mathrm{d}v = 0$

于是 $\iiint_{\Omega}(x + z)\mathrm{d}v = \iiint_{\Omega}z\mathrm{d}v = \iint_{D}\mathrm{d}x\mathrm{d}y\int \limits_{\sqrt{x^2 + y^2}}^{\sqrt{1 - x^2 - y^2}}z\mathrm{d}z$

$$
\begin{array}{l} = \frac {1}{2} \iint_ {D} (1 - 2 x ^ {2} - 2 y ^ {2}) \mathrm {d} x \mathrm {d} y = \iint_ {D} \left(\frac {1}{2} - x ^ {2} - y ^ {2}\right) \mathrm {d} x \mathrm {d} y \\ = \int_ {0} ^ {2 \pi} \mathrm {d} \theta \int_ {0} ^ {\sqrt {\frac {1}{2}}} r \left(\frac {1}{2} - r ^ {2}\right) \mathrm {d} r = \frac {\pi}{8}. \\ \end{array}
$$

方法二

由对称性得 $\iiint_{\Omega} x \, \mathrm{d}v = 0$ ，即 $\iiint_{\Omega} (x + z) \, \mathrm{d}v = \iiint_{\Omega} z \, \mathrm{d}v$

令 $\left\{ \begin{array}{l}x = r\cos \theta \sin \varphi ,\\ y = r\sin \theta \sin \varphi ,\\ z = r\cos \varphi \end{array} \right.$ ， $0\leqslant \theta \leqslant 2\pi ,0\leqslant \varphi \leqslant \frac{\pi}{4},0\leqslant r\leqslant 1)$ ，则

$$
\begin{array}{l} \iiint_ {a} z \mathrm {d} v = \int_ {0} ^ {2 \pi} \mathrm {d} \theta \int_ {0} ^ {\frac {\pi}{4}} \mathrm {d} \varphi \int_ {0} ^ {1} r \cos \varphi \cdot r ^ {2} \sin \varphi \mathrm {d} r \\ = 2 \pi \int_ {0} ^ {\frac {\pi}{4}} \cos \varphi \cdot \sin \varphi d \varphi \int_ {0} ^ {1} r ^ {3} d r = \left. \frac {\pi}{2} \cdot \frac {1}{2} \sin^ {2} \varphi \right| _ {0} ^ {\frac {\pi}{4}} = \frac {\pi}{8}. \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\1989\解析\1989年解析.md', 'ok', 'sequential_year_index', 0.109, '1989:13', 3, 0.109);
