INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1989_main_q19', 'math1_1989_main_q19', 1989, 19, 9, 19, '九、【解】设 $\Sigma : x^2 + y^2 + (z - a)^2 = R^2$ （ $0 < R < 2a$ ），

由 $\left\{ \begin{array}{l}x^{2} + y^{2} + z^{2} = a^{2},\\ x^{2} + y^{2} + (z - a)^{2} = R^{2} \end{array} \right.$ 得 $x^{2} + y^{2} = R^{2} - \frac{R^{4}}{4a^{2}},$

位于定球面 $x^{2} + y^{2} + z^{2} = a^{2}$ 内的曲面为

$$
\Sigma : z = a - \sqrt {R ^ {2} - x ^ {2} - y ^ {2}},
$$

其中， $(x,y)\in D_{xy}\left(x^{2} + y^{2}\leqslant R^{2} - \frac{R^{4}}{4a^{2}}\right),$

$$
\begin{array}{l} S = \iint_ {D _ {x y}} \sqrt {1 + \left(\frac {\partial z}{\partial x}\right) ^ {2} + \left(\frac {\partial z}{\partial y}\right) ^ {2}} d x d y = R \iint_ {D _ {x y}} \frac {d x d y}{\sqrt {R ^ {2} - x ^ {2} - y ^ {2}}} \\ = 2 \pi R \int_ {0} ^ {\sqrt {R ^ {2} - \frac {R ^ {4}}{4 a ^ {2}}}} \frac {r \mathrm {d} r}{\sqrt {R ^ {2} - r ^ {2}}} = - 2 \pi R \int_ {0} ^ {\sqrt {R ^ {2} - \frac {R ^ {4}}{4 a ^ {2}}}} \frac {\mathrm {d} (R ^ {2} - r ^ {2})}{2 \sqrt {R ^ {2} - r ^ {2}}} \\ = 2 \pi \left(R ^ {2} - \frac {R ^ {3}}{2 a}\right), \\ \end{array}
$$

由 $\frac{\mathrm{d}S}{\mathrm{d}R} = 2\pi \left(2R - \frac{3R^2}{2a}\right) = 0$ ，得 $R = \frac{4}{3} a$

当 $0 < R < \frac{4}{3} a$ 时， $\frac{\mathrm{d}S}{\mathrm{d}R} > 0$ ；当 $R > \frac{4}{3} a$ 时， $\frac{\mathrm{d}S}{\mathrm{d}R} < 0$ ，故当 $R = \frac{4}{3} a$ 时， $\Sigma$ 位于定球面内的面积最大。十、填空题', 'E:\数学自用\数据资料\真题\按年份整理\1989\解析\1989年解析.md', 'manual_check', 'sequential_year_index', 0, '1989:19', 8, 0.579);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1989_main_q20', 'math1', 1989, '真题', 'main', 20, '# 九、（本题满分9分）

设半径为 $R$ 的球面 $\Sigma$ 的球心在定球面 $x^{2} + y^{2} + z^{2} = a^{2}(a > 0)$ 上，问当 $R$ 取何值时，球面 $\Sigma$ 位于定球面内部的那部分面积最大？', 'E:\数学自用\数据资料\真题\按年份整理\1989\按题拆分\真题\第20题\题目.md', '1989\按题拆分\真题\第20题\题目.md', 0, 'ok', '1989 真题 第20题 # 九、（本题满分9分）

