INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1990_main_q06', 'math1', 1990, '真题', 'main', 6, '# 二、选择题（本题共5小题，每小题3分，满分15分）

（1）设 $f(x)$ 为连续函数， $F(x) = \int_{x}^{\mathrm{e}^{-x}} f(t) \, \mathrm{d}t$ ，则 $F''(x) = (\quad)$ .

(A) $-\mathrm{e}^{-x}f(\mathrm{e}^{-x}) - f(x)$

(B) $-\mathrm{e}^{-x}f(\mathrm{e}^{-x}) + f(x)$

(C) $\mathrm{e}^{-x}f(\mathrm{e}^{-x}) - f(x)$

(D) $\mathrm{e}^{-x}f(\mathrm{e}^{-x}) + f(x)$', 'E:\数学自用\数据资料\真题\按年份整理\1990\按题拆分\真题\第06题\题目.md', '1990\按题拆分\真题\第06题\题目.md', 0, 'ok', '1990 真题 第6题 # 二、选择题（本题共5小题，每小题3分，满分15分）

（1）设 $f(x)$ 为连续函数， $f(x) = \int_{x}^{\mathrm{e}^{-x}} f(t) \, \mathrm{d}t$ ，则 $f''(x) = (\quad)$ .

(a) $-\mathrm{e}^{-x}f(\mathrm{e}^{-x}) - f(x)$

(b) $-\mathrm{e}^{-x}f(\mathrm{e}^{-x}) + f(x)$

(c) $\mathrm{e}^{-x}f(\mathrm{e}^{-x}) - f(x)$

(d) $\mathrm{e}^{-x}f(\mathrm{e}^{-x}) + f(x)$');
