(1) 求 $\int_{0}^{1} \frac{\ln(1 + x)}{(2 - x)^{2}} \mathrm{d}x$ .', 'E:\数学自用\数据资料\真题\按年份整理\1990\按题拆分\真题\第11题\题目.md', '1990\按题拆分\真题\第11题\题目.md', 0, 'ok', '1990 真题 第11题 # 三、(本题共3小题，每小题5分，满分15分)

(1) 求 $\int_{0}^{1} \frac{\ln(1 + x)}{(2 - x)^{2}} \mathrm{d}x$ .');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1990_main_q11', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1990_main_q11', 'math1_1990_main_q11', 1990, 11, 1, 11, '(1)【解】 $\int_0^1\frac{\ln(1 + x)}{(2 - x)^2}\mathrm{d}x = \int_0^1\ln (1 + x)\mathrm{d}\left(\frac{1}{2 - x}\right)$

$$
\begin{array}{l} = \left. \frac {\ln (1 + x)}{2 - x} \right| _ {0} ^ {1} + \int_ {0} ^ {1} \frac {1}{(x - 2) (x + 1)} d x \\ = \ln 2 + \frac {1}{3} \ln \left| \frac {x - 2}{x + 1} \right| _ {0} ^ {1} = \ln 2 - \frac {2}{3} \ln 2 = \frac {1}{3} \ln 2. \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\1990\解析\1990年解析.md', 'ok', 'sequential_year_index', 0.269, '1990:11', 1, 0.269);
