INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1990_main_q12', 'math1_1990_main_q12', 1990, 12, 2, 12, '(2)【解】 $\frac{\partial z}{\partial x} = 2f_1'' + y\cos x \cdot f_2''$ ,

$$
\begin{array}{l} \frac {\partial^ {2} z}{\partial x \partial y} = 2 \left(- f _ {1 1} ^ {\prime \prime} + \sin x \cdot f _ {1 2} ^ {\prime \prime}\right) + \cos x \cdot f _ {2} ^ {\prime} + y \cos x \left(- f _ {2 1} ^ {\prime \prime} + \sin x \cdot f _ {2 2} ^ {\prime \prime}\right) \\ = - 2 f _ {1 1} ^ {\prime \prime} + (2 \sin x - y \cos x) \cdot f _ {1 2} ^ {\prime \prime} + \cos x \cdot f _ {2} ^ {\prime} + y \sin x \cos x \cdot f _ {2 2} ^ {\prime \prime}. \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\1990\解析\1990年解析.md', 'manual_check', 'sequential_year_index', 0.07, '1990:12', 2, 0.07);
