INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1990_main_q13', 'tag_微分方程');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1990_main_q13', 'math1_1990_main_q13', 1990, 13, 3, 13, '（3）【解】 特征方程为 $\lambda^2 + 4\lambda + 4 = 0$ ，特征根为 $\lambda_1 = \lambda_2 = -2$

$y^{\prime \prime} + 4y^{\prime} + 4y = 0$ 的通解为 $y = (C_1 + C_2x)\mathrm{e}^{-2x}$

令 $y^{\prime \prime} + 4y^{\prime} + 4y = \mathrm{e}^{-2x}$ 的特解为 $y_0(x) = ax^2\mathrm{e}^{-2x}$ ，代入得 $a = \frac{1}{2}$

故 $y^{\prime \prime} + 4y^{\prime} + 4y = \mathrm{e}^{-2x}$ 的通解为

$$
y = (C _ {1} + C _ {2} x) \mathrm {e} ^ {- 2 x} + \frac {1}{2} x ^ {2} \mathrm {e} ^ {- 2 x} (C _ {1}, C _ {2} \text {为 任 意 常 数}).
$$', 'E:\数学自用\数据资料\真题\按年份整理\1990\解析\1990年解析.md', 'ok', 'sequential_year_index', 0.258, '1990:13', 3, 0.258);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1990_main_q14', 'math1', 1990, '真题', 'main', 14, '# 四、（本题满分6分）

求幂级数 $\sum_{n=0}^{\infty}(2n+1)x^{n}$ 的收敛域，并求其和函数.', 'E:\数学自用\数据资料\真题\按年份整理\1990\按题拆分\真题\第14题\题目.md', '1990\按题拆分\真题\第14题\题目.md', 0, 'ok', '1990 真题 第14题 # 四、（本题满分6分）

求幂级数 $\sum_{n=0}^{\infty}(2n+1)x^{n}$ 的收敛域，并求其和函数.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1990_main_q14', 'tag_级数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1990_main_q14', 'math1_1990_main_q14', 1990, 14, 4, 14, '四、【解】 由 $\lim_{n\to \infty}\left|\frac{a_{n + 1}}{a_n}\right| = 1$ 得幂级数的收敛半径 $R = 1$

当 $x = \pm 1$ 时， $(2n + 1)(\pm 1)^n \to \infty (n \to \infty)$ ，即 $x = \pm 1$ 时，幂级数发散，

故幂级数的收敛域为 $(-1, 1)$ .

令 $S(x) = \sum_{n=0}^{\infty}(2n+1)x^{n}$ ,

则 $S(x) = 2x\sum_{n = 1}^{\infty}nx^{n - 1} + \sum_{n = 0}^{\infty}x^{n} = 2x(\sum_{n = 1}^{\infty}x^{n})^{\prime} + \frac{1}{1 - x}$

$$
= 2 x \left(\frac {x}{1 - x}\right) ^ {\prime} + \frac {1}{1 - x} = \frac {1 + x}{(1 - x) ^ {2}}.
$$', 'E:\数学自用\数据资料\真题\按年份整理\1990\解析\1990年解析.md', 'ok', 'sequential_year_index', 0.308, '1990:14', 4, 0.308);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1990_main_q15', 'math1', 1990, '真题', 'main', 15, '# 五、（本题满分8分）

求曲面积分 $I = \iint_{\Sigma} yz \, \mathrm{d}z \, \mathrm{d}x + 2 \, \mathrm{d}x \, \mathrm{d}y$ ，其中 $\Sigma$ 是球面 $x^2 + y^2 + z^2 = 4 (z \geqslant 0)$ 的外侧.', 'E:\数学自用\数据资料\真题\按年份整理\1990\按题拆分\真题\第15题\题目.md', '1990\按题拆分\真题\第15题\题目.md', 0, 'ok', '1990 真题 第15题 # 五、（本题满分8分）

求曲面积分 $i = \iint_{\sigma} yz \, \mathrm{d}z \, \mathrm{d}x + 2 \, \mathrm{d}x \, \mathrm{d}y$ ，其中 $\sigma$ 是球面 $x^2 + y^2 + z^2 = 4 (z \geqslant 0)$ 的外侧.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1990_main_q15', 'tag_积分');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1990_main_q15', 'tag_多元函数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1990_main_q15', 'math1_1990_main_q15', 1990, 15, 5, 15, '# 五、【解】 方法一

令 $\Sigma_0: z = 0 (x^2 + y^2 \leqslant 4)$ ，取下侧，

$$
I = \iint_ {\Sigma + \Sigma_ {0}} y z \mathrm {d} z \mathrm {d} x + 2 \mathrm {d} x \mathrm {d} y - \iint_ {\Sigma_ {0}} y z \mathrm {d} z \mathrm {d} x + 2 \mathrm {d} x \mathrm {d} y,
$$

而 $\iint_{\Sigma + \Sigma_0} yz \, \mathrm{d}z \, \mathrm{d}x + 2 \, \mathrm{d}x \, \mathrm{d}y = \iiint_{\Omega} z \, \mathrm{d}v = \int_0^{2\pi} \, \mathrm{d}\theta \int_0^{\frac{\pi}{2}} \, \mathrm{d}\varphi \int_0^2 r^3 \sin \varphi \cos \varphi \, \mathrm{d}r$

$$
= 2 \pi \int_ {0} ^ {\frac {\pi}{2}} \sin \varphi \cos \varphi d \varphi \int_ {0} ^ {2} r ^ {3} d r = 4 \pi ;
$$

$$
\iint_ {\Sigma_ {0}} y z \mathrm {d} z \mathrm {d} x + 2 \mathrm {d} x \mathrm {d} y = \iint_ {\Sigma_ {0}} 2 \mathrm {d} x \mathrm {d} y = - 2 \iint_ {x ^ {2} + y ^ {2} \leqslant 4} \mathrm {d} x \mathrm {d} y = - 8 \pi ,
$$

故 $I = 12\pi$

方法二

$$
I = \iint_ {\Sigma} y z \mathrm {d} z \mathrm {d} x + 2 \mathrm {d} x \mathrm {d} y = \iint_ {\Sigma} y z \mathrm {d} z \mathrm {d} x + 2 \iint_ {\Sigma} \mathrm {d} x \mathrm {d} y,
$$

令曲面 $\Sigma$ 位于 $xOz$ 平面右侧的部分为 $\Sigma_{1}$ ，由对称性得

$$
\begin{array}{l} \iint_ {\Sigma} y z \mathrm {d} z \mathrm {d} x = 2 \iint_ {\Sigma_ {1}} y z \mathrm {d} z \mathrm {d} x = 2 \iint_ {D _ {x z}} z \sqrt {4 - x ^ {2} - z ^ {2}} \mathrm {d} z \mathrm {d} x \\ = 2 \int_ {0} ^ {\pi} \mathrm {d} \theta \int_ {0} ^ {2} r ^ {2} \sin \theta \cdot \sqrt {4 - r ^ {2}} \mathrm {d} r = 4 \int_ {0} ^ {2} r ^ {2} \sqrt {4 - r ^ {2}} \mathrm {d} r \\ \frac {r = 2 \sin t}{4} \int_ {0} ^ {\frac {\pi}{2}} 4 \sin^ {2} t \cdot 4 \cos^ {2} t d t = 6 4 \int_ {0} ^ {\frac {\pi}{2}} (\sin^ {2} t - \sin^ {4} t) d t \\ = 6 4 \left(\frac {1}{2} \cdot \frac {\pi}{2} - \frac {3}{4} \cdot \frac {1}{2} \cdot \frac {\pi}{2}\right) = 4 \pi ; \\ \end{array}
$$

$$
2 \iint_ {\Sigma} \mathrm {d} x \mathrm {d} y = 2 \iint_ {D _ {x y}} \mathrm {d} x \mathrm {d} y = 2 \times 4 \pi = 8 \pi ,
$$

故 $I = \iint_{\Sigma} yz \, \mathrm{d}z \, \mathrm{d}x + 2 \, \mathrm{d}x \, \mathrm{d}y = 12\pi.$', 'E:\数学自用\数据资料\真题\按年份整理\1990\解析\1990年解析.md', 'ok', 'sequential_year_index', 0.333, '1990:15', 5, 0.333);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1990_main_q16', 'math1', 1990, '真题', 'main', 16, '# 六、（本题满分7分）

设不恒为常数的函数 $f(x)$ 在闭区间 $[a,b]$ 上连续，在开区间 $(a,b)$ 内可导，且 $f(a) = f(b)$ ，证明：在 $(a,b)$ 内至少存在一点 $\xi$ ，使得 $f^{\prime}(\xi) > 0$', 'E:\数学自用\数据资料\真题\按年份整理\1990\按题拆分\真题\第16题\题目.md', '1990\按题拆分\真题\第16题\题目.md', 0, 'ok', '1990 真题 第16题 # 六、（本题满分7分）

设不恒为常数的函数 $f(x)$ 在闭区间 $[a,b]$ 上连续，在开区间 $(a,b)$ 内可导，且 $f(a) = f(b)$ ，证明：在 $(a,b)$ 内至少存在一点 $\xi$ ，使得 $f^{\prime}(\xi) > 0$');
