INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1990_main_q20', 'math1_1990_main_q20', 1990, 20, 1, 20, '(1)【答案】 $\left\{ \begin{array}{ll} \frac{1}{2}\mathrm{e}^{x}, & x < 0, \\ 1 - \frac{1}{2}\mathrm{e}^{-x}, & x \geqslant 0. \end{array} \right.$

【解】 $F(x) = P\{X \leqslant x\} = \int_{-\infty}^{x} f(x) \, \mathrm{d}x,$

当 $x < 0$ 时， $F(x) = \frac{1}{2}\int_{-\infty}^{x}\mathrm{e}^{x}\mathrm{d}x = \frac{1}{2}\mathrm{e}^{x}$

当 $x \geqslant 0$ 时， $F(x) = \int_{-\infty}^{0} f(x) \, \mathrm{d}x + \int_{0}^{x} f(x) \, \mathrm{d}x = \frac{1}{2} + \frac{1}{2} \int_{0}^{x} \mathrm{e}^{-x} \, \mathrm{d}x = 1 - \frac{1}{2} \mathrm{e}^{-x}$ ，

故 $F(x) = \left\{ \begin{array}{ll} \frac{1}{2}\mathrm{e}^{x}, & x < 0,\\ 1 - \frac{1}{2}\mathrm{e}^{-x}, & x\geqslant 0. \end{array} \right.$', 'E:\数学自用\数据资料\真题\按年份整理\1990\解析\1990年解析.md', 'ok', 'sequential_year_index', 0.106, '1990:20', 11, 0.213);
