INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1990_main_q23', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1990_main_q23', 'math1_1990_main_q23', 1990, 23, 11, 23, '十一、【解】区域 $D$ 的面积 $S = 1$ ，则 $(X,Y)$ 的联合概率密度为

$$
f (x, y) = \left\{ \begin{array}{l l} 1, & (x, y) \in D, \\ 0, & (x, y) \notin D. \end{array} \right.
$$

$$
f _ {X} (x) = \int_ {- \infty} ^ {+ \infty} f (x, y) d y,
$$

当 $x \leqslant 0$ 或 $x \geqslant 1$ 时， $f_{X}(x) = 0$

当 $0 < x < 1$ 时， $f_{X}(x) = \int_{-x}^{x} 1 \, \mathrm{d}y = 2x$

则随机变量 $X$ 的边缘概率密度为 $f_{X}(x) = \left\{ \begin{array}{ll}2x, & 0 < x < 1,\\ 0, & \text{其他}. \end{array} \right.$

由 $E(X) = \int_0^1 xf_X(x)\mathrm{d}x = \int_0^1 2x^2\mathrm{d}x = \frac{2}{3}$

$$
E (X ^ {2}) = \int_ {0} ^ {1} x ^ {2} f _ {X} (x) \mathrm {d} x = \int_ {0} ^ {1} 2 x ^ {3} \mathrm {d} x = \frac {1}{2}, \text {得} D (X) = \frac {1}{2} - \frac {4}{9} = \frac {1}{1 8},
$$

故 $D(Z) = D(2X + 1) = 4D(X) = \frac{2}{9}.$', 'E:\数学自用\数据资料\真题\按年份整理\1990\解析\1990年解析.md', 'ok', 'sequential_year_index', 0.098, '1990:23', 11, 0.098);
