INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1991_main_q05', 'math1_1991_main_q05', 1991, 5, 5, 5, '(5)【答案】 $\left[ \begin{array}{cccc}1 & -2 & 0 & 0\\ -2 & 5 & 0 & 0\\ 0 & 0 & \frac{1}{3} & \frac{2}{3}\\ 0 & 0 & -\frac{1}{3} & \frac{1}{3} \end{array} \right].$

【解】 令 $\pmb {B} = \left( \begin{array}{ll}5 & 2\\ 2 & 1 \end{array} \right),\pmb {C} = \left( \begin{array}{ll}1 & -2\\ 1 & 1 \end{array} \right)$ 则 $A^{-1} = \left( \begin{array}{cc}B^{-1} & O\\ O & C^{-1} \end{array} \right)$

由 $\left( \begin{array}{lll}5 & 2 & 1 & 0\\ 2 & 1 & 0 & 1 \end{array} \right)\to \left( \begin{array}{lll}1 & 0 & 1 & -2\\ 2 & 1 & 0 & 1 \end{array} \right)\to \left( \begin{array}{lll}1 & 0 & 1 & -2\\ 0 & 1 & -2 & 5 \end{array} \right),$ 得 $B^{-1} = \left( \begin{array}{cc}1 & -2\\ -2 & 5 \end{array} \right)$

由 $\left( \begin{array}{ccc}1 & -2 & 1 & 0\\ 1 & 1 & 0 & 1 \end{array} \right)\to \left( \begin{array}{ccc}1 & -2 & 1 & 0\\ 0 & 1 & -\frac{1}{3} & \frac{1}{3} \end{array} \right)\to \left( \begin{array}{ccccc}1 & 0 & \frac{1}{3} & \frac{2}{3}\\ 0 & 1 & -\frac{1}{3} & \frac{1}{3} \end{array} \right),$ 得 $C^{-1} = \left( \begin{array}{cc}\frac{1}{3} & \frac{2}{3}\\ -\frac{1}{3} & \frac{1}{3} \end{array} \right),$

故 $\mathbf{A}^{-1} = \left[ \begin{array}{rrr}1 & -2 & 0 & 0\\ -2 & 5 & 0 & 0\\ 0 & 0 & \frac{1}{3} & \frac{2}{3}\\ 0 & 0 & -\frac{1}{3} & \frac{1}{3} \end{array} \right].$

# 二、选择题', 'E:\数学自用\数据资料\真题\按年份整理\1991\解析\1991年解析.md', 'ok', 'sequential_year_index', 0.185, '1991:5', 8, 0.222);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1991_main_q06', 'math1', 1991, '真题', 'main', 6, '# 二、选择题（本题共5小题，每小题3分，满分15分）

(1) 曲线 $y = \frac{1 + \mathrm{e}^{-x^2}}{1 - \mathrm{e}^{-x^2}}$

（A）没有渐近线

（B）仅有水平渐近线

（C）仅有铅直渐近线

（D）既有水平渐近线又有铅直渐近线', 'E:\数学自用\数据资料\真题\按年份整理\1991\按题拆分\真题\第06题\题目.md', '1991\按题拆分\真题\第06题\题目.md', 0, 'ok', '1991 真题 第6题 # 二、选择题（本题共5小题，每小题3分，满分15分）

(1) 曲线 $y = \frac{1 + \mathrm{e}^{-x^2}}{1 - \mathrm{e}^{-x^2}}$

（a）没有渐近线

（b）仅有水平渐近线

（c）仅有铅直渐近线

（d）既有水平渐近线又有铅直渐近线');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1991_main_q06', 'math1_1991_main_q06', 1991, 6, 1, 6, '(1)【答案】 (D).

【解】由 $\lim_{x\to \infty}y = 1$ ，得 $y = 1$ 为曲线 $y = \frac{1 + \mathrm{e}^{-x^2}}{1 - \mathrm{e}^{-x^2}}$ 的水平渐近线；

由 $\lim_{x\to 0}y = \infty$ ，得 $x = 0$ 为曲线 $y = \frac{1 + \mathrm{e}^{-x^2}}{1 - \mathrm{e}^{-x^2}}$ 的铅直渐近线，应选(D).', 'E:\数学自用\数据资料\真题\按年份整理\1991\解析\1991年解析.md', 'ok', 'sequential_year_index', 0.218, '1991:6', 1, 0.218);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1991_main_q07', 'math1', 1991, '真题', 'main', 7, '# 二、选择题（本题共5小题，每小题3分，满分15分）

（2）若连续函数 $f(x)$ 满足关系式 $f(x) = \int_{0}^{2x} f\left(\frac{t}{2}\right) \mathrm{d}t + \ln 2$ ，则 $f(x)$ 等于（ ）.

(A) $\mathrm{e}^x\ln 2$

(B) $\mathrm{e}^{2x}\ln 2$

$\mathrm{(C)}\mathrm{e}^{x} + \ln 2$

$\mathrm{(D)}\mathrm{e}^{2x} + \ln 2$', 'E:\数学自用\数据资料\真题\按年份整理\1991\按题拆分\真题\第07题\题目.md', '1991\按题拆分\真题\第07题\题目.md', 0, 'ok', '1991 真题 第7题 # 二、选择题（本题共5小题，每小题3分，满分15分）

（2）若连续函数 $f(x)$ 满足关系式 $f(x) = \int_{0}^{2x} f\left(\frac{t}{2}\right) \mathrm{d}t + \ln 2$ ，则 $f(x)$ 等于（ ）.

(a) $\mathrm{e}^x\ln 2$

(b) $\mathrm{e}^{2x}\ln 2$

$\mathrm{(c)}\mathrm{e}^{x} + \ln 2$

$\mathrm{(d)}\mathrm{e}^{2x} + \ln 2$');
