INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1991_main_q07', 'math1_1991_main_q07', 1991, 7, 2, 7, '(2)【答案】 (B).

【解】 $f(0) = \ln 2, f(x) = \int_{0}^{2x} f\left(\frac{t}{2}\right) \mathrm{d}t + \ln 2$ 两边对 $x$ 求导得 $f''(x) = 2f(x)$ ，

解得 $f(x) = C\mathrm{e}^{-\int -2\mathrm{d}x} = C\mathrm{e}^{2x}$

由 $f(0) = \ln 2$ 得 $C = \ln 2$ ，故 $f(x) = \mathrm{e}^{2x}\ln 2$ ，应选(B).', 'E:\数学自用\数据资料\真题\按年份整理\1991\解析\1991年解析.md', 'ok', 'sequential_year_index', 0.177, '1991:7', 2, 0.177);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1991_main_q08', 'math1', 1991, '真题', 'main', 8, '# 二、选择题（本题共5小题，每小题3分，满分15分）

（3）已知级数 $\sum_{n = 1}^{\infty}(-1)^{n - 1}a_n = 2,\sum_{n = 1}^{\infty}a_{2n - 1} = 5$ ，则级数 $\sum_{n = 1}^{\infty}a_{n}$ 等于（ ）.

(A)3

(B)7

(C)8

(D)9', 'E:\数学自用\数据资料\真题\按年份整理\1991\按题拆分\真题\第08题\题目.md', '1991\按题拆分\真题\第08题\题目.md', 0, 'ok', '1991 真题 第8题 # 二、选择题（本题共5小题，每小题3分，满分15分）

（3）已知级数 $\sum_{n = 1}^{\infty}(-1)^{n - 1}a_n = 2,\sum_{n = 1}^{\infty}a_{2n - 1} = 5$ ，则级数 $\sum_{n = 1}^{\infty}a_{n}$ 等于（ ）.

(a)3

(b)7

(c)8

(d)9');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1991_main_q08', 'tag_级数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1991_main_q08', 'math1_1991_main_q08', 1991, 8, 3, 8, '（3）【答案】 (C).

【解】 令 $S_{n}^{(1)} = a_{1} + a_{3} + \dots +a_{2n - 1}$ ， $S_{n}^{(2)} = a_{2} + a_{4} + \dots +a_{2n}$

$$
S _ {2 n} ^ {(3)} = a _ {1} - a _ {2} + \dots + a _ {2 n - 1} - a _ {2 n} = S _ {n} ^ {(1)} - S _ {n} ^ {(2)}, \quad S _ {n} = a _ {1} + a _ {2} + \dots + a _ {n},
$$

由题意得 $\lim_{n\to \infty}S_n^{(1)} = 5,\lim_{n\to \infty}S_{2n}^{(3)} = 2,$

于是 $\lim_{n\to \infty}S_{n}^{(2)} = \lim_{n\to \infty}S_{n}^{(1)} - \lim_{n\to \infty}S_{2n}^{(3)} = 3,$

因为 $\lim_{n\to \infty}S_{2n} = \lim_{n\to \infty}S_n^{(1)} + \lim_{n\to \infty}S_n^{(2)} = 8$ ，所以级数 $\sum_{n = 1}^{\infty}a_{n}$ 等于8，应选(C).', 'E:\数学自用\数据资料\真题\按年份整理\1991\解析\1991年解析.md', 'ok', 'sequential_year_index', 0.224, '1991:8', 3, 0.224);
