INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1991_main_q19', 'math1_1991_main_q19', 1991, 19, 1, 19, '（1）【答案】 0.2.

【解】 显然 $X \sim N(2, \sigma^2)$ ，标准化得 $\frac{X - 2}{\sigma} \sim N(0,1)$

由 $P\{2 < X < 4\} = P\left\{0 < \frac{X - 2}{\sigma} < \frac{2}{\sigma}\right\} = \Phi \left(\frac{2}{\sigma}\right) - \Phi (0) = 0.3$ 得

$\Phi \left(\frac{2}{\sigma}\right) - 0.5 = 0.3$ ，即 $\Phi \left(\frac{2}{\sigma}\right) = 0.8.$

故 $P\{X < 0\} = P\{X \leqslant 0\} = P\left\{\frac{X - 2}{\sigma} \leqslant -\frac{2}{\sigma}\right\} = \Phi\left(-\frac{2}{\sigma}\right) = 1 - \Phi\left(\frac{2}{\sigma}\right) = 0.2.$', 'E:\数学自用\数据资料\真题\按年份整理\1991\解析\1991年解析.md', 'manual_check', 'sequential_year_index', 0, '1991:19', 8, 0.192);
