INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1991_main_q23', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1991_main_q23', 'math1_1991_main_q23', 1991, 23, 11, 21, '十一、【解】 $F_{Z}(z) = P\{Z \leqslant z\} = P\{X + 2Y \leqslant z\} = \iint_{x + 2y \leqslant z} f(x, y) \, \mathrm{d}x \, \mathrm{d}y,$

当 $z \leqslant 0$ 时， $F_Z(z) = 0$

当 $z > 0$ 时， $F_{Z}(z) = \int_{0}^{z}\mathrm{d}x\int_{0}^{\frac{z - x}{2}}2\mathrm{e}^{-(x + 2y)}\mathrm{d}y = \int_{0}^{z}\mathrm{e}^{-x}\mathrm{d}x\int_{0}^{\frac{z - x}{2}}2\mathrm{e}^{-2y}\mathrm{d}y$

$$
= \int_ {0} ^ {z} \left(\mathrm {e} ^ {- x} - \mathrm {e} ^ {- z}\right) \mathrm {d} x = 1 - \mathrm {e} ^ {- z} - z \mathrm {e} ^ {- z},
$$

故随机变量 $Z$ 的分布函数为 $F_{Z}(z) = \left\{ \begin{array}{ll}1 - \mathrm{e}^{-z} - z\mathrm{e}^{-z}, & z > 0,\\ 0, & z\leqslant 0. \end{array} \right.$', 'E:\数学自用\数据资料\真题\按年份整理\1991\解析\1991年解析.md', 'manual_check', 'similarity_fallback:0.286', 0.286, '', 11, 0.286);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1992_main_q01', 'math1', 1992, '真题', 'main', 1, '# 一、填空题（本题共5小题，每小题3分，满分15分）

（1）设函数 $y = y(x)$ 由方程 $\mathrm{e}^{x + y} + \cos (xy) = 0$ 确定，则 $\frac{\mathrm{dy}}{\mathrm{dx}} = \_ .$', 'E:\数学自用\数据资料\真题\按年份整理\1992\按题拆分\真题\第01题\题目.md', '1992\按题拆分\真题\第01题\题目.md', 0, 'ok', '1992 真题 第1题 # 一、填空题（本题共5小题，每小题3分，满分15分）

（1）设函数 $y = y(x)$ 由方程 $\mathrm{e}^{x + y} + \cos (xy) = 0$ 确定，则 $\frac{\mathrm{dy}}{\mathrm{dx}} = \_ .$');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1992_main_q01', 'math1_1992_main_q01', 1992, 1, 1, 1, '(1)【答案】 $\frac{\mathrm{e}^{x + y} - y\sin(xy)}{x\sin(xy) - \mathrm{e}^{x + y}}.$

【解】 $\mathrm{e}^{x + y} + \cos (xy) = 0$ 两边对 $x$ 求导得

$\mathrm{e}^{x + y}\cdot \left(1 + \frac{\mathrm{dy}}{\mathrm{dx}}\right) - \sin (xy)\cdot \left(y + x\frac{\mathrm{dy}}{\mathrm{dx}}\right) = 0$ ，解得 $\frac{\mathrm{dy}}{\mathrm{dx}} = \frac{\mathrm{e}^{x + y} - y\sin(xy)}{x\sin(xy) - \mathrm{e}^{x + y}}.$', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'ok', 'sequential_year_index', 0.171, '1992:1', 1, 0.171);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1992_main_q02', 'math1', 1992, '真题', 'main', 2, '# 一、填空题（本题共5小题，每小题3分，满分15分）

（2）函数 $u = \ln (x^{2} + y^{2} + z^{2})$ 在点 $M(1,2, - 2)$ 处的梯度grad $u|_{M} = \_ .$', 'E:\数学自用\数据资料\真题\按年份整理\1992\按题拆分\真题\第02题\题目.md', '1992\按题拆分\真题\第02题\题目.md', 0, 'ok', '1992 真题 第2题 # 一、填空题（本题共5小题，每小题3分，满分15分）

（2）函数 $u = \ln (x^{2} + y^{2} + z^{2})$ 在点 $m(1,2, - 2)$ 处的梯度grad $u|_{m} = \_ .$');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1992_main_q02', 'math1_1992_main_q02', 1992, 2, 2, 2, '(2)【答案】 $\left\{\frac{2}{9}, \frac{4}{9}, -\frac{4}{9}\right\}$ .

【解】 $\frac{\partial u}{\partial x} = \frac{2x}{x^2 + y^2 + z^2}, \frac{\partial u}{\partial y} = \frac{2y}{x^2 + y^2 + z^2}, \frac{\partial u}{\partial z} = \frac{2z}{x^2 + y^2 + z^2},$

$\left.\frac{\partial u}{\partial x}\right|_{M} = \frac{2}{9},\quad \left.\frac{\partial u}{\partial y}\right|_{M} = \frac{4}{9},\quad \left.\frac{\partial u}{\partial z}\right|_{M} = -\frac{4}{9}$ 则 $\mathbf{grad}u\Big|_M = \left\{\frac{2}{9},\frac{4}{9}, - \frac{4}{9}\right\} .$', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'ok', 'sequential_year_index', 0.205, '1992:2', 2, 0.205);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1992_main_q03', 'math1', 1992, '真题', 'main', 3, '# 一、填空题（本题共5小题，每小题3分，满分15分）

（3）设 $f(x) = \left\{ \begin{array}{ll} - 1, & -\pi < x \leqslant 0, \\ 1 + x^2, & 0 < x \leqslant \pi, \end{array} \right.$ 则其以 $2\pi$ 为周期的傅里叶级数在点 $x = \pi$ 处收敛于', 'E:\数学自用\数据资料\真题\按年份整理\1992\按题拆分\真题\第03题\题目.md', '1992\按题拆分\真题\第03题\题目.md', 0, 'ok', '1992 真题 第3题 # 一、填空题（本题共5小题，每小题3分，满分15分）

（3）设 $f(x) = \left\{ \begin{array}{ll} - 1, & -\pi < x \leqslant 0, \\ 1 + x^2, & 0 < x \leqslant \pi, \end{array} \right.$ 则其以 $2\pi$ 为周期的傅里叶级数在点 $x = \pi$ 处收敛于');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1992_main_q03', 'tag_级数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1992_main_q03', 'math1_1992_main_q03', 1992, 3, 3, 3, '(3)【答案】 $\frac{\pi^2}{2}$ .

【解】 $f(x)$ 的傅里叶级数在 $x = \pi$ 处收敛于

$$
\frac {f (\pi - 0) + f (\pi + 0)}{2} = \frac {f (\pi - 0) + f (- \pi + 0)}{2} = \frac {\pi^ {2}}{2}.
$$', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'ok', 'sequential_year_index', 0.138, '1992:3', 4, 0.155);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1992_main_q04', 'math1', 1992, '真题', 'main', 4, '# 一、填空题（本题共5小题，每小题3分，满分15分）

（4）微分方程 $y^\prime +y\tan x = \cos x$ 的通解为', 'E:\数学自用\数据资料\真题\按年份整理\1992\按题拆分\真题\第04题\题目.md', '1992\按题拆分\真题\第04题\题目.md', 0, 'ok', '1992 真题 第4题 # 一、填空题（本题共5小题，每小题3分，满分15分）

（4）微分方程 $y^\prime +y\tan x = \cos x$ 的通解为');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1992_main_q04', 'tag_微分方程');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1992_main_q04', 'math1_1992_main_q04', 1992, 4, 4, 4, '(4)【答案】 $y = (x + C)\cos x$ （ $C$ 为任意常数）.

【解】 微分方程 $y'' + y \tan x = \cos x$ 的通解为

$y = \left(\int \cos x\cdot \mathrm{e}^{\int \tan x\mathrm{d}x}\mathrm{d}x + C\right)\cdot \mathrm{e}^{-\int \tan x\mathrm{d}x} = (x + C)\cos x(C$ 为任意常数）.', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'ok', 'sequential_year_index', 0.323, '1992:4', 4, 0.323);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1992_main_q05', 'math1', 1992, '真题', 'main', 5, '# 一、填空题（本题共5小题，每小题3分，满分15分）

（5）设 $\mathbf{A} = \begin{bmatrix} a_{1}b_{1} & a_{1}b_{2} & \dots & a_{1}b_{n}\\ a_{2}b_{1} & a_{2}b_{2} & \dots & a_{2}b_{n}\\ \vdots & \vdots & & \vdots \\ a_{n}b_{1} & a_{n}b_{2} & \dots & a_{n}b_{n} \end{bmatrix}$ ，其中 $a_i\neq 0,b_i\neq 0,i = 1,2,\dots ,n$ ，则矩阵 $\mathbf{A}$ 的秩

$$
r (\mathbf {A}) = \underline {{\quad}}.
$$', 'E:\数学自用\数据资料\真题\按年份整理\1992\按题拆分\真题\第05题\题目.md', '1992\按题拆分\真题\第05题\题目.md', 0, 'ok', '1992 真题 第5题 # 一、填空题（本题共5小题，每小题3分，满分15分）

（5）设 $\mathbf{a} = \begin{bmatrix} a_{1}b_{1} & a_{1}b_{2} & \dots & a_{1}b_{n}\\ a_{2}b_{1} & a_{2}b_{2} & \dots & a_{2}b_{n}\\ \vdots & \vdots & & \vdots \\ a_{n}b_{1} & a_{n}b_{2} & \dots & a_{n}b_{n} \end{bmatrix}$ ，其中 $a_i\neq 0,b_i\neq 0,i = 1,2,\dots ,n$ ，则矩阵 $\mathbf{a}$ 的秩

$$
r (\mathbf {a}) = \underline {{\quad}}.
$$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1992_main_q05', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1992_main_q05', 'math1_1992_main_q05', 1992, 5, 5, 5, '（5）【答案】1.

【解】方法一 因为 $\mathbf{A}$ 的任意两行都成比例，所以 $r(\mathbf{A})\leqslant 1$

又因为 $\mathbf{A} \neq \mathbf{0}$ , 所以 $r(\mathbf{A}) \geqslant 1$ , 故 $r(\mathbf{A}) = 1$

方法二

$$
\mathbf {A} = \left[ \begin{array}{c} {a _ {1}} \\ {a _ {2}} \\ {\vdots} \\ {a _ {n}} \end{array} \right] (b _ {1}, b _ {2}, \dots , b _ {n}) = \pmb {\alpha} \pmb {\beta} ^ {\mathrm {T}}, \text {其 中} \pmb {\alpha} = \left[ \begin{array}{c} {a _ {1}} \\ {a _ {2}} \\ {\vdots} \\ {a _ {n}} \end{array} \right], \pmb {\beta} = \left[ \begin{array}{c} {b _ {1}} \\ {b _ {2}} \\ {\vdots} \\ {b _ {n}} \end{array} \right],
$$

$$
r (\mathbf {A}) = r (\boldsymbol {\alpha} \boldsymbol {\beta} ^ {\mathrm {T}}) \leqslant r (\boldsymbol {\alpha}) = 1,
$$

再由 $a_{i}\neq 0,b_{i}\neq 0,i = 1,2,\dots ,n$ 得 $\mathbf{A}\neq \mathbf{O}$ ，于是 $r(A)\geqslant 1$ ，故 $r(A) = 1$

# 二、选择题', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'ok', 'sequential_year_index', 0.187, '1992:5', 5, 0.187);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1992_main_q06', 'math1', 1992, '真题', 'main', 6, '# 二、选择题（本题共5小题，每小题3分，满分15分）

（1）当 $x\to 1$ 时，函数 $\frac{x^2 - 1}{x - 1}\mathrm{e}^{\frac{1}{x - 1}}$ 的极限（ ）.

（A）等于2

（B）等于0

（C）为 $\infty$

(D) 不存在但不是 $\infty$', 'E:\数学自用\数据资料\真题\按年份整理\1992\按题拆分\真题\第06题\题目.md', '1992\按题拆分\真题\第06题\题目.md', 0, 'ok', '1992 真题 第6题 # 二、选择题（本题共5小题，每小题3分，满分15分）

（1）当 $x\to 1$ 时，函数 $\frac{x^2 - 1}{x - 1}\mathrm{e}^{\frac{1}{x - 1}}$ 的极限（ ）.

（a）等于2

（b）等于0

（c）为 $\infty$

(d) 不存在但不是 $\infty$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1992_main_q06', 'tag_极限');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1992_main_q06', 'math1_1992_main_q06', 1992, 6, 1, 6, '(1)【答案】 (D).

【解】由 $\lim_{x\to 1^{-}}\frac{x^2 - 1}{x - 1}\mathrm{e}^{\frac{1}{x - 1}} = 2\lim_{x\to 1^{-}}\mathrm{e}^{\frac{1}{x - 1}} = 0,$ $\lim_{x\to 1^{+}}\frac{x^2 - 1}{x - 1}\mathrm{e}^{\frac{1}{x - 1}} = 2\lim_{x\to 1^{+}}\mathrm{e}^{\frac{1}{x - 1}} = +\infty ,$

得 $\lim_{x\to 1}\frac{x^2 - 1}{x - 1}\mathrm{e}^{\frac{1}{x - 1}}$ 不存在但不是 $\infty$ ，应选(D).', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'ok', 'sequential_year_index', 0.189, '1992:6', 1, 0.189);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1992_main_q07', 'math1', 1992, '真题', 'main', 7, '# 二、选择题（本题共5小题，每小题3分，满分15分）

(2) 级数 $\sum_{n=1}^{\infty}(-1)^{n}(1-\cos \frac{\alpha}{n})$ (常数 $\alpha > 0$ )

（A）发散

（B）条件收敛

（C）绝对收敛

(D)收敛性与 $\alpha$ 有关', 'E:\数学自用\数据资料\真题\按年份整理\1992\按题拆分\真题\第07题\题目.md', '1992\按题拆分\真题\第07题\题目.md', 0, 'ok', '1992 真题 第7题 # 二、选择题（本题共5小题，每小题3分，满分15分）

(2) 级数 $\sum_{n=1}^{\infty}(-1)^{n}(1-\cos \frac{\alpha}{n})$ (常数 $\alpha > 0$ )

（a）发散

（b）条件收敛

（c）绝对收敛

(d)收敛性与 $\alpha$ 有关');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1992_main_q07', 'tag_级数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1992_main_q07', 'math1_1992_main_q07', 1992, 7, 2, 7, '（2）【答案】 (C).

【解】 $\left|(-1)^n\left(1 - \cos \frac{\alpha}{n}\right)\right| = 2\sin^2\frac{\alpha}{2n} \sim \frac{\alpha^2}{2} \cdot \frac{1}{n^2},$

因为 $\sum_{n=1}^{\infty} \frac{\alpha^2}{2} \cdot \frac{1}{n^2}$ 收敛，所以 $\sum_{n=1}^{\infty} \left| (-1)^n \left(1 - \cos \frac{\alpha}{n}\right) \right|$ 收敛，即 $\sum_{n=1}^{\infty} (-1)^n \left(1 - \cos \frac{\alpha}{n}\right)$ 绝对收敛，应选(C).', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'ok', 'sequential_year_index', 0.12, '1992:7', 2, 0.12);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1992_main_q08', 'math1', 1992, '真题', 'main', 8, '# 二、选择题（本题共5小题，每小题3分，满分15分）

（3）在曲线 $x = t,y = -t^2,z = t^3$ 的所有切线中，与平面 $x + 2y + z = 4$ 平行的切线（ ）.

（A）只有1条

（B）只有2条

（C）至少3条

(D) 不存在', 'E:\数学自用\数据资料\真题\按年份整理\1992\按题拆分\真题\第08题\题目.md', '1992\按题拆分\真题\第08题\题目.md', 0, 'ok', '1992 真题 第8题 # 二、选择题（本题共5小题，每小题3分，满分15分）

（3）在曲线 $x = t,y = -t^2,z = t^3$ 的所有切线中，与平面 $x + 2y + z = 4$ 平行的切线（ ）.

（a）只有1条

（b）只有2条

（c）至少3条

(d) 不存在');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1992_main_q08', 'math1_1992_main_q08', 1992, 8, 3, 8, '（3）【答案】 （B）.

【解】 曲线的切线向量为 $\pmb{T} = \{1, -2t, 3t^2\}$

由 $\{1, -2t, 3t^2\} \cdot \{1, 2, 1\} = 0$ 得 $t_1 = \frac{1}{3}, t_2 = 1$ ，故与平面 $x + 2y + z = 4$ 平行的切线有2条，应选(B).', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'ok', 'sequential_year_index', 0.176, '1992:8', 3, 0.176);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1992_main_q09', 'math1', 1992, '真题', 'main', 9, '# 二、选择题（本题共5小题，每小题3分，满分15分）

（4）设 $f(x) = 3x^{3} + x^{2}|x|$ ，则使 $f^{(n)}(0)$ 存在的最高阶数 $n$ 为（ ）.

(A)0

(B)1

(C)2

(D)3', 'E:\数学自用\数据资料\真题\按年份整理\1992\按题拆分\真题\第09题\题目.md', '1992\按题拆分\真题\第09题\题目.md', 0, 'ok', '1992 真题 第9题 # 二、选择题（本题共5小题，每小题3分，满分15分）

（4）设 $f(x) = 3x^{3} + x^{2}|x|$ ，则使 $f^{(n)}(0)$ 存在的最高阶数 $n$ 为（ ）.

(a)0

(b)1

(c)2

(d)3');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1992_main_q09', 'math1_1992_main_q09', 1992, 9, 4, 9, '（4）【答案】 (C).

【解】 $f(x) = \left\{ \begin{array}{ll}2x^{3}, & x < 0,\\ 4x^{3}, & x\geqslant 0, \end{array} \right.$ $f^{\prime}(x) = \left\{ \begin{array}{ll}6x^{2}. & x < 0,\\ 12x^{2}, & x > 0, \end{array} \right.$

显然 $f^{\prime}(0) = f^{\prime \prime}(0) = 0$ ， $f''''(x) = \left\{ \begin{array}{ll}12x, & x <   0,\\ 24x, & x\geqslant 0, \end{array} \right.$

$$
f _ {-} ^ {\prime \prime} (0) = \lim  _ {x \rightarrow 0 ^ {-}} \frac {f ^ {\prime \prime} (x)}{x} = 1 2, \quad f _ {+} ^ {\prime \prime} (0) = \lim  _ {x \rightarrow 0 ^ {+}} \frac {f ^ {\prime \prime} (x)}{x} = 2 4,
$$

因为 $f_{-}^{\prime \prime}(0)\neq f_{+}^{\prime \prime}(0)$ ，所以 $f^{(n)}(0)$ 存在的最高阶数 $n = 2$ ，应选(C).', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'ok', 'sequential_year_index', 0.224, '1992:9', 4, 0.224);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1992_main_q10', 'math1', 1992, '真题', 'main', 10, '# 二、选择题（本题共5小题，每小题3分，满分15分）

（5）要使 $\pmb{\xi}_{1} = \begin{pmatrix} 1 \\ 0 \\ 2 \end{pmatrix}, \pmb{\xi}_{2} = \begin{pmatrix} 0 \\ 1 \\ -1 \end{pmatrix}$ 都是线性方程组 $AX = 0$ 的解，只要系数矩阵 $\mathbf{A}$ 为（ ）.

(A)(-2 1 1)

(B) $\begin{pmatrix} 2 & 0 & -1 \\ 0 & 1 & 1 \end{pmatrix}$

（C） $\left( \begin{array}{rrr} - 1 & 0 & 2\\ 0 & 1 & -1 \end{array} \right)$

(D) $\begin{pmatrix} 0 & 1 & -1 \\ 4 & -2 & -2 \\ 0 & 1 & 1 \end{pmatrix}$', 'E:\数学自用\数据资料\真题\按年份整理\1992\按题拆分\真题\第10题\题目.md', '1992\按题拆分\真题\第10题\题目.md', 0, 'ok', '1992 真题 第10题 # 二、选择题（本题共5小题，每小题3分，满分15分）

（5）要使 $\pmb{\xi}_{1} = \begin{pmatrix} 1 \\ 0 \\ 2 \end{pmatrix}, \pmb{\xi}_{2} = \begin{pmatrix} 0 \\ 1 \\ -1 \end{pmatrix}$ 都是线性方程组 $ax = 0$ 的解，只要系数矩阵 $\mathbf{a}$ 为（ ）.

(a)(-2 1 1)

(b) $\begin{pmatrix} 2 & 0 & -1 \\ 0 & 1 & 1 \end{pmatrix}$

（c） $\left( \begin{array}{rrr} - 1 & 0 & 2\\ 0 & 1 & -1 \end{array} \right)$

(d) $\begin{pmatrix} 0 & 1 & -1 \\ 4 & -2 & -2 \\ 0 & 1 & 1 \end{pmatrix}$');
