【解】因为 $\xi_{1}$ 与 $\xi_{2}$ 线性无关，所以三元齐次线性方程组 $AX = 0$ 的基础解系中至少含2个解向量，即 $3 - r(A)\geqslant 2$ ，得 $r(\mathbf{A})\leqslant 1$ ，而选项(B)(C)(D)中矩阵的秩都大于1，所以均不对，只有选项（A）正确.三、', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'manual_check', 'sequential_year_index', 0.076, '1992:10', 8, 0.109);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1992_main_q11', 'math1', 1992, '真题', 'main', 11, '# 三、(本题共3小题，每小题5分，满分15分)

（1）求 $\lim_{x\to 0}\frac{\mathrm{e}^x - \sin x - 1}{1 - \sqrt{1 - x^2}}.$', 'E:\数学自用\数据资料\真题\按年份整理\1992\按题拆分\真题\第11题\题目.md', '1992\按题拆分\真题\第11题\题目.md', 0, 'ok', '1992 真题 第11题 # 三、(本题共3小题，每小题5分，满分15分)

（1）求 $\lim_{x\to 0}\frac{\mathrm{e}^x - \sin x - 1}{1 - \sqrt{1 - x^2}}.$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1992_main_q11', 'tag_极限');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1992_main_q11', 'math1_1992_main_q11', 1992, 11, 1, 11, '(1)【解】由 $1 - \sqrt{1 - x^2} = -[(1 - x^2)^{\frac{1}{2}} - 1] \sim \frac{1}{2} x^2 (x \to 0)$ ，得

$$
\lim  _ {x \rightarrow 0} \frac {\mathrm {e} ^ {x} - \sin x - 1}{1 - \sqrt {1 - x ^ {2}}} = \lim  _ {x \rightarrow 0} \frac {\mathrm {e} ^ {x} - \sin x - 1}{\frac {1}{2} x ^ {2}} = \lim  _ {x \rightarrow 0} \frac {\mathrm {e} ^ {x} - \cos x}{x} = \lim  _ {x \rightarrow 0} (\mathrm {e} ^ {x} + \sin x) = 1.
$$', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'ok', 'sequential_year_index', 0.296, '1992:11', 1, 0.296);
