INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1992_main_q12', 'math1_1992_main_q12', 1992, 12, 2, 12, '(2)【解】 $\frac{\partial z}{\partial x} = f_1'' \cdot \mathrm{e}^x \sin y + 2xf_2''$ ,

$$
\begin{array}{l} \frac {\partial^ {2} z}{\partial x \partial y} = e ^ {x} \sin y \cdot \left(f _ {1 1} ^ {\prime \prime} \cdot e ^ {x} \cos y + 2 y f _ {1 2} ^ {\prime \prime}\right) + f _ {1} ^ {\prime} \cdot e ^ {x} \cos y + 2 x \left(f _ {2 1} ^ {\prime \prime} \cdot e ^ {x} \cos y + 2 y f _ {2 2} ^ {\prime \prime}\right) \\ = \frac {1}{2} e ^ {2 x} \sin 2 y \cdot f _ {1 1} ^ {\prime \prime} + 2 e ^ {x} (y \sin y + x \cos y) f _ {1 2} ^ {\prime \prime} + f _ {1} ^ {\prime} \cdot e ^ {x} \cos y + 4 x y f _ {2 2} ^ {\prime \prime}. \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'ok', 'sequential_year_index', 0.093, '1992:12', 2, 0.093);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1992_main_q13', 'math1', 1992, '真题', 'main', 13, '# 三、(本题共3小题，每小题5分，满分15分)

(3) 设 $f(x) = \begin{cases} 1 + x^2, & x \leqslant 0, \\ \mathrm{e}^{-x}, & x > 0, \end{cases}$ 求 $\int_{1}^{3} f(x - 2) \, \mathrm{d}x$ .', 'E:\数学自用\数据资料\真题\按年份整理\1992\按题拆分\真题\第13题\题目.md', '1992\按题拆分\真题\第13题\题目.md', 0, 'ok', '1992 真题 第13题 # 三、(本题共3小题，每小题5分，满分15分)

(3) 设 $f(x) = \begin{cases} 1 + x^2, & x \leqslant 0, \\ \mathrm{e}^{-x}, & x > 0, \end{cases}$ 求 $\int_{1}^{3} f(x - 2) \, \mathrm{d}x$ .');
