$$
= \int_ {- 1} ^ {0} (1 + x ^ {2}) \mathrm {d} x + \int_ {0} ^ {1} \mathrm {e} ^ {- x} \mathrm {d} x = \frac {7}{3} - \frac {1}{\mathrm {e}}.
$$', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'ok', 'sequential_year_index', 0.14, '1992:13', 1, 0.163);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1992_main_q14', 'math1', 1992, '真题', 'main', 14, '# 四、（本题满分6分）

求微分方程 $y^{\prime \prime} + 2y^{\prime} - 3y = \mathrm{e}^{-3x}$ 的通解', 'E:\数学自用\数据资料\真题\按年份整理\1992\按题拆分\真题\第14题\题目.md', '1992\按题拆分\真题\第14题\题目.md', 0, 'ok', '1992 真题 第14题 # 四、（本题满分6分）

求微分方程 $y^{\prime \prime} + 2y^{\prime} - 3y = \mathrm{e}^{-3x}$ 的通解');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1992_main_q14', 'tag_微分方程');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1992_main_q14', 'math1_1992_main_q14', 1992, 14, 4, 14, '四、【解】 特征方程为 $\lambda^2 + 2\lambda - 3 = 0$ ，特征根为 $\lambda_1 = -3, \lambda_2 = 1$

$y^{\prime \prime} + 2y^{\prime} - 3y = 0$ 的通解为 $y = C_1\mathrm{e}^{-3x} + C_2\mathrm{e}^x$

令 $y^{\prime \prime} + 2y^{\prime} - 3y = \mathrm{e}^{-3x}$ 的特解为 $y_0(x) = ax\mathrm{e}^{-3x}$ ，代入得 $a = -\frac{1}{4}$

故 $y^{\prime \prime} + 2y^{\prime} - 3y = \mathrm{e}^{-3x}$ 的通解为

$y = C_{1}\mathrm{e}^{-3x} + C_{2}\mathrm{e}^{x} - \frac{1}{4} x\mathrm{e}^{-3x}(C_{1},C_{2}$ 为任意常数）.', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'ok', 'sequential_year_index', 0.429, '1992:14', 4, 0.429);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1992_main_q15', 'math1', 1992, '真题', 'main', 15, '# 五、（本题满分8分）

计算曲面积分 $I = \iint_{\Sigma} (x^3 + az^2) \, \mathrm{d}y \, \mathrm{d}z + (y^3 + ax^2) \, \mathrm{d}z \, \mathrm{d}x + (z^3 + ay^2) \, \mathrm{d}x \, \mathrm{d}y$ ，其中 $\Sigma$ 为上半球面 $z = \sqrt{a^2 - x^2 - y^2}$ 的上侧.', 'E:\数学自用\数据资料\真题\按年份整理\1992\按题拆分\真题\第15题\题目.md', '1992\按题拆分\真题\第15题\题目.md', 0, 'ok', '1992 真题 第15题 # 五、（本题满分8分）

计算曲面积分 $i = \iint_{\sigma} (x^3 + az^2) \, \mathrm{d}y \, \mathrm{d}z + (y^3 + ax^2) \, \mathrm{d}z \, \mathrm{d}x + (z^3 + ay^2) \, \mathrm{d}x \, \mathrm{d}y$ ，其中 $\sigma$ 为上半球面 $z = \sqrt{a^2 - x^2 - y^2}$ 的上侧.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1992_main_q15', 'tag_积分');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1992_main_q15', 'tag_多元函数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1992_main_q15', 'math1_1992_main_q15', 1992, 15, 5, 15, '五、【解】补充 $\Sigma_{1}:z = 0(x^{2} + y^{2}\leqslant a^{2})$ ，取下侧，

$$
I = \iint_ {\Sigma} (x ^ {3} + a z ^ {2}) d y d z + (y ^ {3} + a x ^ {2}) d z d x + (z ^ {3} + a y ^ {2}) d x d y
$$

$$
= \left(\iint_ {\Sigma + \Sigma_ {1}} - \iint_ {\Sigma_ {1}}\right) (x ^ {3} + a z ^ {2}) d y d z + (y ^ {3} + a x ^ {2}) d z d x + (z ^ {3} + a y ^ {2}) d x d y,
$$

而 $\iint_{\Sigma + \Sigma_1} (x^3 + az^2) \, \mathrm{d}y \, \mathrm{d}z + (y^3 + ax^2) \, \mathrm{d}z \, \mathrm{d}x + (z^3 + ay^2) \, \mathrm{d}x \, \mathrm{d}y$

$$
\begin{array}{l} = 3 \iiint_ {\Omega} \left(x ^ {2} + y ^ {2} + z ^ {2}\right) \mathrm {d} v = 3 \int_ {0} ^ {2 \pi} \mathrm {d} \theta \int_ {0} ^ {\frac {\pi}{2}} \mathrm {d} \varphi \int_ {0} ^ {a} r ^ {4} \sin \varphi \mathrm {d} r = \frac {6 \pi}{5} a ^ {5}, \\ \iint_ {x _ {1}} \left(x ^ {3} + a z ^ {2}\right) d y d z + \left(y ^ {3} + a x ^ {2}\right) d z d x + \left(z ^ {3} + a y ^ {2}\right) d x d y \\ = \iint_ {\Sigma_ {1}} a y ^ {2} d x d y = - a \iint_ {x ^ {2} + y ^ {2} \leqslant a ^ {2}} y ^ {2} d x d y = - \frac {a}{2} \iint_ {x ^ {2} + y ^ {2} \leqslant a ^ {2}} (x ^ {2} + y ^ {2}) d x d y \\ = - \frac {a}{2} \int_ {0} ^ {2 \pi} \mathrm {d} \theta \int_ {0} ^ {a} r ^ {3} \mathrm {d} r = - \frac {\pi}{4} a ^ {5}, \\ \end{array}
$$

故 $\iint_{\Sigma} (x^3 + az^2) \, \mathrm{d}y \, \mathrm{d}z + (y^3 + ax^2) \, \mathrm{d}z \, \mathrm{d}x + (z^3 + ay^2) \, \mathrm{d}x \, \mathrm{d}y = \frac{6\pi}{5} a^5 + \frac{\pi}{4} a^5 = \frac{29}{20}\pi a^5.$', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'ok', 'sequential_year_index', 0.536, '1992:15', 5, 0.536);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1992_main_q16', 'math1', 1992, '真题', 'main', 16, '# 六、（本题满分7分）

设 $f^{\prime \prime}(x) < 0, f(0) = 0$ ，证明：对任意的 $x_{1} > 0, x_{2} > 0$ ，有 $f(x_{1} + x_{2}) < f(x_{1}) + f(x_{2})$', 'E:\数学自用\数据资料\真题\按年份整理\1992\按题拆分\真题\第16题\题目.md', '1992\按题拆分\真题\第16题\题目.md', 0, 'ok', '1992 真题 第16题 # 六、（本题满分7分）

设 $f^{\prime \prime}(x) < 0, f(0) = 0$ ，证明：对任意的 $x_{1} > 0, x_{2} > 0$ ，有 $f(x_{1} + x_{2}) < f(x_{1}) + f(x_{2})$');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1992_main_q16', 'math1_1992_main_q16', 1992, 16, 6, 16, '六、【解】 不妨设 $0 < x_{1} < x_{2}$ ，由拉格朗日中值定理得

$f(x_{1}) = f(x_{1}) - f(0) = f^{\prime}(\xi_{1})x_{1}$ ，其中 $0 < \xi_{1} < x_{1}$

$f(x_{1} + x_{2}) - f(x_{2}) = f^{\prime}(\xi_{2})x_{1}$ ，其中 $x_{2} <   \xi_{2} <   x_{1} + x_{2}$

因为 $f''''(x) < 0$ ，所以 $f''(x)$ 单调递减，又因为 $\xi_1 < \xi_2$ ，所以 $f''(\xi_1) > f''(\xi_2)$

即 $f(x_{1}) > f(x_{1} + x_{2}) - f(x_{2})$ ，故 $f(x_{1} + x_{2}) <   f(x_{1}) + f(x_{2}).$', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'ok', 'sequential_year_index', 0.257, '1992:16', 6, 0.257);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1992_main_q17', 'math1', 1992, '真题', 'main', 17, '# 七、(本题满分8分)

在变力 $F = yz\mathbf{i} + zx\mathbf{j} + xy\mathbf{k}$ 的作用下，质点由原点沿直线运动到椭球面 $\frac{x^2}{a^2} + \frac{y^2}{b^2} + \frac{z^2}{c^2} = 1$ 上第一卦限的点 $M(\xi, \eta, \zeta)$ ，问：当 $\xi, \eta, \zeta$ 取何值时，力 $F$ 所做的功 $W$ 最大？并求出 $W$ 的最大值.', 'E:\数学自用\数据资料\真题\按年份整理\1992\按题拆分\真题\第17题\题目.md', '1992\按题拆分\真题\第17题\题目.md', 0, 'ok', '1992 真题 第17题 # 七、(本题满分8分)

在变力 $f = yz\mathbf{i} + zx\mathbf{j} + xy\mathbf{k}$ 的作用下，质点由原点沿直线运动到椭球面 $\frac{x^2}{a^2} + \frac{y^2}{b^2} + \frac{z^2}{c^2} = 1$ 上第一卦限的点 $m(\xi, \eta, \zeta)$ ，问：当 $\xi, \eta, \zeta$ 取何值时，力 $f$ 所做的功 $w$ 最大？并求出 $w$ 的最大值.');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1992_main_q17', 'math1_1992_main_q17', 1992, 17, 7, 17, '七、【解】 直线段 $OM: x = \xi t, y = \eta t, z = \zeta t, t$ 从0到1，功 $W$ 为

$$
W = \int_ {O M} y z \mathrm {d} x + z x \mathrm {d} y + x y \mathrm {d} z = \int_ {0} ^ {1} 3 \xi \eta \zeta t ^ {2} \mathrm {d} t = \xi \eta \zeta .
$$

下面求 $W = \xi \eta \zeta$ 在条件 $\frac{\xi^2}{a^2} +\frac{\eta^2}{b^2} +\frac{\zeta^2}{c^2} = 1(\xi \geqslant 0,\eta \geqslant 0,\zeta \geqslant 0)$ 下的最大值.

令 $F(\xi, \eta, \zeta, \lambda) = \xi \eta \zeta + \lambda \left(1 - \frac{\xi^2}{a^2} - \frac{\eta^2}{b^2} - \frac{\zeta^2}{c^2}\right)$ .

由 $\left\{ \begin{array}{l} \frac{\partial F}{\partial \xi} = 0, \\ \frac{\partial F}{\partial \eta} = 0, \\ \frac{\partial F}{\partial \zeta} = 0, \\ \frac{\partial F}{\partial \lambda} = 0, \end{array} \right.$ 得 $\left\{ \begin{array}{l} \eta \zeta = \frac{2\lambda}{a^2} \xi, \\ \xi \zeta = \frac{2\lambda}{b^2} \eta, \\ \xi \eta = \frac{2\lambda}{c^2} \zeta, \\ 1 - \frac{\xi^2}{a^2} - \frac{\eta^2}{b^2} - \frac{\zeta^2}{c^2} = 0. \end{array} \right.$

从而 $\frac{\xi^2}{a^2} = \frac{\eta^2}{b^2} = \frac{\zeta^2}{c^2}$ ，即得 $\frac{\xi^2}{a^2} = \frac{\eta^2}{b^2} = \frac{\zeta^2}{c^2} = \frac{1}{3}$ 。于是得

$$
\xi = \frac {a}{\sqrt {3}}, \quad \eta = \frac {b}{\sqrt {3}}, \quad \zeta = \frac {c}{\sqrt {3}},
$$

由问题的实际意义知 $W_{\max} = \frac{\sqrt{3}}{9} abc$', 'E:\数学自用\数据资料\真题\按年份整理\1992\解析\1992年解析.md', 'manual_check', 'sequential_year_index', 0.075, '1992:17', 7, 0.075);
