INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1993_main_q18', 'math1_1993_main_q18', 1993, 18, 8, 18, '八、【证明】 显然 $r(\mathbf{AB}) = n$

由 $r(\mathbf{AB}) \leqslant r(\mathbf{A}), r(\mathbf{AB}) \leqslant r(\mathbf{B})$ 得 $r(\mathbf{A}) \geqslant n, r(\mathbf{B}) \geqslant n$ .

因为矩阵的秩不超过其行数及列数，所以 $r(\mathbf{A}) \leqslant n, r(\mathbf{B}) \leqslant n$ ，于是 $r(\mathbf{B}) = n$

因为矩阵的秩与矩阵的行向量组的秩、列向量组的秩都相等，所以矩阵 $\pmb{B}$ 的列向量组的秩为 $n$ ，故矩阵 $\pmb{B}$ 的列向量组线性无关.', 'E:\数学自用\数据资料\真题\按年份整理\1993\解析\1993年解析.md', 'manual_check', 'sequential_year_index', 0, '1993:18', 7, 0.118);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1993_main_q19', 'math1', 1993, '真题', 'main', 19, '# 八、（本题满分6分）

设 $\mathbf{A}$ 是 $n\times m$ 矩阵， $\pmb{B}$ 是 $m\times n$ 矩阵，其中 $n <   m,E$ 是 $n$ 阶单位矩阵，若 $\mathbf{AB} = \mathbf{E}$ ，证明 $\pmb{B}$ 的列向量组线性无关.', 'E:\数学自用\数据资料\真题\按年份整理\1993\按题拆分\真题\第19题\题目.md', '1993\按题拆分\真题\第19题\题目.md', 0, 'ok', '1993 真题 第19题 # 八、（本题满分6分）

设 $\mathbf{a}$ 是 $n\times m$ 矩阵， $\pmb{b}$ 是 $m\times n$ 矩阵，其中 $n <   m,e$ 是 $n$ 阶单位矩阵，若 $\mathbf{ab} = \mathbf{e}$ ，证明 $\pmb{b}$ 的列向量组线性无关.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1993_main_q19', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1993_main_q19', 'math1_1993_main_q19', 1993, 19, 9, 19, '九、【解】 轨迹如右图所示.设在时刻 $t,B$ 位于点 $(x,y)$ 处，则

$$
\frac {\mathrm {d} y}{\mathrm {d} x} = \frac {(1 + v t) - y}{- x}.
$$

上式两边对 $x$ 求导，得

$$
x \frac {\mathrm {d} ^ {2} y}{\mathrm {d} x ^ {2}} = - v \frac {\mathrm {d} t}{\mathrm {d} x}.
$$

由于

（\*）

![](images/870089ab4858899c01599f7459e6d66e41281e7d312e9a3fa455be6746dbe2b8.jpg)  
九题图

$$
\begin{array}{l} 2 v = \frac {\mathrm {d} s}{\mathrm {d} t} = \sqrt {1 + \left(\frac {\mathrm {d} y}{\mathrm {d} x}\right) ^ {2}} \cdot \frac {\mathrm {d} x}{\mathrm {d} t}, \\ \frac {\mathrm {d} t}{\mathrm {d} x} = \frac {1}{2 v} \sqrt {1 + \left(\frac {\mathrm {d} y}{\mathrm {d} x}\right) ^ {2}}, \\ \end{array}
$$

将上式代入 $(\ast)$ 式，得到所求的微分方程为

$$
x \frac {\mathrm {d} ^ {2} y}{\mathrm {d} x ^ {2}} + \frac {1}{2} \sqrt {1 + \left(\frac {\mathrm {d} y}{\mathrm {d} x}\right) ^ {2}} = 0,
$$

其初值条件为 $y|_{x = -1} = 0, y''|_{x = -1} = 1.$

# 十、填空题', 'E:\数学自用\数据资料\真题\按年份整理\1993\解析\1993年解析.md', 'manual_check', 'sequential_year_index', 0, '1993:19', 8, 0.196);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1993_main_q20', 'math1', 1993, '真题', 'main', 20, '# 九、（本题满分6分）

设物体 $A$ 从点 $(0,1)$ 出发，以速度大小为常数 $v$ 沿 $y$ 轴正向运动，物体 $B$ 从点 $(-1,0)$ 与 $A$ 同时出发，其速度大小为 $2v$ ，方向始终指向 $A$ ，试建立物体 $B$ 的运动轨迹所满足的微分方程，并写出初始条件.', 'E:\数学自用\数据资料\真题\按年份整理\1993\按题拆分\真题\第20题\题目.md', '1993\按题拆分\真题\第20题\题目.md', 0, 'ok', '1993 真题 第20题 # 九、（本题满分6分）

设物体 $a$ 从点 $(0,1)$ 出发，以速度大小为常数 $v$ 沿 $y$ 轴正向运动，物体 $b$ 从点 $(-1,0)$ 与 $a$ 同时出发，其速度大小为 $2v$ ，方向始终指向 $a$ ，试建立物体 $b$ 的运动轨迹所满足的微分方程，并写出初始条件.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1993_main_q20', 'tag_微分方程');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1993_main_q20', 'math1_1993_main_q20', 1993, 20, 1, 20, '(1)【答案】 $\frac{1}{6}$ .

【解】设 $A_{1} = \{$ 第一次取到正品 $\}$ , $A_{2} = \{$ 第一次取到次品 $\}$ , $B = \{$ 第二次取到次品 $\}$ ,

$P(A_{1}) = \frac{10}{12},\quad P(A_{2}) = \frac{2}{12},\quad P(B\mid A_{1}) = \frac{2}{11},\quad P(B\mid A_{2}) = \frac{1}{11}$ ，则

$$
\begin{array}{l} P (B) = P \left(A _ {1}\right) P \left(B \mid A _ {1}\right) + P \left(A _ {2}\right) P \left(B \mid A _ {2}\right) \\ = \frac {1 0}{1 2} \times \frac {2}{1 1} + \frac {2}{1 2} \times \frac {1}{1 1} = \frac {2}{1 2} = \frac {1}{6}. \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\1993\解析\1993年解析.md', 'manual_check', 'sequential_year_index', 0, '1993:20', 9, 0.037);
