F _ {X} (1) = P \{X \leqslant 1 \} = \frac {1}{2} \int_ {- \infty} ^ {1} e ^ {- | x |} d x = \frac {1}{2} + \frac {1}{2} \int_ {0} ^ {1} e ^ {- x} d x = 1 - \frac {1}{2 e},
