INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1995_main_q18', 'math1_1995_main_q18', 1995, 18, 8, 18, '八、【解】设 $\pmb {\xi} = (x_{1},x_{2},x_{3})^{\mathrm{T}}$ 为 $\lambda_{2} = \lambda_{3} = 1$ 对应的特征向量，

由 $\xi_1^{\mathrm{T}}\xi = 0$ 得 $x_{2} + x_{3} = 0$ ，则 $\lambda_{2} = \lambda_{3} = 1$ 对应的线性无关的特征向量为

$$
\pmb {\xi} _ {2} = \left( \begin{array}{c} 1 \\ 0 \\ 0 \end{array} \right), \quad \pmb {\xi} _ {3} = \left( \begin{array}{c} 0 \\ 1 \\ - 1 \end{array} \right),
$$

令 $\pmb{P} = \left( \begin{array}{rrr}0 & 1 & 0\\ 1 & 0 & 1\\ 1 & 0 & -1 \end{array} \right)$ ，由 $\pmb{P}^{-1}\pmb {A}\pmb {P} = \left( \begin{array}{rrr} - 1 & 0 & 0\\ 0 & 1 & 0\\ 0 & 0 & 1 \end{array} \right)$ 得

$$
\mathbf {A} = \mathbf {P} \left( \begin{array}{c c c} - 1 & 0 & 0 \\ 0 & 1 & 0 \\ 0 & 0 & 1 \end{array} \right) \mathbf {P} ^ {- 1} = \left( \begin{array}{c c c} 1 & 0 & 0 \\ 0 & 0 & - 1 \\ 0 & - 1 & 0 \end{array} \right).
$$', 'E:\数学自用\数据资料\真题\按年份整理\1995\解析\1995年解析.md', 'manual_check', 'sequential_year_index', 0, '1995:18', 7, 0.125);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1995_main_q19', 'math1', 1995, '真题', 'main', 19, '# 八、（本题满分7分）

设3阶实对称矩阵 $\mathbf{A}$ 的特征值为 $\lambda_{1} = -1, \lambda_{2} = \lambda_{3} = 1$ ，对应于 $\lambda_{1}$ 的特征向量为 $\xi_{1} = (0,1,1)^{\mathrm{T}}$ ，求 $\mathbf{A}$', 'E:\数学自用\数据资料\真题\按年份整理\1995\按题拆分\真题\第19题\题目.md', '1995\按题拆分\真题\第19题\题目.md', 0, 'ok', '1995 真题 第19题 # 八、（本题满分7分）

设3阶实对称矩阵 $\mathbf{a}$ 的特征值为 $\lambda_{1} = -1, \lambda_{2} = \lambda_{3} = 1$ ，对应于 $\lambda_{1}$ 的特征向量为 $\xi_{1} = (0,1,1)^{\mathrm{t}}$ ，求 $\mathbf{a}$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1995_main_q19', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1995_main_q19', 'math1_1995_main_q19', 1995, 19, 9, 19, '九、【解】方法一 由 $\mathbf{A}\mathbf{A}^{\mathrm{T}} = \mathbf{E}$ 得 $|\mathbf{A}|\cdot |\mathbf{A}^{\mathrm{T}}| = 1$ ，即 $|\mathbf{A}|^2 = 1$

再由 $|\mathbf{A}| < 0$ 得 $|\mathbf{A}| = -1$ .

于是 $|\mathbf{A} + \mathbf{E}| = |\mathbf{A} + \mathbf{A}\mathbf{A}^{\mathrm{T}}| = |\mathbf{A}|\cdot |\mathbf{E} + \mathbf{A}^{\mathrm{T}}| = -|\left(\mathbf{E} + \mathbf{A}\right)^{\mathrm{T}}| = -|\mathbf{E} + \mathbf{A}|$

故 $|\mathbf{E} + \mathbf{A}| = 0$

方法二 令 $AX = \lambda X(X\neq 0)$

由 $\mathbf{A}\mathbf{X} = \lambda \mathbf{X}$ 得 $\mathbf{X}^{\mathrm{T}}\mathbf{A}^{\mathrm{T}} = \lambda \mathbf{X}^{\mathrm{T}}$ ，两边右乘 $\mathbf{A}\mathbf{X}$ 得

$\mathbf{X}^{\mathrm{T}}\mathbf{A}^{\mathrm{T}}\cdot \mathbf{A}\mathbf{X} = \lambda \mathbf{X}^{\mathrm{T}}\cdot \mathbf{A}\mathbf{X}$ ，即 $\pmb {X}^{\mathrm{T}}\pmb {X} = \lambda^{2}\pmb{X}^{\mathrm{T}}\pmb {X}$ ，或 $(\lambda^2 -1)\pmb{X}^{\mathrm{T}}\pmb {X} = \mathbf{0}$

由 $\mathbf{X}^{\mathrm{T}}\mathbf{X} = \| \mathbf{X}\|^2 >0$ 得 $\lambda^2 -1 = 0$ ，即 $\lambda = \pm 1$

因为 $|\mathbf{A}| < 0$ ，所以 $\mathbf{A}$ 至少有一个特征值为 $-1$ ，从而 $\mathbf{A} + \mathbf{E}$ 的特征值至少有一个为0，

故 $|\mathbf{A} + \mathbf{E}| = 0$

# 十、填空题', 'E:\数学自用\数据资料\真题\按年份整理\1995\解析\1995年解析.md', 'ok', 'sequential_year_index', 0.1, '1995:19', 8, 0.225);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1995_main_q20', 'math1', 1995, '真题', 'main', 20, '# 九、（本题满分6分）

设 $\mathbf{A}$ 是 $n$ 阶矩阵，满足 $\mathbf{A}\mathbf{A}^{\mathrm{T}} = \mathbf{E}$ （ $\mathbf{E}$ 为 $n$ 阶单位矩阵， $\mathbf{A}^{\mathrm{T}}$ 为 $\mathbf{A}$ 的转置矩阵）， $|\mathbf{A}| < 0$ ，求 $|\mathbf{A} + \mathbf{E}|$ .', 'E:\数学自用\数据资料\真题\按年份整理\1995\按题拆分\真题\第20题\题目.md', '1995\按题拆分\真题\第20题\题目.md', 0, 'ok', '1995 真题 第20题 # 九、（本题满分6分）

设 $\mathbf{a}$ 是 $n$ 阶矩阵，满足 $\mathbf{a}\mathbf{a}^{\mathrm{t}} = \mathbf{e}$ （ $\mathbf{e}$ 为 $n$ 阶单位矩阵， $\mathbf{a}^{\mathrm{t}}$ 为 $\mathbf{a}$ 的转置矩阵）， $|\mathbf{a}| < 0$ ，求 $|\mathbf{a} + \mathbf{e}|$ .');
