INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1995_main_q20', 'math1_1995_main_q20', 1995, 20, 1, 20, '（1）【答案】 18.4.

【解】 显然 $X\sim B(10,0.4)$

由 $E(X) = np = 4$ ， $D(X) = np(1 - p) = 10 \times 0.4 \times 0.6 = 2.4$ ，得

$$
E \left(X ^ {2}\right) = D (X) + \left[ E (X) \right] ^ {2} = 2. 4 + 1 6 = 1 8. 4.
$$', 'E:\数学自用\数据资料\真题\按年份整理\1995\解析\1995年解析.md', 'manual_check', 'sequential_year_index', 0, '1995:20', 9, 0.051);
