INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1995_main_q23', 'math1_1995_main_q23', 1995, 23, 11, 22, '十一、【解】 $F_{Y}(y) = P\{Y \leqslant y\} = P\{\mathrm{e}^{X} \leqslant y\}$ ，

当 $y < 1$ 时， $F_{Y}(y) = 0$

当 $y \geqslant 1$ 时， $F_{Y}(y) = P\{X \leqslant \ln y\} = \int_{0}^{\ln y} \mathrm{e}^{-x} \, \mathrm{d}x = -\mathrm{e}^{-x}\left| \begin{array}{c} \ln y \\ 0 \end{array} \right| = 1 - \frac{1}{y}$ ，

即 $F_{Y}(y) = \left\{ \begin{array}{ll}0, & y < 1,\\ 1 - \frac{1}{y}, & y\geqslant 1, \end{array} \right.$ 故 $Y = \mathrm{e}^{X}$ 的概率密度为

$$
f _ {Y} (y) = \left\{ \begin{array}{l l} 0, & y <   1, \\ \frac {1}{y ^ {2}}, & y \geqslant 1. \end{array} \right.
$$', 'E:\数学自用\数据资料\真题\按年份整理\1995\解析\1995年解析.md', 'manual_check', 'similarity_fallback:0.340', 0.34, '', 11, 0.34);
