INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1996_main_q13', 'math1_1996_main_q13', 1996, 13, 1, 13, '(1)【解】 令 $S_{1}:z = 1(x^{2} + y^{2}\leqslant 1)$ ，取下侧，则

$$
\iint_ {S} (2 x + z) \mathrm {d} y \mathrm {d} z + z \mathrm {d} x \mathrm {d} y = \iint_ {S + S _ {1}} (2 x + z) \mathrm {d} y \mathrm {d} z + z \mathrm {d} x \mathrm {d} y - \iint_ {S _ {1}} (2 x + z) \mathrm {d} y \mathrm {d} z + z \mathrm {d} x \mathrm {d} y,
$$

由高斯公式得

$$
\oiint_ {S + S _ {1}} (2 x + z) \mathrm {d} y \mathrm {d} z + z \mathrm {d} x \mathrm {d} y = - 3 \iiint_ {\Omega} \mathrm {d} v = - 3 \int_ {0} ^ {1} \mathrm {d} z \iint_ {x ^ {2} + y ^ {2} \leqslant z} \mathrm {d} x \mathrm {d} y = - 3 \pi \int_ {0} ^ {1} z \mathrm {d} z = - \frac {3 \pi}{2};
$$

$$
\iint_ {S _ {1}} (2 x + z) \mathrm {d} y \mathrm {d} z + z \mathrm {d} x \mathrm {d} y = - \iint_ {x ^ {2} + y ^ {2} \leqslant 1} \mathrm {d} x \mathrm {d} y = - \pi ,
$$

故 $\iint_{S} (2x + z) \, \mathrm{d}y \, \mathrm{d}z + z \, \mathrm{d}x \, \mathrm{d}y = -\frac{\pi}{2}$ .', 'E:\数学自用\数据资料\真题\按年份整理\1996\解析\1996年解析.md', 'ok', 'sequential_year_index', 0.212, '1996:13', 1, 0.212);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1996_main_q14', 'math1', 1996, '真题', 'main', 14, '# 四、（本题共2小题，每小题6分，满分12分）

（2）设变换 $\left\{ \begin{array}{l} u = x - 2y, \\ v = x + ay \end{array} \right.$ 可把方程 $6\frac{\partial^2z}{\partial x^2} + \frac{\partial^2z}{\partial x\partial y} - \frac{\partial^2z}{\partial y^2} = 0$ 化简为 $\frac{\partial^2z}{\partial u\partial v} = 0$ ，求常数 $a$ ，其中 $z = z(x,y)$ 有二阶连续的偏导数.', 'E:\数学自用\数据资料\真题\按年份整理\1996\按题拆分\真题\第14题\题目.md', '1996\按题拆分\真题\第14题\题目.md', 0, 'ok', '1996 真题 第14题 # 四、（本题共2小题，每小题6分，满分12分）

（2）设变换 $\left\{ \begin{array}{l} u = x - 2y, \\ v = x + ay \end{array} \right.$ 可把方程 $6\frac{\partial^2z}{\partial x^2} + \frac{\partial^2z}{\partial x\partial y} - \frac{\partial^2z}{\partial y^2} = 0$ 化简为 $\frac{\partial^2z}{\partial u\partial v} = 0$ ，求常数 $a$ ，其中 $z = z(x,y)$ 有二阶连续的偏导数.');
