INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1996_main_q14', 'math1_1996_main_q14', 1996, 14, 2, 14, '(2)【解】 $\frac{\partial z}{\partial x} = \frac{\partial z}{\partial u} \cdot \frac{\partial u}{\partial x} + \frac{\partial z}{\partial v} \cdot \frac{\partial v}{\partial x} = \frac{\partial z}{\partial u} + \frac{\partial z}{\partial v}, \quad \frac{\partial z}{\partial y} = \frac{\partial z}{\partial u} \cdot \frac{\partial u}{\partial y} + \frac{\partial z}{\partial v} \cdot \frac{\partial v}{\partial y} = -2 \frac{\partial z}{\partial u} + a \frac{\partial z}{\partial v},$

$$
\frac {\partial^ {2} z}{\partial x ^ {2}} = \frac {\partial^ {2} z}{\partial u ^ {2}} \cdot \frac {\partial u}{\partial x} + \frac {\partial^ {2} z}{\partial u \partial v} \cdot \frac {\partial v}{\partial x} + \frac {\partial^ {2} z}{\partial v \partial u} \cdot \frac {\partial u}{\partial x} + \frac {\partial^ {2} z}{\partial v ^ {2}} \cdot \frac {\partial v}{\partial x} = \frac {\partial^ {2} z}{\partial u ^ {2}} + 2 \frac {\partial^ {2} z}{\partial v \partial u} + \frac {\partial^ {2} z}{\partial v ^ {2}},
$$

$$
\frac {\partial^ {2} z}{\partial x \partial y} = - 2 \frac {\partial^ {2} z}{\partial u ^ {2}} + a \frac {\partial^ {2} z}{\partial u \partial v} - 2 \frac {\partial^ {2} z}{\partial v \partial u} + a \frac {\partial^ {2} z}{\partial v ^ {2}} = - 2 \frac {\partial^ {2} z}{\partial u ^ {2}} + (a - 2) \frac {\partial^ {2} z}{\partial v \partial u} + a \frac {\partial^ {2} z}{\partial v ^ {2}},
$$

$$
\begin{array}{l} \frac {\partial^ {2} z}{\partial y ^ {2}} = - 2 \left(\frac {\partial^ {2} z}{\partial u ^ {2}} \cdot \frac {\partial u}{\partial y} + \frac {\partial^ {2} z}{\partial u \partial v} \cdot \frac {\partial v}{\partial y}\right) + a \left(\frac {\partial^ {2} z}{\partial v \partial u} \cdot \frac {\partial u}{\partial y} + \frac {\partial^ {2} z}{\partial v ^ {2}} \cdot \frac {\partial v}{\partial y}\right) \\ = - 2 \left(- 2 \frac {\partial^ {2} z}{\partial u ^ {2}} + a \frac {\partial^ {2} z}{\partial u \partial v}\right) + a \left(- 2 \frac {\partial^ {2} z}{\partial v \partial u} + a \frac {\partial^ {2} z}{\partial v ^ {2}}\right) \\ = 4 \frac {\partial^ {2} z}{\partial u ^ {2}} - 4 a \frac {\partial^ {2} z}{\partial u \partial v} + a ^ {2} \frac {\partial^ {2} z}{\partial v ^ {2}}, \\ \end{array}
$$

代入整理得

$$
(5 a + 1 0) \frac {\partial^ {2} z}{\partial v \partial u} + (- a ^ {2} + a + 6) \frac {\partial^ {2} z}{\partial v ^ {2}} = 0,
$$

于是 $\left\{ \begin{array}{l}5a + 10\neq 0,\\ -a^2 +a + 6 = 0, \end{array} \right.$ 解得 $a = 3$', 'E:\数学自用\数据资料\真题\按年份整理\1996\解析\1996年解析.md', 'ok', 'sequential_year_index', 0.218, '1996:14', 2, 0.218);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1996_main_q15', 'math1', 1996, '真题', 'main', 15, '# 五、（本题满分7分）

求级数 $\sum_{n = 2}^{\infty}\frac{1}{(n^{2} - 1)2^{n}}$ 的和.', 'E:\数学自用\数据资料\真题\按年份整理\1996\按题拆分\真题\第15题\题目.md', '1996\按题拆分\真题\第15题\题目.md', 0, 'ok', '1996 真题 第15题 # 五、（本题满分7分）

求级数 $\sum_{n = 2}^{\infty}\frac{1}{(n^{2} - 1)2^{n}}$ 的和.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1996_main_q15', 'tag_级数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1996_main_q15', 'math1_1996_main_q15', 1996, 15, 5, 15, '五、【解】 令 $S(x) = \sum_{n=2}^{\infty} \frac{x^n}{n^2 - 1} (-1 < x < 1)$ ，

则 $S(x) = \frac{1}{2}\left(\sum_{n = 2}^{\infty}\frac{x^n}{n - 1} -\sum_{n = 2}^{\infty}\frac{x^n}{n + 1}\right),$

$$
S (0) = 0;
$$

当 $x \neq 0$ 时，

$$
\begin{array}{l} S (x) = \frac {x}{2} \sum_ {n = 2} ^ {\infty} \frac {x ^ {n - 1}}{n - 1} - \frac {1}{2 x} \sum_ {n = 2} ^ {\infty} \frac {x ^ {n + 1}}{n + 1} = \frac {x}{2} \sum_ {n = 1} ^ {\infty} \frac {x ^ {n}}{n} - \frac {1}{2 x} \sum_ {n = 3} ^ {\infty} \frac {x ^ {n}}{n} \\ = - \frac {x}{2} \ln (1 - x) - \frac {1}{2 x} \left(\sum_ {n = 1} ^ {\infty} \frac {x ^ {n}}{n} - x - \frac {x ^ {2}}{2}\right) \\ \end{array}
$$

$$
= \left(\frac {1}{2 x} - \frac {x}{2}\right) \ln (1 - x) + \frac {1}{2} + \frac {x}{4},
$$

故 $\sum_{n = 2}^{\infty}\frac{1}{(n^{2} - 1)2^{n}} = S\left(\frac{1}{2}\right) = \frac{5}{8} -\frac{3}{4}\ln 2.$', 'E:\数学自用\数据资料\真题\按年份整理\1996\解析\1996年解析.md', 'ok', 'sequential_year_index', 0.294, '1996:15', 5, 0.294);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1996_main_q16', 'math1', 1996, '真题', 'main', 16, '# 六、（本题满分7分）

设对任意的 $x > 0$ ，曲线 $y = f(x)$ 上点 $(x, f(x))$ 处的切线在 $y$ 轴上的截距等于 $\frac{1}{x} \int_{0}^{x} f(t) \, \mathrm{d}t$ ，求 $f(x)$ 的一般表达式.', 'E:\数学自用\数据资料\真题\按年份整理\1996\按题拆分\真题\第16题\题目.md', '1996\按题拆分\真题\第16题\题目.md', 0, 'ok', '1996 真题 第16题 # 六、（本题满分7分）

设对任意的 $x > 0$ ，曲线 $y = f(x)$ 上点 $(x, f(x))$ 处的切线在 $y$ 轴上的截距等于 $\frac{1}{x} \int_{0}^{x} f(t) \, \mathrm{d}t$ ，求 $f(x)$ 的一般表达式.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1996_main_q16', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1996_main_q16', 'math1_1996_main_q16', 1996, 16, 6, 16, '六、【解】 曲线 $y = f(x)$ 在点 $(x, f(x))$ 的切线为

$$
Y - f (x) = f ^ {\prime} (x) (X - x),
$$

令 $X = 0$ 得 $Y = f(x) - xf''(x)$

由题意得 $f(x) - xf''(x) = \frac{1}{x}\int_{0}^{x}f(t)\mathrm{d}t$ ，整理得 $xf(x) - x^{2}f^{\prime}(x) = \int_{0}^{x}f(t)\mathrm{d}t$

两边求导得 $f^{\prime}(x) + xf^{\prime \prime}(x) = 0$ ，即 $[xf''(x)]'' = 0$

解得 $x f^{\prime}(x) = C_{1}$ ，或 $f^{\prime}(x) = \frac{C_{1}}{x}$ ，故 $f(x) = C_{1} \ln x + C_{2}$ （ $C_{1}, C_{2}$ 为任意常数）.', 'E:\数学自用\数据资料\真题\按年份整理\1996\解析\1996年解析.md', 'ok', 'sequential_year_index', 0.25, '1996:16', 6, 0.25);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1996_main_q17', 'math1', 1996, '真题', 'main', 17, '# 七、(本题满分8分)

(1) 写出 $f(x)$ 在点 $x = c$ 处带拉格朗日余项的一阶泰勒公式；', 'E:\数学自用\数据资料\真题\按年份整理\1996\按题拆分\真题\第17题\题目.md', '1996\按题拆分\真题\第17题\题目.md', 0, 'ok', '1996 真题 第17题 # 七、(本题满分8分)

(1) 写出 $f(x)$ 在点 $x = c$ 处带拉格朗日余项的一阶泰勒公式；');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1996_main_q17', 'math1_1996_main_q17', 1996, 17, 7, 17, '# 七、【证明】（1）由泰勒公式得

$$
f (0) = f (c) + f ^ {\prime} (c) (0 - c) + \frac {f ^ {\prime \prime} (\xi_ {1})}{2 !} (0 - c) ^ {2}, \quad 0 <   \xi_ {1} <   c,
$$

$$
f (1) = f (c) + f ^ {\prime} (c) (1 - c) + \frac {f ^ {\prime \prime} (\xi_ {2})}{2 !} (1 - c) ^ {2}, \quad c <   \xi_ {2} <   1,
$$

两式相减得

$$
f ^ {\prime} (c) = f (1) - f (0) + \frac {c ^ {2}}{2} f ^ {\prime \prime} (\xi_ {1}) - \frac {(1 - c) ^ {2}}{2} f ^ {\prime \prime} (\xi_ {2}).
$$

(2) $|f''(c)| \leqslant |f(1)| + |f(0)| + \frac{c^2}{2} |f''''(\xi_1)| + \frac{(1 - c)^2}{2} |f''''(\xi_2)|$

$$
\leqslant 2 a + \frac {b}{2} \left[ c ^ {2} + (1 - c) ^ {2} \right],
$$

由 $c^2 \leqslant c, (1 - c)^2 \leqslant 1 - c$ 得 $c^2 + (1 - c)^2 \leqslant 1$ ，故 $|f''(c)| \leqslant 2a + \frac{b}{2}$ 。', 'E:\数学自用\数据资料\真题\按年份整理\1996\解析\1996年解析.md', 'manual_check', 'sequential_year_index', 0.069, '1996:17', 6, 0.103);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1996_main_q18', 'math1', 1996, '真题', 'main', 18, '# 七、(本题满分8分)

（2）证明： $\left|f^{\prime}(c)\right|\leqslant 2a + \frac{b}{2}.$', 'E:\数学自用\数据资料\真题\按年份整理\1996\按题拆分\真题\第18题\题目.md', '1996\按题拆分\真题\第18题\题目.md', 0, 'ok', '1996 真题 第18题 # 七、(本题满分8分)

（2）证明： $\left|f^{\prime}(c)\right|\leqslant 2a + \frac{b}{2}.$');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1996_main_q18', 'math1_1996_main_q18', 1996, 18, 8, 18, '八、【证明】（1）令 $\pmb{\xi}^{\mathrm{T}}\pmb {\xi} = \pmb{k}$

$$
\boldsymbol {A} ^ {2} = (\boldsymbol {E} - \boldsymbol {\xi} \boldsymbol {\xi} ^ {\mathrm {T}}) (\boldsymbol {E} - \boldsymbol {\xi} \boldsymbol {\xi} ^ {\mathrm {T}}) = \boldsymbol {E} + (k - 2) \boldsymbol {\xi} \boldsymbol {\xi} ^ {\mathrm {T}},
$$

则 $\mathbf{A}^2 = \mathbf{A}$ 的充分必要条件是 $k = 1$ ，即 $\pmb{\xi}^{\mathrm{T}}\pmb {\xi} = 1$

（2）方法一 当 $\pmb{\xi}^{\mathrm{T}}\pmb {\xi} = 1$ 时，由 $A^2 = A$ 得 $A(E - A) = O$ ，从而 $r(A) + r(E - A)\leqslant n$

再由 $r(\mathbf{A}) + r(\mathbf{E} - \mathbf{A})\geqslant r(\mathbf{E}) = n$ 得 $r(\mathbf{A}) + r(\mathbf{E} - \mathbf{A}) = n$

因为 $\pmb{\xi}$ 为非零向量，所以 $\pmb {\xi}\pmb{\xi}^{\mathrm{T}}\neq \pmb{0}$ ，从而 $E - A = \xi \xi^{\mathrm{T}}\neq O$ ，即 $r(E - A)\geqslant 1$

故 $r(\mathbf{A}) < n$ ，即 $\mathbf{A}$ 是不可逆矩阵

方法二 令 $\pmb{B} = \pmb{\xi}\pmb{\xi}^{\mathrm{T}}$ ，矩阵 $\pmb{B}$ 的特征值为 $\lambda_1 = \pmb{\xi}^{\mathrm{T}}\pmb{\xi} = 1, \lambda_2 = \dots = \lambda_n = 0$

矩阵 $\mathbf{A}$ 的特征值为 $\lambda_{1} = 0, \lambda_{2} = \dots = \lambda_{n} = 1$ ，则 $|\mathbf{A}| = |\mathbf{E} - \mathbf{B}| = 0$

故 $r(\mathbf{A}) < n$ ，即 $\mathbf{A}$ 不可逆', 'E:\数学自用\数据资料\真题\按年份整理\1996\解析\1996年解析.md', 'manual_check', 'sequential_year_index', 0, '1996:18', 7, 0.286);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1996_main_q19', 'math1', 1996, '真题', 'main', 19, '# 八、（本题满分6分）

(1) $A^2 = A$ 的充分必要条件是 $\xi^{\mathrm{T}}\xi = 1$', 'E:\数学自用\数据资料\真题\按年份整理\1996\按题拆分\真题\第19题\题目.md', '1996\按题拆分\真题\第19题\题目.md', 0, 'ok', '1996 真题 第19题 # 八、（本题满分6分）

(1) $a^2 = a$ 的充分必要条件是 $\xi^{\mathrm{t}}\xi = 1$');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1996_main_q19', 'math1_1996_main_q19', 1996, 19, 9, 19, '九、【解】（1）令 $\mathbf{A} = \begin{pmatrix} 5 & -1 & 3 \\ -1 & 5 & -3 \\ 3 & -3 & c \end{pmatrix}, \mathbf{X} = \begin{pmatrix} x_1 \\ x_2 \\ x_3 \end{pmatrix}$ ，则 $f(x_{1},x_{2},x_{3}) = \mathbf{X}^{\mathrm{T}}\mathbf{A}\mathbf{X}$

因为二次型的秩为2，所以 $|\mathbf{A}| = 0$

由 $|\mathbf{A}| = \left| \begin{array}{rrr}5 & -1 & 3\\ -1 & 5 & -3\\ 3 & -3 & c \end{array} \right| = 24c - 72 = 0$ ，得 $c = 3$

容易验证，此时 $\mathbf{A}$ 的秩是2.A的特征多项式为

$$
\left| \lambda E - A \right| = \left| \begin{array}{c c c} \lambda - 5 & 1 & - 3 \\ 1 & \lambda - 5 & 3 \\ - 3 & 3 & \lambda - 3 \end{array} \right| = \lambda (\lambda - 4) (\lambda - 9),
$$

故所求特征值为 $\lambda_1 = 0, \lambda_2 = 4, \lambda_3 = 9$ .

（2）二次型 $f$ 的标准形为 $f = 4y_{2}^{2} + 9y_{3}^{2}$

由此可知 $f(x_{1},x_{2},x_{3}) = 1$ 所表示的曲面是椭圆柱面

# 十、填空题', 'E:\数学自用\数据资料\真题\按年份整理\1996\解析\1996年解析.md', 'manual_check', 'sequential_year_index', 0.053, '1996:19', 8, 0.474);
