INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1997_main_q18', 'math1_1997_main_q18', 1997, 18, 1, 18, '（1）【解】因为 $r(\pmb {B}) = 2 <   4$ ，所以 $\pmb {BX} = \pmb{0}$ 的基础解系含两个线性无关的特征向量，因为 $\alpha_{1},\alpha_{2}$ 线性无关，所以 $\alpha_{1},\alpha_{2}$ 为基础解系，

令 $\pmb{\beta}_{1} = \pmb{\alpha}_{1} = \begin{pmatrix} 1 \\ 1 \\ 2 \\ 3 \end{pmatrix}$ ， $\pmb{\beta}_{2} = \pmb{\alpha}_{2} - \frac{(\pmb{\alpha}_{2}, \pmb{\beta}_{1})}{(\pmb{\beta}_{1}, \pmb{\beta}_{1})} \pmb{\beta}_{1} = \begin{pmatrix} -1 \\ 1 \\ 4 \\ -1 \end{pmatrix} - \frac{1}{3} \begin{pmatrix} 1 \\ 1 \\ 2 \\ 3 \end{pmatrix} = \frac{2}{3} \begin{pmatrix} -2 \\ 1 \\ 5 \\ -3 \end{pmatrix}$ ，

则 $\mathbf{B}\mathbf{X} = \mathbf{0}$ 的解空间的一个标准正交基为 $\gamma_{1} = \frac{1}{\sqrt{15}}\left[ \begin{array}{l}1\\ 1\\ 2\\ 3 \end{array} \right],\quad \gamma_{2} = \frac{1}{\sqrt{39}}\left[ \begin{array}{l} - 2\\ 1\\ 5\\ -3 \end{array} \right].$', 'E:\数学自用\数据资料\真题\按年份整理\1997\解析\1997年解析.md', 'manual_check', 'sequential_year_index', 0, '1997:18', 6, 0.556);
