INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1997_main_q22', 'math1_1997_main_q22', 1997, 22, 9, 22, '九、【解】 显然 $X \sim B\left(3, \frac{2}{5}\right)$ ，即 $P\{X = k\} = \mathrm{C}_3^k\left(\frac{2}{5}\right)^k\left(\frac{3}{5}\right)^{3 - k}, k = 0,1,2,3;$

当 $x < 0$ 时， $F(x) = P\{X \leqslant x\} = 0$

当 $0 \leqslant x < 1$ 时， $F(x) = P\{X \leqslant x\} = P\{X = 0\} = \frac{27}{125}$

当 $1 \leqslant x < 2$ 时， $F(x) = P\{X \leqslant x\} = P\{X = 0\} + P\{X = 1\} = \frac{81}{125}$

当 $2 \leqslant x < 3$ 时， $F(x) = P\{X \leqslant x\} = P\{X = 0\} + P\{X = 1\} + P\{X = 2\} = \frac{117}{125}$

当 $x \geqslant 3$ 时， $F(x) = 1$

即 $F(x) = \left\{ \begin{array}{ll}0, & x <   0,\\ \frac{27}{125}, & 0\leqslant x <   1,\\ \frac{81}{125}, & 1\leqslant x <   2,\\ \frac{117}{125}, & 2\leqslant x <   3,\\ 1, & x\geqslant 3. \end{array} \right.$

$$
E (X) = n p = \frac {6}{5}.
$$', 'E:\数学自用\数据资料\真题\按年份整理\1997\解析\1997年解析.md', 'manual_check', 'sequential_year_index', 0, '1997:22', 2, 0.1);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1997_main_q23', 'math1', 1997, '真题', 'main', 23, '# 九、(本题满分7分)

从学校乘汽车到火车站的途中有3个交通岗,假设在各个交通岗遇到红灯的事件是相互独立的,并且概率都是 $\frac{2}{5}$ . 设 $X$ 为途中遇到红灯的次数,求随机变量 $X$ 的分布律、分布函数和数学期望.', 'E:\数学自用\数据资料\真题\按年份整理\1997\按题拆分\真题\第23题\题目.md', '1997\按题拆分\真题\第23题\题目.md', 0, 'ok', '1997 真题 第23题 # 九、(本题满分7分)

从学校乘汽车到火车站的途中有3个交通岗,假设在各个交通岗遇到红灯的事件是相互独立的,并且概率都是 $\frac{2}{5}$ . 设 $x$ 为途中遇到红灯的次数,求随机变量 $x$ 的分布律、分布函数和数学期望.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1997_main_q23', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1997_main_q23', 'math1_1997_main_q23', 1997, 23, 10, 23, '十、【解】 $E(X) = \int_0^1 xf(x)\mathrm{d}x = (\theta +1)\int_0^1 x^{\theta +1}\mathrm{d}x = \frac{\theta + 1}{\theta + 2},$

由 $E(X) = \overline{X}$ ，即 $\frac{\theta + 1}{\theta + 2} = \overline{X}$ ，解得 $\theta$ 的矩估计量为 $\hat{\theta} = \frac{2\overline{X} - 1}{1 - \overline{X}}$

似然函数为 $L(\theta) = f(x_{1};\theta)f(x_{2};\theta)\dots f(x_{n};\theta)$

$$
= (\theta + 1) ^ {n} \left(x _ {1} x _ {2} \dots x _ {n}\right) ^ {\theta}, \text {其 中} 0 <   x _ {i} <   1, i = 1, 2, \dots , n,
$$

$$
\ln L (\theta) = n \ln (\theta + 1) + \theta \sum_ {i = 1} ^ {n} \ln x _ {i},
$$

由 $\frac{\mathrm{d}}{\mathrm{d}\theta}\ln L(\theta) = \frac{n}{\theta + 1} +\sum_{i = 1}^{n}\ln x_{i} = 0$ ，得 $\theta = -1 - \frac{n}{\sum_{i = 1}^{n}\ln x_i}$

故 $\theta$ 的最大似然估计量为 $\hat{\theta} = -1 - \frac{n}{\sum_{i=1}^{n} \ln X_i}$ .', 'E:\数学自用\数据资料\真题\按年份整理\1997\解析\1997年解析.md', 'manual_check', 'sequential_year_index', 0, '1997:23', 5, 0.025);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1997_main_q24', 'math1', 1997, '真题', 'main', 24, '# 十、(本题满分5分)

设总体 $X$ 的概率密度为

$$
f (x) = \left\{ \begin{array}{l l} (\theta + 1) x ^ {\theta}, & 0 <   x <   1, \\ 0, & \text {其 他}, \end{array} \right.
$$

其中 $\theta > -1$ 是未知参数, $X_{1}, X_{2}, \dots, X_{n}$ 是来自总体 $X$ 的一个容量为 $n$ 的简单随机样本, 分别用矩估计法和极大似然估计法求 $\theta$ 的估计量.', 'E:\数学自用\数据资料\真题\按年份整理\1997\按题拆分\真题\第24题\题目.md', '1997\按题拆分\真题\第24题\题目.md', 0, 'ok', '1997 真题 第24题 # 十、(本题满分5分)

设总体 $x$ 的概率密度为

$$
f (x) = \left\{ \begin{array}{l l} (\theta + 1) x ^ {\theta}, & 0 <   x <   1, \\ 0, & \text {其 他}, \end{array} \right.
$$

其中 $\theta > -1$ 是未知参数, $x_{1}, x_{2}, \dots, x_{n}$ 是来自总体 $x$ 的一个容量为 $n$ 的简单随机样本, 分别用矩估计法和极大似然估计法求 $\theta$ 的估计量.');
