INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q01', 'math1', 1998, '真题', 'main', 1, '# 一、填空题(本题共5小题，每小题3分，满分15分)

(1) $\lim_{x \to 0} \frac{\sqrt{1 + x} + \sqrt{1 - x} - 2}{x^2} = \underline{\quad}$ .', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第01题\题目.md', '1998\按题拆分\真题\第01题\题目.md', 0, 'ok', '1998 真题 第1题 # 一、填空题(本题共5小题，每小题3分，满分15分)

(1) $\lim_{x \to 0} \frac{\sqrt{1 + x} + \sqrt{1 - x} - 2}{x^2} = \underline{\quad}$ .');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1998_main_q01', 'tag_极限');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q01', 'math1_1998_main_q01', 1998, 1, 1, 1, '(1)【答案】 $-\frac{1}{4}$ .

【解】 方法一

由 $(1 + x)^{a} = 1 + ax + \frac{a(a - 1)}{2!} x^{2} + o(x^{2})$ 得

$$
\sqrt {1 + x} = 1 + \frac {1}{2} x - \frac {1}{8} x ^ {2} + o (x ^ {2}), \quad \sqrt {1 - x} = 1 - \frac {1}{2} x - \frac {1}{8} x ^ {2} + o (x ^ {2}),
$$

于是 $\sqrt{1 + x} + \sqrt{1 - x} - 2 = -\frac{1}{4} x^2 + o(x^2) \sim -\frac{1}{4} x^2,$

故 $\lim_{x\to 0}\frac{\sqrt{1 + x} + \sqrt{1 - x} - 2}{x^2} = -\frac{1}{4}.$

方法二

$$
\begin{array}{l} \lim  _ {x \rightarrow 0} \frac {\sqrt {1 + x} + \sqrt {1 - x} - 2}{x ^ {2}} = \lim  _ {x \rightarrow 0} \frac {\frac {1}{2 \sqrt {1 + x}} - \frac {1}{2 \sqrt {1 - x}}}{2 x} \\ = \frac {1}{4} \lim  _ {x \rightarrow 0} \frac {\sqrt {1 - x} - \sqrt {1 + x}}{x \sqrt {1 - x ^ {2}}} = \frac {1}{4} \lim  _ {x \rightarrow 0} \frac {- 2 x}{x (\sqrt {1 + x} + \sqrt {1 - x})} = - \frac {1}{4}. \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'ok', 'sequential_year_index', 0.25, '1998:1', 1, 0.25);
