INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q02', 'math1_1998_main_q02', 1998, 2, 2, 2, '(2)【答案】 $yf''''(xy) + \varphi''(x + y) + y\varphi''''(x + y).$

【解】 $\frac{\partial z}{\partial x} = -\frac{1}{x^2} f(xy) + \frac{y}{x} f''(xy) + y\varphi''(x + y),$

$$
\begin{array}{l} \frac {\partial^ {2} z}{\partial x \partial y} = - \frac {1}{x} f ^ {\prime} (x y) + \frac {1}{x} f ^ {\prime} (x y) + y f ^ {\prime \prime} (x y) + \varphi^ {\prime} (x + y) + y \varphi^ {\prime \prime} (x + y) \\ = y f ^ {\prime \prime} (x y) + \varphi^ {\prime} (x + y) + y \varphi^ {\prime \prime} (x + y). \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'ok', 'sequential_year_index', 0.186, '1998:2', 2, 0.186);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q03', 'math1', 1998, '真题', 'main', 3, '# 一、填空题(本题共5小题，每小题3分，满分15分)

(3) 设 $l$ 为椭圆 $\frac{x^2}{4} + \frac{y^2}{3} = 1$ , 其周长记为 $a$ , 则 $\oint_{l} (2xy + 3x^2 + 4y^2) \, \mathrm{d}s =$ ______.', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第03题\题目.md', '1998\按题拆分\真题\第03题\题目.md', 0, 'ok', '1998 真题 第3题 # 一、填空题(本题共5小题，每小题3分，满分15分)

(3) 设 $l$ 为椭圆 $\frac{x^2}{4} + \frac{y^2}{3} = 1$ , 其周长记为 $a$ , 则 $\oint_{l} (2xy + 3x^2 + 4y^2) \, \mathrm{d}s =$ ______.');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q03', 'math1_1998_main_q03', 1998, 3, 3, 3, '（3）【答案】 $12a$

【解】 由对称性得

$$
\begin{array}{l} \oint_ {L} (2 x y + 3 x ^ {2} + 4 y ^ {2}) \mathrm {d} s = \oint_ {L} (3 x ^ {2} + 4 y ^ {2}) \mathrm {d} s = 1 2 \oint_ {L} \left(\frac {x ^ {2}}{4} + \frac {y ^ {2}}{3}\right) \mathrm {d} s \\ = 1 2 \oint_ {L} d s = 1 2 a. \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'ok', 'sequential_year_index', 0.234, '1998:3', 3, 0.234);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q04', 'math1', 1998, '真题', 'main', 4, '# 一、填空题(本题共5小题，每小题3分，满分15分)

(4) 设 $\mathbf{A}$ 为 $n$ 阶矩阵, $|\mathbf{A}| \neq 0, \mathbf{A}^{*}$ 为 $\mathbf{A}$ 的伴随矩阵, $\mathbf{E}$ 为 $n$ 阶单位矩阵. 若 $\mathbf{A}$ 有特征值 $\lambda$ , 则 $(\mathbf{A}^{*})^{2} + \mathbf{E}$ 必有特征值', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第04题\题目.md', '1998\按题拆分\真题\第04题\题目.md', 0, 'ok', '1998 真题 第4题 # 一、填空题(本题共5小题，每小题3分，满分15分)

(4) 设 $\mathbf{a}$ 为 $n$ 阶矩阵, $|\mathbf{a}| \neq 0, \mathbf{a}^{*}$ 为 $\mathbf{a}$ 的伴随矩阵, $\mathbf{e}$ 为 $n$ 阶单位矩阵. 若 $\mathbf{a}$ 有特征值 $\lambda$ , 则 $(\mathbf{a}^{*})^{2} + \mathbf{e}$ 必有特征值');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1998_main_q04', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q04', 'math1_1998_main_q04', 1998, 4, 4, 4, '(4)【答案】 $\left(\frac{|\mathbf{A}|}{\lambda}\right)^2 + 1.$

【解】设 $\mathbf{A}$ 的对应于特征值 $\lambda$ 的特征向量为 $\alpha$ ，则 $A\alpha = \lambda \alpha$

由 $\mathbf{A}^{*}\pmb {\alpha} = \frac{\left|\mathbf{A}\right|}{\lambda}\pmb{\alpha}$ 得 $[(\mathbf{A}^{*})^{2} + \mathbf{E}]\pmb {\alpha} = \left[\left(\frac{\left|\mathbf{A}\right|}{\lambda}\right)^{2} + 1\right]\pmb{\alpha},$

故 $(\mathbf{A}^{*})^{2} + \mathbf{E}$ 一定有特征值 $\left(\frac{|\mathbf{A}|}{\lambda}\right)^2 +1.$', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'manual_check', 'sequential_year_index', 0.054, '1998:4', 4, 0.054);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q05', 'math1', 1998, '真题', 'main', 5, '# 一、填空题(本题共5小题，每小题3分，满分15分)

(5) 设平面区域 $D$ 由曲线 $y = \frac{1}{x}$ 及直线 $y = 0, x = 1, x = \mathrm{e}^2$ 所围成，二维随机变量 $(X,Y)$ 在区域 $D$ 上服从均匀分布，则 $(X,Y)$ 关于 $X$ 的边缘概率密度在 $x = 2$ 处的值为 ______.', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第05题\题目.md', '1998\按题拆分\真题\第05题\题目.md', 0, 'ok', '1998 真题 第5题 # 一、填空题(本题共5小题，每小题3分，满分15分)

(5) 设平面区域 $d$ 由曲线 $y = \frac{1}{x}$ 及直线 $y = 0, x = 1, x = \mathrm{e}^2$ 所围成，二维随机变量 $(x,y)$ 在区域 $d$ 上服从均匀分布，则 $(x,y)$ 关于 $x$ 的边缘概率密度在 $x = 2$ 处的值为 ______.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1998_main_q05', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q05', 'math1_1998_main_q05', 1998, 5, 5, 5, '(5)【答案】 $\frac{1}{4}$ .

【解】 区域 $D$ 的面积为 $A = \int_{1}^{\mathrm{e}^{2}}\mathrm{d}x\int_{0}^{\frac{1}{x}}\mathrm{d}y = \int_{1}^{\mathrm{e}^{2}}\frac{1}{x}\mathrm{d}x = 2,$

则 $(X,Y)$ 的联合密度为

$$
f (x, y) = \left\{ \begin{array}{l l} \frac {1}{2}, & (x, y) \in D, \\ 0, & (x, y) \notin D. \end{array} \right.
$$

当 $x \leqslant 1$ 或 $x \geqslant \mathrm{e}^2$ 时， $f_{X}(x) = 0$

当 $1 < x < \mathrm{e}^2$ 时， $f_{X}(x) = \int_{0}^{\frac{1}{x}}\frac{1}{2}\mathrm{d}y = \frac{1}{2x},$

故 $f_{X}(2) = \frac{1}{4}$ .

# 二、选择题', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'manual_check', 'sequential_year_index', 0.049, '1998:5', 5, 0.049);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q06', 'math1', 1998, '真题', 'main', 6, '# 二、选择题(本题共5小题，每小题3分，满分15分)

(1) 设 $f(x)$ 连续, 则 $\frac{\mathrm{d}}{\mathrm{d}x} \int_{0}^{x} t f\left(x^{2} - t^{2}\right) \mathrm{d}t = (\quad)$

(A) $xf(x^2)$ .

(B) $-xf(x^{2})$

(C) $2xf(x^{2})$

(D) $-2xf(x^{2})$', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第06题\题目.md', '1998\按题拆分\真题\第06题\题目.md', 0, 'ok', '1998 真题 第6题 # 二、选择题(本题共5小题，每小题3分，满分15分)

(1) 设 $f(x)$ 连续, 则 $\frac{\mathrm{d}}{\mathrm{d}x} \int_{0}^{x} t f\left(x^{2} - t^{2}\right) \mathrm{d}t = (\quad)$

(a) $xf(x^2)$ .

(b) $-xf(x^{2})$

(c) $2xf(x^{2})$

(d) $-2xf(x^{2})$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1998_main_q06', 'tag_连续');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1998_main_q06', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q06', 'math1_1998_main_q06', 1998, 6, 1, 6, '（1）【答案】 （A).

【解】由 $\int_0^x tf(x^2 -t^2)\mathrm{d}t = -\frac{1}{2}\int_0^x f(x^2 -t^2)\mathrm{d}(x^2 -t^2)\frac{x^2 - t^2 = u}{2}\frac{1}{2}\int_0^{x^2}f(u)\mathrm{d}u,$

则 $\frac{\mathrm{d}}{\mathrm{d}x}\int_{0}^{x}tf(x^2 -t^2)\mathrm{d}t = xf(x^2)$ ，应选(A).', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'ok', 'sequential_year_index', 0.25, '1998:6', 1, 0.25);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q07', 'math1', 1998, '真题', 'main', 7, '# 二、选择题(本题共5小题，每小题3分，满分15分)

(2) 函数 $f(x) = (x^2 - x - 2) \mid x^3 - x$ 不可导点的个数是（）

(A)3.

(B)2.

(C)1.

(D)0.', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第07题\题目.md', '1998\按题拆分\真题\第07题\题目.md', 0, 'ok', '1998 真题 第7题 # 二、选择题(本题共5小题，每小题3分，满分15分)

(2) 函数 $f(x) = (x^2 - x - 2) \mid x^3 - x$ 不可导点的个数是（）

(a)3.

(b)2.

(c)1.

(d)0.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1998_main_q07', 'tag_导数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q07', 'math1_1998_main_q07', 1998, 7, 2, 7, '(2)【答案】 (B).

【解】 由 $\lim_{x\to -1}\frac{f(x) - f(-1)}{x + 1} = \lim_{x\to -1}\frac{(x + 1)(x - 2)\mid x^3 - x\mid}{x + 1}$

$$
= \lim  _ {[ - ]} (x - 2) \mid x ^ {3} - x \mid = 0,
$$

得 $f^{\prime}(-1) = 0$

$$
\lim  _ {x \rightarrow 0} \frac {f (x) - f (0)}{x - 0} = \lim  _ {x \rightarrow 0} \frac {| x |}{x} \cdot (x ^ {2} - x - 2) | x ^ {2} - 1 |,
$$

显然 $f_{-}^{\prime}(0) = \lim_{x\to 0^{-}}\frac{|x|}{x}\cdot (x^{2} - x - 2)|x^{2} - 1| = 2,$

$$
f _ {+} ^ {\prime} (0) = \lim  _ {x \rightarrow 0 ^ {+}} \frac {| x |}{x} \cdot (x ^ {2} - x - 2) | x ^ {2} - 1 | = - 2,
$$

因为 $f_{-}^{\prime}(0) \neq f_{+}^{\prime}(0)$ ，所以 $x = 0$ 为不可导的点；

$$
\lim  _ {x \rightarrow 1} \frac {f (x) - f (1)}{x - 1} = \lim  _ {x \rightarrow 1} \frac {| x - 1 |}{x - 1} \cdot (x ^ {2} - x - 2) | x (x + 1) |,
$$

显然 $f_{-}^{\prime}(1) = \lim_{x\to 1^{-}}\frac{|x - 1|}{x - 1}\cdot (x^{2} - x - 2)\mid x(x + 1)\mid = 4,$

$$
f _ {+} ^ {\prime} (1) = \lim  _ {x \rightarrow 1 ^ {+}} \frac {| x - 1 |}{x - 1} \cdot (x ^ {2} - x - 2) | x (x + 1) | = - 4,
$$

因为 $f_{-}^{\prime}(1) \neq f_{+}^{\prime}(1)$ ，所以 $x = 1$ 为不可导的点，即 $f(x)$ 有2个不可导的点，应选(B).', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'ok', 'sequential_year_index', 0.133, '1998:7', 2, 0.133);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q08', 'math1', 1998, '真题', 'main', 8, '# 二、选择题(本题共5小题，每小题3分，满分15分)

(3) 已知函数 $y = y(x)$ 在任意点 $x$ 处的增量 $\Delta y = \frac{y\Delta x}{1 + x^2} + \alpha$ , 且当 $\Delta x \to 0$ 时, $\alpha$ 是 $\Delta x$ 的高阶无穷小, $y(0) = \pi$ , 则 $y(1)$ 等于( )

(A) $2\pi$

(B) $\pi$ .

(C) $\mathrm{e}^{\frac{\pi}{4}}$ .

(D) $\pi \mathrm{e}^{\frac{\pi}{4}}$ .', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第08题\题目.md', '1998\按题拆分\真题\第08题\题目.md', 0, 'ok', '1998 真题 第8题 # 二、选择题(本题共5小题，每小题3分，满分15分)

(3) 已知函数 $y = y(x)$ 在任意点 $x$ 处的增量 $\delta y = \frac{y\delta x}{1 + x^2} + \alpha$ , 且当 $\delta x \to 0$ 时, $\alpha$ 是 $\delta x$ 的高阶无穷小, $y(0) = \pi$ , 则 $y(1)$ 等于( )

(a) $2\pi$

(b) $\pi$ .

(c) $\mathrm{e}^{\frac{\pi}{4}}$ .

(d) $\pi \mathrm{e}^{\frac{\pi}{4}}$ .');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q08', 'math1_1998_main_q08', 1998, 8, 3, 8, '(3)【答案】 (D).

【解】由 $\Delta y = \frac{y\Delta x}{1 + x^2} +\alpha$ 得 $y = y(x)$ 可微，从而 $y = y(x)$ 可导，

且 $\frac{\mathrm{dy}}{\mathrm{dx}} = \frac{y}{1 + x^2}$ 或 $\frac{\mathrm{dy}}{\mathrm{dx}} -\frac{1}{1 + x^2} y = 0$

解得 $y = C\mathrm{e}^{-\int \frac{-1}{1 + x^2}\mathrm{d}x} = C\mathrm{e}^{\arctan x},$

由 $y(0) = \pi$ 得 $C = \pi$ ，于是 $y(x) = \pi \mathrm{e}^{\arctan x}$ 故 $y(1) = \pi \mathrm{e}^{\frac{\pi}{4}}$ ，应选(D).', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'manual_check', 'sequential_year_index', 0.058, '1998:8', 3, 0.058);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q09', 'math1', 1998, '真题', 'main', 9, '# 二、选择题(本题共5小题，每小题3分，满分15分)

(4) 设矩阵 $\left( \begin{array}{lll}a_{1} & b_{1} & c_{1}\\ a_{2} & b_{2} & c_{2}\\ a_{3} & b_{3} & c_{3} \end{array} \right)$ 是满秩的, 则直线 $\frac{x - a_3}{a_1 - a_2} = \frac{y - b_3}{b_1 - b_2} = \frac{z - c_3}{c_1 - c_2}$ 与直线 $\frac{x - a_1}{a_2 - a_3} = \frac{y - b_1}{b_2 - b_3} = \frac{z - c_1}{c_2 - c_3}$

(A) 相交于一点.

(B) 重合.

(C) 平行但不重合.

(D) 异面.', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第09题\题目.md', '1998\按题拆分\真题\第09题\题目.md', 0, 'ok', '1998 真题 第9题 # 二、选择题(本题共5小题，每小题3分，满分15分)

(4) 设矩阵 $\left( \begin{array}{lll}a_{1} & b_{1} & c_{1}\\ a_{2} & b_{2} & c_{2}\\ a_{3} & b_{3} & c_{3} \end{array} \right)$ 是满秩的, 则直线 $\frac{x - a_3}{a_1 - a_2} = \frac{y - b_3}{b_1 - b_2} = \frac{z - c_3}{c_1 - c_2}$ 与直线 $\frac{x - a_1}{a_2 - a_3} = \frac{y - b_1}{b_2 - b_3} = \frac{z - c_1}{c_2 - c_3}$

(a) 相交于一点.

(b) 重合.

(c) 平行但不重合.

(d) 异面.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1998_main_q09', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q09', 'math1_1998_main_q09', 1998, 9, 4, 9, '（4）【答案】 （A）.

【解】因为 $\left| \begin{array}{lll}a_{1} & b_{1} & c_{1}\\ a_{2} & b_{2} & c_{2}\\ a_{3} & b_{3} & c_{3} \end{array} \right| = \left| \begin{array}{ccc}a_{1} - a_{2} & b_{1} - b_{2} & c_{1} - c_{2}\\ a_{2} - a_{3} & b_{2} - b_{3} & c_{2} - c_{3}\\ a_{3} & b_{3} & c_{3} \end{array} \right|\neq 0,$

所以两条直线的方向向量不平行，（B）与（C）不对；

令 $s_1 = \{a_1 - a_2, b_1 - b_2, c_1 - c_2\}$ , $s_2 = \{a_2 - a_3, b_2 - b_3, c_2 - c_3\}$

$M_{1}(a_{3},b_{3},c_{3}),M_{2}(a_{1},b_{1},c_{1})$ 分别为两条直线上的点，

$$
\overrightarrow {M _ {1} M _ {2}} = \left\{a _ {1} - a _ {3}, b _ {1} - b _ {3}, c _ {1} - c _ {3} \right\},
$$

因为 $\overrightarrow{M_1M_2} \cdot (\pmb{s}_1 \times \pmb{s}_2) = \left| \begin{array}{ccc} a_1 - a_3 & b_1 - b_3 & c_1 - c_3 \\ a_1 - a_2 & b_1 - b_2 & c_1 - c_2 \\ a_2 - a_3 & b_2 - b_3 & c_2 - c_3 \end{array} \right| = 0$ ，所以两直线共面且不平行，即两直线交于一点，应选(A).', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'ok', 'sequential_year_index', 0.373, '1998:9', 4, 0.373);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q10', 'math1', 1998, '真题', 'main', 10, '# 二、选择题(本题共5小题，每小题3分，满分15分)

(5) 设 $A, B$ 是两个随机事件，且 $0 < P(A) < 1, P(B) > 0, P(B \mid A) = P(B \mid \overline{A})$ ，则必有（）

$(\mathrm{A})P(A\mid B) = P(\overline{A}\mid B).$

(B) $P(A\mid B)\neq P(\overline{A}\mid B).$

(C) $P(AB) = P(A)P(B)$ .

(D) $P(AB)\neq P(A)P(B).$', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第10题\题目.md', '1998\按题拆分\真题\第10题\题目.md', 0, 'ok', '1998 真题 第10题 # 二、选择题(本题共5小题，每小题3分，满分15分)

(5) 设 $a, b$ 是两个随机事件，且 $0 < p(a) < 1, p(b) > 0, p(b \mid a) = p(b \mid \overline{a})$ ，则必有（）

$(\mathrm{a})p(a\mid b) = p(\overline{a}\mid b).$

(b) $p(a\mid b)\neq p(\overline{a}\mid b).$

(c) $p(ab) = p(a)p(b)$ .

(d) $p(ab)\neq p(a)p(b).$');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q10', 'math1_1998_main_q10', 1998, 10, 5, 10, '（5）【答案】 (C).

【解】由 $P(B\mid A) = P(B\mid \overline{A})$ 得 $\frac{P(AB)}{P(A)} = \frac{P(\overline{A}B)}{P(\overline{A})}$

由减法公式及补概率的公式得 $\frac{P(AB)}{P(A)} = \frac{P(B) - P(AB)}{1 - P(A)}$

整理得 $P(AB) = P(A)P(B)$ ，应选(C).', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'ok', 'sequential_year_index', 0.133, '1998:10', 5, 0.133);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q11', 'math1', 1998, '真题', 'main', 11, '# 三、(本题满分5分)

求直线 $l: \frac{x - 1}{1} = \frac{y}{1} = \frac{z - 1}{-1}$ 在平面 $\pi : x - y + 2z - 1 = 0$ 上的投影直线 $l_{0}$ 的方程, 并求 $l_{0}$ 绕 $y$ 轴旋转一周所成曲面的方程.', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第11题\题目.md', '1998\按题拆分\真题\第11题\题目.md', 0, 'ok', '1998 真题 第11题 # 三、(本题满分5分)

求直线 $l: \frac{x - 1}{1} = \frac{y}{1} = \frac{z - 1}{-1}$ 在平面 $\pi : x - y + 2z - 1 = 0$ 上的投影直线 $l_{0}$ 的方程, 并求 $l_{0}$ 绕 $y$ 轴旋转一周所成曲面的方程.');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q11', 'math1_1998_main_q11', 1998, 11, 3, 11, '三、【解】 方法一 $L$ 的参数方程为 $L:\left\{ \begin{array}{ll}x = 1 + t,\\ y = t,\\ z = 1 - t, \end{array} \right.$ 代入 $\pi$ 得 $L$ 与 $\pi$ 的交点为 $M_{1}(2,1,0)$

$M_0(1,0,1)\in L$ ，过 $M_0$ 且与 $\pi$ 垂直的直线为 $L^{\prime}$ ： $\frac{x - 1}{1} = \frac{y}{-1} = \frac{z - 1}{2},$

$L^{\prime}$ 的参数方程为 $L^{\prime}$ $\begin{cases} x = 1 + t,\\ y = -t,\\ z = 1 + 2t, \end{cases}$ 代入 $\pi$ 得垂足坐标为 $M_2\left(\frac{2}{3},\frac{1}{3},\frac{1}{3}\right)$

$\overrightarrow{M_2M_1} = \left\{\frac{4}{3},\frac{2}{3}, - \frac{1}{3}\right\}$ 故 $L_{0}: \frac{x - 2}{4} = \frac{y - 1}{2} = \frac{z}{-1}.$

设 $L_{0}$ 绕 $y$ 轴旋转一周所得的旋转曲面为 $\Sigma$ ，任取 $P(x,y,z)\in \Sigma$ ，其所在的圆周对应的 $L_{0}$ 上的点为 $P_0(x_0,y,z_0)$ ，圆心为 $T(0,y,0)$

由 $|PT| = |P_0T|$ 得 $x^{2} + z^{2} = x_{0}^{2} + z_{0}^{2}$

再由 $P_{0}(x_{0},y,z_{0})\in L_{0}$ 得 $\frac{x_0 - 2}{4} = \frac{y - 1}{2} = \frac{z_0}{-1}$ 解得 $x_0 = 2y,z_0 = -\frac{y - 1}{2}$

故 $\Sigma$ 的方程为 $4x^{2} - 17y^{2} + 4z^{2} + 2y - 1 = 0.$

方法二

直线 $L: \frac{x - 1}{1} = \frac{y}{1} = \frac{z - 1}{-1}$ 的一般形式为 $L: \left\{ \begin{array}{l} \frac{x - 1}{1} = \frac{y}{1}, \\ \frac{y}{1} = \frac{z - 1}{-1}, \end{array} \right.$ $L: \left\{ \begin{array}{l} x - y - 1 = 0, \\ y + z - 1 = 0, \end{array} \right.$

过直线 $L$ 的平面束为 $\pi_0:(x - y - 1) + \lambda (y + z - 1) = 0$ ，即

$$
\pi_ {0}: x + (\lambda - 1) y + \lambda z - 1 - \lambda = 0,
$$

由 $\{1, - 1,2\} \cdot \{1,\lambda -1,\lambda \} = 0$ 得 $\lambda = -2$

则投影直线为 $L_{0}$ $\left\{ \begin{array}{l}x - 3y - 2z + 1 = 0,\\ x - y + 2z - 1 = 0. \end{array} \right.$

显然 $M_0(2,1,0)\in L_0,L_0$ 的方向向量为

$$
s = \{1, - 3, - 2 \} \times \{1, - 1, 2 \} = \{- 8, - 4, 2 \},
$$

直线 $L_{0}$ 的点向式方程为 $L_{0}:\frac{x - 2}{4} = \frac{y - 1}{2} = \frac{z}{-1}.$

设 $L_{0}$ 绕 $y$ 轴旋转一周所得的旋转曲面为 $\Sigma$ ，任取 $P(x,y,z)\in \Sigma$ ，其所在的圆周对应的 $L_{0}$ 上的点为 $P_0(x_0,y,z_0)$ ，圆心为 $T(0,y,0)$

由 $|PT| = |P_0T|$ 得 $x^{2} + z^{2} = x_{0}^{2} + z_{0}^{2}$

再由 $P_{0}(x_{0},y,z_{0})\in L_{0}$ 得 $\frac{x_0 - 2}{4} = \frac{y - 1}{2} = \frac{z_0}{-1}$ 解得 $x_0 = 2y,z_0 = -\frac{y - 1}{2}$

故 $\Sigma$ 的方程为 $4x^{2} - 17y^{2} + 4z^{2} + 2y - 1 = 0.$', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'ok', 'sequential_year_index', 0.528, '1998:11', 3, 0.528);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q12', 'math1', 1998, '真题', 'main', 12, '# 四、(本题满分6分)

确定常数 $\lambda$ ，使在右半平面 $x > 0$ 上的向量 $A(x,y) = 2xy(x^4 +y^2)^{\lambda}i - x^2 (x^4 +y^2)^{\lambda}j$ 为某二元函数 $u(x,y)$ 的梯度，并求 $u(x,y)$', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第12题\题目.md', '1998\按题拆分\真题\第12题\题目.md', 0, 'ok', '1998 真题 第12题 # 四、(本题满分6分)

确定常数 $\lambda$ ，使在右半平面 $x > 0$ 上的向量 $a(x,y) = 2xy(x^4 +y^2)^{\lambda}i - x^2 (x^4 +y^2)^{\lambda}j$ 为某二元函数 $u(x,y)$ 的梯度，并求 $u(x,y)$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1998_main_q12', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q12', 'math1_1998_main_q12', 1998, 12, 4, 12, '四、【解】 $P(x,y) = 2xy(x^4 +y^2)^{\lambda},\quad Q(x,y) = -x^2 (x^4 +y^2)^{\lambda},$

$$
\frac {\partial Q}{\partial x} = - 2 x \left(x ^ {4} + y ^ {2}\right) ^ {\lambda} - 4 \lambda x ^ {5} \left(x ^ {4} + y ^ {2}\right) ^ {\lambda - 1},
$$

$$
\frac {\partial P}{\partial y} = 2 x \left(x ^ {4} + y ^ {2}\right) ^ {\lambda} + 4 \lambda x y ^ {2} \left(x ^ {4} + y ^ {2}\right) ^ {\lambda - 1},
$$

由 $\frac{\partial P}{\partial y} = \frac{\partial Q}{\partial x}$ 得 $4x(\lambda + 1)(x^4 + y^2) = 0$ ，解得 $\lambda = -1$

则 $u(x,y) = \int_{(1,0)}^{(x,y)}\frac{2xy\mathrm{d}x - x^2\mathrm{d}y}{x^4 + y^2} = \int_1^x 0\mathrm{d}x + \int_0^y\frac{-x^2\mathrm{d}y}{x^4 + y^2} = -\arctan \frac{y}{x^2} +C,$

故所求的二元函数为 $u(x,y) = -\arctan \frac{y}{x^2} +C(C$ 为任意常数).', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'ok', 'sequential_year_index', 0.226, '1998:12', 4, 0.226);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q13', 'math1', 1998, '真题', 'main', 13, '# 五、(本题满分6分)

从船上向海中沉放某种探测器, 按探测要求, 需确定仪器的下沉深度 $y$ (从海平面算起) 与下沉速度 $v$ 之间的函数关系. 设仪器在重力作用下, 从海平面由静止开始铅直下沉, 在下沉过程中还受到阻力和浮力的作用. 设仪器的质量为 $m$ , 体积为 $B$ , 海水比重为 $\rho$ , 仪器所受的阻力与下沉速度成正比, 比例系数为 $k (k > 0)$ . 试建立 $y$ 与 $v$ 所满足的微分方程, 并求出函数关系式 $y = y(v)$ .', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第13题\题目.md', '1998\按题拆分\真题\第13题\题目.md', 0, 'ok', '1998 真题 第13题 # 五、(本题满分6分)

从船上向海中沉放某种探测器, 按探测要求, 需确定仪器的下沉深度 $y$ (从海平面算起) 与下沉速度 $v$ 之间的函数关系. 设仪器在重力作用下, 从海平面由静止开始铅直下沉, 在下沉过程中还受到阻力和浮力的作用. 设仪器的质量为 $m$ , 体积为 $b$ , 海水比重为 $\rho$ , 仪器所受的阻力与下沉速度成正比, 比例系数为 $k (k > 0)$ . 试建立 $y$ 与 $v$ 所满足的微分方程, 并求出函数关系式 $y = y(v)$ .');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1998_main_q13', 'tag_微分方程');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q13', 'math1_1998_main_q13', 1998, 13, 5, 13, '五、【解】 取沉放点为坐标原点， $y$ 轴铅直向下，由牛顿第二定律得

$$
m \frac {\mathrm {d} ^ {2} y}{\mathrm {d} t ^ {2}} = m g - B \rho - k v,
$$

令 $\frac{\mathrm{dy}}{\mathrm{dt}} = v$ ，则 $\frac{\mathrm{d}^2y}{\mathrm{d}t^2} = v\frac{\mathrm{d}v}{\mathrm{d}y}$ 代人得 $\frac{mv\mathrm{d}v}{\mathrm{d}y} = mg - B\rho -kv$

变量分离得 $\frac{mv\mathrm{d}v}{mg - B\rho - kv} = \mathrm{dy}$ ，积分得

$$
y = - \frac {m}{k} v - \frac {m (m g - B \rho)}{k ^ {2}} \ln (m g - B \rho - k v) + C _ {0},
$$

由 $y|_{t = 0} = 0, v|_{t = 0} = 0$ 得 $C_0 = \frac{m(mg - B\rho)}{k^2}\ln (mg - B\rho)$

故 $y = -\frac{m}{k} v - \frac{m(mg - B\rho)}{k^2}\ln \frac{mg - B\rho - kv}{mg - B\rho}.$', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'manual_check', 'sequential_year_index', 0, '1998:13', 1, 0);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q14', 'math1', 1998, '真题', 'main', 14, '# 六、(本题满分7分)

计算 $\iint_{\Sigma} \frac{ax \, \mathrm{d}y \, \mathrm{d}z + (z + a)^2 \, \mathrm{d}x \, \mathrm{d}y}{(x^2 + y^2 + z^2)^{\frac{1}{2}}}$ , 其中 $\Sigma$ 为下半球面 $z = -\sqrt{a^2 - x^2 - y^2}$ 的上侧, $a$ 为大于零的常数.', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第14题\题目.md', '1998\按题拆分\真题\第14题\题目.md', 0, 'ok', '1998 真题 第14题 # 六、(本题满分7分)

计算 $\iint_{\sigma} \frac{ax \, \mathrm{d}y \, \mathrm{d}z + (z + a)^2 \, \mathrm{d}x \, \mathrm{d}y}{(x^2 + y^2 + z^2)^{\frac{1}{2}}}$ , 其中 $\sigma$ 为下半球面 $z = -\sqrt{a^2 - x^2 - y^2}$ 的上侧, $a$ 为大于零的常数.');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q14', 'math1_1998_main_q14', 1998, 14, 6, 14, '六、【解】 $I = \iint_{\Sigma} \frac{ax \, \mathrm{d}y \, \mathrm{d}z + (z + a)^2 \, \mathrm{d}x \, \mathrm{d}y}{\sqrt{x^2 + y^2 + z^2}} = \frac{1}{a} \iint_{\Sigma} ax \, \mathrm{d}y \, \mathrm{d}z + (z + a)^2 \, \mathrm{d}x \, \mathrm{d}y,$

令 $\Sigma_0: z = 0 (x^2 + y^2 \leqslant a^2)$ ，取下侧，则

$$
\iint_ {\Sigma} a x \mathrm {d} y \mathrm {d} z + (z + a) ^ {2} \mathrm {d} x \mathrm {d} y = \iint_ {\Sigma + \Sigma_ {0}} a x \mathrm {d} y \mathrm {d} z + (z + a) ^ {2} \mathrm {d} x \mathrm {d} y - \iint_ {\Sigma_ {0}} a x \mathrm {d} y \mathrm {d} z + (z + a) ^ {2} \mathrm {d} x \mathrm {d} y,
$$

而 $\iint_{\Sigma + \Sigma_0} ax \, \mathrm{d}y \, \mathrm{d}z + (z + a)^2 \, \mathrm{d}x \, \mathrm{d}y = -\iiint_{\Omega} (2z + 3a) \, \mathrm{d}v = -2\iiint_{\Omega} z \, \mathrm{d}v - 3a \cdot \frac{2}{3}\pi a^3$

$$
\begin{array}{l} = - 2 \int_ {0} ^ {2 \pi} d \theta \int_ {\frac {\pi}{2}} ^ {\pi} d \varphi \int_ {0} ^ {a} r ^ {3} \sin \varphi \cos \varphi d r - 2 \pi a ^ {4} \\ = \frac {\pi a ^ {4}}{2} - 2 \pi a ^ {4} = - \frac {3 \pi a ^ {4}}{2}; \\ \end{array}
$$

又 $\iint_{\Sigma_0} ax \, \mathrm{d}y \, \mathrm{d}z + (z + a)^2 \, \mathrm{d}x \, \mathrm{d}y = -\iint_{x^2 + y^2 \leqslant a^2} a^2 \, \mathrm{d}x \, \mathrm{d}y = -\pi a^4,$

故 $I = \frac{1}{a}\left(-\frac{3\pi a^4}{2} + \pi a^4\right) = -\frac{1}{2}\pi a^3.$', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'ok', 'sequential_year_index', 0.347, '1998:14', 6, 0.347);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q15', 'math1', 1998, '真题', 'main', 15, '# 七、(本题满分6分)

求 $\lim_{n\to \infty}\left(\frac{\sin\frac{\pi}{n}}{n + 1} +\frac{\sin\frac{2\pi}{n}}{n + \frac{1}{2}} +\dots +\frac{\sin\pi}{n + \frac{1}{n}}\right)$', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第15题\题目.md', '1998\按题拆分\真题\第15题\题目.md', 0, 'ok', '1998 真题 第15题 # 七、(本题满分6分)

求 $\lim_{n\to \infty}\left(\frac{\sin\frac{\pi}{n}}{n + 1} +\frac{\sin\frac{2\pi}{n}}{n + \frac{1}{2}} +\dots +\frac{\sin\pi}{n + \frac{1}{n}}\right)$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1998_main_q15', 'tag_极限');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q15', 'math1_1998_main_q15', 1998, 15, 7, 15, '七、【解】 $b_{n} = \frac{\sin\frac{\pi}{n}}{n + 1} +\frac{\sin\frac{2\pi}{n}}{n + \frac{1}{2}} +\dots +\frac{\sin\frac{n\pi}{n}}{n + \frac{1}{n}},$

$$
\frac {1}{n + 1} \sum_ {i = 1} ^ {n} \sin \frac {\pi i}{n} \leqslant b _ {n} \leqslant \frac {1}{n} \sum_ {i = 1} ^ {n} \sin \frac {\pi i}{n},
$$

因为 $\lim_{n\to \infty}\frac{1}{n + 1}\sum_{i = 1}^{n}\sin \frac{\pi i}{n} = \lim_{n\to \infty}\frac{n}{n + 1}\cdot \frac{1}{n}\sum_{i = 1}^{n}\sin \frac{\pi i}{n} = \lim_{n\to \infty}\frac{1}{n}\sum_{i = 1}^{n}\sin \frac{\pi i}{n} = \int_0^1\sin \pi x\mathrm{d}x,$

所以由夹逼定理得

$$
\begin{array}{l} \lim  _ {n \rightarrow \infty} \left(\frac {\sin \frac {\pi}{n}}{n + 1} + \frac {\sin \frac {2 \pi}{n}}{n + \frac {1}{2}} + \dots + \frac {\sin \frac {n \pi}{n}}{n + \frac {1}{n}}\right) = \int_ {0} ^ {1} \sin \pi x d x = \frac {1}{\pi} \int_ {0} ^ {1} \sin \pi x d (\pi x) \\ = \frac {1}{\pi} \int_ {0} ^ {\pi} \sin x d x = \frac {2}{\pi}. \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'ok', 'sequential_year_index', 0.4, '1998:15', 7, 0.4);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q16', 'math1', 1998, '真题', 'main', 16, '# 八、(本题满分5分)

设正项数列 $\{a_{n}\}$ 单调减少，且 $\sum_{n = 1}^{\infty}(-1)^{n}a_{n}$ 发散，试问级数 $\sum_{n = 1}^{\infty}\left(\frac{1}{a_n + 1}\right)^n$ 是否收敛？并说明理由.', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第16题\题目.md', '1998\按题拆分\真题\第16题\题目.md', 0, 'ok', '1998 真题 第16题 # 八、(本题满分5分)

设正项数列 $\{a_{n}\}$ 单调减少，且 $\sum_{n = 1}^{\infty}(-1)^{n}a_{n}$ 发散，试问级数 $\sum_{n = 1}^{\infty}\left(\frac{1}{a_n + 1}\right)^n$ 是否收敛？并说明理由.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1998_main_q16', 'tag_级数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q16', 'math1_1998_main_q16', 1998, 16, 8, 16, '八、【解】因为 $\{a_{n}\}$ 单调递减且 $a_{n} > 0$ ，所以 $\lim_{n\to \infty}a_n$ 存在，设 $\lim_{n\to \infty}a_n = A$ ，显然 $A\geqslant 0$

因为交错级数 $\sum_{n=1}^{\infty}(-1)^{n}a_{n}$ 发散且 $\{a_{n}\}$ 单调递减，所以 $A > 0$

对正项级数 $\sum_{n=1}^{\infty}\left(\frac{1}{a_n + 1}\right)^n$

因为 $\lim_{n\to \infty}\sqrt[n]{\left(\frac{1}{a_n + 1}\right)^n} = \lim_{n\to \infty}\frac{1}{a_n + 1} = \frac{1}{A + 1} < 1$ ，所以级数 $\sum_{n = 1}^{\infty}\left(\frac{1}{a_n + 1}\right)^n$ 收敛.', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'ok', 'sequential_year_index', 0.318, '1998:16', 8, 0.318);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q17', 'math1', 1998, '真题', 'main', 17, '# 九、(本题满分6分)

(1) 试证存在 $x_0 \in (0,1)$ , 使得在区间 $[0, x_0]$ 上以 $f(x_0)$ 为高的矩形面积, 等于在区间 $[x_0,1]$ 上以 $y = f(x)$ 为曲边的梯形面积.', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第17题\题目.md', '1998\按题拆分\真题\第17题\题目.md', 0, 'ok', '1998 真题 第17题 # 九、(本题满分6分)

(1) 试证存在 $x_0 \in (0,1)$ , 使得在区间 $[0, x_0]$ 上以 $f(x_0)$ 为高的矩形面积, 等于在区间 $[x_0,1]$ 上以 $y = f(x)$ 为曲边的梯形面积.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1998_main_q17', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q17', 'math1_1998_main_q17', 1998, 17, 9, 17, '九、【证明】 $(1)S_{1}(x_{0}) = x_{0}f(x_{0}),\quad S_{2}(x_{0}) = \int_{x_{0}}^{1}f(x)\mathrm{d}x,$

令 $\varphi (x) = xf(x) - \int_{x}^{1}f(t)\mathrm{d}t$

显然 $F(x) = x\int_{x}^{x}f(t)\mathrm{d}t$ 为 $\varphi (x)$ 的原函数，即 $F^{\prime}(x) = \varphi (x)$

$F(0) = F(1) = 0$ ，由罗尔定理，存在 $x_0\in (0,1)$ ，使得 $F^{\prime}(x_0) = 0$ ，即 $\varphi (x_0) = 0$

故存在 $x_0 \in (0,1)$ ，使得 $S_{1}(x_{0}) = S_{2}(x_{0})$

$$
(2) \varphi^ {\prime} (x) = f (x) + x f ^ {\prime} (x) + f (x) = x f ^ {\prime} (x) + 2 f (x),
$$

由 $f^{\prime}(x) > - \frac{2f(x)}{x}$ 得 $xf^{\prime}(x) + 2f(x) > 0$ ，即 $\varphi ''(x) > 0(0 <   x <   1)$

则 $\varphi (x)$ 在(0，1）内严格递增，故（1）中的 $x_0$ 是唯一的', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'ok', 'sequential_year_index', 0.17, '1998:17', 9, 0.17);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q18', 'math1', 1998, '真题', 'main', 18, '# 九、(本题满分6分)

(2) 又设 $f(x)$ 在区间 $(0,1)$ 内可导，且 $f^{\prime}(x) > -\frac{2f(x)}{x}$ ，证明（1）中的 $x_0$ 是唯一的.', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第18题\题目.md', '1998\按题拆分\真题\第18题\题目.md', 0, 'ok', '1998 真题 第18题 # 九、(本题满分6分)

(2) 又设 $f(x)$ 在区间 $(0,1)$ 内可导，且 $f^{\prime}(x) > -\frac{2f(x)}{x}$ ，证明（1）中的 $x_0$ 是唯一的.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1998_main_q18', 'tag_导数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q18', 'math1_1998_main_q18', 1998, 18, 10, 18, '十、【解】 令 $\mathbf{A} = \begin{pmatrix} 1 & b & 1 \\ b & a & 1 \\ 1 & 1 & 1 \end{pmatrix}, \mathbf{X} = \begin{pmatrix} x \\ y \\ z \end{pmatrix}$ ，则二次曲面表示为 $\mathbf{X}^{\mathrm{T}}\mathbf{A}\mathbf{X} = 4$

因为 $\mathbf{X}^{\mathrm{T}}\mathbf{A}\mathbf{X}$ 经过正交变换可以化为 $\eta^2 +4\xi^2$ ，所以矩阵 $\mathbf{A}$ 的特征值为 $\lambda_1 = 0,\lambda_2 = 1,\lambda_3 = 4$ 由 $\operatorname {tr}\mathbf{A} = \lambda_{1} + \lambda_{2} + \lambda_{3}$ 得 $a + 2 = 5$ ，解得 $a = 3$

由 $|\mathbf{A}| = \lambda_1\lambda_2\lambda_3$ 得 $b = 1$ ，即 $\mathbf{A} = \begin{pmatrix} 1 & 1 & 1\\ 1 & 3 & 1\\ 1 & 1 & 1 \end{pmatrix} .$

由 $0E - A \rightarrow \left( \begin{array}{ccc}1 & 0 & 1\\ 0 & 1 & 0\\ 0 & 0 & 0 \end{array} \right)$ 得 $\lambda_{1} = 0$ 对应的特征向量为 $\pmb{\alpha}_{1} = \left( \begin{array}{c} - 1\\ 0\\ 1 \end{array} \right)$

由 $\pmb {E} - \pmb {A}\rightarrow \left( \begin{array}{lll}1 & 0 & -1\\ 0 & 1 & 1\\ 0 & 0 & 0 \end{array} \right)$ 得 $\lambda_{2} = 1$ 对应的特征向量为 $\pmb{\alpha}_{2} = \left( \begin{array}{l}1\\ -1\\ 1 \end{array} \right)$

由 $4\pmb {E} - \pmb {A}\rightarrow \left( \begin{array}{rrr}1 & 0 & -1\\ 0 & 1 & -2\\ 0 & 0 & 0 \end{array} \right)$ 得 $\lambda_3 = 4$ 对应的特征向量为 $\alpha_{3} = \binom{1}{2}$

规范化得 $\gamma_{1} = \frac{1}{\sqrt{2}}\binom{-1}{0},\quad \gamma_{2} = \frac{1}{\sqrt{3}}\binom{1}{-1},\quad \gamma_{3} = \frac{1}{\sqrt{6}}\binom{1}{2},$

得正交矩阵 $\pmb{P} = \left[ \begin{array}{ccc} - \frac{1}{\sqrt{2}} & \frac{1}{\sqrt{3}} & \frac{1}{\sqrt{6}}\\ 0 & -\frac{1}{\sqrt{3}} & \frac{2}{\sqrt{6}}\\ \frac{1}{\sqrt{2}} & \frac{1}{\sqrt{3}} & \frac{1}{\sqrt{6}} \end{array} \right].$', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'manual_check', 'sequential_year_index', 0, '1998:18', 9, 0.361);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q19', 'math1', 1998, '真题', 'main', 19, '# 十、(本题满分6分)

已知二次曲面方程 $x^{2} + ay^{2} + z^{2} + 2bxy + 2xz + 2yz = 4$ 可以经过正交变换

$$
\left( \begin{array}{c} x \\ y \\ z \end{array} \right) = \boldsymbol {P} \left( \begin{array}{c} \xi \\ \eta \\ \zeta \end{array} \right)
$$

化为椭圆柱面方程 $\eta^2 + 4\zeta^2 = 4$ ，求 $a, b$ 的值和正交矩阵 $\pmb{P}$', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第19题\题目.md', '1998\按题拆分\真题\第19题\题目.md', 0, 'ok', '1998 真题 第19题 # 十、(本题满分6分)

已知二次曲面方程 $x^{2} + ay^{2} + z^{2} + 2bxy + 2xz + 2yz = 4$ 可以经过正交变换

$$
\left( \begin{array}{c} x \\ y \\ z \end{array} \right) = \boldsymbol {p} \left( \begin{array}{c} \xi \\ \eta \\ \zeta \end{array} \right)
$$

化为椭圆柱面方程 $\eta^2 + 4\zeta^2 = 4$ ，求 $a, b$ 的值和正交矩阵 $\pmb{p}$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1998_main_q19', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q19', 'math1_1998_main_q19', 1998, 19, 11, 19, '十一、【证明】 显然 $\mathbf{A}^k\pmb {\alpha} = \mathbf{0}$ ，令 $l_0\pmb {\alpha} + l_1\pmb {A}\pmb {\alpha} + \dots +l_{k - 1}\pmb{A}^{k - 1}\pmb {\alpha} = \mathbf{0},$

将 $l_0\pmb {\alpha} + l_1\pmb {A}\pmb {\alpha} + \dots +l_{k - 1}\pmb{A}^{k - 1}\pmb {\alpha} = \mathbf{0}$ 两边左乘 $\mathbf{A}^{k - 1}$ 得 $l_0\pmb{A}^{k - 1}\pmb {\alpha} = \mathbf{0}$

因为 $A^{k - 1}\alpha \neq 0$ ，所以 $l_0 = 0$

将 $l_{1}\mathbf{A}\pmb{\alpha} + \dots + l_{k - 1}\mathbf{A}^{k - 1}\pmb{\alpha} = \mathbf{0}$ 两边左乘 $\mathbf{A}^{k - 2}$ 得 $l_{1}\mathbf{A}^{k - 1}\pmb{\alpha} = \mathbf{0}$ ，从而 $l_{1} = 0$

依次类推，可得 $l_{2} = \dots = l_{k - 1} = 0$ ，故 $\alpha ,A\alpha ,\dots ,A^{k - 1}\alpha$ 线性无关.', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'manual_check', 'sequential_year_index', 0, '1998:19', 10, 0.208);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q20', 'math1', 1998, '真题', 'main', 20, '# 十一、(本题满分4分)

设 $\mathbf{A}$ 是 $n$ 阶矩阵, 若存在正整数 $k$ , 使线性方程组 $A^k x = 0$ 有解向量 $\alpha$ , 且 $A^{k-1} \alpha \neq 0$ . 证明: 向量组 $\alpha, A \alpha, \dots, A^{k-1} \alpha$ 是线性无关的.', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第20题\题目.md', '1998\按题拆分\真题\第20题\题目.md', 0, 'ok', '1998 真题 第20题 # 十一、(本题满分4分)

设 $\mathbf{a}$ 是 $n$ 阶矩阵, 若存在正整数 $k$ , 使线性方程组 $a^k x = 0$ 有解向量 $\alpha$ , 且 $a^{k-1} \alpha \neq 0$ . 证明: 向量组 $\alpha, a \alpha, \dots, a^{k-1} \alpha$ 是线性无关的.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1998_main_q20', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q20', 'math1_1998_main_q20', 1998, 20, 12, 20, '十二、【解】 令 $\mathbf{A} = \begin{bmatrix} a_{11} & a_{12} & \dots & a_{1,2n}\\ a_{21} & a_{22} & \dots & a_{2,2n}\\ \vdots & \vdots & & \vdots \\ a_{n1} & a_{n2} & \dots & a_{n,2n} \end{bmatrix},\mathbf{X} = \begin{bmatrix} x_1\\ x_2\\ \vdots \\ x_{2n} \end{bmatrix},\mathbf{B} = \begin{bmatrix} b_{11} & b_{21} & \dots & b_{n1}\\ b_{12} & b_{22} & \dots & b_{n2}\\ \vdots & \vdots & & \vdots \\ b_{1,2n} & b_{2,2n} & \dots & b_{n,2n} \end{bmatrix},$

因为 $(b_{11}, b_{12}, \dots, b_{1,2n})^{\mathrm{T}}, (b_{21}, b_{22}, \dots, b_{2,2n})^{\mathrm{T}}, \dots, (b_{n1}, b_{n2}, \dots, b_{n,2n})^{\mathrm{T}}$ 为方程组 $\mathbf{A}\mathbf{X} = \mathbf{0}$ 的基础解系，所以 $r(\mathbf{A}) = 2n - n = n$ 且 $\mathbf{AB} = \mathbf{O}$ .

又因为 $(b_{11}, b_{12}, \dots, b_{1,2n})^{\mathrm{T}}, (b_{21}, b_{22}, \dots, b_{2,2n})^{\mathrm{T}}, \dots, (b_{n1}, b_{n2}, \dots, b_{n,2n})^{\mathrm{T}}$ 线性无关，

所以 $r(\mathbf{B}) = n$

令 $\mathbf{Y} = (y_{1}, y_{2}, \dots, y_{2n})^{\mathrm{T}}$ ，方程组（Ⅱ）表示为 $\mathbf{B}^{\mathrm{T}}\mathbf{Y} = \mathbf{0}$ ，

由 $\mathbf{AB} = \mathbf{0}$ 得 $\mathbf{B}^{\mathrm{T}}\mathbf{A}^{\mathrm{T}} = \mathbf{0}$ ，即 $(a_{11}, a_{12}, \dots, a_{1,2n})^{\mathrm{T}}, (a_{21}, a_{22}, \dots, a_{2,2n})^{\mathrm{T}}, \dots, (a_{n1}, a_{n2}, \dots, a_{n,2n})^{\mathrm{T}}$ 为方程组 $\mathbf{B}^{\mathrm{T}}\mathbf{Y} = \mathbf{0}$ 的解.

因为 $r(\mathbf{A}) = n$ ，所以 $(a_{11}, a_{12}, \dots, a_{1,2n})^{\mathrm{T}}, (a_{21}, a_{22}, \dots, a_{2,2n})^{\mathrm{T}}, \dots, (a_{n1}, a_{n2}, \dots, a_{n,2n})^{\mathrm{T}}$ 线性无关，又因为 $r(\mathbf{B}^{\mathrm{T}}) = n$ ，所以 $(a_{11}, a_{12}, \dots, a_{1,2n})^{\mathrm{T}}, (a_{21}, a_{22}, \dots, a_{2,2n})^{\mathrm{T}}, \dots, (a_{n1}, a_{n2}, \dots, a_{n,2n})^{\mathrm{T}}$ 为方程组（Ⅱ）的一个基础解系.', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'manual_check', 'sequential_year_index', 0.075, '1998:20', 11, 0.094);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q21', 'math1', 1998, '真题', 'main', 21, '# 十二、(本题满分5分)

已知线性方程组

$$
\left( \begin{array}{l} I \end{array} \right) \left\{ \begin{array}{c} a _ {1 1} x _ {1} + a _ {1 2} x _ {2} + \dots + a _ {1, 2 n} x _ {2 n} = 0, \\ a _ {2 1} x _ {1} + a _ {2 2} x _ {2} + \dots + a _ {2, 2 n} x _ {2 n} = 0, \\ \dots \dots \\ a _ {n 1} x _ {1} + a _ {n 2} x _ {2} + \dots + a _ {n, 2 n} x _ {2 n} = 0 \end{array} \right.
$$

的一个基础解系为 $(b_{11}, b_{12}, \dots, b_{1,2n})^{\mathrm{T}}, (b_{21}, b_{22}, \dots, b_{2,2n})^{\mathrm{T}}, \dots, (b_{n1}, b_{n2}, \dots, b_{n,2n})^{\mathrm{T}}$ . 试写出线性方程组

$$
\left( \begin{array}{c} \text {I I} \end{array} \right) \left\{ \begin{array}{l} b _ {1 1} y _ {1} + b _ {1 2} y _ {2} + \dots + b _ {1, 2 n} y _ {2 n} = 0, \\ b _ {2 1} y _ {1} + b _ {2 2} y _ {2} + \dots + b _ {2, 2 n} y _ {2 n} = 0, \\ \dots \dots \\ b _ {n 1} y _ {1} + b _ {n 2} y _ {2} + \dots + b _ {n, 2 n} y _ {2 n} = 0 \end{array} \right.
$$

的通解，并说明理由', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第21题\题目.md', '1998\按题拆分\真题\第21题\题目.md', 0, 'ok', '1998 真题 第21题 # 十二、(本题满分5分)

已知线性方程组

$$
\left( \begin{array}{l} i \end{array} \right) \left\{ \begin{array}{c} a _ {1 1} x _ {1} + a _ {1 2} x _ {2} + \dots + a _ {1, 2 n} x _ {2 n} = 0, \\ a _ {2 1} x _ {1} + a _ {2 2} x _ {2} + \dots + a _ {2, 2 n} x _ {2 n} = 0, \\ \dots \dots \\ a _ {n 1} x _ {1} + a _ {n 2} x _ {2} + \dots + a _ {n, 2 n} x _ {2 n} = 0 \end{array} \right.
$$

的一个基础解系为 $(b_{11}, b_{12}, \dots, b_{1,2n})^{\mathrm{t}}, (b_{21}, b_{22}, \dots, b_{2,2n})^{\mathrm{t}}, \dots, (b_{n1}, b_{n2}, \dots, b_{n,2n})^{\mathrm{t}}$ . 试写出线性方程组

$$
\left( \begin{array}{c} \text {i i} \end{array} \right) \left\{ \begin{array}{l} b _ {1 1} y _ {1} + b _ {1 2} y _ {2} + \dots + b _ {1, 2 n} y _ {2 n} = 0, \\ b _ {2 1} y _ {1} + b _ {2 2} y _ {2} + \dots + b _ {2, 2 n} y _ {2 n} = 0, \\ \dots \dots \\ b _ {n 1} y _ {1} + b _ {n 2} y _ {2} + \dots + b _ {n, 2 n} y _ {2 n} = 0 \end{array} \right.
$$

的通解，并说明理由');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1998_main_q21', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q21', 'math1_1998_main_q21', 1998, 21, 13, 21, '十三、【解】 令 $Z = X - Y$

因为 $X, Y$ 相互独立且都服从正态分布 $N\left(0, \frac{1}{2}\right)$ ，所以 $X - Y \sim N(0, 1)$ ，即 $Z \sim N(0, 1)$

于是 $E(|X - Y|) = E(|Z|) = \frac{1}{\sqrt{2\pi}} \int_{-\infty}^{+\infty} |z| \mathrm{e}^{-\frac{z^2}{2}} \, \mathrm{d}z$

$$
= \frac {2}{\sqrt {2 \pi}} \int_ {0} ^ {+ \infty} z e ^ {- \frac {z ^ {2}}{2}} d z = \frac {2}{\sqrt {2 \pi}} \int_ {0} ^ {+ \infty} e ^ {- \frac {z ^ {2}}{2}} d \left(\frac {z ^ {2}}{2}\right) = \frac {2}{\sqrt {2 \pi}} \int_ {0} ^ {+ \infty} e ^ {- t} d t = \frac {2}{\sqrt {2 \pi}},
$$

又 $E(|X - Y|^2) = E(|Z|^2) = E(Z^2) = D(Z) + [E(Z)]^2 = 1$

故 $D(|X - Y|) = E(|X - Y|^2) - [E(|X - Y|)]^2 = 1 - \frac{2}{\pi}.$', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'manual_check', 'sequential_year_index', 0, '1998:21', 12, 0.392);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q22', 'math1', 1998, '真题', 'main', 22, '# 十三、(本题满分6分)

设两个随机变量 $X, Y$ 相互独立，且都服从均值为0，方差为 $\frac{1}{2}$ 的正态分布，求随机变量 $|X - Y|$ 的方差.', 'E:\数学自用\数据资料\真题\按年份整理\1998\按题拆分\真题\第22题\题目.md', '1998\按题拆分\真题\第22题\题目.md', 0, 'ok', '1998 真题 第22题 # 十三、(本题满分6分)

设两个随机变量 $x, y$ 相互独立，且都服从均值为0，方差为 $\frac{1}{2}$ 的正态分布，求随机变量 $|x - y|$ 的方差.');
