INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1998_main_q22', 'math1_1998_main_q22', 1998, 22, 14, 22, '十四、【解】设 $\overline{X}$ 为样本均值，则 $\overline{X} \sim N\left(3.4, \frac{6^2}{n}\right)$ 或 $\frac{\overline{X} - 3.4}{\sqrt{n}} \sim N(0,1)$

由 $P\{1.4 < \overline{X} < 5.4\} = P\left\{-\frac{2}{\frac{6}{\sqrt{n}}} < \frac{\overline{X} - 3.4}{\frac{6}{\sqrt{n}}} < \frac{2}{\frac{6}{\sqrt{n}}}\right\} = 2\Phi \left(\frac{\sqrt{n}}{3}\right) - 1 > 0.95$ 得

$\Phi \left(\frac{\sqrt{n}}{3}\right) > 0.975$ ，即 $\frac{\sqrt{n}}{3} >1.96$

解得 $n > 34.57$ ，故 $n$ 至少取35.', 'E:\数学自用\数据资料\真题\按年份整理\1998\解析\1998年解析.md', 'manual_check', 'sequential_year_index', 0, '1998:22', 13, 0.233);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1998_main_q23', 'math1', 1998, '真题', 'main', 23, '# 十四、(本题满分4分)

从正态总体 $N(3.4,6^2)$ 中抽取容量为 $n$ 的样本，如果要求其样本均值位于区间（1.4，5.4）内的概率不小于0.95，问样本容量 $n$ 至少应取多大？

