INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1999_main_q03', 'math1_1999_main_q03', 1999, 3, 3, 3, '(3)【答案】 $C_1\mathrm{e}^{-2x} + C_2\mathrm{e}^{2x} + \frac{1}{4} x\mathrm{e}^{2x}(C_1,C_2$ 为任意常数）.

【解】 特征方程为 $\lambda^2 - 4 = 0$ ，特征根为 $\lambda_1 = -2, \lambda_2 = 2$

则 $y^{\prime \prime} - 4y = 0$ 的通解为 $y = C_{1}\mathrm{e}^{-2x} + C_{2}\mathrm{e}^{2x}$

令 $y^{\prime \prime} - 4y = \mathrm{e}^{2x}$ 的特解为 $y_0(x) = ax\mathrm{e}^{2x}$ ，代入得 $a = \frac{1}{4}$

故 $y^{\prime \prime} - 4y = \mathrm{e}^{2x}$ 的通解为 $y = C_{1}\mathrm{e}^{-2x} + C_{2}\mathrm{e}^{2x} + \frac{1}{4} x\mathrm{e}^{2x}(C_{1},C_{2}$ 为任意常数).', 'E:\数学自用\数据资料\真题\按年份整理\1999\解析\1999年解析.md', 'ok', 'sequential_year_index', 0.3, '1999:3', 3, 0.3);
