INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1999_main_q04', 'math1_1999_main_q04', 1999, 4, 4, 4, '（4）【答案】 $\lambda_{1} = \lambda_{2} = \dots = \lambda_{n - 1} = 0, \lambda_{n} = n$

【解】方法一 由 $|\lambda E - A| = \left| \begin{array}{cccc}\lambda -1 & -1 & \dots & -1\\ -1 & \lambda -1 & \dots & -1\\ \vdots & \vdots & & \vdots \\ -1 & -1 & \dots & \lambda -1 \end{array} \right| = \lambda^{n - 1}(\lambda -n) = 0$ 得

$\mathbf{A}$ 的特征值为 $\lambda_{1} = \lambda_{2} = \dots = \lambda_{n - 1} = 0, \lambda_{n} = n$

方法二 因为 $\mathbf{A}^{\mathrm{T}} = \mathbf{A}$ ，所以 $\mathbf{A}$ 可对角化，从而 $\mathbf{A}$ 的非零特征值的个数与 $r(\mathbf{A})$ 相同，

由 $r(\mathbf{A}) = 1$ 得 $A$ 只有一个非零特征值，

又因为 $\operatorname{tr} A = n = \lambda_1 + \lambda_2 + \dots + \lambda_n$ ，所以 $A$ 的特征值为 $\lambda_1 = \lambda_2 = \dots = \lambda_{n-1} = 0, \lambda_n = n$ .', 'E:\数学自用\数据资料\真题\按年份整理\1999\解析\1999年解析.md', 'manual_check', 'sequential_year_index', 0.025, '1999:4', 4, 0.025);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1999_main_q05', 'math1', 1999, '真题', 'main', 5, '# 一、填空题(本题共5小题，每小题3分，满分15分)

(5) 设两两相互独立的三事件 $A, B$ 和 $C$ 满足条件: $ABC = \emptyset$ , $P(A) = P(B) = P(C) < \frac{1}{2}$ , 且已知 $P(A \cup B \cup C) = \frac{9}{16}$ , 则 $P(A) = \_$ .', 'E:\数学自用\数据资料\真题\按年份整理\1999\按题拆分\真题\第05题\题目.md', '1999\按题拆分\真题\第05题\题目.md', 0, 'ok', '1999 真题 第5题 # 一、填空题(本题共5小题，每小题3分，满分15分)

(5) 设两两相互独立的三事件 $a, b$ 和 $c$ 满足条件: $abc = \emptyset$ , $p(a) = p(b) = p(c) < \frac{1}{2}$ , 且已知 $p(a \cup b \cup c) = \frac{9}{16}$ , 则 $p(a) = \_$ .');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1999_main_q05', 'math1_1999_main_q05', 1999, 5, 5, 5, '(5)【答案】 $\frac{1}{4}$ .

【解】 令 $P(A) = p$

而 $P(A \cup B \cup C) = P(A) + P(B) + P(C) - P(AB) - P(AC) - P(BC) + P(ABC)$

$$
= 3 p - 3 p ^ {2},
$$

则 $3p - 3p^2 = \frac{9}{16}$ ，解得 $p = \frac{1}{4}$ 或 $p = \frac{3}{4}$

由 $P(A) < \frac{1}{2}$ 得 $P(A) = \frac{1}{4}$ .

# 二、选择题', 'E:\数学自用\数据资料\真题\按年份整理\1999\解析\1999年解析.md', 'ok', 'sequential_year_index', 0.15, '1999:5', 5, 0.15);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1999_main_q06', 'math1', 1999, '真题', 'main', 6, '# 二、选择题(本题共5小题，每小题3分，满分15分)

（1）设 $f(x)$ 是连续函数， $F(x)$ 是 $f(x)$ 的原函数，则( )

(A) 当 $f(x)$ 是奇函数时, $F(x)$ 必是偶函数.  
(B) 当 $f(x)$ 是偶函数时, $F(x)$ 必是奇函数.  
（C）当 $f(x)$ 是周期函数时， $F(x)$ 必是周期函数  
（D）当 $f(x)$ 是单调增函数时， $F(x)$ 必是单调增函数', 'E:\数学自用\数据资料\真题\按年份整理\1999\按题拆分\真题\第06题\题目.md', '1999\按题拆分\真题\第06题\题目.md', 0, 'ok', '1999 真题 第6题 # 二、选择题(本题共5小题，每小题3分，满分15分)

（1）设 $f(x)$ 是连续函数， $f(x)$ 是 $f(x)$ 的原函数，则( )

(a) 当 $f(x)$ 是奇函数时, $f(x)$ 必是偶函数.  
(b) 当 $f(x)$ 是偶函数时, $f(x)$ 必是奇函数.  
（c）当 $f(x)$ 是周期函数时， $f(x)$ 必是周期函数  
（d）当 $f(x)$ 是单调增函数时， $f(x)$ 必是单调增函数');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_1999_main_q06', 'tag_连续');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1999_main_q06', 'math1_1999_main_q06', 1999, 6, 1, 6, '（1）【答案】 （A).

【解】 若 $f(x)$ 是奇函数， $F(x) = \int_{a}^{x} f(t) \, \mathrm{d}t$

则 $F(-x) = \int_{a}^{-x}f(t)\mathrm{d}t\frac{t = -u}{-a}\int_{-a}^{x}f(-u)(-\mathrm{d}u) = \int_{-a}^{x}f(u)\mathrm{d}u$

$$
= \int_ {- a} ^ {a} f (u) \mathrm {d} u + \int_ {a} ^ {x} f (u) \mathrm {d} u = \int_ {a} ^ {x} f (u) \mathrm {d} u = F (x),
$$

即 $F(x)$ 为偶函数，应选(A).', 'E:\数学自用\数据资料\真题\按年份整理\1999\解析\1999年解析.md', 'ok', 'sequential_year_index', 0.096, '1999:6', 1, 0.096);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_1999_main_q07', 'math1', 1999, '真题', 'main', 7, '# 二、选择题(本题共5小题，每小题3分，满分15分)

(2) 设 $f(x) = \begin{cases} \frac{1 - \cos x}{\sqrt{x}}, & x > 0, \\ x^2 g(x), & x \leqslant 0, \end{cases}$ 其中 $g(x)$ 是有界函数, 则 $f(x)$ 在 $x = 0$ 处 ( )

(A) 极限不存在.

（B）极限存在，但不连续

(C) 连续, 但不可导.

(D) 可导.', 'E:\数学自用\数据资料\真题\按年份整理\1999\按题拆分\真题\第07题\题目.md', '1999\按题拆分\真题\第07题\题目.md', 0, 'ok', '1999 真题 第7题 # 二、选择题(本题共5小题，每小题3分，满分15分)

(2) 设 $f(x) = \begin{cases} \frac{1 - \cos x}{\sqrt{x}}, & x > 0, \\ x^2 g(x), & x \leqslant 0, \end{cases}$ 其中 $g(x)$ 是有界函数, 则 $f(x)$ 在 $x = 0$ 处 ( )

(a) 极限不存在.

（b）极限存在，但不连续

(c) 连续, 但不可导.

(d) 可导.');
