INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_1999_main_q07', 'math1_1999_main_q07', 1999, 7, 2, 7, '(2)【答案】 (D).

【解】 $f_{+}^{\prime}(0) = \lim_{x\to 0^{+}}\frac{f(x) - f(0)}{x - 0} = \lim_{x\to 0^{+}}\frac{1 - \cos x}{x\sqrt{x}} = 0;$

$$
f _ {-} ^ {\prime} (0) = \lim  _ {x \rightarrow 0 ^ {-}} \frac {f (x) - f (0)}{x - 0} = \lim  _ {x \rightarrow 0 ^ {-}} x g (x) = 0,
$$

因为 $f_{+}^{\prime}(0) = f_{-}^{\prime}(0)$ ，所以 $f(x)$ 在 $x = 0$ 处可导，应选(D).', 'E:\数学自用\数据资料\真题\按年份整理\1999\解析\1999年解析.md', 'ok', 'sequential_year_index', 0.1, '1999:7', 2, 0.1);
