INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2000_main_q01', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2000_main_q01', 'math1_2000_main_q01', 2000, 1, 1, 1, '(1)【答案】 $\frac{\pi}{4}$ .

【解】 方法一

$$
\begin{array}{l} \int_ {0} ^ {1} \sqrt {2 x - x ^ {2}} d x = \int_ {0} ^ {1} \sqrt {1 - (x - 1) ^ {2}} d (x - 1) = \int_ {- 1} ^ {0} \sqrt {1 - x ^ {2}} d x \\ = \int_ {0} ^ {1} \sqrt {1 - x ^ {2}} \mathrm {d} x \xlongequal {x = \sin t} \int_ {0} ^ {\frac {\pi}{2}} \cos^ {2} t \mathrm {d} t = I _ {2} = \frac {1}{2} \times \frac {\pi}{2} = \frac {\pi}{4}. \\ \end{array}
$$

方法二 根据定积分的几何应用， $\int_0^1\sqrt{2x - x^2}\mathrm{d}x$ 即以曲线 $y = \sqrt{2x - x^2}$ （ $0\leqslant x\leqslant 1$ ）为曲边的曲边梯形的面积.

如图所示，显然 $\int_0^1\sqrt{2x - x^2}\mathrm{d}x = \frac{\pi}{4}.$', 'E:\数学自用\数据资料\真题\按年份整理\2000\解析\2000年解析.md', 'ok', 'year_question_no', 0.259, '2000:1', 1, 0.259);
