INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2000_main_q03', 'tag_微分方程');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2000_main_q03', 'math1_2000_main_q03', 2000, 3, 3, 3, '（3）【答案】 $y = \frac{C_1}{x^2} + C_2 (C_1, C_2$ 为任意常数）.

【解】 方法一 由 $xy^{\prime \prime} + 3y^{\prime} = 0$ ，得 $y^{\prime \prime} + \frac{3}{x} y^{\prime} = 0.$

解得 $y^\prime = C_0\mathrm{e}^{-\int \frac{3}{x}\mathrm{d}x} = \frac{C_0}{x^3}$ 积分得原方程的通解为 $y = \frac{C_1}{x^2} +C_2(C_1,C_2$ 为任意常数）

方法二 由 $xy'''' + 3y'' = 0$ ，得 $x^3 y'''' + 3x^2 y'' = 0$ 或 $(x^3 y'')'' = 0$

于是 $x^{3}y^{\prime} = C_{0}$ ，解得 $y^\prime = \frac{C_0}{x^3}$ 积分得原方程通解为 $y = \frac{C_1}{x^2} +C_2(C_1,C_2$ 为任意常数）', 'E:\数学自用\数据资料\真题\按年份整理\2000\解析\2000年解析.md', 'ok', 'year_question_no', 0.156, '2000:3', 3, 0.156);
