INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2000_main_q11', 'math1_2000_main_q11', 2000, 11, 11, 11, '(11)【解】 由 $\lim_{x\to 0^{+}}\left(\frac{2 + \mathrm{e}^{\frac{1}{x}}}{1 + \mathrm{e}^{\frac{4}{x}}} +\frac{\sin x}{|x|}\right) = \lim_{x\to 0^{+}}\frac{2 + \mathrm{e}^{\frac{1}{x}}}{1 + \mathrm{e}^{\frac{4}{x}}} +\lim_{x\to 0^{+}}\frac{\sin x}{x} = 0 + 1 = 1,$

$$
\lim  _ {x \rightarrow 0 ^ {-}} \left(\frac {2 + \mathrm {e} ^ {\frac {1}{x}}}{1 + \mathrm {e} ^ {\frac {4}{x}}} + \frac {\sin x}{| x |}\right) = \lim  _ {x \rightarrow 0 ^ {-}} \frac {2 + \mathrm {e} ^ {\frac {1}{x}}}{1 + \mathrm {e} ^ {\frac {4}{x}}} - \lim  _ {x \rightarrow 0 ^ {-}} \frac {\sin x}{x} = 2 - 1 = 1,
$$

得 $\lim_{x\to 0}\left(\frac{2 + \mathrm{e}^{\frac{1}{x}}}{1 + \mathrm{e}^{\frac{4}{x}}} +\frac{\sin x}{|x|}\right) = 1.$', 'E:\数学自用\数据资料\真题\按年份整理\2000\解析\2000年解析.md', 'ok', 'year_question_no', 0.556, '2000:11', 11, 0.556);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2000_main_q12', 'math1', 2000, '真题', 'main', 12, '# 四、(本题满分5分)

设 $z = f\left(xy, \frac{x}{y}\right) + g\left(\frac{y}{x}\right)$ , 其中 $f$ 具有二阶连续偏导数, $g$ 具有二阶连续导数, 求 $\frac{\partial^2 z}{\partial x \partial y}$ .', 'E:\数学自用\数据资料\真题\按年份整理\2000\按题拆分\真题\第12题\题目.md', '2000\按题拆分\真题\第12题\题目.md', 0, 'ok', '2000 真题 第12题 # 四、(本题满分5分)

设 $z = f\left(xy, \frac{x}{y}\right) + g\left(\frac{y}{x}\right)$ , 其中 $f$ 具有二阶连续偏导数, $g$ 具有二阶连续导数, 求 $\frac{\partial^2 z}{\partial x \partial y}$ .');
