INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2000_main_q12', 'math1_2000_main_q12', 2000, 12, 12, 12, '（12）【解】 由复合函数求偏导法则，得

$$
\begin{array}{l} \frac {\partial z}{\partial x} = y f _ {1} ^ {\prime} + \frac {1}{y} f _ {2} ^ {\prime} - \frac {y}{x ^ {2}} g ^ {\prime}, \\ \frac {\partial^ {2} z}{\partial x \partial y} = f _ {1} ^ {\prime} + y \left(x f _ {1 1} ^ {\prime \prime} - \frac {x}{y ^ {2}} f _ {1 2} ^ {\prime \prime}\right) - \frac {1}{y ^ {2}} f _ {2} ^ {\prime} + \frac {1}{y} \left(x f _ {2 1} ^ {\prime \prime} - \frac {x}{y ^ {2}} f _ {2 2} ^ {\prime \prime}\right) - \frac {1}{x ^ {2}} g ^ {\prime} - \frac {y}{x ^ {3}} g ^ {\prime \prime} \\ = f _ {1} ^ {\prime} - \frac {1}{y ^ {2}} f _ {2} ^ {\prime} + x y f _ {1 1} ^ {\prime \prime} - \frac {x}{y ^ {3}} f _ {2 2} ^ {\prime \prime} - \frac {1}{x ^ {2}} g ^ {\prime} - \frac {y}{x ^ {3}} g ^ {\prime \prime}. \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\2000\解析\2000年解析.md', 'ok', 'year_question_no', 0.081, '2000:12', 12, 0.081);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2000_main_q13', 'math1', 2000, '真题', 'main', 13, '# 五、(本题满分6分)

计算曲线积分 $I = \oint_{L} \frac{x \, \mathrm{d}y - y \, \mathrm{d}x}{4x^2 + y^2}$ , 其中 $L$ 是以点 $(1,0)$ 为中心, $R$ 为半径的圆周 $(R > 1)$ , 取逆时针方向.', 'E:\数学自用\数据资料\真题\按年份整理\2000\按题拆分\真题\第13题\题目.md', '2000\按题拆分\真题\第13题\题目.md', 0, 'ok', '2000 真题 第13题 # 五、(本题满分6分)

计算曲线积分 $i = \oint_{l} \frac{x \, \mathrm{d}y - y \, \mathrm{d}x}{4x^2 + y^2}$ , 其中 $l$ 是以点 $(1,0)$ 为中心, $r$ 为半径的圆周 $(r > 1)$ , 取逆时针方向.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2000_main_q13', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2000_main_q13', 'math1_2000_main_q13', 2000, 13, 13, 13, '(13)【解】 令 $P(x,y) = \frac{-y}{4x^2 + y^2},\quad Q(x,y) = \frac{x}{4x^2 + y^2},$

$$
\frac {\partial Q}{\partial x} = \frac {\partial P}{\partial y} = \frac {y ^ {2} - 4 x ^ {2}}{(4 x ^ {2} + y ^ {2}) ^ {2}} \quad ((x, y) \neq (0, 0)).
$$

如图所示，作 $L_{0}:4x^{2} + y^{2} = r^{2}(r > 0$ 且 $L_{0}$ 位于 $L$ 内，取逆时针方向），设 $L_{0}^{-}$ 与 $L$ 围成的区域为 $D_{1},L_{0}$ 围成的区域为 $D_{2}$ ，由格林公式得

![](images/64aa779820cc1b10b00482248c881d80c3deeaa442cec3fa8e323964ed3a7165.jpg)  
三(13)题图

$$
\oint_ {L + L _ {0} ^ {-}} \frac {x d y - y d x}{4 x ^ {2} + y ^ {2}} = \iint_ {D _ {1}} \left(\frac {\partial Q}{\partial x} - \frac {\partial P}{\partial y}\right) d x d y = 0,
$$

于是 $\oint_{L} \frac{x \, \mathrm{d}y - y \, \mathrm{d}x}{4x^2 + y^2} = \oint_{L_0} \frac{x \, \mathrm{d}y - y \, \mathrm{d}x}{4x^2 + y^2} = \frac{1}{r^2} \oint_{L_0} x \, \mathrm{d}y - y \, \mathrm{d}x$

$$
= \frac {1}{r ^ {2}} \iint_ {D _ {2}} 2 \mathrm {d} \sigma = \frac {2}{r ^ {2}} \iint_ {D _ {2}} \mathrm {d} \sigma = \frac {2}{r ^ {2}} \cdot \pi \cdot r \cdot \frac {r}{2} = \pi .
$$', 'E:\数学自用\数据资料\真题\按年份整理\2000\解析\2000年解析.md', 'ok', 'year_question_no', 0.28, '2000:13', 13, 0.28);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2000_main_q14', 'math1', 2000, '真题', 'main', 14, '# 六、(本题满分7分)

设对于半空间 $x > 0$ 内任意的光滑有向封闭曲面 $S$ , 都有

$$
\iint_ {S} x f (x) \mathrm {d} y \mathrm {d} z - x y f (x) \mathrm {d} z \mathrm {d} x - \mathrm {e} ^ {2 x} z \mathrm {d} x \mathrm {d} y = 0,
$$

其中函数 $f(x)$ 在 $(0, +\infty)$ 内具有连续的一阶导数，且 $\lim_{x \to 0^+} f(x) = 1$ 。求 $f(x)$', 'E:\数学自用\数据资料\真题\按年份整理\2000\按题拆分\真题\第14题\题目.md', '2000\按题拆分\真题\第14题\题目.md', 0, 'ok', '2000 真题 第14题 # 六、(本题满分7分)

设对于半空间 $x > 0$ 内任意的光滑有向封闭曲面 $s$ , 都有

$$
\iint_ {s} x f (x) \mathrm {d} y \mathrm {d} z - x y f (x) \mathrm {d} z \mathrm {d} x - \mathrm {e} ^ {2 x} z \mathrm {d} x \mathrm {d} y = 0,
$$

其中函数 $f(x)$ 在 $(0, +\infty)$ 内具有连续的一阶导数，且 $\lim_{x \to 0^+} f(x) = 1$ 。求 $f(x)$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2000_main_q14', 'tag_极限');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2000_main_q14', 'tag_连续');
