INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2000_main_q14', 'math1_2000_main_q14', 2000, 14, 14, 14, '(14)【解】 $P = xf(x)$ ， $Q = -xyf(x)$ ， $R = -\mathrm{e}^{2x}z$

由高斯公式得

$$
\iint_ {S} x f (x) \mathrm {d} y \mathrm {d} z - x y f (x) \mathrm {d} z \mathrm {d} x - \mathrm {e} ^ {2 x} z \mathrm {d} x \mathrm {d} y = \pm \iiint_ {\Omega} \left(\frac {\partial P}{\partial x} + \frac {\partial Q}{\partial y} + \frac {\partial R}{\partial z}\right) \mathrm {d} v
$$

$= \pm \iiint_{\Omega} [f(x) + xf''(x) - xf(x) - \mathrm{e}^{2x}] \, \mathrm{d}v = 0$ ，其中 $\Omega$ 为S围成的有界闭区域.

由曲面 $S$ 的任意性，得 $f(x) + xf''(x) - xf(x) - \mathrm{e}^{2x} = 0$

整理得 $f^{\prime}(x) + \left(\frac{1}{x} - 1\right)f(x) = \frac{\mathrm{e}^{2x}}{x}$ ,

解得 $f(x) = \left[\int \frac{\mathrm{e}^{2x}}{x}\mathrm{e}^{\int \left(\frac{1}{x} - 1\right)\mathrm{d}x}\mathrm{d}x + C\right]\mathrm{e}^{-\int \left(\frac{1}{x} - 1\right)\mathrm{d}x} = \frac{\mathrm{e}^x(\mathrm{e}^x + C)}{x}.$

因为 $\lim_{x\to 0^{+}}f(x) = 1$ ，所以 $C = -1$ ，于是 $f(x) = \frac{\mathrm{e}^x(\mathrm{e}^x - 1)}{x}$', 'E:\数学自用\数据资料\真题\按年份整理\2000\解析\2000年解析.md', 'ok', 'year_question_no', 0.312, '2000:14', 14, 0.312);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2000_main_q15', 'math1', 2000, '真题', 'main', 15, '# 七、(本题满分6分)

求幂级数 $\sum_{n=1}^{\infty} \frac{1}{3^n + (-2)^n} \frac{x^n}{n}$ 的收敛区间，并讨论该区间端点处的收敛性.', 'E:\数学自用\数据资料\真题\按年份整理\2000\按题拆分\真题\第15题\题目.md', '2000\按题拆分\真题\第15题\题目.md', 0, 'ok', '2000 真题 第15题 # 七、(本题满分6分)

求幂级数 $\sum_{n=1}^{\infty} \frac{1}{3^n + (-2)^n} \frac{x^n}{n}$ 的收敛区间，并讨论该区间端点处的收敛性.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2000_main_q15', 'tag_级数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2000_main_q15', 'math1_2000_main_q15', 2000, 15, 15, 15, '(15)【解】由 $\lim_{n\to \infty}\left|\frac{a_{n + 1}}{a_n}\right| = \lim_{n\to \infty}\frac{n}{n + 1}\cdot \frac{3^n + (-2)^n}{3^{n + 1} + (-2)^{n + 1}} = \frac{1}{3}$ 得 $\sum_{n = 1}^{\infty}\frac{1}{3^n + (-2)^n}\cdot \frac{x^n}{n}$ 的收敛半径为 $R = 3$ ，幂级数 $\sum_{n = 1}^{\infty}\frac{1}{3^n + (-2)^n}\cdot \frac{x^n}{n}$ 的收敛区间为(-3，3).

当 $x = 3$ 时， $\sum_{n = 1}^{\infty}\frac{1}{3^n + (-2)^n}\cdot \frac{3^n}{n} = \sum_{n = 1}^{\infty}\frac{3^n}{3^n + (-2)^n}\cdot \frac{1}{n},$

因为 $\frac{3^n}{3^n + (-2)^n} \cdot \frac{1}{n} > \frac{1}{2n} > 0$ 且 $\sum_{n=1}^{\infty} \frac{1}{2n}$ 发散, 所以 $\sum_{n=1}^{\infty} \frac{1}{3^n + (-2)^n} \cdot \frac{3^n}{n}$ 发散,

即 $x = 3$ 时，级数 $\sum_{n=1}^{\infty} \frac{1}{3^n + (-2)^n} \cdot \frac{x^n}{n}$ 发散；

当 $x = -3$ 时，

$$
\begin{array}{l} \sum_ {n = 1} ^ {\infty} \frac {1}{3 ^ {n} + (- 2) ^ {n}} \cdot \frac {(- 3) ^ {n}}{n} = \sum_ {n = 1} ^ {\infty} \frac {3 ^ {n}}{3 ^ {n} + (- 2) ^ {n}} \cdot \frac {(- 1) ^ {n}}{n} \\ = \sum_ {n = 1} ^ {\infty} \frac {(- 1) ^ {n}}{n} - \sum_ {n = 1} ^ {\infty} \frac {2 ^ {n}}{3 ^ {n} + (- 2) ^ {n}} \cdot \frac {1}{n}, \\ \end{array}
$$

对正项级数 $\sum_{n=1}^{\infty} \frac{2^n}{3^n + (-2)^n} \cdot \frac{1}{n}$ ,

由 $\lim_{n\to \infty}\left\{\left[\frac{2^{n + 1}}{3^{n + 1} + (-2)^{n + 1}}\cdot \frac{1}{n + 1}\right]\Bigg{/}\left[\frac{2^n}{3^n + (-2)^n}\cdot \frac{1}{n}\right]\right\} = \frac{2}{3} < 1$ 得级数 $\sum_{n = 1}^{\infty}\frac{2^n}{3^n + (-2)^n}$

$\frac{1}{n}$ 收敛，再由 $\sum_{n=1}^{\infty} \frac{(-1)^n}{n}$ 收敛得 $x = -3$ 时，级数 $\sum_{n=1}^{\infty} \frac{1}{3^n + (-2)^n} \cdot \frac{x^n}{n}$ 收敛.', 'E:\数学自用\数据资料\真题\按年份整理\2000\解析\2000年解析.md', 'ok', 'year_question_no', 0.444, '2000:15', 15, 0.444);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2000_main_q16', 'math1', 2000, '真题', 'main', 16, '# 八、(本题满分7分)

设有一半径为 $R$ 的球体, $P_{0}$ 是此球的表面上的一个定点, 球体上任一点的密度与该点到 $P_{0}$ 距离的平方成正比 (比例常数 $k > 0$ ), 求球体的重心位置.', 'E:\数学自用\数据资料\真题\按年份整理\2000\按题拆分\真题\第16题\题目.md', '2000\按题拆分\真题\第16题\题目.md', 0, 'ok', '2000 真题 第16题 # 八、(本题满分7分)

设有一半径为 $r$ 的球体, $p_{0}$ 是此球的表面上的一个定点, 球体上任一点的密度与该点到 $p_{0}$ 距离的平方成正比 (比例常数 $k > 0$ ), 求球体的重心位置.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2000_main_q16', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2000_main_q16', 'math1_2000_main_q16', 2000, 16, 16, 16, '（16）【解】设球体为 $\Omega :x^{2} + y^{2} + z^{2}\leqslant R^{2}$ ，点 $P_{0}(0,0,R)$ 为球面 $\Sigma$ 上一点，且设 $\varOmega$ 的重心坐标为 $(\overline{x},\overline{y},\overline{z})$ ，由对称性得 $\overline{x} = 0,\overline{y} = 0$

$$
\bar {z} = \frac {\iiint_ {\Omega} z \cdot k [ x ^ {2} + y ^ {2} + (z - R) ^ {2} ] \mathrm {d} v}{\iiint_ {\Omega} k [ x ^ {2} + y ^ {2} + (z - R) ^ {2} ] \mathrm {d} v} = \frac {\iiint_ {\Omega} z [ x ^ {2} + y ^ {2} + (z - R) ^ {2} ] \mathrm {d} v}{\iiint_ {\Omega} [ x ^ {2} + y ^ {2} + (z - R) ^ {2} ] \mathrm {d} v},
$$

由奇偶性得 $\iiint_{\Omega}[x^2 + y^2 + (z - R)^2] \mathrm{d}v = \iiint_{\Omega}(x^2 + y^2 + z^2) \mathrm{d}v + \iiint_{\Omega}R^2 \mathrm{d}v$

$$
\begin{array}{l} = \int_ {0} ^ {2 \pi} \mathrm {d} \theta \int_ {0} ^ {\pi} \mathrm {d} \varphi \int_ {0} ^ {R} r ^ {4} \sin \varphi \mathrm {d} r + \frac {4 \pi R ^ {5}}{3} \\ = 2 \pi \int_ {0} ^ {\pi} \sin \varphi \mathrm {d} \varphi \int_ {0} ^ {R} r ^ {4} \mathrm {d} r + \frac {4 \pi R ^ {5}}{3} = \frac {3 2 \pi R ^ {5}}{1 5}, \\ \end{array}
$$

$$
\iiint_ {\Omega} z \left[ x ^ {2} + y ^ {2} + (z - R) ^ {2} \right] \mathrm {d} v = - 2 R \iiint_ {\Omega} z ^ {2} \mathrm {d} v = - \frac {2 R}{3} \iiint_ {\Omega} \left(x ^ {2} + y ^ {2} + z ^ {2}\right) \mathrm {d} v = - \frac {8 \pi R ^ {6}}{1 5},
$$

于是 $\overline{z} = -\frac{R}{4}$ 故 $\Omega$ 的重心坐标为 $\left(0,0, - \frac{R}{4}\right)$

方法点评：本题考查三重积分的物理应用.

积分学的物理应用是数学一的考点，主要有：

（1）重心

设 $D$ 为平面区域，面密度为 $\rho (x,y)$ ，则重心坐标为

$$
\bar {x} = \frac {\iint_ {D} x \rho (x , y) \mathrm {d} \sigma}{\iint_ {D} \rho (x , y) \mathrm {d} \sigma}, \quad \bar {y} = \frac {\iint_ {D} y \rho (x , y) \mathrm {d} \sigma}{\iint_ {D} \rho (x , y) \mathrm {d} \sigma};
$$

设 $\Omega$ 为几何体，体密度为 $\rho (x,y,z)$ ，则重心坐标为

$$
\bar {x} = \frac {\iiint_ {\Omega} x \rho (x , y , z) \mathrm {d} v}{\iiint_ {\Omega} \rho (x , y , z) \mathrm {d} v}, \quad \bar {y} = \frac {\iiint_ {\Omega} y \rho (x , y , z) \mathrm {d} v}{\iiint_ {\Omega} \rho (x , y , z) \mathrm {d} v}, \quad \bar {z} = \frac {\iiint_ {\Omega} z \rho (x , y , z) \mathrm {d} v}{\iiint_ {\Omega} \rho (x , y , z) \mathrm {d} v};
$$

设 $L$ 为平面曲线段，线密度为 $\rho (x,y)$ ，则重心坐标为

$$
\bar {x} = \frac {\int_ {L} x \rho (x , y) \mathrm {d} s}{\int_ {L} \rho (x , y) \mathrm {d} s}, \quad \bar {y} = \frac {\int_ {L} y \rho (x , y) \mathrm {d} s}{\int_ {L} \rho (x , y) \mathrm {d} s};
$$

设 $\Sigma$ 为曲面，面密度为 $\rho (x,y,z)$ ，则重心坐标为

$$
\bar {x} = \frac {\iint_ {\Sigma} x \rho (x , y , z) \mathrm {d} S}{\iint_ {\Sigma} \rho (x , y , z) \mathrm {d} S}, \quad \bar {y} = \frac {\iint_ {\Sigma} y \rho (x , y , z) \mathrm {d} S}{\iint_ {\Sigma} \rho (x , y , z) \mathrm {d} S}, \quad \bar {z} = \frac {\iint_ {\Sigma} z \rho (x , y , z) \mathrm {d} S}{\iint_ {\Sigma} \rho (x , y , z) \mathrm {d} S}.
$$

# （2）转动惯量

设 $D$ 为平面区域，面密度为 $\rho (x,y)$ ，则转动惯量为

$$
I _ {x} = \iint_ {D} y ^ {2} \rho (x, y) d \sigma , \quad I _ {y} = \iint_ {D} x ^ {2} \rho (x, y) d \sigma , \quad I _ {o} = \iint_ {D} (x ^ {2} + y ^ {2}) \rho (x, y) d \sigma .
$$

对几何体、空间曲线、空间曲面绕某直线旋转的转动惯量有类似公式.', 'E:\数学自用\数据资料\真题\按年份整理\2000\解析\2000年解析.md', 'ok', 'year_question_no', 0.015, '2000:16', 15, 0.03);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2000_main_q17', 'math1', 2000, '真题', 'main', 17, '# 九、(本题满分6分)

设函数 $f(x)$ 在 $[0, \pi]$ 上连续，且 $\int_0^\pi f(x) \mathrm{d}x = 0, \int_0^\pi f(x) \cos x \mathrm{d}x = 0$ 。试证：在 $(0, \pi)$ 内至少存在两个不同的点 $\xi_1, \xi_2$ ，使 $f(\xi_1) = f(\xi_2) = 0$ 。', 'E:\数学自用\数据资料\真题\按年份整理\2000\按题拆分\真题\第17题\题目.md', '2000\按题拆分\真题\第17题\题目.md', 0, 'ok', '2000 真题 第17题 # 九、(本题满分6分)

设函数 $f(x)$ 在 $[0, \pi]$ 上连续，且 $\int_0^\pi f(x) \mathrm{d}x = 0, \int_0^\pi f(x) \cos x \mathrm{d}x = 0$ 。试证：在 $(0, \pi)$ 内至少存在两个不同的点 $\xi_1, \xi_2$ ，使 $f(\xi_1) = f(\xi_2) = 0$ 。');
