INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2000_main_q17', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2000_main_q17', 'math1_2000_main_q17', 2000, 17, 17, 17, '(17)【解】令 $F(x) = \int_{0}^{x}f(t)\mathrm{d}t,F(0) = F(\pi) = 0.$

由罗尔定理，存在 $c \in (0, \pi)$ ，使得 $F''(c) = 0$ ，即 $f(c) = 0$

用反证法. 不妨设在 $(0, \pi)$ 内 $f(x)$ 除 $c$ 外没有其他零点，则 $f(x)$ 在 $(0, c)$ 与 $(c, \pi)$ 内异号，不妨设当 $x \in (0, c)$ 时， $f(x) > 0$ ；当 $x \in (c, \pi)$ 时， $f(x) < 0$ .

$$
\int_ {0} ^ {\pi} (\cos x - \cos c) f (x) d x = \int_ {0} ^ {c} (\cos x - \cos c) f (x) d x + \int_ {c} ^ {\pi} (\cos x - \cos c) f (x) d x,
$$

因为 $(\cos x - \cos c)f(x)$ 在 $[0, c]$ 上连续， $(\cos x - \cos c)f(x) \geqslant 0$ 且不恒为零，所以 $\int_{0}^{c} (\cos x - \cos c)f(x) \mathrm{d}x > 0.$

同理 $\int_{c}^{\pi} (\cos x - \cos c) f(x) \mathrm{d}x > 0$ ，故 $\int_{0}^{\pi} (\cos x - \cos c) f(x) \mathrm{d}x > 0$ .

而 $\int_0^\pi (\cos x - \cos c)f(x)\mathrm{d}x = \int_0^\pi \cos xf(x)\mathrm{d}x - \cos c\int_0^\pi f(x)\mathrm{d}x = 0$ ，矛盾，所以 $f(x)$ 在 $(0,\pi)$ 内至少有两个零点.', 'E:\数学自用\数据资料\真题\按年份整理\2000\解析\2000年解析.md', 'ok', 'year_question_no', 0.224, '2000:17', 17, 0.224);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2000_main_q18', 'math1', 2000, '真题', 'main', 18, '# 十、(本题满分6分)

设矩阵 $\mathbf{A}$ 的伴随矩阵 $A^{*} = \begin{pmatrix} 1 & 0 & 0 & 0\\ 0 & 1 & 0 & 0\\ 1 & 0 & 1 & 0\\ 0 & -3 & 0 & 8 \end{pmatrix}$ , 且 $\mathbf{A}\mathbf{B}\mathbf{A}^{-1} = \mathbf{B}\mathbf{A}^{-1} + 3\mathbf{E}$ , 其中 $\mathbf{E}$ 为4阶单位矩阵, 求矩阵 $\mathbf{B}$ .', 'E:\数学自用\数据资料\真题\按年份整理\2000\按题拆分\真题\第18题\题目.md', '2000\按题拆分\真题\第18题\题目.md', 0, 'ok', '2000 真题 第18题 # 十、(本题满分6分)

设矩阵 $\mathbf{a}$ 的伴随矩阵 $a^{*} = \begin{pmatrix} 1 & 0 & 0 & 0\\ 0 & 1 & 0 & 0\\ 1 & 0 & 1 & 0\\ 0 & -3 & 0 & 8 \end{pmatrix}$ , 且 $\mathbf{a}\mathbf{b}\mathbf{a}^{-1} = \mathbf{b}\mathbf{a}^{-1} + 3\mathbf{e}$ , 其中 $\mathbf{e}$ 为4阶单位矩阵, 求矩阵 $\mathbf{b}$ .');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2000_main_q18', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2000_main_q18', 'math1_2000_main_q18', 2000, 18, 18, 18, '（18）【解】 $|\mathbf{A}^{*}| = 8$ ，由 $|\mathbf{A}^{*}| = |\mathbf{A}|^{3}$ ，得 $|\mathbf{A}| = 2$

由 $\mathbf{A}\mathbf{B}\mathbf{A}^{-1} = \mathbf{B}\mathbf{A}^{-1} + 3\mathbf{E}$ ，得 $\mathbf{AB} = \mathbf{B} + 3\mathbf{A}$ ，解得 $(A - E)\pmb {B} = 3\pmb{A}$

于是 $\pmb {B} = 3(\pmb {A} - \pmb {E})^{-1}\pmb {A} = 3[\pmb{A}^{-1}(\pmb {A} - \pmb {E})]^{-1} = 6(2\pmb {E} - 2\pmb{A}^{-1})^{-1} = 6(2\pmb {E} - \pmb{A}^{*})^{-1},$

因为 $2\pmb {E} - \pmb{A}^{*} = \left[ \begin{array}{cccc}1 & 0 & 0 & 0\\ 0 & 1 & 0 & 0\\ -1 & 0 & 1 & 0\\ 0 & 3 & 0 & -6 \end{array} \right],$ 所以 $(2\pmb {E} - \pmb{A}^{*})^{-1} = \left[ \begin{array}{cccc}1 & 0 & 0 & 0\\ 0 & 1 & 0 & 0\\ 1 & 0 & 1 & 0\\ 0 & \frac{1}{2} & 0 & -\frac{1}{6} \end{array} \right],$

于是 $\pmb{B} = \begin{bmatrix} 6 & 0 & 0 & 0\\ 0 & 6 & 0 & 0\\ 6 & 0 & 6 & 0\\ 0 & 3 & 0 & -1 \end{bmatrix} .$', 'E:\数学自用\数据资料\真题\按年份整理\2000\解析\2000年解析.md', 'ok', 'year_question_no', 0.304, '2000:18', 18, 0.304);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2000_main_q19', 'math1', 2000, '真题', 'main', 19, '# 十一、(本题满分8分)

（1）求 $\binom{x_{n+1}}{y_{n+1}}$ 与 $\binom{x_n}{y_n}$ 的关系式并写成矩阵形式： $\begin{pmatrix} x_{n+1} \\ y_{n+1} \end{pmatrix} = A \begin{pmatrix} x_n \\ y_n \end{pmatrix}$ ;', 'E:\数学自用\数据资料\真题\按年份整理\2000\按题拆分\真题\第19题\题目.md', '2000\按题拆分\真题\第19题\题目.md', 0, 'ok', '2000 真题 第19题 # 十一、(本题满分8分)

（1）求 $\binom{x_{n+1}}{y_{n+1}}$ 与 $\binom{x_n}{y_n}$ 的关系式并写成矩阵形式： $\begin{pmatrix} x_{n+1} \\ y_{n+1} \end{pmatrix} = a \begin{pmatrix} x_n \\ y_n \end{pmatrix}$ ;');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2000_main_q19', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2000_main_q19', 'math1_2000_main_q19', 2000, 19, 19, 19, '（19）【解】（I）由题意得

$$
\left\{ \begin{array}{l} x _ {n + 1} = \frac {5}{6} x _ {n} + \frac {2}{5} \left(\frac {1}{6} x _ {n} + y _ {n}\right), \\ y _ {n + 1} = \frac {3}{5} \left(\frac {1}{6} x _ {n} + y _ {n}\right), \end{array} \right.
$$

整理得 $\begin{cases} x_{n + 1} = \frac{9}{10} x_n + \frac{2}{5} y_n, \\ y_{n + 1} = \frac{1}{10} x_n + \frac{3}{5} y_n. \end{cases}$

9 2 10 5 1 3 10 5 5

（Ⅱ）令 $P = (\pmb{\eta}_1, \pmb{\eta}_2) = \begin{pmatrix} 4 & -1 \\ 1 & 1 \end{pmatrix}$ ，因为 $\pmb{\eta}_1, \pmb{\eta}_2$ 不成比例，所以 $\pmb{\eta}_1, \pmb{\eta}_2$ 线性无关.由 $A\pmb{\eta}_1 = \pmb{\eta}_1$ ，得 $\pmb{\eta}_1$ 为 $\mathbf{A}$ 的属于特征值 $\lambda_1 = 1$ 的特征向量；

由 $A\pmb{\eta}_2 = \frac{1}{2}\pmb{\eta}_2$ ，得 $\pmb{\eta}_{2}$ 为 $\mathbf{A}$ 的属于特征值 $\lambda_{2} = \frac{1}{2}$ 的特征向量.

$\binom{x_{n+1}}{y_{n+1}}=\mathbf{A}\binom{x_n}{y_n}=\mathbf{A}^2\binom{x_{n-1}}{y_{n-1}}=\cdots=\mathbf{A}^n\binom{x_1}{y_1},$

由 $P^{-1}AP = \left( \begin{array}{ll}1 & 0\\ 0 & \frac{1}{2} \end{array} \right)$ ，得 $A = P\left( \begin{array}{ll}1 & 0\\ 0 & \frac{1}{2} \end{array} \right)P^{-1}$ ，于是 $A^n = P\left( \begin{array}{ll}1 & 0\\ 0 & \frac{1}{2^n} \end{array} \right)P^{-1}$

而 $P^{-1} = \frac{1}{5}\left( \begin{array}{ll}1 & 1\\ -1 & 4 \end{array} \right)$ ，因此 $A^n = P\left( \begin{array}{cc}1 & 0\\ 0 & \frac{1}{2^n} \end{array} \right)P^{-1} = \frac{1}{5}\left( \begin{array}{cc}4 + \frac{1}{2^n} & 4 - \frac{1}{2^{n - 2}}\\ 1 - \frac{1}{2^n} & 1 + \frac{1}{2^{n - 2}} \end{array} \right),$

故 $\binom{x_{n+1}}{y_{n+1}} = A^n \cdot \frac{1}{2} \binom{1}{1} = \frac{1}{10} \binom{8 - \frac{3}{2^n}}{2 + \frac{3}{2^n}}$ .', 'E:\数学自用\数据资料\真题\按年份整理\2000\解析\2000年解析.md', 'ok', 'year_question_no', 0.261, '2000:19', 19, 0.261);
