INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2001_main_q18', 'math1_2001_main_q18', 2001, 18, 18, 18, '(18)【解】（I）由 $\mathbf{A}\mathbf{P} = (\mathbf{A}\mathbf{x},\mathbf{A}^2\mathbf{x},\mathbf{A}^3\mathbf{x}) = (\mathbf{A}\mathbf{x},\mathbf{A}^2\mathbf{x},3\mathbf{A}\mathbf{x} - 2\mathbf{A}^2\mathbf{x}) = \mathbf{P}\left( \begin{array}{ccc}0 & 0 & 0\\ 1 & 0 & 3\\ 0 & 1 & -2 \end{array} \right) = \mathbf{PB}$ ，

得 $\mathbf{A} = \mathbf{P}\mathbf{B}\mathbf{P}^{-1}$ ，其中 $\pmb {B} = \left( \begin{array}{lll}0 & 0 & 0\\ 1 & 0 & 3\\ 0 & 1 & -2 \end{array} \right).$

（Ⅱ）由 $|\lambda \pmb {E} - \pmb {B}| = \left| \begin{array}{ccc}\lambda & 0 & 0\\ -1 & \lambda & -3\\ 0 & -1 & \lambda +2 \end{array} \right| = (\lambda +3)\lambda (\lambda -1) = 0,$

得 $\pmb{B}$ 的特征值为 $\lambda_{1} = -3, \lambda_{2} = 0, \lambda_{3} = 1$

因为 $\mathbf{A} \sim \mathbf{B}$ , 所以 $\mathbf{A}$ 的特征值为 $\lambda_{1} = -3, \lambda_{2} = 0, \lambda_{3} = 1$ , 于是 $\mathbf{A} + \mathbf{E}$ 的特征值为 $\mu_{1} = -2$ , $\mu_{2} = 1, \mu_{3} = 2$ , 故 $|\mathbf{A} + \mathbf{E}| = -4$ .

方法点评：求矩阵的特征值通常有如下三个方法：

（1）定义法，即令 $AX = \lambda X(X\neq 0)$ ，通过矩阵满足的方程求出矩阵的特征值.

【例】设 $\mathbf{A}$ 为方阵，且 $A^2 = 2A$ ，求 $\mathbf{A}$ 的特征值.

【解】令 $AX = \lambda X$ ，由 $A^2 = 2A$ 得 $(\lambda^2 - 2\lambda)X = 0$ ，因为 $X \neq 0$ ，所以 $\lambda = 0$ 或 $\lambda = 2$

（2）公式法，即通过特征方程 $|\lambda E - A| = 0$ 求出特征值.  
（3）关联矩阵法，即若 $\mathbf{A}\sim \mathbf{B}$ ，则 $|\lambda E - A| = |\lambda E - B|$ ，从而 $\mathbf{A},\mathbf{B}$ 特征值相同.', 'E:\数学自用\数据资料\真题\按年份整理\2001\解析\2001年解析.md', 'ok', 'year_question_no', 0.014, '2001:18', 17, 0.236);
