INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2001_main_q20', 'math1_2001_main_q20', 2001, 20, 20, 20, '(20)【解】令 $Y_{i} = X_{i} + X_{n + i}(1\leqslant i\leqslant n)$ ，因为 $X_{1},X_{2},\dots ,X_{2n}$ 相互独立且服从正态分布，所以 $Y_{i}\sim N(2\mu ,2\sigma^{2})(1\leqslant i\leqslant n)$

不妨设 $Y_{1}, Y_{2}, \dots, Y_{n}$ 为来自总体 $N(2\mu, 2\sigma^{2})$ 的简单随机样本， $\overline{Y} = \frac{1}{n} \sum_{i=1}^{n} Y_{i} = 2\overline{X}$ ，

于是统计量 $Y = \sum_{i=1}^{n}(X_i + X_{n+i} - 2\overline{X})^2 = \sum_{i=1}^{n}(Y_i - \overline{Y})^2$

由 $\frac{\sum_{i=1}^{n}(Y_i - \overline{Y})^2}{2\sigma^2} \sim \chi^2(n-1)$ ，得 $E\left(\frac{\sum_{i=1}^{n}(Y_i - \overline{Y})^2}{2\sigma^2}\right) = n-1$ ，故 $E(Y) = 2(n-1)\sigma^2$ .', 'E:\数学自用\数据资料\真题\按年份整理\2001\解析\2001年解析.md', 'ok', 'year_question_no', 0, '2001:20', 1, 0);
