INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2001_main_q22', 'math1_2001_main_q22', 2001, 22, 10, 10, '（10）【答案】（A）.

【解】方法一 由 $X + Y = n$ ，得 $Y = -X + n$ ，于是

$$
D (X) = D (Y), \quad \operatorname {C o v} (X, Y) = \operatorname {C o v} (X, - X + n) = - D (X).
$$

故 $\rho_{XY} = \frac{\operatorname{Cov}(X,Y)}{\sqrt{D(X)}\cdot\sqrt{D(Y)}} = -\frac{D(X)}{D(X)} = -1$ ，应选（A）.

方法二 因为 $P\{Y = -X + n\} = 1$ 且 $-1 < 0$ ，所以 $\rho_{XY} = -1$ ，应选(A).

方法点评：设 $X, Y$ 为两个随机变量，若 $\rho_{XY} = 1$ ，称随机变量 $X, Y$ 正相关，其充分必要条件为 $P\{Y = aX + b\} = 1 (a > 0)$

设 $X, Y$ 为两个随机变量，若 $\rho_{XY} = -1$ ，称随机变量 $X, Y$ 负相关，其充分必要条件为 $P\{Y = aX + b\} = 1 (a < 0)$ 。

# 三、解答题', 'E:\数学自用\数据资料\真题\按年份整理\2001\解析\2001年解析.md', 'manual_check', 'similarity_fallback:0.200', 0.2, '', 10, 0.2);
