INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2002_main_q02', 'math1_2002_main_q02', 2002, 2, 2, 2, '(2)【答案】 -2.

【解】 当 $x = 0$ 时， $y = 0$

$\mathrm{e}^y + 6xy + x^2 - 1 = 0$ 两边对 $x$ 求导，得 $\mathrm{e}^y \frac{\mathrm{d}y}{\mathrm{d}x} + 6y + 6x \frac{\mathrm{d}y}{\mathrm{d}x} + 2x = 0$ 则 $y''(0) = 0$ . $\mathrm{e}^y \frac{\mathrm{d}y}{\mathrm{d}x} + 6y + 6x \frac{\mathrm{d}y}{\mathrm{d}x} + 2x = 0$ 两边对 $x$ 求导，

得 $\mathrm{e}^{y}\left(\frac{\mathrm{dy}}{\mathrm{dx}}\right)^{2} + \mathrm{e}^{y}\frac{\mathrm{d}^{2}y}{\mathrm{dx}^{2}} +12\frac{\mathrm{dy}}{\mathrm{dx}} +6x\frac{\mathrm{d}^{2}y}{\mathrm{dx}^{2}} +2 = 0$ ，于是 $y^{\prime \prime}(0) = -2.$', 'E:\数学自用\数据资料\真题\按年份整理\2002\解析\2002年解析.md', 'ok', 'year_question_no', 0.186, '2002:2', 2, 0.186);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2002_main_q03', 'math1', 2002, '真题', 'main', 3, '# 一、填空题(本题共5小题，每小题3分，满分15分)

(3) 微分方程 $y y^{\prime \prime} + (y^{\prime})^{2} = 0$ 满足初始条件 $y \Big|_{x=0} = 1, y^{\prime} \Big|_{x=0} = \frac{1}{2}$ 的特解是', 'E:\数学自用\数据资料\真题\按年份整理\2002\按题拆分\真题\第03题\题目.md', '2002\按题拆分\真题\第03题\题目.md', 0, 'ok', '2002 真题 第3题 # 一、填空题(本题共5小题，每小题3分，满分15分)

(3) 微分方程 $y y^{\prime \prime} + (y^{\prime})^{2} = 0$ 满足初始条件 $y \big|_{x=0} = 1, y^{\prime} \big|_{x=0} = \frac{1}{2}$ 的特解是');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2002_main_q03', 'tag_微分方程');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2002_main_q03', 'math1_2002_main_q03', 2002, 3, 3, 3, '(3)【答案】 $y = \sqrt{x + 1}$ .

【解】方法一 令 $y'' = p$ ，则 $y'''' = p \frac{\mathrm{d}p}{\mathrm{d}y}$ ，方程 $yy'''' + y''^2 = 0$ 化为 $yp \frac{\mathrm{d}p}{\mathrm{d}y} + p^2 = 0$ 。因为 $p \neq 0$ ，所以 $\frac{\mathrm{d}p}{\mathrm{d}y} + \frac{1}{y} p = 0$ ，解得 $p = C_1 \mathrm{e}^{-\int \frac{1}{y} \mathrm{d}y} = \frac{C_1}{y}$ 。

由 $y(0) = 1, y''(0) = \frac{1}{2}$ , 得 $C_1 = \frac{1}{2}$ , 于是 $yy'' = \frac{1}{2}$ , 解得 $\frac{1}{2} y^2 = \frac{x}{2} + C$ .

由 $y(0) = 1$ ，得 $C = \frac{1}{2}$ 故 $y = \sqrt{x + 1}$

方法二 由 $yy'''' + y''^2 = 0$ ，得 $(yy'')'' = 0$ ，解得 $yy'' = C_1$

由 $y(0) = 1, y''(0) = \frac{1}{2}$ , 得 $C_1 = \frac{1}{2}$ , 即 $yy'' = \frac{1}{2}$ 或 $(y^2)'' = 1$ , 解得 $y^2 = x + C_2$ .

由 $y(0) = 1$ ，得 $C_2 = 1$ ，故满足初始条件的特解为 $y = \sqrt{x + 1}$

方法点评：本题考查可降阶的微分方程的求解。特定类型微分方程的求解可以用相应类型微分方程的解法求解，注意运用灵活简洁的方法，往往可使解题简单且正确率高。', 'E:\数学自用\数据资料\真题\按年份整理\2002\解析\2002年解析.md', 'ok', 'year_question_no', 0.311, '2002:3', 3, 0.311);
