INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2002_main_q08', 'math1_2002_main_q08', 2002, 8, 8, 8, '（8）【答案】 （B）.

【解】若 $\lim_{x\to +\infty}f''(x)\neq 0$ ，不妨设 $\lim_{x\to +\infty}f''(x) = A > 0.$

取 $\varepsilon_0 = \frac{A}{2} > 0$ ，则存在 $X > 0$ ，当 $x > X$ 时， $|f''(x) - A| < \frac{A}{2}$ ，于是 $f''(x) > \frac{A}{2}$ .

当 $x > X$ 时， $f(x) - f(X) = f''(\xi)(x - X)$ ，其中 $\xi \in (X, x)$

则 $f(x) > f(X) + \frac{A}{2} (x - X)$

因为 $\lim_{x\to +\infty}\left[f(X) + \frac{A}{2} (x - X)\right] = +\infty$ ，所以 $\lim_{x\to +\infty}f(x) = +\infty$ ，与 $f(x)$ 有界矛盾，应选(B).', 'E:\数学自用\数据资料\真题\按年份整理\2002\解析\2002年解析.md', 'ok', 'year_question_no', 0.032, '2002:8', 2, 0.032);
