INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2002_main_q12', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2002_main_q12', 'math1_2002_main_q12', 2002, 12, 12, 12, '(12)【解】 $\frac{\mathrm{d}}{\mathrm{d}x}\int_{0}^{\arctan x}\mathrm{e}^{-t^2}\mathrm{d}t = \mathrm{e}^{-\arctan^2 x}\cdot \frac{1}{1 + x^2},\quad \frac{\mathrm{d}}{\mathrm{d}x}\int_{0}^{\arctan x}\mathrm{e}^{-t^2}\mathrm{d}t\Bigg|_{x = 0} = 1,$

因为曲线 $y = f(x)$ 与 $y = \int_{0}^{\arctan x}\mathrm{e}^{-t^2}\mathrm{d}t$ 在(0，0）处切线相同，所以 $f^{\prime}(0) = 1$ 且 $f(0) = 0$ 所以切线方程为 $y = x$

而且 $\lim_{n\to \infty}nf\left(\frac{2}{n}\right) = 2\lim_{n\to \infty}\frac{f\left(\frac{2}{n}\right)}{\frac{2}{n}} = 2\lim_{n\to \infty}\frac{f\left(\frac{2}{n}\right) - f(0)}{\frac{2}{n}} = 2f''(0) = 2.$', 'E:\数学自用\数据资料\真题\按年份整理\2002\解析\2002年解析.md', 'ok', 'year_question_no', 0.438, '2002:12', 12, 0.438);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2002_main_q13', 'math1', 2002, '真题', 'main', 13, '# 五、(本题满分7分)

计算二重积分 $\iint_{D} \mathrm{e}^{\max \left\{x^{2}, y^{2}\right\}} \mathrm{d} x \mathrm{~d} y$ ，其中 $D = \{(x, y) \mid 0 \leqslant x \leqslant 1, 0 \leqslant y \leqslant 1\}$ .', 'E:\数学自用\数据资料\真题\按年份整理\2002\按题拆分\真题\第13题\题目.md', '2002\按题拆分\真题\第13题\题目.md', 0, 'ok', '2002 真题 第13题 # 五、(本题满分7分)

计算二重积分 $\iint_{d} \mathrm{e}^{\max \left\{x^{2}, y^{2}\right\}} \mathrm{d} x \mathrm{~d} y$ ，其中 $d = \{(x, y) \mid 0 \leqslant x \leqslant 1, 0 \leqslant y \leqslant 1\}$ .');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2002_main_q13', 'tag_积分');
