INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2002_main_q25', 'math1_2002_main_q25', 2002, 25, 20, 20, '(20)【解】 $E(X) = 0 \times \theta^2 + 1 \times 2\theta (1 - \theta) + 2\theta^2 + 3 (1 - 2\theta) = 3 - 4\theta,$

$$
\bar {x} = \frac {3 + 1 + 3 + 0 + 3 + 1 + 2 + 3}{8} = 2,
$$

令 $E(X) = \overline{x}$ 得 $\theta$ 的矩估计值为 $\hat{\theta} = \frac{1}{4}$ .

似然函数为 $L(\theta) = 4\theta^6 (1 - \theta)^2 (1 - 2\theta)^4$

$$
\ln L (\theta) = \ln 4 + 6 \ln \theta + 2 \ln (1 - \theta) + 4 \ln (1 - 2 \theta),
$$

由 $\frac{\mathrm{d}}{\mathrm{d}\theta}\ln L(\theta) = \frac{6}{\theta} -\frac{2}{1 - \theta} -\frac{8}{1 - 2\theta} = 0$ ，得 $\theta = \frac{7\pm\sqrt{13}}{12}$

因为 $\theta = \frac{7 + \sqrt{13}}{12} >\frac{1}{2}$ 所以 $\theta$ 的极大似然估计值为 $\hat{\theta} = \frac{7 - \sqrt{13}}{12}$', 'E:\数学自用\数据资料\真题\按年份整理\2002\解析\2002年解析.md', 'manual_check', 'similarity_fallback:0.120', 0.12, '', 20, 0.12);
