INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2003_main_q07', 'math1_2003_main_q07', 2003, 7, 7, 7, '（7）【答案】 (C).

【解】设 $f^{\prime}(x)$ 与 $x$ 轴交点的横坐标从左到右分别为 $a, b, c$ ，显然 $f(x)$ 有三个驻点 $x = a$ ， $x = b$ ， $x = c$ 及一个不可导点 $x = 0$ .

当 $x < a$ 时， $f''(x) > 0$ ，当 $x \in (a, b)$ 时， $f''(x) < 0$ ，则 $x = a$ 为 $f(x)$ 的极大值点；

当 $x\in (b,0)$ 时， $f^{\prime}(x) > 0$ ，则 $x = b$ 为 $f(x)$ 的极小值点；

当 $x\in (0,c)$ 时， $f^{\prime}(x) <   0$ ，则 $x = 0$ 为 $f(x)$ 的极大值点；

当 $x > c$ 时， $f''(x) > 0$ ，则 $x = c$ 为 $f(x)$ 的极小值点，

故 $f(x)$ 有两个极大值点和两个极小值点，应选(C).

方法点评：求函数的极值时按如下步骤进行：

（1）找出 $f(x)$ 的驻点及不可导的点；  
（2）判断每个点是否为极值点（按照具体情况选用第一充分条件和第二充分条件）.', 'E:\数学自用\数据资料\真题\按年份整理\2003\解析\2003年解析.md', 'ok', 'year_question_no', 0.085, '2003:7', 7, 0.085);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2003_main_q08', 'math1', 2003, '真题', 'main', 8, '# 二、选择题(本题共6小题，每小题4分，满分24分)

(2) 设 $\{a_{n}\}, \{b_{n}\}, \{c_{n}\}$ 均为非负数列, 且 $\lim_{n \to \infty} a_{n} = 0, \lim_{n \to \infty} b_{n} = 1, \lim_{n \to \infty} c_{n} = \infty$ , 则必有 ( )

(A) $a_{n} < b_{n}$ 对任意 $n$ 成立.  
(B) $b_{n} < c_{n}$ 对任意 $n$ 成立.  
(C) 极限 $\lim_{n\to \infty}a_n c_n$ 不存在.  
(D) 极限 $\lim_{n\to \infty}b_n c_n$ 不存在.', 'E:\数学自用\数据资料\真题\按年份整理\2003\按题拆分\真题\第08题\题目.md', '2003\按题拆分\真题\第08题\题目.md', 0, 'ok', '2003 真题 第8题 # 二、选择题(本题共6小题，每小题4分，满分24分)

(2) 设 $\{a_{n}\}, \{b_{n}\}, \{c_{n}\}$ 均为非负数列, 且 $\lim_{n \to \infty} a_{n} = 0, \lim_{n \to \infty} b_{n} = 1, \lim_{n \to \infty} c_{n} = \infty$ , 则必有 ( )

(a) $a_{n} < b_{n}$ 对任意 $n$ 成立.  
(b) $b_{n} < c_{n}$ 对任意 $n$ 成立.  
(c) 极限 $\lim_{n\to \infty}a_n c_n$ 不存在.  
(d) 极限 $\lim_{n\to \infty}b_n c_n$ 不存在.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2003_main_q08', 'tag_极限');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2003_main_q08', 'math1_2003_main_q08', 2003, 8, 8, 8, '（8）【答案】 (D).

【解】方法一 取 $a_{n} = \frac{3}{n}, b_{n} = 1, c_{n} = \frac{n}{3}$ ，显然(A)，(B)，(C)不成立，应选(D).

方法二 取 $\varepsilon = \frac{1}{2}$ ，因为 $\lim_{n\to \infty}b_n = 1$ ，所以存在 $N > 0$ ，当 $n > N$ 时，

$\left|b_{n} - 1\right| < \frac{1}{2}$ ，从而有 $b_{n} > \frac{1}{2}$

当 $n > N$ 时， $\left|b_{n}c_{n}\right| > \frac{1}{2}\left|c_{n}\right|$

由 $\lim_{n\to \infty}c_n = \infty$ 得 $\lim_{n\to \infty}\left|b_n c_n\right| = +\infty$ ，故 $\lim_{n\to \infty}b_n c_n = \infty$ ，应选(D).', 'E:\数学自用\数据资料\真题\按年份整理\2003\解析\2003年解析.md', 'ok', 'year_question_no', 0.056, '2003:8', 8, 0.056);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2003_main_q09', 'math1', 2003, '真题', 'main', 9, '# 二、选择题(本题共6小题，每小题4分，满分24分)

(3) 已知函数 $f(x, y)$ 在点 $(0, 0)$ 的某个邻域内连续, 且 $\lim_{\substack{x \to 0 \\ y \to 0}} \frac{f(x, y) - xy}{(x^2 + y^2)^2} = 1$ , 则( )

(A) 点 $(0,0)$ 不是 $f(x,y)$ 的极值点.  
（B）点 $(0,0)$ 是 $f(x,y)$ 的极大值点  
(C) 点 $(0, 0)$ 是 $f(x, y)$ 的极小值点.  
(D) 根据所给条件无法判别点 $(0,0)$ 是否为 $f(x,y)$ 的极值点.', 'E:\数学自用\数据资料\真题\按年份整理\2003\按题拆分\真题\第09题\题目.md', '2003\按题拆分\真题\第09题\题目.md', 0, 'ok', '2003 真题 第9题 # 二、选择题(本题共6小题，每小题4分，满分24分)

(3) 已知函数 $f(x, y)$ 在点 $(0, 0)$ 的某个邻域内连续, 且 $\lim_{\substack{x \to 0 \\ y \to 0}} \frac{f(x, y) - xy}{(x^2 + y^2)^2} = 1$ , 则( )

(a) 点 $(0,0)$ 不是 $f(x,y)$ 的极值点.  
（b）点 $(0,0)$ 是 $f(x,y)$ 的极大值点  
(c) 点 $(0, 0)$ 是 $f(x, y)$ 的极小值点.  
(d) 根据所给条件无法判别点 $(0,0)$ 是否为 $f(x,y)$ 的极值点.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2003_main_q09', 'tag_极限');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2003_main_q09', 'tag_连续');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2003_main_q09', 'math1_2003_main_q09', 2003, 9, 9, 9, '（9）【答案】 （A）.

【解】 由 $\lim_{\substack{x\to 0\\ y\to 0}}\frac{f(x,y) - xy}{(x^2 + y^2)^2} = 1$ 及 $f(x,y)$ 的连续性，得 $f(0,0) = 0$

再由 $\lim_{\substack{x\to 0\\ y\to 0}}\frac{f(x,y) - xy}{(x^2 + y^2)^2} = 1$ ，得 $f(x,y) - xy = (x^{2} + y^{2})^{2} + o[(x^{2} + y^{2})^{2}]$

或 $f(x,y) = xy + (x^{2} + y^{2})^{2} + o[(x^{2} + y^{2})^{2}]$

当 $y = x$ 时， $f(x, x) = x^2 + 4x^4 + o(x^4) = x^2 + o(x^2) > 0$

当 $y = -x$ 时， $f(x, -x) = -x^2 + 4x^4 + o(x^4) = -x^2 + o(x^2) < 0$ ，则 $(0,0)$ 不是函数 $f(x, y)$ 的极值点，应选(A).', 'E:\数学自用\数据资料\真题\按年份整理\2003\解析\2003年解析.md', 'ok', 'year_question_no', 0.211, '2003:9', 9, 0.211);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2003_main_q10', 'math1', 2003, '真题', 'main', 10, '# 二、选择题(本题共6小题，每小题4分，满分24分)

(4) 设向量组 $\mathrm{I}:\pmb{\alpha}_{1},\pmb{\alpha}_{2},\dots,\pmb{\alpha}_{r}$ 可由向量组 $\mathrm{II}:\pmb{\beta}_{1},\pmb{\beta}_{2},\dots,\pmb{\beta}_{s}$ 线性表示, 则( )

(A) 当 $r < s$ 时, 向量组 $\mathbb{I}$ 必线性相关.

(B) 当 $r > s$ 时, 向量组 $\mathbb{I}$ 必线性相关

(C) 当 $r < s$ 时, 向量组 I 必线性相关.

(D) 当 $r > s$ 时, 向量组 I 必线性相关', 'E:\数学自用\数据资料\真题\按年份整理\2003\按题拆分\真题\第10题\题目.md', '2003\按题拆分\真题\第10题\题目.md', 0, 'ok', '2003 真题 第10题 # 二、选择题(本题共6小题，每小题4分，满分24分)

(4) 设向量组 $\mathrm{i}:\pmb{\alpha}_{1},\pmb{\alpha}_{2},\dots,\pmb{\alpha}_{r}$ 可由向量组 $\mathrm{ii}:\pmb{\beta}_{1},\pmb{\beta}_{2},\dots,\pmb{\beta}_{s}$ 线性表示, 则( )

(a) 当 $r < s$ 时, 向量组 $\mathbb{i}$ 必线性相关.

(b) 当 $r > s$ 时, 向量组 $\mathbb{i}$ 必线性相关

(c) 当 $r < s$ 时, 向量组 i 必线性相关.

(d) 当 $r > s$ 时, 向量组 i 必线性相关');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2003_main_q10', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2003_main_q10', 'math1_2003_main_q10', 2003, 10, 10, 10, '(10)【答案】 (D).

【解】方法一 因为向量组I可由向量组Ⅱ线性表示，所以 $r(\mathrm{I})\leqslant r(\mathrm{II})$

显然 $r(\mathrm{II})\leqslant s$ ，于是 $r(\mathrm{I})\leqslant s$

当 $r > s$ 时，因为 $r(\mathrm{I})\leqslant s <   r$ ，即向量组I的秩小于向量组I所含的向量个数，所以向量组I线性相关，应选(D).

方法二 取 $\mathrm{I}:\pmb{\alpha}_{1} = \binom{1}{2},\mathrm{II}:\pmb{\beta}_{1} = \binom{1}{0},\pmb{\beta}_{2} = \binom{0}{1}$ 显然向量组I可由向量组Ⅱ线性表示且 $r < s$ ，但向量组Ⅱ线性无关，（A)，（C）不对；

取 $\mathrm{I}:\pmb{\alpha}_{1} = \binom{1}{1},\pmb{\alpha}_{2} = \binom{2}{2},\mathrm{II}:\pmb{\beta}_{1} = \binom{1}{1}$ 显然向量组I可由向量组Ⅱ线性表示且 $r > s$ 但向量组Ⅱ线性无关，(B）不对，应选(D).', 'E:\数学自用\数据资料\真题\按年份整理\2003\解析\2003年解析.md', 'ok', 'year_question_no', 0.183, '2003:10', 10, 0.183);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2003_main_q11', 'math1', 2003, '真题', 'main', 11, '# 二、选择题(本题共6小题，每小题4分，满分24分)

(5) 设有齐次线性方程组 $Ax = 0$ 和 $Bx = 0$ , 其中 $A, B$ 均为 $m \times n$ 矩阵, 现有 4 个命题:

① 若 $Ax = 0$ 的解均是 $Bx = 0$ 的解, 则秩 $(A) \geqslant$ 秩 $(B)$ ;

② 若秩 $(A) \geqslant$ 秩 $(B)$ , 则 $Ax = 0$ 的解均是 $Bx = 0$ 的解;  
③ 若 $Ax = 0$ 与 $Bx = 0$ 同解, 则秩 $(A) =$ 秩 $(B)$ ;  
④若秩 $(A) =$ 秩 $(B)$ , 则 $Ax = 0$ 与 $Bx = 0$ 同解.

以上命题中正确的是( )

(A)①②.

(B)①③.

(C)②④.

(D) ③④.', 'E:\数学自用\数据资料\真题\按年份整理\2003\按题拆分\真题\第11题\题目.md', '2003\按题拆分\真题\第11题\题目.md', 0, 'ok', '2003 真题 第11题 # 二、选择题(本题共6小题，每小题4分，满分24分)

(5) 设有齐次线性方程组 $ax = 0$ 和 $bx = 0$ , 其中 $a, b$ 均为 $m \times n$ 矩阵, 现有 4 个命题:

① 若 $ax = 0$ 的解均是 $bx = 0$ 的解, 则秩 $(a) \geqslant$ 秩 $(b)$ ;

② 若秩 $(a) \geqslant$ 秩 $(b)$ , 则 $ax = 0$ 的解均是 $bx = 0$ 的解;  
③ 若 $ax = 0$ 与 $bx = 0$ 同解, 则秩 $(a) =$ 秩 $(b)$ ;  
④若秩 $(a) =$ 秩 $(b)$ , 则 $ax = 0$ 与 $bx = 0$ 同解.

以上命题中正确的是( )

(a)①②.

(b)①③.

(c)②④.

(d) ③④.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2003_main_q11', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2003_main_q11', 'math1_2003_main_q11', 2003, 11, 11, 11, '（11）【答案】 (B).

【解】方法一 若 $AX = 0$ 的解为 $BX = 0$ 的解，则 $AX = 0$ 的基础解系所含的线性无关的解向量的个数不超过 $BX = 0$ 的基础解系所含的线性无关的解向量个数，即 $n - r(A) \leqslant n - r(B)$ ，从而 $r(A) \geqslant r(B)$ ；

若 $AX = 0$ 与 $BX = 0$ 同解，则 $r(A) = r(B)$ ，反之不对，故应选（B）.

方法二 取 $A = \begin{pmatrix} 1 & 1 & -2 \\ 1 & 0 & -1 \end{pmatrix}, B = (1 & 1 & 1), r(A) = 2 \geqslant r(B) = 1,$

但 $X = \left( \begin{array}{l}1\\ 1\\ 1 \end{array} \right)$ 为 $AX = 0$ 的解，不是 $BX = 0$ 的解，第2个命题不对；

取 $\mathbf{A} = (1\quad 1\quad -1)$ ， $\pmb {B} = (1\quad -1\quad -1)$ ， $r(\mathbf{A}) = r(\mathbf{B})$

但 $AX = 0$ 与 $BX = 0$ 不同解，第4个命题不对，应选（B）.

方法点评：本题考查两个齐次线性方程组的解与系数矩阵的秩的关系，

齐次线性方程组系数矩阵的秩即为方程组中约束条件的个数，系数矩阵的秩越大则约束条件越多，解就越少；系数矩阵的秩越小则约束条件越少，解就越多。设 $AX = 0$ 与 $BX = 0$ 为两个齐次线性方程组，则：

（1）若 $AX = 0$ 与 $BX = 0$ 同解，则 $r(A) = r(B)$ ，反之不对；  
（2）若 $AX = 0$ 的解为 $BX = 0$ 的解，则 $r(A) \geqslant r(B)$   
（3）若 $AX = 0$ 的解为 $BX = 0$ 的解，反之不对，则 $r(A) > r(B)$   
（4）若 $AX = 0$ 的解为 $BX = 0$ 的解，且 $r(A) = r(B)$ ，则 $AX = 0$ 与 $BX = 0$ 同解.', 'E:\数学自用\数据资料\真题\按年份整理\2003\解析\2003年解析.md', 'ok', 'year_question_no', 0.208, '2003:11', 11, 0.208);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2003_main_q12', 'math1', 2003, '真题', 'main', 12, '# 二、选择题(本题共6小题，每小题4分，满分24分)

(6) 设随机变量 $X \sim t(n) (n > 1), Y = \frac{1}{X^2}$ ，则（

(A) $Y \sim \chi^2(n)$ .

(B) $Y \sim \chi^2(n - 1)$ .

(C) $Y \sim F(n, 1)$ .

(D) $Y \sim F(1, n)$ .', 'E:\数学自用\数据资料\真题\按年份整理\2003\按题拆分\真题\第12题\题目.md', '2003\按题拆分\真题\第12题\题目.md', 0, 'ok', '2003 真题 第12题 # 二、选择题(本题共6小题，每小题4分，满分24分)

(6) 设随机变量 $x \sim t(n) (n > 1), y = \frac{1}{x^2}$ ，则（

(a) $y \sim \chi^2(n)$ .

(b) $y \sim \chi^2(n - 1)$ .

(c) $y \sim f(n, 1)$ .

(d) $y \sim f(1, n)$ .');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2003_main_q12', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2003_main_q12', 'math1_2003_main_q12', 2003, 12, 12, 12, '（12）【答案】 (C).

【解】因为 $X\sim t(n)$ ，所以存在 $U\sim N(0,1),V\sim \chi^2 (n)$ 且 $U,V$ 独立，

使得 $X = \frac{U}{\sqrt{V / n}}$ ，于是 $Y = \frac{1}{X^2} = \frac{V / n}{U^2 / 1}$

注意到 $U^2\sim \chi^2 (1)$ 且与 $V$ 独立，故 $Y\sim F(n,1)$ ，应选(C).

# 三、解答题', 'E:\数学自用\数据资料\真题\按年份整理\2003\解析\2003年解析.md', 'ok', 'year_question_no', 0.096, '2003:12', 12, 0.096);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2003_main_q13', 'math1', 2003, '真题', 'main', 13, '# 三、(本题满分10分)

(1) 求 $D$ 的面积 $A$ ;', 'E:\数学自用\数据资料\真题\按年份整理\2003\按题拆分\真题\第13题\题目.md', '2003\按题拆分\真题\第13题\题目.md', 0, 'ok', '2003 真题 第13题 # 三、(本题满分10分)

(1) 求 $d$ 的面积 $a$ ;');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2003_main_q13', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2003_main_q13', 'math1_2003_main_q13', 2003, 13, 13, 13, '（13）【解】（I）方法一 设切点坐标为 $(a, \ln a)$

由导数的几何意义得 $\frac{\ln a}{a} = \frac{1}{a}$ ，解得 $a = \mathrm{e}$

即切点坐标为 $(\mathrm{e},1)$ ，故切线为 $y = \frac{x}{\mathrm{e}}$

方法二 设切点坐标为 $(a, \ln a)$ ，所求的切线为

$$
y - \ln a = \frac {1}{a} (x - a)  , \text {或}   y = \frac {x}{a} + \ln a - 1,
$$

![](images/e72fc6fde46f5415dbba398affb724d0a0469443375acbaba2ea79de466cbc3c.jpg)  
三(13)题图

因为切线经过原点，所以 $\ln a - 1 = 0$ ，即 $a = \mathrm{e}$ ，故所求的切线为 $y = \frac{x}{\mathrm{e}}$

所以 $A = \frac{1}{2} \times \mathrm{e} \times 1 - \int_{1}^{\mathrm{e}} \ln x \, \mathrm{d}x = \frac{\mathrm{e}}{2} - 1$ .

（Ⅱ）切线 $y = \frac{x}{\mathrm{e}},x = \mathrm{e}$ 及 $x$ 轴围成的三角形区域绕 $x = \mathrm{e}$ 旋转而成的圆锥体的体积为

$$
V _ {1} = \frac {1}{3} \times \pi \mathrm {e} ^ {2} \times 1 = \frac {\pi \mathrm {e} ^ {2}}{3};
$$

曲线 $y = \ln x, x = \mathrm{e}$ 及 $x$ 轴围成的区域绕 $x = \mathrm{e}$ 旋转而成的体积为 $V_{2}$

取 $[x, x + \mathrm{d}x] \subset [1, \mathrm{e}]$ ， $\mathrm{d}V_{2} = 2\pi (\mathrm{e} - x) \times \ln x \times \mathrm{d}x$

$$
V _ {2} = 2 \pi \int_ {1} ^ {\mathrm {e}} (\mathrm {e} - x) \ln x \mathrm {d} x = 2 \pi \mathrm {e} \int_ {1} ^ {\mathrm {e}} \ln x \mathrm {d} x - 2 \pi \int_ {1} ^ {\mathrm {e}} x \ln x \mathrm {d} x = \frac {\pi}{2} (4 \mathrm {e} - \mathrm {e} ^ {2} - 1),
$$

于是 $V = V_{1} - V_{2} = \frac{\pi}{6} (5\mathrm{e}^{2} - 12\mathrm{e} + 3)$', 'E:\数学自用\数据资料\真题\按年份整理\2003\解析\2003年解析.md', 'ok', 'year_question_no', 0, '2003:13', 1, 0);
