INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2003_main_q20', 'math1_2003_main_q20', 2003, 20, 17, 17, '(17)【解】（I） $\frac{\mathrm{d}x}{\mathrm{d}y} = \frac{1}{\frac{\mathrm{d}y}{\mathrm{d}x}} = \frac{1}{y''(x)}$

$$
\frac {\mathrm {d} ^ {2} x}{\mathrm {d} y ^ {2}} = \frac {\mathrm {d} \left(\frac {\mathrm {d} x}{\mathrm {d} y}\right)}{\mathrm {d} y} = \frac {\mathrm {d} \left[ \frac {1}{y ^ {\prime} (x)} \right] / \mathrm {d} x}{\mathrm {d} y / \mathrm {d} x} = \frac {\left[ \frac {1}{y ^ {\prime} (x)} \right] ^ {\prime}}{y ^ {\prime} (x)} = - \frac {y ^ {\prime \prime} (x)}{y ^ {\prime 3} (x)} = - \frac {\frac {\mathrm {d} ^ {2} y}{\mathrm {d} x ^ {2}}}{\left(\frac {\mathrm {d} y}{\mathrm {d} x}\right) ^ {3}},
$$

代入原方程整理得 $\frac{\mathrm{d}^2y}{\mathrm{d}x^2} - y = \sin x$

（Ⅱ） $\frac{\mathrm{d}^2y}{\mathrm{d}x^2} - y = 0$ 的特征方程为 $\lambda^2 - 1 = 0$ ，特征值为 $\lambda_1 = -1, \lambda_2 = 1$

$\frac{\mathrm{d}^2y}{\mathrm{d}x^2} - y = 0$ 的通解为 $y = C_1 \mathrm{e}^{-x} + C_2 \mathrm{e}^x$ .

令 $\frac{\mathrm{d}^2y}{\mathrm{d}x^2} - y = \sin x$ 的特解为 $y_0(x) = a\cos x + b\sin x$ ，代入原方程得 $a = 0, b = -\frac{1}{2}$ ，原方程的通解为 $y = C_1\mathrm{e}^{-x} + C_2\mathrm{e}^x - \frac{1}{2}\sin x$ 。

由初始条件 $y(0) = 0, y''(0) = \frac{3}{2}$ 得 $C_1 = -1, C_2 = 1$ ，故 $y = \mathrm{e}^x - \mathrm{e}^{-x} - \frac{1}{2}\sin x$ .

方法点评：本题考查原函数与反函数一阶导数与二阶导数之间的关系及微分方程的求解. 函数与其反函数一阶导数与二阶导数之间的关系有如下两点：

（1）设 $y = f(x)$ 可导且 $f^{\prime}(x)\neq 0$ ，则 $y = f(x)$ 存在反函数 $x = g(y),x = g(y)$ 可导且 $g^{\prime}(y) = \frac{1}{f^{\prime}(x)}.$   
（2）设 $y = f(x)$ 二阶可导且 $f^{\prime}(x)\neq 0$ ，则 $y = f(x)$ 存在反函数 $x = g(y),x = g(y)$ 二 阶可导且 $g^{\prime \prime}(y) = \frac{\mathrm{d}[g^{\prime}(y)]}{\mathrm{d}y} = \frac{\mathrm{d}\left[\frac{1}{f^{\prime}(x)}\right]}{\mathrm{d}y} = \frac{\mathrm{d}}{\mathrm{d}x}\left[\frac{1}{f^{\prime}(x)}\right]^{''} = \frac{\left[\frac{1}{f^{\prime}(x)}\right]^{''}}{\mathrm{d}y} = \frac{f^{\prime\prime}(x)}{f^{\prime3}(x)}.$', 'E:\数学自用\数据资料\真题\按年份整理\2003\解析\2003年解析.md', 'manual_check', 'similarity_fallback:0.244', 0.244, '', 17, 0.244);
