$$
\boldsymbol {A} = \left(\boldsymbol {\alpha} _ {1}, \boldsymbol {\alpha} _ {2}, \boldsymbol {\alpha} _ {3}\right), \boldsymbol {B} = \left(\boldsymbol {\alpha} _ {1} + \boldsymbol {\alpha} _ {2} + \boldsymbol {\alpha} _ {3}, \boldsymbol {\alpha} _ {1} + 2 \boldsymbol {\alpha} _ {2} + 4 \boldsymbol {\alpha} _ {3}, \boldsymbol {\alpha} _ {1} + 3 \boldsymbol {\alpha} _ {2} + 9 \boldsymbol {\alpha} _ {3}\right).
$$

如果 $|\mathbf{A}| = 1$ ，那么 $|\mathbf{B}| =$', 'E:\数学自用\数据资料\真题\按年份整理\2005\按题拆分\真题\第05题\题目.md', '2005\按题拆分\真题\第05题\题目.md', 0, 'ok', '2005 真题 第5题 (5) 设 $\alpha_{1}, \alpha_{2}, \alpha_{3}$ 均为 3 维列向量, 记矩阵

$$
\boldsymbol {a} = \left(\boldsymbol {\alpha} _ {1}, \boldsymbol {\alpha} _ {2}, \boldsymbol {\alpha} _ {3}\right), \boldsymbol {b} = \left(\boldsymbol {\alpha} _ {1} + \boldsymbol {\alpha} _ {2} + \boldsymbol {\alpha} _ {3}, \boldsymbol {\alpha} _ {1} + 2 \boldsymbol {\alpha} _ {2} + 4 \boldsymbol {\alpha} _ {3}, \boldsymbol {\alpha} _ {1} + 3 \boldsymbol {\alpha} _ {2} + 9 \boldsymbol {\alpha} _ {3}\right).
$$

如果 $|\mathbf{a}| = 1$ ，那么 $|\mathbf{b}| =$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2005_main_q05', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2005_main_q05', 'math1_2005_main_q05', 2005, 5, 5, 5, '（5）【答案】2.

【解】方法一 因为 $B = (\alpha_{1} + \alpha_{2} + \alpha_{3},\alpha_{1} + 2\alpha_{2} + 4\alpha_{3},\alpha_{1} + 3\alpha_{2} + 9\alpha_{3})$

$$
= \mathbf {A} \left( \begin{array}{c c c} 1 & 1 & 1 \\ 1 & 2 & 3 \\ 1 & 4 & 9 \end{array} \right),
$$

所以 $|\pmb {B}| = |\pmb {A}|\cdot \left| \begin{array}{lll}1 & 1 & 1\\ 1 & 2 & 3\\ 1 & 4 & 9 \end{array} \right| = (3 - 1)(3 - 2)(2 - 1) = 2.$

方法二 $|\pmb {B}| = |\pmb {\alpha}_1 + \pmb {\alpha}_2 + \pmb {\alpha}_3,\pmb {\alpha}_1 + 2\pmb {\alpha}_2 + 4\pmb {\alpha}_3,\pmb {\alpha}_1 + 3\pmb {\alpha}_2 + 9\pmb {\alpha}_3|$

$$
\begin{array}{l} = \left| \boldsymbol {\alpha} _ {1} + \boldsymbol {\alpha} _ {2} + \boldsymbol {\alpha} _ {3}, \boldsymbol {\alpha} _ {2} + 3 \boldsymbol {\alpha} _ {3}, \boldsymbol {\alpha} _ {2} + 5 \boldsymbol {\alpha} _ {3} \right| \\ = \left| \boldsymbol {\alpha} _ {1} + \boldsymbol {\alpha} _ {2} + \boldsymbol {\alpha} _ {3}, \boldsymbol {\alpha} _ {2} + 3 \boldsymbol {\alpha} _ {3}, 2 \boldsymbol {\alpha} _ {3} \right| = 2 \left| \boldsymbol {\alpha} _ {1} + \boldsymbol {\alpha} _ {2} + \boldsymbol {\alpha} _ {3}, \boldsymbol {\alpha} _ {2} + 3 \boldsymbol {\alpha} _ {3}, \boldsymbol {\alpha} _ {3} \right| \\ = 2 \left| \boldsymbol {\alpha} _ {1} + \boldsymbol {\alpha} _ {2}, \boldsymbol {\alpha} _ {2}, \boldsymbol {\alpha} _ {3} \right| = 2 \left| \boldsymbol {\alpha} _ {1}, \boldsymbol {\alpha} _ {2}, \boldsymbol {\alpha} _ {3} \right| = 2. \\ \end{array}
$$

方法点评：本题注意范德蒙德行列式的使用.', 'E:\数学自用\数据资料\真题\按年份整理\2005\解析\2005年解析.md', 'ok', 'year_question_no', 0.333, '2005:5', 5, 0.333);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2005_main_q06', 'math1', 2005, '真题', 'main', 6, '(6) 从数 $1,2,3,4$ 中任取一个数，记为 $X$ ，再从 $1,\dots ,X$ 中任取一个数，记为 $Y$ ，则 $P\{Y = 2\} =$

# 二、选择题(本题共8小题，每小题4分，满分32分)', 'E:\数学自用\数据资料\真题\按年份整理\2005\按题拆分\真题\第06题\题目.md', '2005\按题拆分\真题\第06题\题目.md', 0, 'ok', '2005 真题 第6题 (6) 从数 $1,2,3,4$ 中任取一个数，记为 $x$ ，再从 $1,\dots ,x$ 中任取一个数，记为 $y$ ，则 $p\{y = 2\} =$

# 二、选择题(本题共8小题，每小题4分，满分32分)');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2005_main_q06', 'math1_2005_main_q06', 2005, 6, 6, 6, '(6)【答案】 $\frac{13}{48}$ .

【解】令 $A_{i} = \{X = i\} (i = 1,2,3,4),B = \{Y = 2\}$ ，则 $P(A_{i}) = \frac{1}{4} (i = 1,2,3,4)$

$$
P (B \mid A _ {1}) = 0, \quad P (B \mid A _ {2}) = \frac {1}{2}, \quad P (B \mid A _ {3}) = \frac {1}{3}, \quad P (B \mid A _ {4}) = \frac {1}{4},
$$

由全概率公式得 $P\{Y = 2\} = P(B) = \sum_{i = 1}^{4}P(A_i)P(B\mid A_i) = \frac{1}{4}\left(\frac{1}{2} +\frac{1}{3} +\frac{1}{4}\right) = \frac{13}{48}.$

# 二、选择题', 'E:\数学自用\数据资料\真题\按年份整理\2005\解析\2005年解析.md', 'ok', 'year_question_no', 0.111, '2005:6', 6, 0.111);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2005_main_q07', 'math1', 2005, '真题', 'main', 7, '(7) 设函数 $f(x) = \lim_{n \to \infty} \sqrt[n]{1 + |x|^{3n}}$ ，则 $f(x)$ 在 $(- \infty, + \infty)$ 内（ ）

(A) 处处可导.

(B) 恰有一个不可导点.

(C) 恰有两个不可导点.

(D) 至少有三个不可导点.', 'E:\数学自用\数据资料\真题\按年份整理\2005\按题拆分\真题\第07题\题目.md', '2005\按题拆分\真题\第07题\题目.md', 0, 'ok', '2005 真题 第7题 (7) 设函数 $f(x) = \lim_{n \to \infty} \sqrt[n]{1 + |x|^{3n}}$ ，则 $f(x)$ 在 $(- \infty, + \infty)$ 内（ ）

(a) 处处可导.

(b) 恰有一个不可导点.

(c) 恰有两个不可导点.

(d) 至少有三个不可导点.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2005_main_q07', 'tag_极限');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2005_main_q07', 'tag_导数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2005_main_q07', 'math1_2005_main_q07', 2005, 7, 7, 7, '（7）【答案】 (C).

【解】当 $|x|\leqslant 1$ 时， $1\leqslant \sqrt[n]{1 + |x|^3n}\leqslant \sqrt[n]{2}$ ，由夹逼定理得 $\lim_{n\to \infty}\sqrt[n]{1 + |x|^3n} = 1;$

当 $|x| > 1$ 时， $|x|^3 = \sqrt[n]{|x|^{3n}} \leqslant \sqrt[n]{1 + |x|^{3n}} \leqslant \sqrt[n]{|x|^{3n} + |x|^{3n}} = \sqrt[n]{2}|x|^3,$

由夹逼定理得 $\lim_{n\to \infty}\sqrt[n]{1 + |x|^{\frac{3n}{2}}} = |x|^3$

即 $f(x) = \left\{ \begin{array}{ll}1, & |x|\leqslant 1,\\ |x|^3, & |x| > 1. \end{array} \right.$

$$
f _ {-} ^ {\prime} (- 1) = \lim  _ {x \rightarrow - 1 ^ {-}} \frac {f (x) - f (- 1)}{x + 1} = \lim  _ {x \rightarrow - 1 ^ {-}} \frac {- x ^ {3} - 1}{x + 1} = - 3,
$$

$$
f _ {+} ^ {\prime} (- 1) = \lim  _ {x \rightarrow - 1 ^ {+}} \frac {f (x) - f (- 1)}{x + 1} = \lim  _ {x \rightarrow - 1 ^ {+}} \frac {1 - 1}{x + 1} = 0,
$$

因为 $f_{-}^{\prime}(-1) \neq f_{+}^{\prime}(-1)$ ，所以 $f(x)$ 在 $x = -1$ 处不可导；

$$
f _ {-} ^ {\prime} (1) = \lim  _ {x \rightarrow 1 ^ {-}} \frac {f (x) - f (1)}{x - 1} = \lim  _ {x \rightarrow 1 ^ {-}} \frac {1 - 1}{x - 1} = 0,
$$

$$
f _ {+} ^ {\prime} (1) = \lim  _ {x \rightarrow 1 ^ {+}} \frac {f (x) - f (1)}{x - 1} = \lim  _ {x \rightarrow - 1 ^ {+}} \frac {x ^ {3} - 1}{x - 1} = 3,
$$

因为 $f_{-}^{\prime}(1)\neq f_{+}^{\prime}(1)$ ，所以 $f(x)$ 在 $x = 1$ 处不可导，

即 $f(x)$ 在 $(-\infty , + \infty)$ 内连续，但有两个不可导点，应选(C).

方法点评：讨论由极限形式表示的函数的连续性与可导性时，先计算极限，求出函数的表达式，再讨论函数的有关特性.', 'E:\数学自用\数据资料\真题\按年份整理\2005\解析\2005年解析.md', 'ok', 'year_question_no', 0.262, '2005:7', 7, 0.262);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2005_main_q08', 'math1', 2005, '真题', 'main', 8, '(8) 设 $F(x)$ 是连续函数 $f(x)$ 的一个原函数, “ $M \Leftrightarrow N$ ” 表示“ $M$ 的充分必要条件是 $N$ ”, 则必有 ( )

(A) $F(x)$ 是偶函数 $\Leftrightarrow f(x)$ 是奇函数  
(B) $F(x)$ 是奇函数 $\Leftrightarrow f(x)$ 是偶函数  
(C) $F(x)$ 是周期函数 $\Leftrightarrow f(x)$ 是周期函数  
(D) $F(x)$ 是单调函数 $\Leftrightarrow f(x)$ 是单调函数', 'E:\数学自用\数据资料\真题\按年份整理\2005\按题拆分\真题\第08题\题目.md', '2005\按题拆分\真题\第08题\题目.md', 0, 'ok', '2005 真题 第8题 (8) 设 $f(x)$ 是连续函数 $f(x)$ 的一个原函数, “ $m \leftrightarrow n$ ” 表示“ $m$ 的充分必要条件是 $n$ ”, 则必有 ( )

(a) $f(x)$ 是偶函数 $\leftrightarrow f(x)$ 是奇函数  
(b) $f(x)$ 是奇函数 $\leftrightarrow f(x)$ 是偶函数  
(c) $f(x)$ 是周期函数 $\leftrightarrow f(x)$ 是周期函数  
(d) $f(x)$ 是单调函数 $\leftrightarrow f(x)$ 是单调函数');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2005_main_q08', 'tag_连续');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2005_main_q08', 'math1_2005_main_q08', 2005, 8, 8, 8, '（8）【答案】 （A）.

【解】方法一 $f(x) = 3x^{2}$ 为偶函数，但 $F(x) = x^{3} + C$ 不一定是奇函数，(B)不对； $f(x) = \cos x - 1$ 为周期函数， $F(x) = \sin x - x + C$ 不是周期函数，(C)不对； $f(x) = 2x$ 为单调增函数， $F(x) = x^{2} + C$ 不是单调函数，(D)不对，应选(A).

方法二 设 $f(-x) = -f(x)$ ，令 $F(x) = \int_{a}^{x} f(t) \, \mathrm{d}t$ ，

则 $F(-x) = \int_{a}^{-x}f(t)\mathrm{d}t\stackrel {t = -u}{=}\int_{-a}^{x}f(-u)(-\mathrm{d}u) = \int_{-a}^{x}f(u)\mathrm{d}u$

$$
= \int_ {- a} ^ {a} f (u) d u + \int_ {a} ^ {x} f (u) d u = \int_ {a} ^ {x} f (u) d u = F (x),
$$

于是 $F(x)$ 为偶函数；

反之，设 $F(-x) = F(x)$ ，两边求导得 $-F''(-x) = F''(x)$ ，或 $f(-x) = -f(x)$ ，即 $f(x)$ 为奇函数，应选(A).

方法点评：设 $F(x)$ 为 $f(x)$ 的原函数，则 $f(x)$ 与 $F(x)$ 的奇偶性、周期性如下：

(1) $f(x)$ 是奇函数的充要条件是 $F(x)$ 为偶函数；  
(2) $f(x)$ 是偶函数时， $F(x)$ 不一定是奇函数， $f(x)$ 的所有原函数中只有

$F(x) = \int_{0}^{x}f(t)\mathrm{d}t$ 为奇函数，但当 $F(x)$ 是奇函数时， $f(x)$ 一定是偶函数；

（3）若 $f(x)$ 为周期函数， $F(x)$ 不一定是周期函数，但当 $F(x)$ 为周期函数时， $f(x)$ 一定为周期函数.', 'E:\数学自用\数据资料\真题\按年份整理\2005\解析\2005年解析.md', 'ok', 'year_question_no', 0.397, '2005:8', 8, 0.397);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2005_main_q09', 'math1', 2005, '真题', 'main', 9, '(9) 设函数 $u(x, y) = \varphi(x + y) + \varphi(x - y) + \int_{x - y}^{x + y} \psi(t) \, \mathrm{d}t$ , 其中函数 $\varphi$ 具有二阶导数, $\psi$ 具有一阶导数, 则必有 ( )

(A) $\frac{\partial^2 u}{\partial x^2} = -\frac{\partial^2 u}{\partial y^2}$ .

(B) $\frac{\partial^2 u}{\partial x^2} = \frac{\partial^2 u}{\partial y^2}$ .

(C) $\frac{\partial^2 u}{\partial x \partial y} = \frac{\partial^2 u}{\partial y^2}$ .

(D) $\frac{\partial^2 u}{\partial x \partial y} = \frac{\partial^2 u}{\partial x^2}$ .', 'E:\数学自用\数据资料\真题\按年份整理\2005\按题拆分\真题\第09题\题目.md', '2005\按题拆分\真题\第09题\题目.md', 0, 'ok', '2005 真题 第9题 (9) 设函数 $u(x, y) = \varphi(x + y) + \varphi(x - y) + \int_{x - y}^{x + y} \psi(t) \, \mathrm{d}t$ , 其中函数 $\varphi$ 具有二阶导数, $\psi$ 具有一阶导数, 则必有 ( )

(a) $\frac{\partial^2 u}{\partial x^2} = -\frac{\partial^2 u}{\partial y^2}$ .

(b) $\frac{\partial^2 u}{\partial x^2} = \frac{\partial^2 u}{\partial y^2}$ .

(c) $\frac{\partial^2 u}{\partial x \partial y} = \frac{\partial^2 u}{\partial y^2}$ .

(d) $\frac{\partial^2 u}{\partial x \partial y} = \frac{\partial^2 u}{\partial x^2}$ .');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2005_main_q09', 'tag_导数');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2005_main_q09', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2005_main_q09', 'math1_2005_main_q09', 2005, 9, 9, 9, '（9）【答案】 （B）.

【解】 由 $\frac{\partial u}{\partial x} = \varphi''(x + y) + \varphi''(x - y) + \psi(x + y) - \psi(x - y)$ ，

$$
\frac {\partial u}{\partial y} = \varphi^ {\prime} (x + y) - \varphi^ {\prime} (x - y) + \psi (x + y) + \psi (x - y),
$$

得 $\frac{\partial^2 u}{\partial x^2} = \varphi''''(x + y) + \varphi''''(x - y) + \psi''(x + y) - \psi''(x - y)$ ,

$$
\frac {\partial^ {2} u}{\partial y ^ {2}} = \varphi^ {\prime \prime} (x + y) + \varphi^ {\prime \prime} (x - y) + \psi^ {\prime} (x + y) - \psi^ {\prime} (x - y),
$$

显然 $\frac{\partial^2u}{\partial x^2} = \frac{\partial^2u}{\partial y^2}$ ，应选（B）.', 'E:\数学自用\数据资料\真题\按年份整理\2005\解析\2005年解析.md', 'ok', 'year_question_no', 0.213, '2005:9', 9, 0.213);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2005_main_q10', 'math1', 2005, '真题', 'main', 10, '(10) 设有三元方程 $xy - z\ln y + \mathrm{e}^{xz} = 1$ ，根据隐函数存在定理，存在点 $(0,1,1)$ 的一个邻域，在此邻域内该方程（ ）

(A) 只能确定一个具有连续偏导数的隐函数 $z = z(x, y)$ .  
（B）可确定两个具有连续偏导数的隐函数 $y = y(x,z)$ 和 $z = z(x,y)$ .  
(C) 可确定两个具有连续偏导数的隐函数 $x = x(y, z)$ 和 $z = z(x, y)$ .  
(D) 可确定两个具有连续偏导数的隐函数 $x = x(y, z)$ 和 $y = y(x, z)$ .', 'E:\数学自用\数据资料\真题\按年份整理\2005\按题拆分\真题\第10题\题目.md', '2005\按题拆分\真题\第10题\题目.md', 0, 'ok', '2005 真题 第10题 (10) 设有三元方程 $xy - z\ln y + \mathrm{e}^{xz} = 1$ ，根据隐函数存在定理，存在点 $(0,1,1)$ 的一个邻域，在此邻域内该方程（ ）

(a) 只能确定一个具有连续偏导数的隐函数 $z = z(x, y)$ .  
（b）可确定两个具有连续偏导数的隐函数 $y = y(x,z)$ 和 $z = z(x,y)$ .  
(c) 可确定两个具有连续偏导数的隐函数 $x = x(y, z)$ 和 $z = z(x, y)$ .  
(d) 可确定两个具有连续偏导数的隐函数 $x = x(y, z)$ 和 $y = y(x, z)$ .');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2005_main_q10', 'tag_连续');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2005_main_q10', 'tag_导数');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2005_main_q10', 'tag_多元函数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2005_main_q10', 'math1_2005_main_q10', 2005, 10, 10, 10, '（10）【答案】 (D).

【解】 令 $F(x,y,z) = xy - z\ln y + \mathrm{e}^{xz} - 1$

$$
F _ {x} ^ {\prime} (x, y, z) = y + z \mathrm {e} ^ {x z}, \quad F _ {y} ^ {\prime} (x, y, z) = x - \frac {z}{y}, \quad F _ {z} ^ {\prime} (x, y, z) = - \ln y + x \mathrm {e} ^ {x z},
$$

因为 $F_{x}^{\prime}(0,1,1) = 2\neq 0,F_{y}^{\prime}(0,1,1) = -1\neq 0,F_{z}^{\prime}(0,1,1) = 0$ ，所以 $xy - z\ln y + \mathrm{e}^{xz} = 1$ 在点(0，1，1）确定两个具有连续偏导数的函数 $x = x(y,z)$ 及 $y = y(x,z)$ ，应选(D).

方法点评：本题需要掌握多元隐函数的存在定理，

设 $F(x,y,z)$ 连续可偏导， $F(x_0,y_0,z_0) = 0$ ，若 $F_x''(x_0,y_0,z_0) \neq 0$ ，则在点 $(x_0,y_0,z_0)$ 的邻域内确定二元函数 $x = x(y,z)$ ，其他情况类似.', 'E:\数学自用\数据资料\真题\按年份整理\2005\解析\2005年解析.md', 'ok', 'year_question_no', 0.326, '2005:10', 10, 0.326);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2005_main_q11', 'math1', 2005, '真题', 'main', 11, '(11) 设 $\lambda_{1}, \lambda_{2}$ 是矩阵 $\mathbf{A}$ 的两个不同的特征值, 对应的特征向量分别为 $\alpha_{1}, \alpha_{2}$ , 则 $\alpha_{1}, A\left(\alpha_{1} + \alpha_{2}\right)$ 线性无关的充分必要条件是 ( )

$(\mathrm{A})\lambda_{1}\neq 0.$

(B) $\lambda_{2} \neq 0$ .

$\left(\mathrm{C}\right)\lambda_{1} = 0.$

$\left(\mathrm{D}\right)\lambda_{2} = 0.$', 'E:\数学自用\数据资料\真题\按年份整理\2005\按题拆分\真题\第11题\题目.md', '2005\按题拆分\真题\第11题\题目.md', 0, 'ok', '2005 真题 第11题 (11) 设 $\lambda_{1}, \lambda_{2}$ 是矩阵 $\mathbf{a}$ 的两个不同的特征值, 对应的特征向量分别为 $\alpha_{1}, \alpha_{2}$ , 则 $\alpha_{1}, a\left(\alpha_{1} + \alpha_{2}\right)$ 线性无关的充分必要条件是 ( )

$(\mathrm{a})\lambda_{1}\neq 0.$

(b) $\lambda_{2} \neq 0$ .

$\left(\mathrm{c}\right)\lambda_{1} = 0.$

$\left(\mathrm{d}\right)\lambda_{2} = 0.$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2005_main_q11', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2005_main_q11', 'math1_2005_main_q11', 2005, 11, 11, 11, '（11）【答案】 (B).

【解】方法一 因为矩阵的不同特征值对应的特征向量线性无关，所以 $\alpha_{1},\alpha_{2}$ 线性无关由 $A\pmb{\alpha}_{1} = \lambda_{1}\pmb{\alpha}_{1},A\pmb{\alpha}_{2} = \lambda_{2}\pmb{\alpha}_{2}$ ，得 $A(\pmb {\alpha}_1 + \pmb {\alpha}_2) = \lambda_1\pmb {\alpha}_1 + \lambda_2\pmb {\alpha}_2$

$(\pmb{\alpha}_{1}, \pmb{A}(\pmb{\alpha}_{1} + \pmb{\alpha}_{2})) = (\pmb{\alpha}_{1}, \pmb{\alpha}_{2})\left( \begin{array}{cc} 1 & \lambda_{1} \\ 0 & \lambda_{2} \end{array} \right), \pmb{\alpha}_{1}, \pmb{A}(\pmb{\alpha}_{1} + \pmb{\alpha}_{2})$ 线性无关的充分必要条件是矩阵 $\left( \begin{array}{cc} 1 & \lambda_{1} \\ 0 & \lambda_{2} \end{array} \right)$ 可逆，即 $\left| \begin{array}{cc} 1 & \lambda_{1} \\ 0 & \lambda_{2} \end{array} \right| \neq 0$ 故 $\lambda_{2} \neq 0$ ，应选(B).

方法二 令 $k_{1}\pmb{\alpha}_{1} + k_{2}\pmb{A}(\pmb{\alpha}_{1} + \pmb{\alpha}_{2}) = \mathbf{0}$ , 由 $\mathbf{A}(\pmb{\alpha}_{1} + \pmb{\alpha}_{2}) = \lambda_{1}\pmb{\alpha}_{1} + \lambda_{2}\pmb{\alpha}_{2}$ , 得 $k_{1}\pmb{\alpha}_{1} + k_{2}(\lambda_{1}\pmb{\alpha}_{1} + \lambda_{2}\pmb{\alpha}_{2}) = \mathbf{0}$ , 整理得 $(k_{1} + \lambda_{1}k_{2})\pmb{\alpha}_{1} + \lambda_{2}k_{2}\pmb{\alpha}_{2} = \mathbf{0}$ .

因为 $\alpha_{1},\alpha_{2}$ 线性无关，所以 $\begin{cases} k_1 + \lambda_1k_2 = 0,\\ \lambda_2k_2 = 0, \end{cases}$ 于是 $\pmb{\alpha}_{1},\pmb {A}(\pmb{\alpha}_{1} + \pmb{\alpha}_{2})$ 线性无关的充分必要条件是 $k_{1}\pmb{\alpha}_{1} + k_{2}\pmb {A}(\pmb{\alpha}_{1} + \pmb{\alpha}_{2}) = \mathbf{0}$ 当且仅当 $k_{1} = k_{2} = 0$ ，即方程组 $\left\{ \begin{array}{l}k_{1} + \lambda_{1}k_{2} = 0,\\ \lambda_{2}k_{2} = 0 \end{array} \right.$ 只有零解，于是 $\left| \begin{array}{ll}1 & \lambda_1\\ 0 & \lambda_2 \end{array} \right|\neq 0$ ，故 $\lambda_{2}\neq 0$ ，应选(B).', 'E:\数学自用\数据资料\真题\按年份整理\2005\解析\2005年解析.md', 'ok', 'year_question_no', 0.464, '2005:11', 11, 0.464);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2005_main_q12', 'math1', 2005, '真题', 'main', 12, '(12) 设 $\mathbf{A}$ 为 $n (n \geqslant 2)$ 阶可逆矩阵, 交换 $\mathbf{A}$ 的第 1 行与第 2 行得矩阵 $\mathbf{B}, \mathbf{A}^{*}, \mathbf{B}^{*}$ 分别为 $\mathbf{A}, \mathbf{B}$ 的伴随矩阵, 则( )

(A) 交换 $A^{*}$ 的第1列与第2列得 $\pmb{B}^{*}$   
(B) 交换 $A^{*}$ 的第1行与第2行得 $\pmb{B}^{*}$   
(C) 交换 $A^{*}$ 的第1列与第2列得 $-B^{*}$ .  
(D) 交换 $A^{*}$ 的第1行与第2行得 $-B^{*}$ .', 'E:\数学自用\数据资料\真题\按年份整理\2005\按题拆分\真题\第12题\题目.md', '2005\按题拆分\真题\第12题\题目.md', 0, 'ok', '2005 真题 第12题 (12) 设 $\mathbf{a}$ 为 $n (n \geqslant 2)$ 阶可逆矩阵, 交换 $\mathbf{a}$ 的第 1 行与第 2 行得矩阵 $\mathbf{b}, \mathbf{a}^{*}, \mathbf{b}^{*}$ 分别为 $\mathbf{a}, \mathbf{b}$ 的伴随矩阵, 则( )

(a) 交换 $a^{*}$ 的第1列与第2列得 $\pmb{b}^{*}$   
(b) 交换 $a^{*}$ 的第1行与第2行得 $\pmb{b}^{*}$   
(c) 交换 $a^{*}$ 的第1列与第2列得 $-b^{*}$ .  
(d) 交换 $a^{*}$ 的第1行与第2行得 $-b^{*}$ .');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2005_main_q12', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2005_main_q12', 'math1_2005_main_q12', 2005, 12, 12, 12, '（12）【答案】 (C).

【解】 令 $E_{12} = \begin{pmatrix} 0 & 1 & 0\\ 1 & 0 & 0\\ 0 & 0 & 1 \end{pmatrix}$ ，由题意得 $\pmb {B} = \pmb{E}_{12}\pmb{A}$

由 $|\pmb {B}| = |\pmb{E}_{12}|\cdot |\pmb {A}| = -|\pmb {A}|,\quad \pmb{B}^{-1} = \pmb{A}^{-1}\pmb{E}_{12}^{-1} = \pmb{A}^{-1}\pmb{E}_{12},$

得 $\pmb{B}^{*} = |\pmb{B}| \pmb{B}^{-1} = -|\pmb{A}| \cdot \pmb{A}^{-1} \pmb{E}_{12} = -\pmb{A}^{*} \pmb{E}_{12}$ 或 $-\pmb{B}^{*} = \pmb{A}^{*} \pmb{E}_{12}$ ,

即交换 $\mathbf{A}^{*}$ 的第1、2两列得 $-\mathbf{B}^{*}$ ，应选(C).

方法点评：本题考查初等变换与伴随矩阵.

设 $\mathbf{A}$ 为可逆矩阵，当研究 $A^{*}$ 时，一般需要使用公式 $A^{*} = |A|A^{-1}$ ，即将伴随矩阵问题转化为逆矩阵问题，注意使用如下结论：

（1）设 $\mathbf{A},\mathbf{B}$ 为可逆的 $n$ 阶矩阵，则 $(\mathbf{AB})^{*} = \mathbf{B}^{*}\mathbf{A}^{*}$   
（2）设 $\mathbf{A},\mathbf{B}$ 分别为可逆的 $m$ 阶及 $n$ 阶矩阵，则

$$
\begin{array}{l} \left( \begin{array}{c c} \mathbf {A} & \mathbf {O} \\ \mathbf {O} & \mathbf {B} \end{array} \right) ^ {*} = \left| \begin{array}{c c} \mathbf {A} & \mathbf {O} \\ \mathbf {O} & \mathbf {B} \end{array} \right| \cdot \left( \begin{array}{c c} \mathbf {A} & \mathbf {O} \\ \mathbf {O} & \mathbf {B} \end{array} \right) ^ {- 1} = \left( \begin{array}{c c} | \mathbf {B} | \mathbf {A} ^ {*} & \mathbf {O} \\ \mathbf {O} & | \mathbf {A} | \mathbf {B} ^ {*} \end{array} \right); \\ \left( \begin{array}{l l} \mathbf {O} & \mathbf {A} \\ \mathbf {B} & \mathbf {O} \end{array} \right) ^ {*} = \left| \begin{array}{l l} \mathbf {O} & \mathbf {A} \\ \mathbf {B} & \mathbf {O} \end{array} \right| \cdot \left( \begin{array}{l l} \mathbf {O} & \mathbf {A} \\ \mathbf {B} & \mathbf {O} \end{array} \right) ^ {- 1} = (- 1) ^ {m n} \binom {\mathbf {O}} {| \mathbf {B} | \mathbf {A} ^ {*}} \begin{array}{c c} | \mathbf {A} | \mathbf {B} ^ {*} \\ \mathbf {O} \end{array} . \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\2005\解析\2005年解析.md', 'ok', 'year_question_no', 0.293, '2005:12', 12, 0.293);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2005_main_q13', 'math1', 2005, '真题', 'main', 13, '(13) 设二维随机变量 $(X, Y)$ 的概率分布为

<table><tr><td>X Y</td><td>0</td><td>1</td></tr><tr><td>0</td><td>0.4</td><td>a</td></tr><tr><td>1</td><td>b</td><td>0.1</td></tr></table>

已知随机事件 $\{X = 0\}$ 与 $\{X + Y = 1\}$ 相互独立, 则( )

(A) $a = 0.2, b = 0.3$ .

(B) $a = 0.4, b = 0.1$ .

(C) $a = 0.3, b = 0.2$ .

(D) $a = 0.1, b = 0.4$ .', 'E:\数学自用\数据资料\真题\按年份整理\2005\按题拆分\真题\第13题\题目.md', '2005\按题拆分\真题\第13题\题目.md', 0, 'ok', '2005 真题 第13题 (13) 设二维随机变量 $(x, y)$ 的概率分布为

<table><tr><td>x y</td><td>0</td><td>1</td></tr><tr><td>0</td><td>0.4</td><td>a</td></tr><tr><td>1</td><td>b</td><td>0.1</td></tr></table>

已知随机事件 $\{x = 0\}$ 与 $\{x + y = 1\}$ 相互独立, 则( )

(a) $a = 0.2, b = 0.3$ .

(b) $a = 0.4, b = 0.1$ .

(c) $a = 0.3, b = 0.2$ .

(d) $a = 0.1, b = 0.4$ .');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2005_main_q13', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2005_main_q13', 'math1_2005_main_q13', 2005, 13, 13, 13, '（13）【答案】（B）.

【解】 $P\{X = 0\} = 0.4 + a$

$$
\begin{array}{l} P \{X + Y = 1 \} = P \{X = 0, Y = 1 \} + P \{X = 1, Y = 0 \} = a + b, \\ P \{X = 0, X + Y = 1 \} = P \{X = 0, Y = 1 \} = a, \\ \end{array}
$$

因为 $\{X = 0\}$ 与 $\{X + Y = 1\}$ 相互独立，所以 $(a + b)(0.4 + a) = a$ ，又因为 $a + b = 0.5$ 所以 $a = 0.4, b = 0.1$ ，应选(B).', 'E:\数学自用\数据资料\真题\按年份整理\2005\解析\2005年解析.md', 'ok', 'year_question_no', 0.138, '2005:13', 13, 0.138);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2005_main_q14', 'math1', 2005, '真题', 'main', 14, '(14) 设 $X_{1}, X_{2}, \dots, X_{n} (n \geqslant 2)$ 为来自总体 $N(0,1)$ 的简单随机样本, $\overline{X}$ 为样本均值, $S^{2}$ 为样本方差, 则( )

(A) $n\overline{X} \sim N(0,1)$ .

(B) $nS^2 \sim \chi^2(n)$ .

(C) $\frac{(n - 1)\overline{X}}{S} \sim t(n - 1)$ .

$\frac{(n - 1)X_1^2}{\sum_{i = 2}^{n}X_i^2}\sim F(1,n - 1).$

# 三、解答题(本题共9小题，满分94分.解答应写出文字说明、证明过程或演算步骤)', 'E:\数学自用\数据资料\真题\按年份整理\2005\按题拆分\真题\第14题\题目.md', '2005\按题拆分\真题\第14题\题目.md', 0, 'ok', '2005 真题 第14题 (14) 设 $x_{1}, x_{2}, \dots, x_{n} (n \geqslant 2)$ 为来自总体 $n(0,1)$ 的简单随机样本, $\overline{x}$ 为样本均值, $s^{2}$ 为样本方差, 则( )

(a) $n\overline{x} \sim n(0,1)$ .

(b) $ns^2 \sim \chi^2(n)$ .

(c) $\frac{(n - 1)\overline{x}}{s} \sim t(n - 1)$ .

$\frac{(n - 1)x_1^2}{\sum_{i = 2}^{n}x_i^2}\sim f(1,n - 1).$

# 三、解答题(本题共9小题，满分94分.解答应写出文字说明、证明过程或演算步骤)');
