INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2005_main_q14', 'math1_2005_main_q14', 2005, 14, 14, 14, '（14）【答案】 (D).

【解】 由 $X_{1} \sim N(0,1)$ ，得 $X_{1}^{2} \sim X^{2}(1)$

由 $X_{i}\sim N(0,1)(i = 2,3,\dots ,n)$ ，得 $\sum_{i = 2}^{n}X_{i}^{2}\sim \chi^{2}(n - 1)$ 且 $X_{1}^{2}$ 与 $\sum_{i = 2}^{n}X_{i}^{2}$ 独立，

由 $F$ 分布的定义得 $\frac{X_1^2 / 1}{\sum_{i = 2}^{n}X_i^2 / (n - 1)}\sim F(1,n - 1)$ ，即 $\frac{(n - 1)X_1^2}{\sum_{i = 2}^{n}X_i^2}\sim F(1,n - 1)$ ，应选(D).

方法点评：设总体 $X \sim N(\mu, \sigma^2), X_1, X_2, \dots, X_n$ 为来自总体 $X$ 的简单随机样本，熟练掌握如下结论：

(1) $\frac{\overline{X} - \mu}{\frac{\sigma}{\sqrt{n}}} \sim N(0, 1)$ ;

(2) $\frac{\overline{X} - \mu}{\frac{S}{\sqrt{n}}} \sim t(n - 1)$ ;

(3) $\frac{(n - 1)S^2}{\sigma^2} \sim \chi^2(n - 1)$ ;

(4) $\frac{1}{\sigma^2} \sum_{i=1}^{n} (X_i - \mu)^2 \sim \chi^2(n)$ .

# 三、解答题', 'E:\数学自用\数据资料\真题\按年份整理\2005\解析\2005年解析.md', 'ok', 'year_question_no', 0.314, '2005:14', 14, 0.314);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2005_main_q15', 'math1', 2005, '真题', 'main', 15, '(15) (本题满分 11 分)

设 $D = \{(x,y) \mid x^2 + y^2 \leqslant \sqrt{2}, x \geqslant 0, y \geqslant 0\}$ , $[1 + x^2 + y^2]$ 表示不超过 $1 + x^2 + y^2$ 的最大整数，计算二重积分 $\iint_{D} xy[1 + x^2 + y^2] \, \mathrm{d}x \, \mathrm{d}y$ .', 'E:\数学自用\数据资料\真题\按年份整理\2005\按题拆分\真题\第15题\题目.md', '2005\按题拆分\真题\第15题\题目.md', 0, 'ok', '2005 真题 第15题 (15) (本题满分 11 分)

设 $d = \{(x,y) \mid x^2 + y^2 \leqslant \sqrt{2}, x \geqslant 0, y \geqslant 0\}$ , $[1 + x^2 + y^2]$ 表示不超过 $1 + x^2 + y^2$ 的最大整数，计算二重积分 $\iint_{d} xy[1 + x^2 + y^2] \, \mathrm{d}x \, \mathrm{d}y$ .');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2005_main_q15', 'tag_积分');
