INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2005_main_q17', 'math1_2005_main_q17', 2005, 17, 17, 17, '(17)【解】由已知条件得 $f(0) = 0, f(3) = 2, f''(0) = 2, f''(3) = -2, f''''(3) = 0.$

由分部积分得

$$
\begin{array}{l} \int_ {0} ^ {3} \left(x ^ {2} + x\right) f ^ {\prime \prime} (x) d x = \int_ {0} ^ {3} \left(x ^ {2} + x\right) d f ^ {\prime \prime} (x) \\ = (x ^ {2} + x) f ^ {\prime \prime} (x) \left| _ {0} ^ {3} - \int_ {0} ^ {3} (2 x + 1) f ^ {\prime \prime} (x) d x \right. \\ = - \int_ {0} ^ {3} (2 x + 1) d f ^ {\prime} (x) = - (2 x + 1) f ^ {\prime} (x) \left| _ {0} ^ {3} + 2 \int_ {0} ^ {3} f ^ {\prime} (x) d x \right. \\ = - 7 f ^ {\prime} (3) + f ^ {\prime} (0) + 2 \int_ {0} ^ {3} f ^ {\prime} (x) d x = 1 6 + 2 f (x) \Bigg | _ {0} ^ {3} = 2 0. \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\2005\解析\2005年解析.md', 'ok', 'year_question_no', 0.044, '2005:17', 19, 0.063);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2005_main_q18', 'math1', 2005, '真题', 'main', 18, '(18) (本题满分 12 分)

已知函数 $f(x)$ 在 $[0,1]$ 上连续，在 $(0,1)$ 内可导，且 $f(0) = 0$ ， $f(1) = 1$ 。证明：

（I）存在 $\xi \in (0,1)$ ，使得 $f(\xi) = 1 - \xi$   
（Ⅱ）存在两个不同的点 $\eta, \zeta \in (0,1)$ ，使得 $f''(\eta)f''(\zeta) = 1$', 'E:\数学自用\数据资料\真题\按年份整理\2005\按题拆分\真题\第18题\题目.md', '2005\按题拆分\真题\第18题\题目.md', 0, 'ok', '2005 真题 第18题 (18) (本题满分 12 分)

已知函数 $f(x)$ 在 $[0,1]$ 上连续，在 $(0,1)$ 内可导，且 $f(0) = 0$ ， $f(1) = 1$ 。证明：

（i）存在 $\xi \in (0,1)$ ，使得 $f(\xi) = 1 - \xi$   
（ⅱ）存在两个不同的点 $\eta, \zeta \in (0,1)$ ，使得 $f''(\eta)f''(\zeta) = 1$');
