INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2005_main_q18', 'math1_2005_main_q18', 2005, 18, 18, 18, '（18）【证明】（I）令 $\varphi (x) = f(x) - 1 + x,\varphi (0) = -1,\varphi (1) = 1.$

因为 $\varphi (0)\varphi (1) < 0$ ，所以由零点定理，存在 $\xi \in (0,1)$ ，使得 $\varphi (\xi) = 0$ ，即 $f(\xi) = 1 - \xi$

（Ⅱ）由微分中值定理，存在 $\eta \in (0,c),\zeta \in (c,1)$ ，使得

$$
f ^ {\prime} (\eta) = \frac {f (\xi) - f (0)}{\xi} = \frac {1 - \xi}{\xi}, \quad f ^ {\prime} (\zeta) = \frac {f (1) - f (\xi)}{1 - \xi} = \frac {\xi}{1 - \xi},
$$

故 $f^{\prime}(\eta)f^{\prime}(\zeta) = 1$

方法点评：本题考查零点定理与拉格朗日中值定理

设 $f(x)$ 在 $[a,b]$ 上连续，在 $(a,b)$ 内可导，若题中只出现 $f^{\prime}(\xi),f^{\prime}(\eta)$ ，则一般需要找出三个点，两次使用拉格朗日中值定理.本题已知条件出现 $f(0) = 0,f(1) = 1$ 连同 $f(\xi) = 1 - \xi$ 故三个点为 $0,\xi ,1$', 'E:\数学自用\数据资料\真题\按年份整理\2005\解析\2005年解析.md', 'ok', 'year_question_no', 0.315, '2005:18', 18, 0.315);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2005_main_q19', 'math1', 2005, '真题', 'main', 19, '(19) (本题满分 12 分)

设函数 $\varphi(y)$ 具有连续导数，在围绕原点的任意分段光滑简单闭曲线 $L$ 上，曲线积分 $\oint_{L} \frac{\varphi(y) \, \mathrm{d}x + 2xy \, \mathrm{d}y}{2x^2 + y^4}$ 的值恒为同一常数。

（I）证明：对右半平面 $x > 0$ 内的任意分段光滑简单闭曲线 $C$ ，有

$$
\oint_ {C} \frac {\varphi (y) \mathrm {d} x + 2 x y \mathrm {d} y}{2 x ^ {2} + y ^ {4}} = 0;
$$

（Ⅱ）求函数 $\varphi (y)$ 的表达式', 'E:\数学自用\数据资料\真题\按年份整理\2005\按题拆分\真题\第19题\题目.md', '2005\按题拆分\真题\第19题\题目.md', 0, 'ok', '2005 真题 第19题 (19) (本题满分 12 分)

设函数 $\varphi(y)$ 具有连续导数，在围绕原点的任意分段光滑简单闭曲线 $l$ 上，曲线积分 $\oint_{l} \frac{\varphi(y) \, \mathrm{d}x + 2xy \, \mathrm{d}y}{2x^2 + y^4}$ 的值恒为同一常数。

（i）证明：对右半平面 $x > 0$ 内的任意分段光滑简单闭曲线 $c$ ，有

$$
\oint_ {c} \frac {\varphi (y) \mathrm {d} x + 2 x y \mathrm {d} y}{2 x ^ {2} + y ^ {4}} = 0;
$$

（ⅱ）求函数 $\varphi (y)$ 的表达式');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2005_main_q19', 'tag_连续');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2005_main_q19', 'tag_导数');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2005_main_q19', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2005_main_q19', 'math1_2005_main_q19', 2005, 19, 19, 19, '(19)【解】（I） $P(x, y) = \frac{\varphi(y)}{2x^2 + y^4}, Q(x, y) = \frac{2xy}{2x^2 + y^4}$ ,

$$
\frac {\partial Q}{\partial x} = \frac {2 y (2 x ^ {2} + y ^ {4}) - 8 x ^ {2} y}{(2 x ^ {2} + y ^ {4}) ^ {2}}, \quad \frac {\partial P}{\partial y} = \frac {(2 x ^ {2} + y ^ {4}) \varphi^ {\prime} (y) - 4 y ^ {3} \varphi (y)}{(2 x ^ {2} + y ^ {4}) ^ {2}},
$$

设 $C$ 是任意一条右半平面 $x > 0$ 内正向闭曲线，如图所示，在 $C$ 上取两点 $A,B$ 将 $C$ 分为 $L_{1},L_{2}$ ，再取从点 $A$ 至点 $B$ 的有向曲线 $L_{3}$ 使得 $L_1^-$ + $L_{3}$ 与 $L_{2} + L_{3}$ 都是绕原点的正向闭曲线，由已知条件得 $\oint_{L_1^- +L_3}\frac{\varphi(y)\mathrm{d}x + 2xy\mathrm{d}y}{2x^2 + y^4} = A,\oint_{L_2 + L_3}\frac{\varphi(y)\mathrm{d}x + 2xy\mathrm{d}y}{2x^2 + y^4} = A,$

两式相减得

$$
\oint_ {c} \frac {\varphi (y) d x + 2 x y d y}{2 x ^ {2} + y ^ {4}} = 0.
$$

![](images/edec8ffa75bfcd733339dba1dec13f8a98d4740e3991aa56fb5f01845d494e5d.jpg)  
三(19)题图

（Ⅱ）因为对任意右半平面的闭曲线 $C$ 都有 $\oint_{C} \frac{\varphi(y) \mathrm{d}x + 2xy \mathrm{d}y}{2x^2 + y^4} = 0$ ，所以曲线积分与路径无关，于是 $\frac{\partial Q}{\partial x} = \frac{\partial P}{\partial y}$ ，即 $2y^5 - 4x^2 y = 2x^2 \varphi''(y) + \varphi''(y)y^4 - 4y^3 \varphi(y)$ ，

比较 $x$ 相同次数的系数得 $\left\{ \begin{array}{l}\varphi^{\prime}(y) = -2y,\\ \varphi^{\prime}(y)y - 4\varphi (y) = 2y^{2}. \end{array} \right.$

由 $\varphi''(y) = -2y$ ，得 $\varphi(y) = -y^2 + C$ ，代入 $y\varphi''(y) - 4\varphi(y) = 2y^2$ 中得 $C = 0$ 故 $\varphi(y) = -y^2$

方法点评：本题考查对坐标的曲线积分、格林公式、曲线积分与路径无关的条件及积分学与微分方程相结合的应用. 曲线积分与路径无关的等价命题有：

（1）曲线积分 $\int_{L} P \mathrm{d}x + Q \mathrm{d}y$ 与路径无关；  
(2) 对区域 $D$ 内任意的闭曲线 $C$ 有 $\oint_{C} P \mathrm{~d} x + Q \mathrm{~d} y = 0$ ;  
(3) 在区域 $D$ 内 $\frac{\partial Q}{\partial x} = \frac{\partial P}{\partial y}$ ;  
（4）存在二元函数 $u(x,y)$ ，使得 $\mathrm{d}u = P\mathrm{d}x + Q\mathrm{d}y$

本题对任意一条不绕原点的闭曲线的曲线积分为零，则有 $\frac{\partial Q}{\partial x} = \frac{\partial P}{\partial y}$ ，从而可得一微分方程，解出未知函数.', 'E:\数学自用\数据资料\真题\按年份整理\2005\解析\2005年解析.md', 'ok', 'year_question_no', 0.326, '2005:19', 19, 0.326);
