INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2007_main_q11', 'math1_2007_main_q11', 2007, 11, 11, 11, '(11)【答案】 $\frac{\sqrt{\mathrm{e}}}{2}$ .

【解】 $\int_{1}^{2}\frac{1}{x^3}\mathrm{e}^{\frac{1}{x}}\mathrm{d}x = -\int_{1}^{2}\frac{1}{x}\mathrm{e}^{\frac{1}{x}}\mathrm{d}\left(\frac{1}{x}\right) = \int_{\frac{1}{2}}^{1}t\mathrm{e}^{t}\mathrm{d}t = (t - 1)\mathrm{e}^{t}\Bigg{|}_{\frac{1}{2}}^{1} = \frac{\sqrt{\mathrm{e}}}{2}.$', 'E:\数学自用\数据资料\真题\按年份整理\2007\解析\2007年解析.md', 'ok', 'year_question_no', 0.8, '2007:11', 11, 0.8);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2007_main_q12', 'math1', 2007, '真题', 'main', 12, '(12) 设 $f(u, v)$ 为二元可微函数， $z = f(x^y, y^x)$ ，则 $\frac{\partial z}{\partial x} = \_$', 'E:\数学自用\数据资料\真题\按年份整理\2007\按题拆分\真题\第12题\题目.md', '2007\按题拆分\真题\第12题\题目.md', 0, 'ok', '2007 真题 第12题 (12) 设 $f(u, v)$ 为二元可微函数， $z = f(x^y, y^x)$ ，则 $\frac{\partial z}{\partial x} = \_$');
