INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2008_main_q18', 'math1_2008_main_q18', 2008, 18, 18, 18, '(18)【证明】（I） $\Delta F(x) = F(x + \Delta x) - F(x) = \int_{0}^{x + \Delta x} f(t) \, \mathrm{d}t - \int_{0}^{x} f(t) \, \mathrm{d}t = \int_{x}^{x + \Delta x} f(t) \, \mathrm{d}t,$

因为 $f(x)$ 连续，所以由积分中值定理

$\Delta F(x) = \int_{x}^{x + \Delta x}f(t)\mathrm{d}t = f(\xi)\Delta x$ ，其中 $\xi$ 位于 $x$ 与 $x + \Delta x$ 之间，

从而 $\frac{\Delta F(x)}{\Delta x} = f(\xi)$ ，于是 $\lim_{\Delta x \to 0} \frac{\Delta F(x)}{\Delta x} = \lim_{\Delta x \to 0} f(\xi) = f(x)$ ，即 $F''(x) = f(x)$

（Ⅱ）设 $f(x + 2) = f(x)$ ，则

$$
G (x + 2) = 2 \int_ {0} ^ {x + 2} f (t) d t - (x + 2) \int_ {0} ^ {2} f (t) d t
$$

$$
\begin{array}{l} = 2 \int_ {0} ^ {x} f (t) d t - x \int_ {0} ^ {2} f (t) d t + 2 \int_ {x} ^ {x + 2} f (t) d t - 2 \int_ {0} ^ {2} f (t) d t \\ = G (x) + 2 \int_ {x} ^ {x + 2} f (t) d t - 2 \int_ {0} ^ {2} f (t) d t, \\ \end{array}
$$

由周期函数的平移性质得 $\int_{x}^{x + 2}f(t)\mathrm{d}t = \int_{0}^{2}f(t)\mathrm{d}t$ ，于是 $2\int_{x}^{x + 2}f(t)\mathrm{d}t - 2\int_{0}^{2}f(t)\mathrm{d}t = 0$ 故 $G(x + 2) = G(x)$ ，即 $G(x)$ 是以2为周期的函数.', 'E:\数学自用\数据资料\真题\按年份整理\2008\解析\2008年解析.md', 'ok', 'year_question_no', 0.357, '2008:18', 18, 0.357);
