INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2009_main_q18', 'math1_2009_main_q18', 2009, 18, 18, 18, '(18)【证明】（I）令 $\varphi (x) = f(x) - f(a) - \frac{f(b) - f(a)}{b - a} (x - a)$ ，显然 $\varphi (x)$ 在 $[a,b]$ 上连续，在 $(a,b)$ 内可导.

又 $\varphi(a) = \varphi(b) = 0$ ，所以由罗尔定理，存在 $\xi \in (a, b)$ ，使得 $\varphi''(\xi) = 0$

而 $\varphi^{\prime}(x) = f^{\prime}(x) - \frac{f(b) - f(a)}{b - a}$ ，所以 $f^{\prime}(\xi) - \frac{f(b) - f(a)}{b - a} = 0$ ，即

$$
f (b) - f (a) = f ^ {\prime} (\xi) (b - a).
$$

（Ⅱ）取 $x\in (0,\delta)$ ，因为 $f(x)$ 在 $[0,\delta ]$ 上连续，在 $(0,\delta)$ 内可导，所以由拉格朗日中值定理，存在 $\xi \in (0,x)$ ，使得 $f(x) - f(0) = f^{\prime}(\xi)x$ ，即 $\frac{f(x) - f(0)}{x} = f^{\prime}(\xi)$ ，两边取极限得

$$
\lim  _ {x \rightarrow 0 ^ {+}} \frac {f (x) - f (0)}{x} = \lim  _ {x \rightarrow 0 ^ {+}} f ^ {\prime} (\xi).
$$

因为 $\lim_{x\to 0^{+}}f^{\prime}(x) = A$ ，所以 $\lim_{x\to 0^{+}}f^{\prime}(\xi) = \lim_{\xi \to 0^{+}}f^{\prime}(\xi) = A.$

于是 $\lim_{x\to 0^{+}}\frac{f(x) - f(0)}{x} = \lim_{x\to 0^{+}}f^{\prime}(\xi) = A$ ，即 $f_{+}^{\prime}(0) = A$', 'E:\数学自用\数据资料\真题\按年份整理\2009\解析\2009年解析.md', 'ok', 'year_question_no', 0.421, '2009:18', 18, 0.421);
