INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2011_main_q19', 'math1_2011_main_q19', 2011, 19, 19, 18, '(19)【解】 $I = \int_{0}^{1}x\mathrm{d}x\int_{0}^{1}yf_{xy}^{\prime \prime}(x,y)\mathrm{d}y = \int_{0}^{1}x\mathrm{d}x\int_{0}^{1}y\mathrm{d}f_{x}^{\prime}(x,y),$

由 $\int_0^1 y\mathrm{d}f_x''(x,y) = yf_x''(x,y)\Big|_0^1 -\int_0^1 f_x''(x,y)\mathrm{d}y = f_x''(x,1) - \int_0^1 f_x''(x,y)\mathrm{d}y,$

得 $I = \int_{0}^{1}x f^{\prime}_{x}(x,1)\mathrm{d}x - \int_{0}^{1}x\mathrm{d}x\int_{0}^{1}f^{\prime}_{x}(x,y)\mathrm{d}y = \int_{0}^{1}x\mathrm{d}f(x,1) - \int_{0}^{1}x\mathrm{d}x\int_{0}^{1}f^{\prime}_{x}(x,y)\mathrm{d}y,$

由 $f(x,1) = 0$ 得

$$
I = - \int_ {0} ^ {1} x \mathrm {d} x \int_ {0} ^ {1} f _ {x} ^ {\prime} (x, y) \mathrm {d} y = - \int_ {0} ^ {1} \mathrm {d} y \int_ {0} ^ {1} x f _ {x} ^ {\prime} (x, y) \mathrm {d} x,
$$

$$
\int_ {0} ^ {1} x f _ {x} ^ {\prime} (x, y) \mathrm {d} x = \int_ {0} ^ {1} x \mathrm {d} f (x, y) = x f (x, y) | _ {0} ^ {1} - \int_ {0} ^ {1} f (x, y) \mathrm {d} x = f (1, y) - \int_ {0} ^ {1} f (x, y) \mathrm {d} x,
$$

由 $f(1,y) = 0$ 得 $\int_0^1 xf''_x(x,y)\mathrm{d}x = -\int_0^1 f(x,y)\mathrm{d}x,$

故 $I = \int_{0}^{1}\mathrm{d}y\int_{0}^{1}f(x,y)\mathrm{d}x = \iint_{D}f(x,y)\mathrm{d}x\mathrm{d}y = a.$

方法点评：本题主要考查二重积分转化为累次积分及改变累次积分的积分次序，抽象函数的定积分的分部积分法.', 'E:\数学自用\数据资料\真题\按年份整理\2011\解析\2011年解析.md', 'ok', 'year_question_no', 0.27, '2011:19', 19, 0.27);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2011_main_q20', 'math1', 2011, '真题', 'main', 20, '(20) (本题满分 11 分)

设向量组 $\pmb{\alpha}_{1} = (1,0,1)^{\mathrm{T}},\pmb{\alpha}_{2} = (0,1,1)^{\mathrm{T}},\pmb{\alpha}_{3} = (1,3,5)^{\mathrm{T}}$ 不能由向量组 $\pmb{\beta}_{1} = (1,1,1)^{\mathrm{T}},$ $\pmb {\beta}_2 = (1,2,3)^{\mathrm{T}},\pmb {\beta}_3 = (3,4,a)^{\mathrm{T}}$ 线性表示.

(I)求 $a$ 的值；  
（Ⅱ）将 $\beta_{1},\beta_{2},\beta_{3}$ 用 $\alpha_{1},\alpha_{2},\alpha_{3}$ 线性表示', 'E:\数学自用\数据资料\真题\按年份整理\2011\按题拆分\真题\第20题\题目.md', '2011\按题拆分\真题\第20题\题目.md', 0, 'ok', '2011 真题 第20题 (20) (本题满分 11 分)

设向量组 $\pmb{\alpha}_{1} = (1,0,1)^{\mathrm{t}},\pmb{\alpha}_{2} = (0,1,1)^{\mathrm{t}},\pmb{\alpha}_{3} = (1,3,5)^{\mathrm{t}}$ 不能由向量组 $\pmb{\beta}_{1} = (1,1,1)^{\mathrm{t}},$ $\pmb {\beta}_2 = (1,2,3)^{\mathrm{t}},\pmb {\beta}_3 = (3,4,a)^{\mathrm{t}}$ 线性表示.

(i)求 $a$ 的值；  
（ⅱ）将 $\beta_{1},\beta_{2},\beta_{3}$ 用 $\alpha_{1},\alpha_{2},\alpha_{3}$ 线性表示');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2011_main_q20', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2011_main_q20', 'math1_2011_main_q20', 2011, 20, 20, 19, '(20)【解】（I）方法一 $\pmb{\alpha}_{1},\pmb{\alpha}_{2},\pmb{\alpha}_{3}$ 为3个3维向量，因为 $|\pmb{\alpha}_1,\pmb{\alpha}_2,\pmb{\alpha}_3| = \begin{vmatrix} 1 & 0 & 1\\ 0 & 1 & 3\\ 1 & 1 & 5 \end{vmatrix} = 1\neq 0,$

所以 $\alpha_{1},\alpha_{2},\alpha_{3}$ 线性无关.因为 $\beta_{1},\beta_{2},\beta_{3}$ 一定可由 $\alpha_{1},\alpha_{2},\alpha_{3}$ 线性表示，而 $\alpha_{1},\alpha_{2},\alpha_{3}$ 不能由 $\beta_{1},\beta_{2},\beta_{3}$ 线性表示，所以 $\beta_{1},\beta_{2},\beta_{3}$ 的秩小于 $\alpha_{1},\alpha_{2},\alpha_{3}$ 的秩，

从而 $|\pmb{\beta}_1, \pmb{\beta}_2, \pmb{\beta}_3| = \left| \begin{array}{ccc} 1 & 1 & 3 \\ 1 & 2 & 4 \\ 1 & 3 & a \end{array} \right| = \left| \begin{array}{ccc} 1 & 1 & 3 \\ 0 & 1 & 1 \\ 0 & 2 & a - 3 \end{array} \right| = a - 5 = 0$ ，故 $a = 5$ .

方法二 $\pmb{\beta}_{1},\pmb{\beta}_{2},\pmb{\beta}_{3},\pmb{\alpha}_{i}(i = 1,2,3)$ 为4个3维向量，则 $\pmb{\beta}_{1},\pmb{\beta}_{2},\pmb{\beta}_{3},\pmb{\alpha}_{i}(i = 1,2,3)$ 一定线性相关.

若 $\pmb{\beta}_{1},\pmb{\beta}_{2},\pmb{\beta}_{3}$ 线性无关，而 $\pmb{\beta}_{1},\pmb{\beta}_{2},\pmb{\beta}_{3},\pmb{\alpha}_{i}(i = 1,2,3)$ 线性相关，则 $\pmb{\alpha}_{i}(i = 1,2,3)$ 可由向量组 $\pmb{\beta}_{1},\pmb{\beta}_{2},\pmb{\beta}_{3}$ 线性表示，矛盾，于是 $|\pmb{\beta}_{1},\pmb{\beta}_{2},\pmb{\beta}_{3}| = 0$

由 $|\pmb{\beta}_1, \pmb{\beta}_2, \pmb{\beta}_3| = \left| \begin{array}{lll} 1 & 1 & 3 \\ 1 & 2 & 4 \\ 1 & 3 & a \end{array} \right| = a - 5 = 0$ ，得 $a = 5$ .

（Ⅱ）将矩阵 $(\alpha_{1},\alpha_{2},\alpha_{3},\beta_{1},\beta_{2},\beta_{3})$ 进行初等行变换得

$$
\left(\boldsymbol {\alpha} _ {1}, \boldsymbol {\alpha} _ {2}, \boldsymbol {\alpha} _ {3}, \boldsymbol {\beta} _ {1}, \boldsymbol {\beta} _ {2}, \boldsymbol {\beta} _ {3}\right) = \left(\begin{array}{c c c c c c}1&0&1&1&1&3\\0&1&3&1&2&4\\1&1&5&1&3&5\end{array}\right)\rightarrow \left(\begin{array}{c c c c c c}1&0&0&2&1&5\\0&1&0&4&2&1 0\\0&0&1&- 1&0&- 2\end{array}\right),
$$

于是 $\begin{cases} \pmb{\beta}_{1} = 2\pmb{\alpha}_{1} + 4\pmb{\alpha}_{2} - \pmb{\alpha}_{3}, \\ \pmb{\beta}_{2} = \pmb{\alpha}_{1} + 2\pmb{\alpha}_{2} + 0\pmb{\alpha}_{3}, \\ \pmb{\beta}_{3} = 5\pmb{\alpha}_{1} + 10\pmb{\alpha}_{2} - 2\pmb{\alpha}_{3}. \end{cases}$

方法点评：本题使用向量组的如下性质：

（1）若一个向量组的向量个数大于向量的维数，则该向量组一定线性相关；  
（2）若一个向量组的个数与维数相等，则该向量组线性相关的充分必要条件是该向量组构成的行列式为零；  
（3）若向量组 $\mathbf{A}$ 可由向量组 $\pmb{B}$ 线性表示，但向量组 $\pmb{B}$ 不可由向量组 $\mathbf{A}$ 线性表示，则向量组 $\mathbf{A}$ 的秩小于向量组 $\pmb{B}$ 的秩.', 'E:\数学自用\数据资料\真题\按年份整理\2011\解析\2011年解析.md', 'ok', 'year_question_no', 0.254, '2011:20', 20, 0.254);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2011_main_q21', 'math1', 2011, '真题', 'main', 21, '(21) (本题满分 11 分)

设 $A$ 为3阶实对称矩阵， $A$ 的秩为2，且

$$
\boldsymbol {A} \left( \begin{array}{c c} 1 & 1 \\ 0 & 0 \\ - 1 & 1 \end{array} \right) = \left( \begin{array}{c c} - 1 & 1 \\ 0 & 0 \\ 1 & 1 \end{array} \right).
$$

(I)求 $\mathbf{A}$ 的所有特征值与特征向量；  
（Ⅱ）求矩阵 $A$', 'E:\数学自用\数据资料\真题\按年份整理\2011\按题拆分\真题\第21题\题目.md', '2011\按题拆分\真题\第21题\题目.md', 0, 'ok', '2011 真题 第21题 (21) (本题满分 11 分)

设 $a$ 为3阶实对称矩阵， $a$ 的秩为2，且

$$
\boldsymbol {a} \left( \begin{array}{c c} 1 & 1 \\ 0 & 0 \\ - 1 & 1 \end{array} \right) = \left( \begin{array}{c c} - 1 & 1 \\ 0 & 0 \\ 1 & 1 \end{array} \right).
$$

(i)求 $\mathbf{a}$ 的所有特征值与特征向量；  
（ⅱ）求矩阵 $a$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2011_main_q21', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2011_main_q21', 'math1_2011_main_q21', 2011, 21, 21, 20, '(21)【解】（I）由 $r(\mathbf{A}) = 2 < 3$ ，得 $\left|\mathbf{A}\right| = 0$ ，于是 $\lambda_{1} = 0$ 为 $\mathbf{A}$ 的一个特征值.

又由已知条件，得 $A\left( \begin{array}{l}1\\ 0\\ -1 \end{array} \right) = -\left( \begin{array}{l}1\\ 0\\ -1 \end{array} \right),A\left( \begin{array}{l}1\\ 0\\ 1 \end{array} \right) = \left( \begin{array}{l}1\\ 0\\ 1 \end{array} \right)$ 根据特征值与特征向量的定义得 $\lambda_{2} = -1$ 为 $\mathbf{A}$ 的特征值，其对应的特征向量为 $\xi_{2} = \left( \begin{array}{l}1\\ 0\\ -1 \end{array} \right)$

$\lambda_{3} = 1$ 为 $\mathbf{A}$ 的特征值，其对应的特征向量为 $\xi_{3} = \begin{pmatrix} 1 \\ 0 \\ 1 \end{pmatrix}$ .

令 $\xi_{1} = \begin{pmatrix} x_{1}\\ x_{2}\\ x_{3} \end{pmatrix}$ 为 $\lambda_1 = 0$ 对应的一个特征向量，由实对称矩阵不同特征值对应的特征向量正

交得 $\left\{ \begin{array}{l} \xi_1^{\mathrm{T}} \xi_2 = 0, \\ \xi_1^{\mathrm{T}} \xi_3 = 0, \end{array} \right.$ 即 $\left\{ \begin{array}{l} x_1 - x_3 = 0, \\ x_1 + x_3 = 0, \end{array} \right.$ 基础解系为 $\xi_1 = \binom{0}{1}$ , 即 $\xi_1 = \binom{0}{1}$ 为 $\lambda_1 = 0$ 对应的一个特征向量. 故 $A$ 的特征值为 $\lambda_1 = 0, \lambda_2 = -1, \lambda_3 = 1$ , 其对应的所有特征向量为 $C_1 \xi_1, C_2 \xi_2, C_3 \xi_3 (C_1, C_2, C_3$ 为不为零的任意常数).

（Ⅱ）方法一 令 $P = (\xi_{1},\xi_{2},\xi_{3}) = \begin{pmatrix} 0 & 1 & 1\\ 1 & 0 & 0\\ 0 & -1 & 1 \end{pmatrix}$ ，由 $P^{-1}AP = \begin{pmatrix} 0 & 0 & 0\\ 0 & -1 & 0\\ 0 & 0 & 1 \end{pmatrix}$ ，得

$$
\mathbf {A} = \mathbf {P} \left( \begin{array}{c c c} 0 & 0 & 0 \\ 0 & - 1 & 0 \\ 0 & 0 & 1 \end{array} \right) \mathbf {P} ^ {- 1} = \left( \begin{array}{c c c} 0 & 0 & 1 \\ 0 & 0 & 0 \\ 1 & 0 & 0 \end{array} \right).
$$

方法二 由 $A(\xi_1, \xi_2, \xi_3) = (A\xi_1, A\xi_2, A\xi_3) = (0, -\xi_2, \xi_3)$ ，得

$$
\mathbf {A} = (\mathbf {0}, - \xi_ {2}, \xi_ {3}) (\xi_ {1}, \xi_ {2}, \xi_ {3}) ^ {- 1} = \left( \begin{array}{c c c} 0 & - 1 & 1 \\ 0 & 0 & 0 \\ 0 & 1 & 1 \end{array} \right) \left( \begin{array}{c c c} 0 & 1 & 1 \\ 1 & 0 & 0 \\ 0 & - 1 & 1 \end{array} \right) ^ {- 1} = \left( \begin{array}{c c c} 0 & 0 & 1 \\ 0 & 0 & 0 \\ 1 & 0 & 0 \end{array} \right).
$$

方法点评：本题注重考查特征值与特征向量的定义，很多考生忽视了定义而不知道本题所给已知条件如何解读。事实上求特征值常用方法有：

（1）公式法，即由 $|\lambda E - A| = 0$ 求出特征值；

（2）定义法，即令 $AX = \lambda X$ ，根据矩阵的关系式，求出矩阵 $\mathbf{A}$ 的特征值；

（3）关联矩阵法，即找矩阵 $\pmb{B}$ ，使得 $P^{-1}AP = B$ ，即 $\mathbf{A}\sim \mathbf{B}$ ，从而 $|\lambda E - A| = |\lambda E - B|$ ，于是求出 $\mathbf{A}$ 的特征值.

求特征向量常用方法有：

（1）设 $\lambda_0$ 为 $\mathbf{A}$ 的特征值，则属于 $\lambda_0$ 的特征向量为 $(\lambda_0 E - A) X = 0$ 的非零解；

（2）定义法，满足 $AX = \lambda_0X$ 的非零 $X$ 即为 $\lambda_0$ 对应的特征向量；

（3）利用矩阵关系求特征向量，如 $A^{-1}\pmb {\alpha} = \lambda_0\pmb{\alpha}$ ，则 $\pmb{\alpha}$ 为 $\mathbf{A}$ 的属于特征值 $\frac{1}{\lambda_0}$ 的特征向量.', 'E:\数学自用\数据资料\真题\按年份整理\2011\解析\2011年解析.md', 'ok', 'year_question_no', 0.492, '2011:21', 21, 0.492);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2011_main_q22', 'math1', 2011, '真题', 'main', 22, '(22) (本题满分 11 分)

设随机变量 $X$ 与 $Y$ 的概率分布分别为

<table><tr><td>X</td><td>0</td><td>1</td></tr><tr><td>P</td><td>1/3</td><td>2/3</td></tr></table>

<table><tr><td>Y</td><td>-1</td><td>0</td><td>1</td></tr><tr><td>P</td><td>1/3</td><td>1/3</td><td>1/3</td></tr></table>

且 $P\{X^2 = Y^2\} = 1$

(I) 求二维随机变量 $(X, Y)$ 的概率分布；  
（Ⅱ）求 $Z = XY$ 的概率分布；  
(III) 求 $X$ 与 $Y$ 的相关系数 $\rho_{XY}$ .', 'E:\数学自用\数据资料\真题\按年份整理\2011\按题拆分\真题\第22题\题目.md', '2011\按题拆分\真题\第22题\题目.md', 0, 'ok', '2011 真题 第22题 (22) (本题满分 11 分)

设随机变量 $x$ 与 $y$ 的概率分布分别为

<table><tr><td>x</td><td>0</td><td>1</td></tr><tr><td>p</td><td>1/3</td><td>2/3</td></tr></table>

<table><tr><td>y</td><td>-1</td><td>0</td><td>1</td></tr><tr><td>p</td><td>1/3</td><td>1/3</td><td>1/3</td></tr></table>

且 $p\{x^2 = y^2\} = 1$

(i) 求二维随机变量 $(x, y)$ 的概率分布；  
（ⅱ）求 $z = xy$ 的概率分布；  
(iii) 求 $x$ 与 $y$ 的相关系数 $\rho_{xy}$ .');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2011_main_q22', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2011_main_q22', 'math1_2011_main_q22', 2011, 22, 22, 21, '（22）【解】（I）由 $P\{X^2 = Y^2\} = 1$ ，得 $P\{X^2 \neq Y^2\} = 0$

于是 $P\{X = 0,Y = -1\} = P\{X = 0,Y = 1\} = P\{X = 1,Y = 0\} = 0$

故 $(X,Y)$ 的联合分布律为

<table><tr><td rowspan="2">X</td><td colspan="3">Y</td></tr><tr><td>-1</td><td>0</td><td>1</td></tr><tr><td>0</td><td>0</td><td>1/3</td><td>0</td></tr><tr><td>1</td><td>1/3</td><td>0</td><td>1/3</td></tr></table>

（Ⅱ） $Z = XY$ 的可能取值为 $-1,0,1$ ，且

$$
P \{Z = - 1 \} = P \{X = 1, Y = - 1 \} = \frac {1}{3},
$$

$$
\begin{array}{l} P \{Z = 0 \} = P \{X = 0, Y = - 1 \} + P \{X = 0, Y = 0 \} + \\ P \{X = 0, Y = 1 \} + P \{X = 1, Y = 0 \} \\ = \frac {1}{3}, \\ \end{array}
$$

$P\{Z = 1\} = 1 - P\{Z = -1\} - P\{Z = 0\} = \frac{1}{3}$ , 则 $Z$ 的分布律为 $Z \sim \left( \begin{array}{ccc} -1 & 0 & 1 \\ \frac{1}{3} & \frac{1}{3} & \frac{1}{3} \end{array} \right)$ .

（Ⅲ）由 $E(X) = \frac{2}{3}, E(Y) = 0, E(XY) = E(Z) = 0,$

得 $\operatorname{Cov}(X, Y) = E(XY) - E(X)E(Y) = 0$ ，于是 $\rho_{XY} = 0$', 'E:\数学自用\数据资料\真题\按年份整理\2011\解析\2011年解析.md', 'ok', 'year_question_no', 0.33, '2011:22', 22, 0.33);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2011_main_q23', 'math1', 2011, '真题', 'main', 23, '(23) (本题满分 11 分)

设 $X_{1}, X_{2}, \dots, X_{n}$ 为来自正态总体 $N(\mu_0, \sigma^2)$ 的简单随机样本，其中 $\mu_0$ 已知， $\sigma^2 > 0$ 未知， $\overline{X}$ 和 $S^2$ 分别表示样本均值和样本方差.

(I) 求参数 $\sigma^2$ 的最大似然估计 $\widehat{\sigma^2}$ ;  
(II) 计算 $E(\widehat{\sigma^2})$ 和 $D(\widehat{\sigma^2})$ .', 'E:\数学自用\数据资料\真题\按年份整理\2011\按题拆分\真题\第23题\题目.md', '2011\按题拆分\真题\第23题\题目.md', 0, 'ok', '2011 真题 第23题 (23) (本题满分 11 分)

设 $x_{1}, x_{2}, \dots, x_{n}$ 为来自正态总体 $n(\mu_0, \sigma^2)$ 的简单随机样本，其中 $\mu_0$ 已知， $\sigma^2 > 0$ 未知， $\overline{x}$ 和 $s^2$ 分别表示样本均值和样本方差.

(i) 求参数 $\sigma^2$ 的最大似然估计 $\widehat{\sigma^2}$ ;  
(ii) 计算 $e(\widehat{\sigma^2})$ 和 $d(\widehat{\sigma^2})$ .');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2011_main_q23', 'math1_2011_main_q23', 2011, 23, 23, 22, '(23)【解】（I）似然函数为 $L(\sigma^2) = f(x_1)f(x_2)\dots f(x_n) = (2\pi \sigma^2)^{-\frac{n}{2}}\mathrm{e}^{-\frac{1}{2\sigma^2}\sum_{i = 1}^{n}(x_i - \mu_0)^2},$

取对数得 $\ln L(\sigma^2) = -\frac{n}{2}\ln 2\pi -\frac{n}{2}\ln \sigma^2 -\frac{1}{2\sigma^2}\sum_{i = 1}^{n}(x_i - \mu_0)^2,$

由 $\frac{\mathrm{d}}{\mathrm{d}(\sigma^2)}\ln L(\sigma^2) = -\frac{n}{2\sigma^2} +\frac{1}{2\sigma^4}\sum_{i = 1}^{n}(x_i - \mu_0)^2 = 0$ ，得 $\sigma^2 = \frac{1}{n}\sum_{i = 1}^{n}(x_i - \mu_0)^2$ 故 $\sigma^2$ 的最大似然估计量为 $\hat{\sigma}^2 = \frac{1}{n}\sum_{i = 1}^{n}(X_i - \mu_0)^2.$

（Ⅱ）方法一 $E(\hat{\sigma}^2) = \frac{1}{n}\sum_{i = 1}^{n}E(X_i - \mu_0)^2 = E(X - \mu_0)^2$

$$
\begin{array}{l} = D \left(X - \mu_ {0}\right) + \left[ E \left(X - \mu_ {0}\right) \right] ^ {2} = D (X) = \sigma^ {2}, \\ D \left(\hat {\sigma} ^ {2}\right) = \frac {1}{n ^ {2}} \sum_ {i = 1} ^ {n} D \left(X _ {i} - \mu_ {0}\right) ^ {2} = \frac {1}{n} D \left(X - \mu_ {0}\right) ^ {2} = \frac {\sigma^ {4}}{n} D \left(\frac {X - \mu_ {0}}{\sigma}\right) ^ {2}, \\ \end{array}
$$

因为 $\frac{X - \mu_0}{\sigma} \sim N(0,1)$ ，所以 $\left(\frac{X - \mu_0}{\sigma}\right)^2 \sim \chi^2(1)$ ，于是 $D\left(\frac{X - \mu_0}{\sigma}\right)^2 = 2$ 故 $D(\hat{\sigma}^2) = \frac{2\sigma^4}{n}$ .

方法二 因为 $\sum_{i=1}^{n}\left(\frac{X_i - \mu_0}{\sigma}\right)^2 \sim \chi^2(n)$ ，所以 $\sum_{i=1}^{n}D\left(\frac{X_i - \mu_0}{\sigma}\right)^2 = 2n$

$$
D \left(\hat {\sigma} ^ {2}\right) = D \left[ \frac {\sigma^ {2}}{n} \sum_ {i = 1} ^ {n} \left(\frac {X _ {i} - \mu_ {0}}{\sigma}\right) ^ {2} \right] = \frac {\sigma^ {4}}{n ^ {2}} \sum_ {i = 1} ^ {n} D \left(\frac {X _ {i} - \mu_ {0}}{\sigma}\right) ^ {2} = \frac {2 \sigma^ {4}}{n}.
$$', 'E:\数学自用\数据资料\真题\按年份整理\2011\解析\2011年解析.md', 'ok', 'year_question_no', 0.076, '2011:23', 23, 0.076);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2012_main_q01', 'math1', 2012, '真题', 'main', 1, '(1)曲线 $y = \frac{{x}^{2} + x}{{x}^{2} - 1}$ 的渐近线的条数为(   )

(A)0.

(B)1.

(C)2.

(D)3.', 'E:\数学自用\数据资料\真题\按年份整理\2012\按题拆分\真题\第01题\题目.md', '2012\按题拆分\真题\第01题\题目.md', 0, 'ok', '2012 真题 第1题 (1)曲线 $y = \frac{{x}^{2} + x}{{x}^{2} - 1}$ 的渐近线的条数为(   )

(a)0.

(b)1.

(c)2.

(d)3.');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2012_main_q01', 'math1_2012_main_q01', 2012, 1, 1, 1, '(1)【答案】 (C).

【解】 由 $\lim_{x\to \infty}y = 1$ ，得 $y = 1$ 为曲线 $y = \frac{x^2 + x}{x^2 - 1}$ 的水平渐近线；

由 $\lim_{x\to 1}y = \infty$ ，得 $x = 1$ 为曲线 $y = \frac{x^2 + x}{x^2 - 1}$ 的铅直渐近线；

显然 $x = -1$ 不是曲线 $y = \frac{x^2 + x}{x^2 - 1}$ 的铅直渐近线，且曲线没有斜渐近线，

故曲线 $y = \frac{x^2 + x}{x^2 - 1}$ 有两条渐近线，应选(C).

方法点评：本题考查曲线的渐近线. 渐近线是基础而频繁的考点，需要熟练掌握其求法. 曲线的渐近线共有三种，即水平渐近线、铅直渐近线和斜渐近线.

若 $\lim_{x\to \infty}f(x) = A$ ，则 $y = A$ 为曲线 $y = f(x)$ 的水平渐近线；

若 $\lim_{x\to a}f(x) = \infty$ ，则 $x = a$ 为曲线 $y = f(x)$ 的铅直渐近线；

若 $\lim_{x\to \infty}\frac{f(x)}{x} = a(\neq 0,\infty),\lim_{x\to \infty}[f(x) - ax] = b$ ，则 $y = ax + b$ 为曲线 $y = f(x)$ 的斜渐近线.', 'E:\数学自用\数据资料\真题\按年份整理\2012\解析\2012年解析.md', 'ok', 'year_question_no', 0.417, '2012:1', 1, 0.417);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2012_main_q02', 'math1', 2012, '真题', 'main', 2, '(2) 设函数 $f(x) = \left(\mathrm{e}^{x} - 1\right)\left(\mathrm{e}^{2 x} - 2\right) \dots \left(\mathrm{e}^{n x} - n\right)$ ，其中 $n$ 为正整数，则 $f^{\prime}(0) = (\quad)$

(A) $(-1)^{n - 1}(n - 1)!$ .

(B) $(-1)^{n}(n - 1)!$ .

(C) $(-1)^{n - 1} n!$ .

$(\mathrm{D})(-1)^n n!$', 'E:\数学自用\数据资料\真题\按年份整理\2012\按题拆分\真题\第02题\题目.md', '2012\按题拆分\真题\第02题\题目.md', 0, 'ok', '2012 真题 第2题 (2) 设函数 $f(x) = \left(\mathrm{e}^{x} - 1\right)\left(\mathrm{e}^{2 x} - 2\right) \dots \left(\mathrm{e}^{n x} - n\right)$ ，其中 $n$ 为正整数，则 $f^{\prime}(0) = (\quad)$

(a) $(-1)^{n - 1}(n - 1)!$ .

(b) $(-1)^{n}(n - 1)!$ .

(c) $(-1)^{n - 1} n!$ .

$(\mathrm{d})(-1)^n n!$');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2012_main_q02', 'math1_2012_main_q02', 2012, 2, 2, 2, '（2）【答案】 （A）.

【解】 方法一 由

$$
\begin{array}{l} f ^ {\prime} (x) = \mathrm {e} ^ {x} (\mathrm {e} ^ {2 x} - 2) \dots (\mathrm {e} ^ {n x} - n) + 2 (\mathrm {e} ^ {x} - 1) \mathrm {e} ^ {2 x} (\mathrm {e} ^ {3 x} - 3) \dots (\mathrm {e} ^ {n x} - n) + \dots + \\ n \left(\mathrm {e} ^ {x} - 1\right) \left(\mathrm {e} ^ {2 x} - 2\right) \dots \left(\mathrm {e} ^ {(n - 1) x} - n + 1\right) \mathrm {e} ^ {n x}, \\ \end{array}
$$

得 $f^{\prime}(0) = (-1)^{n - 1}(n - 1)!$

应选(A).

方法二 由导数的定义，得

$$
f ^ {\prime} (0) = \lim  _ {x \rightarrow 0} \frac {f (x) - f (0)}{x} = \lim  _ {x \rightarrow 0} \frac {e ^ {x} - 1}{x} \left(e ^ {2 x} - 2\right) \dots \left(e ^ {n x} - n\right) = (- 1) ^ {n - 1} (n - 1)!
$$

应选(A).', 'E:\数学自用\数据资料\真题\按年份整理\2012\解析\2012年解析.md', 'ok', 'year_question_no', 0.317, '2012:2', 2, 0.317);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2012_main_q03', 'math1', 2012, '真题', 'main', 3, '(3) 如果函数 $f(x, y)$ 在点 $(0, 0)$ 处连续, 那么下列命题正确的是( )

(A) 若极限 $\lim_{\substack{x \to 0 \\ y \to 0}} \frac{f(x, y)}{|x| + |y|}$ 存在，则 $f(x, y)$ 在点 $(0, 0)$ 处可微.  
(B) 若极限 $\lim_{\substack{x \to 0 \\ y \to 0}} \frac{f(x, y)}{x^2 + y^2}$ 存在，则 $f(x, y)$ 在点 $(0, 0)$ 处可微.  
(C) 若 $f(x, y)$ 在点 $(0, 0)$ 处可微, 则极限 $\lim_{\substack{x \to 0 \\ y \to 0}} \frac{f(x, y)}{|x| + |y|}$ 存在.  
(D) 若 $f(x, y)$ 在点 $(0, 0)$ 处可微, 则极限 $\lim_{\substack{x \to 0 \\ y \to 0}} \frac{f(x, y)}{x^2 + y^2}$ 存在.', 'E:\数学自用\数据资料\真题\按年份整理\2012\按题拆分\真题\第03题\题目.md', '2012\按题拆分\真题\第03题\题目.md', 0, 'ok', '2012 真题 第3题 (3) 如果函数 $f(x, y)$ 在点 $(0, 0)$ 处连续, 那么下列命题正确的是( )

(a) 若极限 $\lim_{\substack{x \to 0 \\ y \to 0}} \frac{f(x, y)}{|x| + |y|}$ 存在，则 $f(x, y)$ 在点 $(0, 0)$ 处可微.  
(b) 若极限 $\lim_{\substack{x \to 0 \\ y \to 0}} \frac{f(x, y)}{x^2 + y^2}$ 存在，则 $f(x, y)$ 在点 $(0, 0)$ 处可微.  
(c) 若 $f(x, y)$ 在点 $(0, 0)$ 处可微, 则极限 $\lim_{\substack{x \to 0 \\ y \to 0}} \frac{f(x, y)}{|x| + |y|}$ 存在.  
(d) 若 $f(x, y)$ 在点 $(0, 0)$ 处可微, 则极限 $\lim_{\substack{x \to 0 \\ y \to 0}} \frac{f(x, y)}{x^2 + y^2}$ 存在.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2012_main_q03', 'tag_极限');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2012_main_q03', 'tag_连续');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2012_main_q03', 'math1_2012_main_q03', 2012, 3, 3, 3, '（3）【答案】 (B).

【解】方法一 由 $f(x,y)$ 在 $(0,0)$ 连续及 $\lim_{\substack{x\to 0\\ y\to 0}}\frac{f(x,y)}{x^2 + y^2}$ 存在，得 $f(0,0) = 0$

取 $y = 0$ ，由 $\lim_{x\to 0}\frac{f(x,0)}{x^2} = \lim_{x\to 0}\frac{f(x,0) - f(0,0)}{x}\cdot \frac{1}{x}$ 存在，得 $\lim_{x\to 0}\frac{f(x,0) - f(0,0)}{x} = 0$ 即 $f_{x}^{\prime}(0,0) = 0$ ，同理 $f_{y}^{\prime}(0,0) = 0$

由 $\lim_{\substack{x\to 0\\ y\to 0}}\frac{\Delta z - f_x''(0,0)x - f_y''(0,0)y}{x^2 + y^2} = \lim_{\substack{x\to 0\\ y\to 0}}\frac{f(x,y)}{x^2 + y^2}$ 存在，得

$\Delta z - f_x''(0,0)x - f_y''(0,0)y = o(\rho)$ ，故 $f(x,y)$ 在(0，0）处可微，应选(B).

方法二 由 $\lim_{\substack{x\to 0\\ y\to 0}}\frac{f(x,y)}{x^2 + y^2}$ 存在，得 $f(0,0) = 0$

令 $\rho = \sqrt{x^2 + y^2}$ ，设 $\lim_{\substack{x\to 0\\ y\to 0}}\frac{f(x,y)}{x^2 + y^2} = A$ ，则 $\Delta z = f(x,y) - f(0,0) = 0\cdot x + 0\cdot y + o(\rho)$ ，由可微的定义得 $f(x,y)$ 在(0，0）处可微，应选(B).

方法三 取 $f(x, y) = |x| + |y|$ ， $\lim_{\substack{x \to 0 \\ y \to 0}} \frac{f(x, y)}{|x| + |y|} = 1$ ，因为 $\lim_{x \to 0} \frac{f(x, 0) - f(0, 0)}{x} = \lim_{x \to 0} \frac{|x|}{x}$ 不存在，所以 $f(x, y)$ 在 $(0, 0)$ 处对 $x$ 不可偏导，由对称性， $f(x, y)$ 在 $(0, 0)$ 处对 $y$ 也不可偏导，于是 $f(x, y)$ 在 $(0, 0)$ 处不可微，（A）不对；

取 $f(x,y) = x$ ，显然 $f(x,y)$ 在(0，0）处可微，因为 $\lim_{x\to 0}\frac{f(x,0)}{|x|} = \lim_{x\to 0}\frac{x}{|x|}$ 不存在，所以 $\lim_{\substack{x\to 0\\ y\to 0}}\frac{f(x,y)}{|x| + |y|}$ 不存在，（C）不对；

取 $f(x,y) = xy$ ，因为 $f(x,y)$ 连续可偏导，所以 $f(x,y)$ 在(0,0)处可微，但 $\lim_{\substack{x\to 0\\ y\to 0}}\frac{f(x,y)}{x^2 + y^2}$ 不存在，（D）不对，应选(B).

方法点评：本题考查二元函数可微的判断. 判断二元函数 $f(x, y)$ 在点 $(x_0, y_0)$ 处可微一般有如下几个方法：

(1) 若 $f(x, y)$ 连续可偏导，则 $f(x, y)$ 在 $(x_0, y_0)$ 处可微；  
(2) 若 $\Delta z = f(x, y) - f(x_0, y_0) = A(x - x_0) + B(y - y_0) + o(\sqrt{(x - x_0)^2 + (y - y_0)^2})$ 则 $f(x, y)$ 在 $(x_0, y_0)$ 处可微；

(3) 若 $f(x, y)$ 在 $(x_0, y_0)$ 处可偏导，则 $f(x, y)$ 在 $(x_0, y_0)$ 处可微的充分必要条件是

$$
\lim  _ {x \rightarrow x _ {0} \atop y \rightarrow y _ {0}} \frac {f (x , y) - f (x _ {0} , y _ {0}) - f _ {x} ^ {\prime} (x _ {0} , y _ {0}) (x - x _ {0}) - f _ {y} ^ {\prime} (x _ {0} , y _ {0}) (y - y _ {0})}{\rho} = 0,
$$

其中 $\rho = \sqrt{(x - x_0)^2 + (y - y_0)^2}$', 'E:\数学自用\数据资料\真题\按年份整理\2012\解析\2012年解析.md', 'ok', 'year_question_no', 0.367, '2012:3', 3, 0.367);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2012_main_q04', 'math1', 2012, '真题', 'main', 4, '(4) 设 $I_{k} = \int_{0}^{k\pi}\mathrm{e}^{x^{2}}\sin x\mathrm{d}x(k = 1,2,3)$ , 则有( )

(A) $I_{1} < I_{2} < I_{3}$ .

(B) $I_{3} < I_{2} < I_{1}$ .

(C) $I_{2} < I_{3} < I_{1}$ .

(D) $I_{2} < I_{1} < I_{3}$ .', 'E:\数学自用\数据资料\真题\按年份整理\2012\按题拆分\真题\第04题\题目.md', '2012\按题拆分\真题\第04题\题目.md', 0, 'ok', '2012 真题 第4题 (4) 设 $i_{k} = \int_{0}^{k\pi}\mathrm{e}^{x^{2}}\sin x\mathrm{d}x(k = 1,2,3)$ , 则有( )

(a) $i_{1} < i_{2} < i_{3}$ .

(b) $i_{3} < i_{2} < i_{1}$ .

(c) $i_{2} < i_{3} < i_{1}$ .

(d) $i_{2} < i_{1} < i_{3}$ .');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2012_main_q04', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2012_main_q04', 'math1_2012_main_q04', 2012, 4, 4, 4, '（4）【答案】 (D).

【解】 由 $I_{2} - I_{1} = \int_{\pi}^{2\pi}\mathrm{e}^{x^{2}}\sin x\mathrm{d}x <   0$ ，得 $I_{1} > I_{2}$

由 $I_{3} - I_{2} = \int_{2\pi}^{3\pi}\mathrm{e}^{x^{2}}\sin x\mathrm{d}x > 0$ ，得 $I_{2} <   I_{3}$

$$
I _ {3} - I _ {1} = \int_ {\pi} ^ {3 \pi} \mathrm {e} ^ {x ^ {2}} \sin x \mathrm {d} x = \int_ {\pi} ^ {2 \pi} \mathrm {e} ^ {x ^ {2}} \sin x \mathrm {d} x + \int_ {2 \pi} ^ {3 \pi} \mathrm {e} ^ {x ^ {2}} \sin x \mathrm {d} x,
$$

而 $\int_{2\pi}^{3\pi}\mathrm{e}^{x^2}\sin x\mathrm{d}x = \int_{\pi}^{2\pi}\mathrm{e}^{(t + \pi)^2}\sin (t + \pi)\mathrm{d}t = -\int_{\pi}^{2\pi}\mathrm{e}^{(x + \pi)^2}\sin x\mathrm{d}x,$

由 $I_{3} - I_{1} = \int_{\pi}^{2\pi}\left[\mathrm{e}^{x^{2}} - \mathrm{e}^{(x + \pi)^{2}}\right]\sin x\mathrm{d}x > 0$ ，得 $I_{1} < I_{3}$ ，于是 $I_{2} < I_{1} < I_{3}$ ，应选(D).', 'E:\数学自用\数据资料\真题\按年份整理\2012\解析\2012年解析.md', 'ok', 'year_question_no', 0.351, '2012:4', 4, 0.351);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2012_main_q05', 'math1', 2012, '真题', 'main', 5, '(5) 设 $\pmb{\alpha}_{1} = \begin{pmatrix} 0 \\ 0 \\ c_{1} \end{pmatrix}, \pmb{\alpha}_{2} = \begin{pmatrix} 0 \\ 1 \\ c_{2} \end{pmatrix}, \pmb{\alpha}_{3} = \begin{pmatrix} 1 \\ -1 \\ c_{3} \end{pmatrix}, \pmb{\alpha}_{4} = \begin{pmatrix} -1 \\ 1 \\ c_{4} \end{pmatrix}$ , 其中 $c_{1}, c_{2}, c_{3}, c_{4}$ 为任意常数, 则下列向量组线性相关的为( )

(A) $\alpha_{1}, \alpha_{2}, \alpha_{3}$ .

(B) $\pmb{\alpha}_{1}, \pmb{\alpha}_{2}, \pmb{\alpha}_{4}$ .

(C) $\alpha_{1}, \alpha_{3}, \alpha_{4}$ .

(D) $\alpha_{2}, \alpha_{3}, \alpha_{4}$ .', 'E:\数学自用\数据资料\真题\按年份整理\2012\按题拆分\真题\第05题\题目.md', '2012\按题拆分\真题\第05题\题目.md', 0, 'ok', '2012 真题 第5题 (5) 设 $\pmb{\alpha}_{1} = \begin{pmatrix} 0 \\ 0 \\ c_{1} \end{pmatrix}, \pmb{\alpha}_{2} = \begin{pmatrix} 0 \\ 1 \\ c_{2} \end{pmatrix}, \pmb{\alpha}_{3} = \begin{pmatrix} 1 \\ -1 \\ c_{3} \end{pmatrix}, \pmb{\alpha}_{4} = \begin{pmatrix} -1 \\ 1 \\ c_{4} \end{pmatrix}$ , 其中 $c_{1}, c_{2}, c_{3}, c_{4}$ 为任意常数, 则下列向量组线性相关的为( )

(a) $\alpha_{1}, \alpha_{2}, \alpha_{3}$ .

(b) $\pmb{\alpha}_{1}, \pmb{\alpha}_{2}, \pmb{\alpha}_{4}$ .

(c) $\alpha_{1}, \alpha_{3}, \alpha_{4}$ .

(d) $\alpha_{2}, \alpha_{3}, \alpha_{4}$ .');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2012_main_q05', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2012_main_q05', 'math1_2012_main_q05', 2012, 5, 5, 5, '（5）【答案】 (C).

【解】方法一 $\pmb{\alpha}_{3} + \pmb{\alpha}_{4} = \binom{0}{c_{3} + c_{4}}$ ，因为 $\pmb{\alpha}_{3} + \pmb{\alpha}_{4}$ 与 $\pmb{\alpha}_{1}$ 成比例，所以 $\pmb{\alpha}_{1},\pmb{\alpha}_{3} + \pmb{\alpha}_{4}$ 线性相关，故 $\pmb{\alpha}_{1},\pmb{\alpha}_{3},\pmb{\alpha}_{4}$ 线性相关，应选(C).

方法二 因为 $|\pmb{\alpha}_1, \pmb{\alpha}_3, \pmb{\alpha}_4| = \left| \begin{array}{ccc} 0 & 1 & -1 \\ 0 & -1 & 1 \\ c_1 & c_3 & c_4 \end{array} \right| = 0$ ，所以 $\pmb{\alpha}_1, \pmb{\alpha}_3, \pmb{\alpha}_4$ 线性相关，应选(C).', 'E:\数学自用\数据资料\真题\按年份整理\2012\解析\2012年解析.md', 'ok', 'year_question_no', 0.107, '2012:5', 21, 0.147);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2012_main_q06', 'math1', 2012, '真题', 'main', 6, '(6) 设 $A$ 为3阶矩阵， $P$ 为3阶可逆矩阵，且 $P^{-1}AP = \begin{pmatrix} 1 & 0 & 0 \\ 0 & 1 & 0 \\ 0 & 0 & 2 \end{pmatrix}$ . 若 $P = (\alpha_{1},\alpha_{2},\alpha_{3})$ ， $Q = (\alpha_{1} + \alpha_{2},\alpha_{2},\alpha_{3})$ ，则 $Q^{-1}AQ = (\quad)$

(A) $\left( \begin{array}{lll}1 & 0 & 0\\ 0 & 2 & 0\\ 0 & 0 & 1 \end{array} \right)$

(B) $\left( \begin{array}{lll}1 & 0 & 0\\ 0 & 1 & 0\\ 0 & 0 & 2 \end{array} \right)$

(C) $\left( \begin{array}{lll}2 & 0 & 0\\ 0 & 1 & 0\\ 0 & 0 & 2 \end{array} \right)$

(D) $\left( \begin{array}{lll}2 & 0 & 0\\ 0 & 2 & 0\\ 0 & 0 & 1 \end{array} \right)$', 'E:\数学自用\数据资料\真题\按年份整理\2012\按题拆分\真题\第06题\题目.md', '2012\按题拆分\真题\第06题\题目.md', 0, 'ok', '2012 真题 第6题 (6) 设 $a$ 为3阶矩阵， $p$ 为3阶可逆矩阵，且 $p^{-1}ap = \begin{pmatrix} 1 & 0 & 0 \\ 0 & 1 & 0 \\ 0 & 0 & 2 \end{pmatrix}$ . 若 $p = (\alpha_{1},\alpha_{2},\alpha_{3})$ ， $q = (\alpha_{1} + \alpha_{2},\alpha_{2},\alpha_{3})$ ，则 $q^{-1}aq = (\quad)$

(a) $\left( \begin{array}{lll}1 & 0 & 0\\ 0 & 2 & 0\\ 0 & 0 & 1 \end{array} \right)$

(b) $\left( \begin{array}{lll}1 & 0 & 0\\ 0 & 1 & 0\\ 0 & 0 & 2 \end{array} \right)$

(c) $\left( \begin{array}{lll}2 & 0 & 0\\ 0 & 1 & 0\\ 0 & 0 & 2 \end{array} \right)$

(d) $\left( \begin{array}{lll}2 & 0 & 0\\ 0 & 2 & 0\\ 0 & 0 & 1 \end{array} \right)$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2012_main_q06', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2012_main_q06', 'math1_2012_main_q06', 2012, 6, 6, 6, '（6）【答案】 (B).

【解】 由 $Q = (\pmb{\alpha}_1 + \pmb{\alpha}_2, \pmb{\alpha}_2, \pmb{\alpha}_3) = \pmb{P} \begin{pmatrix} 1 & 0 & 0 \\ 1 & 1 & 0 \\ 0 & 0 & 1 \end{pmatrix}$ ,

得 $Q^{-1}AQ = \begin{pmatrix} 1 & 0 & 0\\ 1 & 1 & 0\\ 0 & 0 & 1 \end{pmatrix} ^{-1}\pmb{P}^{-1}\pmb {A}\pmb {P}\begin{pmatrix} 1 & 0 & 0\\ 1 & 1 & 0\\ 0 & 0 & 1 \end{pmatrix}$

$$
= \left( \begin{array}{c c c} 1 & 0 & 0 \\ - 1 & 1 & 0 \\ 0 & 0 & 1 \end{array} \right) \left( \begin{array}{c c c} 1 & 0 & 0 \\ 0 & 1 & 0 \\ 0 & 0 & 2 \end{array} \right) \left( \begin{array}{c c c} 1 & 0 & 0 \\ 1 & 1 & 0 \\ 0 & 0 & 1 \end{array} \right) = \left( \begin{array}{c c c} 1 & 0 & 0 \\ 0 & 1 & 0 \\ 0 & 0 & 2 \end{array} \right),
$$

应选(B).', 'E:\数学自用\数据资料\真题\按年份整理\2012\解析\2012年解析.md', 'ok', 'year_question_no', 0.377, '2012:6', 6, 0.377);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2012_main_q07', 'math1', 2012, '真题', 'main', 7, '(7) 设随机变量 $X$ 与 $Y$ 相互独立, 且分别服从参数为 1 与参数为 4 的指数分布, 则 $P\{X < Y\} = (\quad)$

(A) $\frac{1}{5}$ .

(B) $\frac{1}{3}$ .

(C) $\frac{2}{3}$ .

(D) $\frac{4}{5}$ .', 'E:\数学自用\数据资料\真题\按年份整理\2012\按题拆分\真题\第07题\题目.md', '2012\按题拆分\真题\第07题\题目.md', 0, 'ok', '2012 真题 第7题 (7) 设随机变量 $x$ 与 $y$ 相互独立, 且分别服从参数为 1 与参数为 4 的指数分布, 则 $p\{x < y\} = (\quad)$

(a) $\frac{1}{5}$ .

(b) $\frac{1}{3}$ .

(c) $\frac{2}{3}$ .

(d) $\frac{4}{5}$ .');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2012_main_q07', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2012_main_q07', 'math1_2012_main_q07', 2012, 7, 7, 7, '（7）【答案】 （A).

【解】 $X$ 的密度函数为 $f_{X}(x) = \left\{ \begin{array}{ll}\mathrm{e}^{-x}, & x > 0,\\ 0, & x\leqslant 0; \end{array} \right.$

$Y$ 的密度函数为 $f_{Y}(y) = \left\{ \begin{array}{ll}4\mathrm{e}^{-4y}, & y > 0,\\ 0, & y\leqslant 0. \end{array} \right.$

因为 $X, Y$ 独立，所以 $X, Y$ 的联合密度为

$$
f (x  , y) = f _ {X} (x) f _ {Y} (y) = \left\{ \begin{array}{l l} 4 \mathrm {e} ^ {- (x + 4 y)}  , & x > 0, y > 0, \\ 0, & \text {其 他}, \end{array} \right.
$$

于是 $P\{X < Y\} = \iint_{x < y} f(x, y) \, \mathrm{d}x \, \mathrm{d}y = \int_{0}^{+\infty} \mathrm{e}^{-x} \, \mathrm{d}x \int_{x}^{+\infty} 4 \mathrm{e}^{-4y} \, \mathrm{d}y = \int_{0}^{+\infty} \mathrm{e}^{-5x} \, \mathrm{d}x = \frac{1}{5}$ ,

应选(A).', 'E:\数学自用\数据资料\真题\按年份整理\2012\解析\2012年解析.md', 'ok', 'year_question_no', 0.022, '2012:7', 23, 0.067);
