INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2014_main_q08', 'math1_2014_main_q08', 2014, 8, 8, 8, '(8)【答案】 (D).

【解】 $E(Y_{1}) = \frac{1}{2}\int_{-\infty}^{+\infty}y[f_{1}(y) + f_{2}(y)]\mathrm{d}y = \frac{1}{2} [E(X_{1}) + E(X_{2})]$

[ E(Y_{2}) = \frac{1}{2} [E(X_{1}) + E(X_{2})] ]，显然 $E(Y_{1}) = E(Y_{2})$

$$
E \left(Y _ {1} ^ {2}\right) = \frac {1}{2} \int_ {- \infty} ^ {+ \infty} y ^ {2} \left[ f _ {1} (y) + f _ {2} (y) \right] d y = \frac {1}{2} \left[ E \left(X _ {1} ^ {2}\right) + E \left(X _ {2} ^ {2}\right) \right],
$$

$$
\begin{array}{l} D \left(Y _ {1}\right) = \frac {1}{2} \left[ E \left(X _ {1} ^ {2}\right) + E \left(X _ {2} ^ {2}\right) \right] - \frac {1}{4} \left[ E \left(X _ {1}\right) \right] ^ {2} - \frac {1}{4} \left[ E \left(X _ {2}\right) \right] ^ {2} - \frac {1}{2} E \left(X _ {1}\right) E \left(X _ {2}\right) \\ = \frac {1}{4} D \left(X _ {1}\right) + \frac {1}{4} D \left(X _ {2}\right) + \frac {1}{4} \left[ E \left(X _ {1} ^ {2}\right) + E \left(X _ {2} ^ {2}\right) \right] - \frac {1}{2} E \left(X _ {1}\right) E \left(X _ {2}\right), \\ = \frac {1}{4} D \left(X _ {1}\right) + \frac {1}{4} D \left(X _ {2}\right) + \frac {1}{4} E \left(X _ {1} - X _ {2}\right) ^ {2}, \\ \end{array}
$$

[ D(Y_{2}) = \frac{1}{4} [D(X_{1}) + D(X_{2})] ]，显然 $D(Y_{1}) > D(Y_{2})$ ，应选(D).

# 二、填空题', 'E:\数学自用\数据资料\真题\按年份整理\2014\解析\2014年解析.md', 'ok', 'year_question_no', 0.169, '2014:8', 8, 0.169);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2014_main_q09', 'math1', 2014, '真题', 'main', 9, '(9)曲面 $z = x^{2}(1 - \sin y) + y^{2}(1 - \sin x)$ 在点(1,0,1)处的切平面方程为', 'E:\数学自用\数据资料\真题\按年份整理\2014\按题拆分\真题\第09题\题目.md', '2014\按题拆分\真题\第09题\题目.md', 0, 'ok', '2014 真题 第9题 (9)曲面 $z = x^{2}(1 - \sin y) + y^{2}(1 - \sin x)$ 在点(1,0,1)处的切平面方程为');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2014_main_q09', 'math1_2014_main_q09', 2014, 9, 9, 9, '(9)【答案】 $2x - y - z - 1 = 0.$

【解】 $F = x^{2}(1 - \sin y) + y^{2}(1 - \sin x) - z$

$$
\boldsymbol {n} = (2 x (1 - \sin y) - y ^ {2} \cos x, 2 y (1 - \sin x) - x ^ {2} \cos y, - 1),
$$

在点 $(1,0,1)$ 处的法向量为 $n = (2, - 1, - 1)$ ，切平面为

$$
\pi : 2 (x - 1) - y - (z - 1) = 0 \text {, 即} 2 x - y - z - 1 = 0.
$$', 'E:\数学自用\数据资料\真题\按年份整理\2014\解析\2014年解析.md', 'ok', 'year_question_no', 0.522, '2014:9', 9, 0.522);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2014_main_q10', 'math1', 2014, '真题', 'main', 10, '(10) 设 $f(x)$ 是周期为 4 的可导奇函数, 且 $f''(x) = 2(x - 1), x \in [0, 2]$ , 则 $f(7) =$ ________.', 'E:\数学自用\数据资料\真题\按年份整理\2014\按题拆分\真题\第10题\题目.md', '2014\按题拆分\真题\第10题\题目.md', 0, 'ok', '2014 真题 第10题 (10) 设 $f(x)$ 是周期为 4 的可导奇函数, 且 $f''(x) = 2(x - 1), x \in [0, 2]$ , 则 $f(7) =$ ________.');
