INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2014_main_q14', 'math1_2014_main_q14', 2014, 14, 14, 14, '(14)【答案】 $\frac{2}{5n}$ .

【解】 $E(X^{2}) = \frac{2}{3\theta^{2}}\int_{\theta}^{2\theta}x^{3}\mathrm{d}x = \frac{5}{2}\theta^{2},$

由 $E\left(c\sum_{i = 1}^{n}X_{i}^{2}\right) = \frac{5nc}{2}\theta^{2} = \theta^{2}$ ，得 $c = \frac{2}{5n}$

# 三、解答题', 'E:\数学自用\数据资料\真题\按年份整理\2014\解析\2014年解析.md', 'ok', 'year_question_no', 0.08, '2014:14', 23, 0.22);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2014_main_q15', 'math1', 2014, '真题', 'main', 15, '(15)(本题满分10分)

求极限 $\lim_{x\to +\infty}\frac{\int_1^x[t^2(\mathrm{e}^{\frac{1}{t}} - 1) - t]\mathrm{d}t}{x^2\ln\left(1 + \frac{1}{x}\right)}.$', 'E:\数学自用\数据资料\真题\按年份整理\2014\按题拆分\真题\第15题\题目.md', '2014\按题拆分\真题\第15题\题目.md', 0, 'ok', '2014 真题 第15题 (15)(本题满分10分)

求极限 $\lim_{x\to +\infty}\frac{\int_1^x[t^2(\mathrm{e}^{\frac{1}{t}} - 1) - t]\mathrm{d}t}{x^2\ln\left(1 + \frac{1}{x}\right)}.$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2014_main_q15', 'tag_极限');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2014_main_q15', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2014_main_q15', 'math1_2014_main_q15', 2014, 15, 15, 15, '（15）【解】 方法一

$$
\begin{array}{l} \lim  _ {x \rightarrow + \infty} \frac {\int_ {1} ^ {x} \left[ t ^ {2} \left(\mathrm {e} ^ {\frac {1}{t}} - 1\right) - t \right] \mathrm {d} t}{x ^ {2} \ln \left(1 + \frac {1}{x}\right)} = \lim  _ {x \rightarrow + \infty} \frac {\int_ {1} ^ {x} \left[ t ^ {2} \left(\mathrm {e} ^ {\frac {1}{t}} - 1\right) - t \right] \mathrm {d} t}{x} \cdot \frac {\frac {1}{x}}{\ln \left(1 + \frac {1}{x}\right)} \\ = \lim  _ {x \rightarrow + \infty} \frac {\int_ {1} ^ {x} \left[ t ^ {2} \left(\mathrm {e} ^ {\frac {1}{t}} - 1\right) - t \right] \mathrm {d} t}{x} = \lim  _ {x \rightarrow + \infty} \left[ x ^ {2} \left(\mathrm {e} ^ {\frac {1}{x}} - 1\right) - x \right] \\ = \lim  _ {x \rightarrow + \infty} x ^ {2} \left(\mathrm {e} ^ {\frac {1}{x}} - 1 - \frac {1}{x}\right) ^ {\frac {1}{x} = t} = \lim  _ {t \rightarrow 0} \frac {\mathrm {e} ^ {t} - 1 - t}{t ^ {2}} = \lim  _ {t \rightarrow 0} \frac {\mathrm {e} ^ {t} - 1}{2 t} = \frac {1}{2}. \\ \end{array}
$$

方法二

$$
\begin{array}{l} \lim  _ {x \rightarrow + \infty} \frac {\int_ {1} ^ {x} \left[ t ^ {2} \left(\mathrm {e} ^ {\frac {1}{t}} - 1\right) - t \right] \mathrm {d} t}{x ^ {2} \ln \left(1 + \frac {1}{x}\right)} = \lim  _ {x \rightarrow + \infty} \frac {\int_ {1} ^ {x} \left[ t ^ {2} \left(\mathrm {e} ^ {\frac {1}{t}} - 1\right) - t \right] \mathrm {d} t}{x} \\ = \lim  _ {x \rightarrow + \infty} \left[ x ^ {2} \left(\mathrm {e} ^ {\frac {1}{x}} - 1\right) - x \right] = \lim  _ {x \rightarrow + \infty} \left[ x ^ {2} \left(\frac {1}{x} + \frac {1}{2 x ^ {2}} + o \left(\frac {1}{x ^ {2}}\right)\right) - x \right] \\ = \lim  _ {x \rightarrow + \infty} x ^ {2} \left[ \frac {1}{2 x ^ {2}} + o \left(\frac {1}{x ^ {2}}\right)\right] = \frac {1}{2}. \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\2014\解析\2014年解析.md', 'ok', 'year_question_no', 0.556, '2014:15', 15, 0.556);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2014_main_q16', 'math1', 2014, '真题', 'main', 16, '(16)(本题满分 10 分)

设函数 $y = f(x)$ 由方程 $y^{3} + xy^{2} + x^{2}y + 6 = 0$ 确定，求 $f(x)$ 的极值.', 'E:\数学自用\数据资料\真题\按年份整理\2014\按题拆分\真题\第16题\题目.md', '2014\按题拆分\真题\第16题\题目.md', 0, 'ok', '2014 真题 第16题 (16)(本题满分 10 分)

设函数 $y = f(x)$ 由方程 $y^{3} + xy^{2} + x^{2}y + 6 = 0$ 确定，求 $f(x)$ 的极值.');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2014_main_q16', 'math1_2014_main_q16', 2014, 16, 16, 16, '(16)【解】 $y^{3} + xy^{2} + x^{2}y + 6 = 0$ 两边对 $x$ 求导得

$$
3 y ^ {2} \frac {\mathrm {d} y}{\mathrm {d} x} + y ^ {2} + 2 x y \frac {\mathrm {d} y}{\mathrm {d} x} + 2 x y + x ^ {2} \frac {\mathrm {d} y}{\mathrm {d} x} = 0,
$$

令 $\frac{\mathrm{dy}}{\mathrm{dx}} = 0$ 得 $y = -2x$ 或 $y = 0$ （不适合原方程，舍去），

将 $y = -2x$ 代入原方程得 $\left\{ \begin{array}{l} x = 1, \\ y = -2. \end{array} \right.$

$3y^{2}\frac{\mathrm{dy}}{\mathrm{dx}} +y^{2} + 2xy\frac{\mathrm{dy}}{\mathrm{dx}} +2xy + x^{2}\frac{\mathrm{dy}}{\mathrm{dx}} = 0$ 两边再对 $x$ 求导整理得

$$
\left(3 y ^ {2} + 2 x y + x ^ {2}\right) y ^ {\prime \prime} + 2 (x + 3 y) y ^ {\prime 2} + 4 (x + y) y ^ {\prime} + 2 y = 0,
$$

将 $\left\{ \begin{array}{l}x = 1,\\ y = -2 \end{array} \right.$ 代入得 $\frac{\mathrm{d}^2y}{\mathrm{d}x^2} = \frac{4}{9} >0$ 故 $x = 1$ 为函数 $y = f(x)$ 极小值点，极小值为 $y = -2$', 'E:\数学自用\数据资料\真题\按年份整理\2014\解析\2014年解析.md', 'ok', 'year_question_no', 0.324, '2014:16', 16, 0.324);
