INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2014_main_q18', 'math1_2014_main_q18', 2014, 18, 18, 18, '(18)【解】方法一 令 $\Sigma_0: z = 1(x^2 + y^2 \leqslant 1)$ ，取下侧，其中 $\Sigma$ 与 $\Sigma_0$ 围成的几何体为 $\Omega$ ，由高斯公式得

$$
\iint_ {\Sigma + \Sigma_ {0}} (x - 1) ^ {3} d y d z + (y - 1) ^ {3} d z d x + (z - 1) d x d y = - \iiint_ {\Omega} [ 3 (x - 1) ^ {2} + 3 (y - 1) ^ {2} + 1 ] d v
$$

由三重积分的对称性与奇偶性性质得 $\iiint_{\Omega} x \, \mathrm{d}v = 0$ ， $\iiint_{\Omega} y \, \mathrm{d}v = 0$

从而 $I = -\iiint_{\Omega} [3(x^2 + y^2) - 6x - 6y + 7] \, \mathrm{d}v = -\iiint_{\Omega} [3(x^2 + y^2) + 7] \, \mathrm{d}v$

$$
\begin{array}{l} = - \int_ {0} ^ {1} d z \iint_ {x ^ {2} + y ^ {2} \leqslant z} [ 3 (x ^ {2} + y ^ {2}) + 7 ] d v = - \int_ {0} ^ {1} d z \int_ {0} ^ {2 \pi} d \theta \int_ {0} ^ {\sqrt {z}} (3 r ^ {3} + 7 r) d r \\ = - 2 \pi \int_ {0} ^ {1} \left(\frac {3}{4} z ^ {2} + \frac {7}{2} z\right) d z = - 2 \pi \left(\frac {1}{4} + \frac {7}{4}\right) = - 4 \pi , \\ \end{array}
$$

由于 $\iint_{\Sigma_0}(x - 1)^3\mathrm{d}y\mathrm{d}z + (y - 1)^3\mathrm{d}z\mathrm{d}x + (z - 1)\mathrm{d}x\mathrm{d}y = \iint_{\Sigma_0}(z - 1)\mathrm{d}x\mathrm{d}y = 0,$

故 $I = \iint_{\Sigma}(x - 1)^{3}\mathrm{d}y\mathrm{d}z + (y - 1)^{3}\mathrm{d}z\mathrm{d}x + (z - 1)\mathrm{d}x\mathrm{d}y = -4\pi .$

方法二 由 $z = x^2 + y^2$ 得 $\frac{\partial z}{\partial x} = 2x, \frac{\partial z}{\partial y} = 2y$ ，曲面的法向量为 $\pmb{n} = (-2x, -2y, 1)$ ，

$$
\cos \alpha = - \frac {2 x}{\sqrt {1 + 4 x ^ {2} + 4 y ^ {2}}}, \cos \beta = - \frac {2 y}{\sqrt {1 + 4 x ^ {2} + 4 y ^ {2}}}, \cos \gamma = - \frac {1}{\sqrt {1 + 4 x ^ {2} + 4 y ^ {2}}},
$$

$$
\mathrm {d} y \mathrm {d} z = \cos \alpha \mathrm {d} S = \frac {\cos \alpha}{\cos \gamma} \cdot \cos \gamma \mathrm {d} S = - 2 x \mathrm {d} x \mathrm {d} y,
$$

$$
\mathrm {d} z \mathrm {d} x = \cos \beta \mathrm {d} S = \frac {\cos \beta}{\cos \gamma} \cdot \cos \gamma \mathrm {d} S = - 2 y \mathrm {d} x \mathrm {d} y,
$$

令 $D = \{(x,y)\mid x^2 +y^2\leqslant 1\}$ ，则

$$
\begin{array}{l} I = \iint_ {\Sigma} \left[ (x - 1) ^ {3} (- 2 x) + (y - 1) ^ {3} (- 2 y) + (z - 1) \right] d x d y \\ = \iint_ {D} \left[ (x - 1) ^ {3} (- 2 x) + (y - 1) ^ {3} (- 2 y) + (x ^ {2} + y ^ {2} - 1) \right] d x d y \\ = \iint_ {D} (- 2 x ^ {4} - 2 y ^ {4} - 5 x ^ {2} - 5 y ^ {2} - 1) d x d y \\ = - \int_ {0} ^ {2 \pi} d \theta \int_ {0} ^ {1} (2 r ^ {5} \cos^ {4} \theta + 2 r ^ {5} \sin^ {4} \theta + 5 r ^ {3} + r) d r \\ = - \int_ {0} ^ {2 \pi} \left(\frac {1}{3} \cos^ {4} \theta + \frac {1}{3} \sin^ {4} \theta + \frac {5}{4} + \frac {1}{2}\right) d \theta \\ = - \frac {8}{3} I _ {4} - \frac {5 \pi}{2} - \pi = - 4 \pi . \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\2014\解析\2014年解析.md', 'ok', 'year_question_no', 0.468, '2014:18', 18, 0.468);
