INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2016_main_q18', 'math1_2016_main_q18', 2016, 18, 18, 18, '（18）【解】由高斯公式得 $I = \iint_{\Sigma}(x^{2} + 1)\mathrm{d}y\mathrm{d}z - 2y\mathrm{d}z\mathrm{d}x + 3z\mathrm{d}x\mathrm{d}y = \iiint_{\Omega}(2x + 1)\mathrm{d}v,$

而 $\iiint_{\Omega} \mathrm{d}v = \frac{1}{3} \times \frac{1}{2} \times 2 \times 1 \times 1 = \frac{1}{3}$ ,

$$
\begin{array}{l} \iiint_ {\Omega} x \mathrm {d} v = \int_ {0} ^ {1} x \mathrm {d} x \int_ {0} ^ {2 (1 - x)} \mathrm {d} y \int_ {0} ^ {1 - x - \frac {y}{2}} \mathrm {d} z = \int_ {0} ^ {1} x \mathrm {d} x \int_ {0} ^ {2 (1 - x)} \left(1 - x - \frac {y}{2}\right) \mathrm {d} y \\ = \int_ {0} ^ {1} x (1 - x) ^ {2} d x = \frac {1}{1 2}, \\ \end{array}
$$

故 $I = \frac{1}{3} +2\times \frac{1}{12} = \frac{1}{2}$', 'E:\数学自用\数据资料\真题\按年份整理\2016\解析\2016年解析.md', 'ok', 'year_question_no', 0.274, '2016:18', 18, 0.274);
