INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2016_main_q21', 'math1_2016_main_q21', 2016, 21, 21, 21, '（21）【解】（I）由 $|\lambda E - A| = \left| \begin{array}{ccc}\lambda & 1 & -1\\ -2 & \lambda +3 & 0\\ 0 & 0 & \lambda \end{array} \right| = \lambda (\lambda +1)(\lambda +2) = 0$ 得

矩阵 $\mathbf{A}$ 的特征值为 $\lambda_{1} = -1, \lambda_{2} = -2, \lambda_{3} = 0$

将 $\lambda_{1} = -1$ 代入 $(\lambda E - A)X = 0$ ，由 $-E - A = \begin{pmatrix} -1 & 1 & -1 \\ -2 & 2 & 0 \\ 0 & 0 & -1 \end{pmatrix} \rightarrow \begin{pmatrix} 1 & -1 & 0 \\ 0 & 0 & 1 \\ 0 & 0 & 0 \end{pmatrix}$ 得 $\lambda_{1} = -1$ 对

应的特征向量为 $\xi_{1} = \begin{pmatrix} 1 \\ 1 \\ 0 \end{pmatrix}$

将 $\lambda_{2} = -2$ 代入 $(\lambda E - A)X = 0$ ，由 $-2E - A = \begin{pmatrix} -2 & 1 & -1 \\ -2 & 1 & 0 \\ 0 & 0 & -2 \end{pmatrix} \rightarrow \begin{bmatrix} 1 & -\frac{1}{2} & 0 \\ 0 & 0 & 1 \\ 0 & 0 & 0 \end{bmatrix}$ 得

$\lambda_{2} = -2$ 对应的特征向量为 $\xi_{2} = \begin{pmatrix} 1 \\ 2 \\ 0 \end{pmatrix}$

将 $\lambda_{3} = 0$ 代入 $(\lambda E - A)X = 0$ ，由 $-A = \begin{pmatrix} 0 & 1 & -1 \\ -2 & 3 & 0 \\ 0 & 0 & 0 \end{pmatrix} \rightarrow \begin{bmatrix} 1 & 0 & -\frac{3}{2} \\ 0 & 1 & -1 \\ 0 & 0 & 0 \end{bmatrix}$ 得 $\lambda_{3} = 0$ 对应

的特征向量为 $\xi_{3} = \begin{pmatrix} 3\\ 2\\ 2 \end{pmatrix} .$

令 $\pmb{P} = \begin{pmatrix} 1 & 1 & 3 \\ 1 & 2 & 2 \\ 0 & 0 & 2 \end{pmatrix}$ , 由 $\pmb{P}^{-1}\pmb{A}\pmb{P} = \begin{pmatrix} -1 & 0 & 0 \\ 0 & -2 & 0 \\ 0 & 0 & 0 \end{pmatrix}$ 得

$$
\begin{array}{l} \boldsymbol {A} ^ {9 9} = \boldsymbol {P} \left( \begin{array}{c c c} (- 1) ^ {9 9} & 0 & 0 \\ 0 & (- 2) ^ {9 9} & 0 \\ 0 & 0 & 0 \end{array} \right) \boldsymbol {P} ^ {- 1} = \left( \begin{array}{c c c} 1 & 1 & 3 \\ 1 & 2 & 2 \\ 0 & 0 & 2 \end{array} \right) \left( \begin{array}{c c c} (- 1) ^ {9 9} & 0 & 0 \\ 0 & (- 2) ^ {9 9} & 0 \\ 0 & 0 & 0 \end{array} \right) \left( \begin{array}{c c c} 2 & - 1 & - 2 \\ - 1 & 1 & \frac {1}{2} \\ 0 & 0 & \frac {1}{2} \end{array} \right) \\ = \left( \begin{array}{c c c} 2 ^ {9 9} - 2 & 1 - 2 ^ {9 9} & 2 - 2 ^ {9 8} \\ 2 ^ {1 0 0} - 2 & 1 - 2 ^ {1 0 0} & 2 - 2 ^ {9 9} \\ 0 & 0 & 0 \end{array} \right). \\ \end{array}
$$

（Ⅱ）由 $\pmb{B}^{2} = \pmb{BA}$ 得 $\pmb{B}^{100} = \pmb{B}^{98}\pmb{B}^{2} = \pmb{B}^{99}\pmb{A} = \dots = \pmb{BA}^{99}$

即 $(\pmb{\beta}_1, \pmb{\beta}_2, \pmb{\beta}_3) = (\pmb{\alpha}_1, \pmb{\alpha}_2, \pmb{\alpha}_3)\left( \begin{array}{ccc} 2^{99} - 2 & 1 - 2^{99} & 2 - 2^{98} \\ 2^{100} - 2 & 1 - 2^{100} & 2 - 2^{99} \\ 0 & 0 & 0 \end{array} \right),$

$\begin{array}{l}\pmb {\beta}_1 = (2^{99} - 2)\pmb {\alpha}_1 + (2^{100} - 2)\pmb {\alpha}_2 + 0\pmb {\alpha}_3,\\ \pmb {\beta}_2 = (1 - 2^{99})\pmb {\alpha}_1 + (1 - 2^{100})\pmb {\alpha}_2 + 0\pmb {\alpha}_3,\\ \pmb {\beta}_3 = (2 - 2^{98})\pmb {\alpha}_1 + (2 - 2^{99})\pmb {\alpha}_2 + 0\pmb {\alpha}_3. \end{array}$ 故', 'E:\数学自用\数据资料\真题\按年份整理\2016\解析\2016年解析.md', 'ok', 'year_question_no', 0.338, '2016:21', 21, 0.338);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2016_main_q22', 'math1', 2016, '真题', 'main', 22, '(22) (本题满分 11 分)

设二维随机变量 $(X,Y)$ 在区域 $D = \{(x,y) \mid 0 < x < 1, x^2 < y < \sqrt{x}\}$ 上服从均匀分布，令 $U = \left\{ \begin{array}{ll} 1, & X \leqslant Y, \\ 0, & X > Y. \end{array} \right.$

(I) 写出 $(X, Y)$ 的概率密度;  
（Ⅱ）问 $U$ 与 $X$ 是否相互独立？并说明理由；  
（Ⅲ）求 $Z = U + X$ 的分布函数 $F(z)$', 'E:\数学自用\数据资料\真题\按年份整理\2016\按题拆分\真题\第22题\题目.md', '2016\按题拆分\真题\第22题\题目.md', 0, 'ok', '2016 真题 第22题 (22) (本题满分 11 分)

设二维随机变量 $(x,y)$ 在区域 $d = \{(x,y) \mid 0 < x < 1, x^2 < y < \sqrt{x}\}$ 上服从均匀分布，令 $u = \left\{ \begin{array}{ll} 1, & x \leqslant y, \\ 0, & x > y. \end{array} \right.$

(i) 写出 $(x, y)$ 的概率密度;  
（ⅱ）问 $u$ 与 $x$ 是否相互独立？并说明理由；  
（ⅲ）求 $z = u + x$ 的分布函数 $f(z)$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2016_main_q22', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2016_main_q22', 'math1_2016_main_q22', 2016, 22, 22, 22, '（22）【解】（I）区域 $D$ 的面积为 $A = \int_{0}^{1}(\sqrt{x} -x^{2})\mathrm{d}x = \frac{2}{3} -\frac{1}{3} = \frac{1}{3},$

随机变量 $(X,Y)$ 的联合密度为 $f(x,y) = \left\{ \begin{array}{ll}3, & (x,y)\in D,\\ 0, & (x,y)\notin D. \end{array} \right.$

（Ⅱ）设 $(U,X)$ 的联合分布函数为 $G(u,x)$

$$
G \left(0, \frac {1}{2}\right) = P \left\{U \leqslant 0, X \leqslant \frac {1}{2} \right\} = P \left\{X > Y, X \leqslant \frac {1}{2} \right\} = \int_ {0} ^ {\frac {1}{2}} d x \int_ {x ^ {2}} ^ {x} 3 d y = \frac {1}{4},
$$

$$
P \{U \leqslant 0 \} = P \{X > Y \} = \int_ {0} ^ {1} \mathrm {d} x \int_ {x ^ {2}} ^ {x} 3 \mathrm {d} y = \frac {1}{2},
$$

$$
P \left\{X \leqslant \frac {1}{2} \right\} = \int_ {0} ^ {\frac {1}{2}} d x \int_ {x ^ {2}} ^ {\sqrt {x}} 3 d y = \frac {\sqrt {2}}{2} - \frac {1}{8},
$$

因为 $\frac{1}{4} \neq \frac{1}{2} \times \left(\frac{\sqrt{2}}{2} - \frac{1}{8}\right)$ , 所以 $U$ 与 $X$ 不独立.

（Ⅲ）当 $z < 0$ 时， $F(z) = 0$

当 $0 \leqslant z < 1$ 时，

$$
F (z) = P \{Z \leqslant z \} = P \{U = 0, X \leqslant z \} = P \{X > Y, X \leqslant z \} = \int_ {0} ^ {z} d x \int_ {x ^ {2}} ^ {x} 3 d y = \frac {3}{2} z ^ {2} - z ^ {3};
$$

当 $1 \leqslant z < 2$ 时，

$$
\begin{array}{l} F (z) = P \{U + X \leqslant z \} = P \{U = 0, X \leqslant z \} + P \{U = 1, X \leqslant z - 1 \} \\ = \frac {1}{2} + 2 (z - 1) ^ {\frac {3}{2}} - \frac {3}{2} (z - 1) ^ {2}; \\ \end{array}
$$

当 $z \geqslant 2$ 时， $F(z) = 1$

故 $F(z) = \left\{ \begin{array}{ll}0, & z <   0,\\ \frac{3}{2} z^2 -z^3, & 0\leqslant z <   1,\\ \frac{1}{2} +2(z - 1)^{\frac{3}{2}} - \frac{3}{2} (z - 1)^2, & 1\leqslant z <   2,\\ 1, & z\geqslant 2. \end{array} \right.$', 'E:\数学自用\数据资料\真题\按年份整理\2016\解析\2016年解析.md', 'ok', 'year_question_no', 0.225, '2016:22', 22, 0.225);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2016_main_q23', 'math1', 2016, '真题', 'main', 23, '(23) (本题满分 11 分)

设总体 $X$ 的概率密度为 $f(x;\theta) = \left\{ \begin{array}{ll} \frac{3x^2}{\theta^3}, & 0 < x < \theta, \\ 0, & \text{其他}, \end{array} \right.$ 其中 $\theta \in (0, +\infty)$ 为未知参数， $X_1, X_2, X_3$ 为来自总体 $X$ 的简单随机样本，令 $T = \max \{X_1, X_2, X_3\}$ .

(I)求 $T$ 的概率密度；  
（Ⅱ）确定 $a$ ，使得 $aT$ 为 $\theta$ 的无偏估计', 'E:\数学自用\数据资料\真题\按年份整理\2016\按题拆分\真题\第23题\题目.md', '2016\按题拆分\真题\第23题\题目.md', 0, 'ok', '2016 真题 第23题 (23) (本题满分 11 分)

设总体 $x$ 的概率密度为 $f(x;\theta) = \left\{ \begin{array}{ll} \frac{3x^2}{\theta^3}, & 0 < x < \theta, \\ 0, & \text{其他}, \end{array} \right.$ 其中 $\theta \in (0, +\infty)$ 为未知参数， $x_1, x_2, x_3$ 为来自总体 $x$ 的简单随机样本，令 $t = \max \{x_1, x_2, x_3\}$ .

(i)求 $t$ 的概率密度；  
（ⅱ）确定 $a$ ，使得 $at$ 为 $\theta$ 的无偏估计');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2016_main_q23', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2016_main_q23', 'math1_2016_main_q23', 2016, 23, 23, 23, '(23)【解】（I）总体 $X$ 的分布函数为 $F(x) = \int_{-\infty}^{x}f(t)\mathrm{d}t.$

当 $x < 0$ 时， $F(x) = 0$

当 $x \geqslant \theta$ 时， $F(x) = 1$

当 $0 \leqslant x < \theta$ 时， $F(x) = \int_{0}^{x} \frac{3x^2}{\theta^3} \, \mathrm{d}x = \frac{x^3}{\theta^3}$ ，

即 $F(x) = \left\{ \begin{array}{ll}0, & x <   0,\\ \frac{x^3}{\theta^3}, & 0\leqslant x <   \theta ,\\ 1, & x\geqslant \theta . \end{array} \right.$

设 $T$ 的分布函数为 $F_{T}(t)$ ，则

$$
\begin{array}{l} F _ {T} (t) = P \{T \leqslant t \} = P \{\max  \left\{X _ {1}, X _ {2}, X _ {3} \right\} \leqslant t \} \\ = P \left\{X _ {1} \leqslant t, X _ {2} \leqslant t, X _ {3} \leqslant t \right\} \\ = P \left\{X _ {1} \leqslant t \right\} P \left\{X _ {2} \leqslant t \right\} P \left\{X _ {3} \leqslant t \right\} \\ = P ^ {3} \{X \leqslant t \} = F ^ {3} (t) = \left\{ \begin{array}{l l} 0, & t <   0, \\ \frac {t ^ {9}}{\theta^ {9}}, & 0 \leqslant t <   \theta , \\ 1, & t \geqslant \theta . \end{array} \right. \\ \end{array}
$$

随机变量 $T$ 的概率密度为 $f_{T}(t) = \begin{cases} \frac{9t^{8}}{\theta^{9}}, & 0 < t < \theta, \\ 0, & \text{其他.} \end{cases}$

$(\mathrm{II})E(aT) = aE(T) = a\int_{0}^{\theta}t\cdot \frac{9t^{8}}{\theta^{9}}\mathrm{d}t = \frac{9a}{10}\theta ,$

由 $E(aT) = \theta$ 得 $a = \frac{10}{9}$ ，即当 $a = \frac{10}{9}$ 时， $aT$ 为参数 $\theta$ 的无偏估计.', 'E:\数学自用\数据资料\真题\按年份整理\2016\解析\2016年解析.md', 'ok', 'year_question_no', 0.341, '2016:23', 23, 0.341);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2017_main_q01', 'math1', 2017, '真题', 'main', 1, '(1) 若函数 $f(x) = \left\{ \begin{array}{ll} \frac{1 - \cos \sqrt{x}}{ax}, & x > 0, \\ b, & x \leqslant 0 \end{array} \right.$ ，在 $x = 0$ 处连续，则（ ）

(A) $ab = \frac{1}{2}$ .

(B) $ab = -\frac{1}{2}$ .

(C) $ab = 0$

(D) $ab = 2$', 'E:\数学自用\数据资料\真题\按年份整理\2017\按题拆分\真题\第01题\题目.md', '2017\按题拆分\真题\第01题\题目.md', 0, 'ok', '2017 真题 第1题 (1) 若函数 $f(x) = \left\{ \begin{array}{ll} \frac{1 - \cos \sqrt{x}}{ax}, & x > 0, \\ b, & x \leqslant 0 \end{array} \right.$ ，在 $x = 0$ 处连续，则（ ）

(a) $ab = \frac{1}{2}$ .

(b) $ab = -\frac{1}{2}$ .

(c) $ab = 0$

(d) $ab = 2$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2017_main_q01', 'tag_连续');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2017_main_q01', 'math1_2017_main_q01', 2017, 1, 1, 1, '(1)【答案】 (A).

【解】 $f(0 + 0) = \lim_{x\to 0^{+}}\frac{1 - \cos\sqrt{x}}{ax} = \frac{1}{2a},$ $f(0) = f(0 - 0) = b,$

因为 $f(x)$ 在 $x = 0$ 处连续，所以 $f(0 + 0) = f(0) = f(0 - 0)$

从而 $ab = \frac{1}{2}$ ，应选（A）.', 'E:\数学自用\数据资料\真题\按年份整理\2017\解析\2017年解析.md', 'ok', 'year_question_no', 0.178, '2017:1', 1, 0.178);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2017_main_q02', 'math1', 2017, '真题', 'main', 2, '(2) 设函数 $f(x)$ 可导, 且 $f(x)f''(x) > 0$ , 则( )

(A) $f(1) > f(-1)$ .

(B) $f(1) < f(-1)$ .

(C) $|f(1)| > |f(-1)|$ .

(D) $|f(1)| < |f(-1)|$ .', 'E:\数学自用\数据资料\真题\按年份整理\2017\按题拆分\真题\第02题\题目.md', '2017\按题拆分\真题\第02题\题目.md', 0, 'ok', '2017 真题 第2题 (2) 设函数 $f(x)$ 可导, 且 $f(x)f''(x) > 0$ , 则( )

(a) $f(1) > f(-1)$ .

(b) $f(1) < f(-1)$ .

(c) $|f(1)| > |f(-1)|$ .

(d) $|f(1)| < |f(-1)|$ .');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2017_main_q02', 'tag_导数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2017_main_q02', 'math1_2017_main_q02', 2017, 2, 2, 2, '(2)【答案】 (C).

【解】方法一 若 $f(x) > 0$ ，则 $f^{\prime}(x) > 0$ ，从而 $f(1) > f(-1) > 0$

若 $f(x) < 0$ ，则 $f^{\prime}(x) < 0$ ，从而 $f(1) < f(-1) < 0$

故 $|f(1)| > |f(-1)|$ ，应选(C).

方法二 由 $f(x) \cdot f''(x) = \left[\frac{1}{2} f^2(x)\right]'' > 0$ 得 $f^2(x)$ 单调递增，

从而 $f^2 (1) > f^2 (-1)$ ，故 $|f(1)| > |f(-1)|$ ，应选(C).', 'E:\数学自用\数据资料\真题\按年份整理\2017\解析\2017年解析.md', 'ok', 'year_question_no', 0.222, '2017:2', 2, 0.222);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2017_main_q03', 'math1', 2017, '真题', 'main', 3, '(3) 函数 $f(x, y, z) = x^{2}y + z^{2}$ 在点 $(1, 2, 0)$ 处沿向量 $\mathbf{n} = (1, 2, 2)$ 的方向导数为（）

(A)12.

(B)6.

(C)4.

(D)2.', 'E:\数学自用\数据资料\真题\按年份整理\2017\按题拆分\真题\第03题\题目.md', '2017\按题拆分\真题\第03题\题目.md', 0, 'ok', '2017 真题 第3题 (3) 函数 $f(x, y, z) = x^{2}y + z^{2}$ 在点 $(1, 2, 0)$ 处沿向量 $\mathbf{n} = (1, 2, 2)$ 的方向导数为（）

(a)12.

(b)6.

(c)4.

(d)2.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2017_main_q03', 'tag_导数');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2017_main_q03', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2017_main_q03', 'math1_2017_main_q03', 2017, 3, 3, 3, '(3)【答案】 (D).

【解】 $\frac{\partial f}{\partial x} = 2xy,\quad \frac{\partial f}{\partial y} = x^2,\quad \frac{\partial f}{\partial z} = 2z,$

$$
\left. \frac {\partial f}{\partial x} \right| _ {(1, 2, 0)} = 4, \quad \left. \frac {\partial f}{\partial y} \right| _ {(1, 2, 0)} = 1, \quad \left. \frac {\partial f}{\partial z} \right| _ {(1, 2, 0)} = 0,
$$

$$
\cos \alpha = \frac {1}{3}, \quad \cos \beta = \frac {2}{3}, \quad \cos \gamma = \frac {2}{3},
$$

所求的方向导数为 $\left.\frac{\partial f}{\partial\boldsymbol{n}}\right|_{(1,2,0)} = 4\times \frac{1}{3} +1\times \frac{2}{3} = 2$ ，应选(D).', 'E:\数学自用\数据资料\真题\按年份整理\2017\解析\2017年解析.md', 'ok', 'year_question_no', 0.158, '2017:3', 3, 0.158);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2017_main_q04', 'math1', 2017, '真题', 'main', 4, '(4) 甲、乙两人赛跑, 计时开始时, 甲在乙前方 10 (单位: $m$ ) 处, 图中, 实线表示甲的速度曲线

$v = v_{1}(t)$ (单位: $\mathrm{m} / \mathrm{s}$ ), 虚线表示乙的速度曲线 $v = v_{2}(t)$ , 三块阴影部分面积的数值依次是 10, 20, 3. 计时开始后乙追上甲的时刻记为 $t_{0}$ (单位: $\mathrm{s}$ ), 则( )

![](images/8e8f4df12e914f4ef16f2f4912ebc91d19101c0d902a3618f59ad880069238a3.jpg)

(A) $t_0 = 10$   
(B) $15 < t_{0} < 20$ .   
(C) $t_0 = 25$   
$(\mathrm{D})t_{0} > 25$', 'E:\数学自用\数据资料\真题\按年份整理\2017\按题拆分\真题\第04题\题目.md', '2017\按题拆分\真题\第04题\题目.md', 1, 'ok', '2017 真题 第4题 (4) 甲、乙两人赛跑, 计时开始时, 甲在乙前方 10 (单位: $m$ ) 处, 图中, 实线表示甲的速度曲线

$v = v_{1}(t)$ (单位: $\mathrm{m} / \mathrm{s}$ ), 虚线表示乙的速度曲线 $v = v_{2}(t)$ , 三块阴影部分面积的数值依次是 10, 20, 3. 计时开始后乙追上甲的时刻记为 $t_{0}$ (单位: $\mathrm{s}$ ), 则( )

![](images/8e8f4df12e914f4ef16f2f4912ebc91d19101c0d902a3618f59ad880069238a3.jpg)

(a) $t_0 = 10$   
(b) $15 < t_{0} < 20$ .   
