INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2020_main_q08', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2020_main_q08', 'math1_2020_main_q08', 2020, 8, 8, 8, '（8）【答案】 (B).

【解】 $E(X) = \frac{1}{2}, E(X^2) = \frac{1}{2}$ ，则 $D(X) = E(X^2) - [E(X)]^2 = \frac{1}{4}$ .

由中心极限定理得 $\sum_{i = 1}^{100}X_{i}$ 近似服从 $N(50,25)$

从而 $\frac{\sum_{i=1}^{100} X_i - 50}{5}$ 近似服从 $N(0,1)$ ，故

$$
P \left\{\sum_ {i = 1} ^ {1 0 0} X _ {i} \leqslant 5 5 \right\} = P \left\{\frac {\sum_ {i = 1} ^ {1 0 0} X _ {i} - 5 0}{5} \leqslant 1 \right\} \approx \Phi (1), \text {应 选 (B)}.
$$

# 二、填空题', 'E:\数学自用\数据资料\真题\按年份整理\2020\解析\2020年解析.md', 'ok', 'year_question_no', 0.13, '2020:8', 8, 0.13);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2020_main_q09', 'math1', 2020, '真题', 'main', 9, '9) $\lim_{x\to 0}\left[\frac{1}{\mathrm{e}^x - 1} -\frac{1}{\ln(1 + x)}\right] = \underline{\quad}$', 'E:\数学自用\数据资料\真题\按年份整理\2020\按题拆分\真题\第09题\题目.md', '2020\按题拆分\真题\第09题\题目.md', 0, 'ok', '2020 真题 第9题 9) $\lim_{x\to 0}\left[\frac{1}{\mathrm{e}^x - 1} -\frac{1}{\ln(1 + x)}\right] = \underline{\quad}$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2020_main_q09', 'tag_极限');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2020_main_q09', 'math1_2020_main_q09', 2020, 9, 9, 9, '（9）【答案】 -1.

【解】 $\lim_{x\to 0}\left[\frac{1}{\mathrm{e}^x - 1} -\frac{1}{\ln(1 + x)}\right] = \lim_{x\to 0}\frac{\ln(1 + x) - \mathrm{e}^x + 1}{x^2}$

$$
\begin{array}{l} = \lim  _ {x \rightarrow 0} \frac {\frac {1}{1 + x} - e ^ {x}}{2 x} = \frac {1}{2} \lim  _ {x \rightarrow 0} \frac {1}{1 + x} \cdot \frac {1 - (x + 1) e ^ {x}}{x} = \frac {1}{2} \lim  _ {x \rightarrow 0} \frac {1 - (x + 1) e ^ {x}}{x} \\ = - \frac {1}{2} \lim  _ {x \rightarrow 0} (x + 2) e ^ {x} = - 1. \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\2020\解析\2020年解析.md', 'ok', 'year_question_no', 0.875, '2020:9', 9, 0.875);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2020_main_q10', 'math1', 2020, '真题', 'main', 10, '10）设 $\left\{ \begin{array}{l}x = \sqrt{t^2 + 1},\\ y = \ln (t + \sqrt{t^2 + 1}), \end{array} \right.$ 则 $\frac{\mathrm{d}^2y}{\mathrm{d}x^2}\bigg|_{t = 1} = .$', 'E:\数学自用\数据资料\真题\按年份整理\2020\按题拆分\真题\第10题\题目.md', '2020\按题拆分\真题\第10题\题目.md', 0, 'ok', '2020 真题 第10题 10）设 $\left\{ \begin{array}{l}x = \sqrt{t^2 + 1},\\ y = \ln (t + \sqrt{t^2 + 1}), \end{array} \right.$ 则 $\frac{\mathrm{d}^2y}{\mathrm{d}x^2}\bigg|_{t = 1} = .$');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2020_main_q10', 'math1_2020_main_q10', 2020, 10, 10, 10, '（10）【答案】 $-\sqrt{2}$

【解】 $\frac{\mathrm{dy}}{\mathrm{dx}} = \frac{\frac{1}{\sqrt{t^2 + 1}}}{\frac{t}{\sqrt{t^2 + 1}}} = \frac{1}{t},$

$$
\frac {\mathrm {d} ^ {2} y}{\mathrm {d} x ^ {2}} = \frac {\mathrm {d} \left(\frac {1}{t}\right) / \mathrm {d} t}{\mathrm {d} x / \mathrm {d} t} = \frac {- \frac {1}{t ^ {2}}}{\frac {t}{\sqrt {t ^ {2} + 1}}} = - \frac {\sqrt {t ^ {2} + 1}}{t ^ {3}},
$$

故 $\frac{\mathrm{d}^2y}{\mathrm{d}x^2}\bigg|_{t = 1} = -\sqrt{2}.$', 'E:\数学自用\数据资料\真题\按年份整理\2020\解析\2020年解析.md', 'ok', 'year_question_no', 0.308, '2020:10', 6, 0.308);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2020_main_q11', 'math1', 2020, '真题', 'main', 11, '11）设函数 $f(x)$ 满足 $f^{\prime \prime}(x) + af^{\prime}(x) + f(x) = 0(a > 0)$ ，且 $f(0) = m, f^{\prime}(0) = n$ ，则 $\int_0^{+\infty}f(x)\mathrm{d}x = \underline{\quad}$', 'E:\数学自用\数据资料\真题\按年份整理\2020\按题拆分\真题\第11题\题目.md', '2020\按题拆分\真题\第11题\题目.md', 0, 'ok', '2020 真题 第11题 11）设函数 $f(x)$ 满足 $f^{\prime \prime}(x) + af^{\prime}(x) + f(x) = 0(a > 0)$ ，且 $f(0) = m, f^{\prime}(0) = n$ ，则 $\int_0^{+\infty}f(x)\mathrm{d}x = \underline{\quad}$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2020_main_q11', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2020_main_q11', 'math1_2020_main_q11', 2020, 11, 11, 11, '(11)【答案】 $n + am$

【解】由 $f^{\prime \prime}(x) + af^{\prime}(x) + f(x) = 0$ 得特征方程为

$$
\lambda^ {2} + a \lambda + 1 = 0,
$$

因为 $\lambda_1 + \lambda_2 = -a < 0, \lambda_1\lambda_2 = 1 > 0$ ，所以 $\lambda_1 < 0, \lambda_2 < 0$

于是 $f(x) = C_{1}\mathrm{e}^{\lambda_{1}x} + C_{2}\mathrm{e}^{\lambda_{2}x},f^{\prime}(x) = C_{1}\lambda_{1}\mathrm{e}^{\lambda_{1}x} + C_{2}\lambda_{2}\mathrm{e}^{\lambda_{2}x},$

显然 $\lim_{x\to +\infty}f(x) = \lim_{x\to +\infty}f''(x) = 0,$

故 $\int_0^{+\infty}f(x)\mathrm{d}x = -\int_0^{+\infty}\left[f^{\prime \prime}(x) + af^{\prime}(x)\right]\mathrm{d}x = -f^{\prime}(x)\mid_{0}^{+\infty} - af(x)\mid_{0}^{+\infty} = n + am.$', 'E:\数学自用\数据资料\真题\按年份整理\2020\解析\2020年解析.md', 'ok', 'year_question_no', 0.333, '2020:11', 11, 0.333);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2020_main_q12', 'math1', 2020, '真题', 'main', 12, '12）设函数 $f(x,y) = \int_0^{xy}\mathrm{e}^{xt^2}\mathrm{d}t$ ，则 $\frac{\partial^2f}{\partial x\partial y}\bigg|_{(1,1)} = \underline{\quad}$', 'E:\数学自用\数据资料\真题\按年份整理\2020\按题拆分\真题\第12题\题目.md', '2020\按题拆分\真题\第12题\题目.md', 0, 'ok', '2020 真题 第12题 12）设函数 $f(x,y) = \int_0^{xy}\mathrm{e}^{xt^2}\mathrm{d}t$ ，则 $\frac{\partial^2f}{\partial x\partial y}\bigg|_{(1,1)} = \underline{\quad}$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2020_main_q12', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2020_main_q12', 'math1_2020_main_q12', 2020, 12, 12, 12, '(12)【答案】 4e.

【解】 $f(x,y) = \int_{0}^{xy}\mathrm{e}^{xt^2}\mathrm{d}t = \frac{1}{\sqrt{x}}\int_{0}^{xy}\mathrm{e}^{(\sqrt{x} t)^2}\mathrm{d}(\sqrt{x} t) = \frac{1}{\sqrt{x}}\int_{0}^{x^{\frac{3}{2} y}}\mathrm{e}^{t^2}\mathrm{d}t,$

$$
\frac {\partial f}{\partial x} = \frac {3}{2} y \mathrm {e} ^ {x ^ {3} y ^ {2}} - \frac {\int_ {0} ^ {x ^ {\frac {3}{2}} y} \mathrm {e} ^ {t ^ {2}} \mathrm {d} t}{2 x ^ {\frac {3}{2}}}, \quad \frac {\partial^ {2} f}{\partial x \partial y} = \frac {3}{2} \mathrm {e} ^ {x ^ {3} y ^ {2}} + 3 x ^ {3} y ^ {2} \mathrm {e} ^ {x ^ {3} y ^ {2}} - \frac {1}{2} \mathrm {e} ^ {x ^ {3} y ^ {2}},
$$

故 $\left.\frac{\partial^2f}{\partial x\partial y}\right|_{(1,1)} = 4\mathrm{e}.$', 'E:\数学自用\数据资料\真题\按年份整理\2020\解析\2020年解析.md', 'ok', 'year_question_no', 0.619, '2020:12', 12, 0.619);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2020_main_q13', 'math1', 2020, '真题', 'main', 13, '（13）行列式 $\left| \begin{array}{cccc}a & 0 & -1 & 1\\ 0 & a & 1 & -1\\ -1 & 1 & a & 0\\ 1 & -1 & 0 & a \end{array} \right| = \underline{\quad}$', 'E:\数学自用\数据资料\真题\按年份整理\2020\按题拆分\真题\第13题\题目.md', '2020\按题拆分\真题\第13题\题目.md', 0, 'ok', '2020 真题 第13题 （13）行列式 $\left| \begin{array}{cccc}a & 0 & -1 & 1\\ 0 & a & 1 & -1\\ -1 & 1 & a & 0\\ 1 & -1 & 0 & a \end{array} \right| = \underline{\quad}$');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2020_main_q13', 'math1_2020_main_q13', 2020, 13, 13, 13, '（13）【答案】 $a^4 - 4a^2$

【解】 $\left| \begin{array}{cccc}a & 0 & -1 & 1\\ 0 & a & 1 & -1\\ -1 & 1 & a & 0\\ 1 & -1 & 0 & a \end{array} \right| = -\left| \begin{array}{cccc}1 & 0 & -1 & a\\ -1 & a & 1 & 0\\ 0 & 1 & a & -1\\ a & -1 & 0 & 1 \end{array} \right| = -\left| \begin{array}{cccc}1 & 0 & -1 & a\\ 0 & a & 0 & a\\ 0 & 1 & a & -1\\ 0 & -1 & a & 1 - a^2 \end{array} \right|$

$$
\begin{array}{l} = - \left| \begin{array}{c c c} a & 0 & a \\ 1 & a & - 1 \\ - 1 & a & 1 - a ^ {2} \end{array} \right| = - a \left| \begin{array}{c c c} 1 & 0 & 1 \\ 1 & a & - 1 \\ - 1 & a & 1 - a ^ {2} \end{array} \right| \\ = - a \left| \begin{array}{c c c} 1 & 0 & 1 \\ 0 & a & - 2 \\ 0 & a & 2 - a ^ {2} \end{array} \right| = - 4 a ^ {2} + a ^ {4}. \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\2020\解析\2020年解析.md', 'ok', 'year_question_no', 0.792, '2020:13', 13, 0.792);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2020_main_q14', 'math1', 2020, '真题', 'main', 14, '（14）设 $X$ 服从区间 $\left(-\frac{\pi}{2}, \frac{\pi}{2}\right)$ 上的均匀分布， $Y = \sin X$ ，则 $\operatorname{Cov}(X, Y) =$ ______.

# 三、解答题（15～23小题，共94分.解答应写出文字说明、证明过程或演算步骤.）', 'E:\数学自用\数据资料\真题\按年份整理\2020\按题拆分\真题\第14题\题目.md', '2020\按题拆分\真题\第14题\题目.md', 0, 'ok', '2020 真题 第14题 （14）设 $x$ 服从区间 $\left(-\frac{\pi}{2}, \frac{\pi}{2}\right)$ 上的均匀分布， $y = \sin x$ ，则 $\operatorname{cov}(x, y) =$ ______.

# 三、解答题（15～23小题，共94分.解答应写出文字说明、证明过程或演算步骤.）');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2020_main_q14', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2020_main_q14', 'math1_2020_main_q14', 2020, 14, 14, 14, '(14)【答案】 $\frac{2}{\pi}$ .

【解】 $X$ 的概率密度为

$$
f (x) = \left\{ \begin{array}{l l} \frac {1}{\pi}, & - \frac {\pi}{2} <   x <   \frac {\pi}{2}, \\ 0, & \text {其 他}, \end{array} \right.
$$

$$
E (X) = 0,
$$

$$
\begin{array}{l} E (X Y) = E (X \sin X) = \frac {1}{\pi} \int_ {- \frac {\pi}{2}} ^ {\frac {\pi}{2}} x \sin x d x = - \frac {2}{\pi} \int_ {0} ^ {\frac {\pi}{2}} x d (\cos x) \\ = - \frac {2}{\pi} \left(x \cos x \left| _ {0} ^ {\frac {\pi}{2}} - \int_ {0} ^ {\frac {\pi}{2}} \cos x d x \right.\right) = \frac {2}{\pi}, \\ \end{array}
$$

故 $\operatorname{Cov}(X, Y) = E(XY) - E(X)E(Y) = E(XY) = \frac{2}{\pi}$ .

# 三、解答题', 'E:\数学自用\数据资料\真题\按年份整理\2020\解析\2020年解析.md', 'ok', 'year_question_no', 0.093, '2020:14', 14, 0.093);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2020_main_q15', 'math1', 2020, '真题', 'main', 15, '（15）（本题满分10分）

求函数 $f(x,y) = x^{3} + 8y^{3} - xy$ 的极值.', 'E:\数学自用\数据资料\真题\按年份整理\2020\按题拆分\真题\第15题\题目.md', '2020\按题拆分\真题\第15题\题目.md', 0, 'ok', '2020 真题 第15题 （15）（本题满分10分）

求函数 $f(x,y) = x^{3} + 8y^{3} - xy$ 的极值.');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2020_main_q15', 'math1_2020_main_q15', 2020, 15, 15, 15, '(15)【解】 由 $\left\{ \begin{array}{l}3x^{2} - y = 0,\\ 24y^{2} - x = 0 \end{array} \right.$ 得 $\left\{ \begin{array}{l}x = 0,\\ y = 0, \end{array} \right.$ $\left\{ \begin{array}{l}x = \frac{1}{6},\\ y = \frac{1}{12}; \end{array} \right.$

$$
\frac {\partial^ {2} f}{\partial x ^ {2}} = 6 x, \quad \frac {\partial^ {2} f}{\partial x \partial y} = - 1, \quad \frac {\partial^ {2} f}{\partial y ^ {2}} = 4 8 y,
$$

当 $(x,y) = (0,0)$ 时， $A = 0,B = -1,C = 0$

因为 $AC - B^2 < 0$ ，所以点 $(0,0)$ 不是函数 $f(x,y)$ 的极值点；

当 $(x,y) = \left(\frac{1}{6},\frac{1}{12}\right)$ 时， $A = 1,B = -1,C = 4$

因为 $AC - B^2 = 3 > 0$ 且 $A > 0$ ，所以点 $\left(\frac{1}{6},\frac{1}{12}\right)$ 为函数 $f(x,y)$ 的极小值点，极小值为

$$
f \left(\frac {1}{6}, \frac {1}{1 2}\right) = \frac {1}{6 ^ {3}} + 8 \times \frac {1}{1 2 ^ {3}} - \frac {1}{6} \times \frac {1}{1 2} = - \frac {1}{2 1 6}.
$$', 'E:\数学自用\数据资料\真题\按年份整理\2020\解析\2020年解析.md', 'ok', 'year_question_no', 0.261, '2020:15', 15, 0.261);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2020_main_q16', 'math1', 2020, '真题', 'main', 16, '（16）（本题满分10分）

计算曲线积分 $I = \int_{L} \frac{4x - y}{4x^2 + y^2} \mathrm{d}x + \frac{x + y}{4x^2 + y^2} \mathrm{d}y$ ，其中 $L$ 是 $x^2 + y^2 = 2$ ，方向为逆时针方向。', 'E:\数学自用\数据资料\真题\按年份整理\2020\按题拆分\真题\第16题\题目.md', '2020\按题拆分\真题\第16题\题目.md', 0, 'ok', '2020 真题 第16题 （16）（本题满分10分）

计算曲线积分 $i = \int_{l} \frac{4x - y}{4x^2 + y^2} \mathrm{d}x + \frac{x + y}{4x^2 + y^2} \mathrm{d}y$ ，其中 $l$ 是 $x^2 + y^2 = 2$ ，方向为逆时针方向。');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2020_main_q16', 'tag_积分');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2020_main_q16', 'math1_2020_main_q16', 2020, 16, 16, 16, '(16)【解】 $P(x,y) = \frac{4x - y}{4x^2 + y^2},\quad Q(x,y) = \frac{x + y}{4x^2 + y^2},$

$$
\begin{array}{l} \frac {\partial Q}{\partial x} = \frac {- 4 x ^ {2} + y ^ {2} - 8 x y}{(4 x ^ {2} + y ^ {2}) ^ {2}}, \quad \frac {\partial P}{\partial y} = \frac {- 4 x ^ {2} + y ^ {2} - 8 x y}{(4 x ^ {2} + y ^ {2}) ^ {2}}, \\ \frac {\partial Q}{\partial x} = \frac {\partial P}{\partial y} ((x, y) \neq (0, 0)). \\ \end{array}
$$

取 $L_{0}:4x^{2} + y^{2} = r^{2}(r > 0,L_{0}$ 在 $L$ 内，逆时针)，且设 $L$ 与 $L_0^-$ 所围成的区域为 $D_{1},L_{0}$ 围成的区域为 $D_{2}$ ，

由 $\oint_{L + L_0^-}P\mathrm{d}x + Q\mathrm{d}y = \iint_{D_1}0\mathrm{d}x\mathrm{d}y = 0$ 得

$$
\begin{array}{l} I = \int_ {L} \frac {4 x - y}{4 x ^ {2} + y ^ {2}} d x + \frac {x + y}{4 x ^ {2} + y ^ {2}} d y = \oint_ {L _ {0}} \frac {4 x - y}{4 x ^ {2} + y ^ {2}} d x + \frac {x + y}{4 x ^ {2} + y ^ {2}} d y \\ = \frac {1}{r ^ {2}} \oint_ {L _ {0}} (4 x - y) d x + (x + y) d y = \frac {2}{r ^ {2}} \iint_ {D _ {2}} d x d y = \frac {2}{r ^ {2}} \times \pi \times r \times \frac {r}{2} = \pi . \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\2020\解析\2020年解析.md', 'ok', 'year_question_no', 0.349, '2020:16', 16, 0.349);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2020_main_q17', 'math1', 2020, '真题', 'main', 17, '（17）（本题满分10分）

设数列 $\{a_{n}\}$ 满足： $a_1 = 1,(n + 1)a_{n + 1} = \left(n + \frac{1}{2}\right)a_n$ ，证明：当 $|x| < 1$ 时，幂级数 $\sum_{n = 1}^{\infty}a_{n}x^{n}$ 收敛，并求其和函数.', 'E:\数学自用\数据资料\真题\按年份整理\2020\按题拆分\真题\第17题\题目.md', '2020\按题拆分\真题\第17题\题目.md', 0, 'ok', '2020 真题 第17题 （17）（本题满分10分）

设数列 $\{a_{n}\}$ 满足： $a_1 = 1,(n + 1)a_{n + 1} = \left(n + \frac{1}{2}\right)a_n$ ，证明：当 $|x| < 1$ 时，幂级数 $\sum_{n = 1}^{\infty}a_{n}x^{n}$ 收敛，并求其和函数.');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2020_main_q17', 'tag_级数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2020_main_q17', 'math1_2020_main_q17', 2020, 17, 17, 17, '(17)【解】由 $(n + 1)a_{n + 1} = \left(n + \frac{1}{2}\right)a_n$ 得 $\frac{a_{n + 1}}{a_n} = \frac{n + \frac{1}{2}}{n + 1},$

从而 $\lim_{n\to \infty}\frac{a_{n + 1}}{a_n} = 1$ ，即幂级数 $\sum_{n = 1}^{\infty}a_{n}x^{n}$ 的收敛半径为 $R = 1$

故当 $|x| < 1$ 时，幂级数 $\sum_{n=1}^{\infty} a_n x^n$ 收敛.

令 $S(x) = \sum_{n=1}^{\infty} a_n x^n$ ，则

$$
\begin{array}{l} S ^ {\prime} (x) = 1 + \sum_ {n = 1} ^ {\infty} (n + 1) a _ {n + 1} x ^ {n} = 1 + \sum_ {n = 1} ^ {\infty} \left(n + \frac {1}{2}\right) a _ {n} x ^ {n} \\ = 1 + x \sum_ {n = 1} ^ {\infty} n a _ {n} x ^ {n - 1} + \frac {1}{2} \sum_ {n = 1} ^ {\infty} a _ {n} x ^ {n} = 1 + x S ^ {\prime} (x) + \frac {1}{2} S (x), \\ \end{array}
$$

即 $S^{\prime}(x) - \frac{1}{2(1 - x)} S(x) = \frac{1}{1 - x}$ ，解得

$$
S (x) = (- 2 \sqrt {1 - x} + C) \frac {1}{\sqrt {1 - x}} = \frac {C}{\sqrt {1 - x}} - 2,
$$

由 $S(0) = 0$ 得 $C = 2$ ，故 $S(x) = \frac{2}{\sqrt{1 - x}} - 2.$', 'E:\数学自用\数据资料\真题\按年份整理\2020\解析\2020年解析.md', 'ok', 'year_question_no', 0.404, '2020:17', 17, 0.404);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2020_main_q18', 'math1', 2020, '真题', 'main', 18, '（18）（本题满分10分）

设 $\Sigma$ 为曲面 $z = \sqrt{x^2 + y^2}$ （ $1 \leqslant x^2 + y^2 \leqslant 4$ ）的下侧， $f(x)$ 是连续函数，计算

$$
I = \iint_ {\Sigma} [ x f (x y) + 2 x - y ] d y d z + [ y f (x y) + 2 y + x ] d z d x + [ z f (x y) + z ] d x d y.
$$', 'E:\数学自用\数据资料\真题\按年份整理\2020\按题拆分\真题\第18题\题目.md', '2020\按题拆分\真题\第18题\题目.md', 0, 'ok', '2020 真题 第18题 （18）（本题满分10分）

设 $\sigma$ 为曲面 $z = \sqrt{x^2 + y^2}$ （ $1 \leqslant x^2 + y^2 \leqslant 4$ ）的下侧， $f(x)$ 是连续函数，计算

$$
i = \iint_ {\sigma} [ x f (x y) + 2 x - y ] d y d z + [ y f (x y) + 2 y + x ] d z d x + [ z f (x y) + z ] d x d y.
$$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2020_main_q18', 'tag_连续');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2020_main_q18', 'math1_2020_main_q18', 2020, 18, 18, 18, '(18)【解】因为 $\Sigma$ 的法向量为 $(x, y, -z)$ ，所以

$$
\begin{array}{l} I = \iint_ {\Sigma} \frac {1}{\sqrt {2 (x ^ {2} + y ^ {2})}} \left[ \left(x ^ {2} + y ^ {2} - z ^ {2}\right) f (x y) + 2 x ^ {2} + 2 y ^ {2} - z ^ {2} \right] d S \\ = \frac {\sqrt {2}}{2} \iint_ {\Sigma} \sqrt {x ^ {2} + y ^ {2}} d S. \\ \end{array}
$$

记 $D = \{(x,y)\mid 1\leqslant x^2 +y^2\leqslant 4\}$ ，又

$$
\sqrt {\left(\frac {\partial z}{\partial x}\right) ^ {2} + \left(\frac {\partial z}{\partial y}\right) ^ {2} + 1} = \sqrt {\left(\frac {x}{\sqrt {x ^ {2} + y ^ {2}}}\right) ^ {2} + \left(\frac {y}{\sqrt {x ^ {2} + y ^ {2}}}\right) ^ {2} + 1} = \sqrt {2}.
$$

故

$$
\begin{array}{l} I = \iint_ {D} \sqrt {x ^ {2} + y ^ {2}} d x d y \\ = \int_ {0} ^ {2 \pi} \mathrm {d} \theta \int_ {1} ^ {2} r ^ {2} \mathrm {d} r \\ = \frac {1 4}{3} \pi . \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\2020\解析\2020年解析.md', 'ok', 'year_question_no', 0.233, '2020:18', 18, 0.233);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2020_main_q19', 'math1', 2020, '真题', 'main', 19, '（19）（本题满分10分）

设函数 $f(x)$ 在区间 $[0,2]$ 上具有连续导数， $f(0) = f(2) = 0, M = \max_{x\in [0,2]}\{|f(x)|\}$ ，证明：

（I）存在 $\xi \in (0,2)$ ，使得 $|f''(\xi)| \geqslant M$ ；  
（Ⅱ）若对任意的 $x\in (0,2),|f''(x)|\leqslant M$ ，则 $M = 0$', 'E:\数学自用\数据资料\真题\按年份整理\2020\按题拆分\真题\第19题\题目.md', '2020\按题拆分\真题\第19题\题目.md', 0, 'ok', '2020 真题 第19题 （19）（本题满分10分）

设函数 $f(x)$ 在区间 $[0,2]$ 上具有连续导数， $f(0) = f(2) = 0, m = \max_{x\in [0,2]}\{|f(x)|\}$ ，证明：

（i）存在 $\xi \in (0,2)$ ，使得 $|f''(\xi)| \geqslant m$ ；  
（ⅱ）若对任意的 $x\in (0,2),|f''(x)|\leqslant m$ ，则 $m = 0$');
