INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2021_main_q04', 'math1_2021_main_q04', 2021, 4, 4, 4, '（4）【答案】 （B）.

【解】 $\lim_{n\to \infty}\sum_{k = 1}^{n}f\left(\frac{2k - 1}{2n}\right)\frac{1}{n} = \lim_{n\to \infty}\sum_{k = 1}^{n}f\left(\frac{2k}{2n}\right)\frac{1}{n} = \lim_{n\to \infty}\frac{1}{n}\sum_{k = 1}^{n}f\left(\frac{k}{n}\right) = \int_{0}^{1}f(x)\mathrm{d}x$ ，应选(B).（5）【答案】 (B).

【解】 令 $\mathbf{A} = \begin{pmatrix} 0 & 1 & 1\\ 1 & 2 & 1\\ 1 & 1 & 0 \end{pmatrix} ,\mathbf{X} = \begin{pmatrix} x_{1}\\ x_{2}\\ x_{3} \end{pmatrix}$ ，则 $f = X^{\mathrm{T}}AX$

由 $|\lambda \pmb {E} - \pmb {A}| = \left| \begin{array}{rrr}\lambda & -1 & -1\\ -1 & \lambda -2 & -1\\ -1 & -1 & \lambda \end{array} \right| = (\lambda +1)\left| \begin{array}{rrr}1 & 0 & 0\\ -1 & \lambda -2 & -2\\ -1 & -1 & \lambda -1 \end{array} \right|$

$$
= (\lambda + 1) \left(\lambda^ {2} - 3 \lambda\right) = 0
$$

得 $\lambda_{1} = -1, \lambda_{2} = 0, \lambda_{3} = 3$ ，应选（B）.', 'E:\数学自用\数据资料\真题\按年份整理\2021\解析\2021年解析.md', 'ok', 'year_question_no', 0.327, '2021:4', 4, 0.327);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2021_main_q05', 'math1', 2021, '真题', 'main', 5, '（5）设二次型 $f(x_{1},x_{2},x_{3}) = (x_{1} + x_{2})^{2} + (x_{2} + x_{3})^{2} - (x_{3} - x_{1})^{2}$ 的正惯性指数与负惯性指数依次为（ ）.

(A)2,0

(B)1,1

(C)2,1

(D)1,2', 'E:\数学自用\数据资料\真题\按年份整理\2021\按题拆分\真题\第05题\题目.md', '2021\按题拆分\真题\第05题\题目.md', 0, 'ok', '2021 真题 第5题 （5）设二次型 $f(x_{1},x_{2},x_{3}) = (x_{1} + x_{2})^{2} + (x_{2} + x_{3})^{2} - (x_{3} - x_{1})^{2}$ 的正惯性指数与负惯性指数依次为（ ）.

(a)2,0

(b)1,1

(c)2,1

(d)1,2');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2021_main_q05', 'math1_2021_main_q05', 2021, 5, 2, 2, '（2）【答案】 (C).

【解】 $f(x + 1, \mathrm{e}^x) = x(x + 1)^2$ 两边对 $x$ 求导得

$$
f _ {1} ^ {\prime} (x + 1, \mathrm {e} ^ {x}) + \mathrm {e} ^ {x} f _ {2} ^ {\prime} (x + 1, \mathrm {e} ^ {x}) = (x + 1) ^ {2} + 2 x (x + 1),
$$

取 $x = 0$ 得 $f_{1}^{\prime}(1,1) + f_{2}^{\prime}(1,1) = 1$

$f(x,x^{2}) = 2x^{2}\ln x$ 两边对 $x$ 求导得

$$
f _ {1} ^ {\prime} (x, x ^ {2}) + 2 x f _ {2} ^ {\prime} (x, x ^ {2}) = 4 x \ln x + 2 x,
$$

取 $x = 1$ 得 $f_{1}^{\prime}(1,1) + 2f_{2}^{\prime}(1,1) = 2$

解得 $f_{1}^{\prime}(1,1) = 0, f_{2}^{\prime}(1,1) = 1$ ，故 $\mathrm{d}f(1,1) = \mathrm{d}y$ ，应选(C).', 'E:\数学自用\数据资料\真题\按年份整理\2021\解析\2021年解析.md', 'manual_check', 'similarity_fallback:0.140', 0.14, '', 2, 0.14);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2021_main_q06', 'math1', 2021, '真题', 'main', 6, '（6）已知 $\pmb{\alpha}_{1} = \begin{pmatrix} 1 \\ 0 \\ 1 \end{pmatrix}, \pmb{\alpha}_{2} = \begin{pmatrix} 1 \\ 2 \\ 1 \end{pmatrix}, \pmb{\alpha}_{3} = \begin{pmatrix} 3 \\ 1 \\ 2 \end{pmatrix}, \pmb{\beta}_{1} = \pmb{\alpha}_{1}, \pmb{\beta}_{2} = \pmb{\alpha}_{2} - k\pmb{\beta}_{1}, \pmb{\beta}_{3} = \pmb{\alpha}_{3} - l_{1}\pmb{\beta}_{1} - l_{2}\pmb{\beta}_{2}$ ，若 $\pmb{\beta}_{1}, \pmb{\beta}_{2}, \pmb{\beta}_{3}$ 两两相交，则 $l_{1}, l_{2}$ 依次为（ ）.

(A) $\frac{5}{2}, \frac{1}{2}$

(B) $-\frac{5}{2}, \frac{1}{2}$

(C) $\frac{5}{2}, -\frac{1}{2}$

(D) $-\frac{5}{2}, - \frac{1}{2}$', 'E:\数学自用\数据资料\真题\按年份整理\2021\按题拆分\真题\第06题\题目.md', '2021\按题拆分\真题\第06题\题目.md', 0, 'ok', '2021 真题 第6题 （6）已知 $\pmb{\alpha}_{1} = \begin{pmatrix} 1 \\ 0 \\ 1 \end{pmatrix}, \pmb{\alpha}_{2} = \begin{pmatrix} 1 \\ 2 \\ 1 \end{pmatrix}, \pmb{\alpha}_{3} = \begin{pmatrix} 3 \\ 1 \\ 2 \end{pmatrix}, \pmb{\beta}_{1} = \pmb{\alpha}_{1}, \pmb{\beta}_{2} = \pmb{\alpha}_{2} - k\pmb{\beta}_{1}, \pmb{\beta}_{3} = \pmb{\alpha}_{3} - l_{1}\pmb{\beta}_{1} - l_{2}\pmb{\beta}_{2}$ ，若 $\pmb{\beta}_{1}, \pmb{\beta}_{2}, \pmb{\beta}_{3}$ 两两相交，则 $l_{1}, l_{2}$ 依次为（ ）.

(a) $\frac{5}{2}, \frac{1}{2}$

(b) $-\frac{5}{2}, \frac{1}{2}$

(c) $\frac{5}{2}, -\frac{1}{2}$

(d) $-\frac{5}{2}, - \frac{1}{2}$');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2021_main_q06', 'math1_2021_main_q06', 2021, 6, 6, 5, '（6）【答案】 （A）.

【解】由施密特正交化得 $l_{1} = \frac{(\pmb{\alpha}_{3},\pmb{\beta}_{1})}{(\pmb{\beta}_{1},\pmb{\beta}_{1})} = \frac{5}{2}, l_{2} = \frac{(\pmb{\alpha}_{3},\pmb{\beta}_{2})}{(\pmb{\beta}_{2},\pmb{\beta}_{2})} = \frac{2}{4} = \frac{1}{2}$ 应选(A).

方法点评：将线性无关的向量组化为两两正交的规范向量组即施密特正交规范化，实对称矩阵的对角化的正交变换法需要将线性无关的特征向量进行正交化和单位化.设 $\pmb{\alpha}_{1},\pmb{\alpha}_{2},\pmb{\alpha}_{3}$ 线性无关， $\pmb {\beta}_1 = \pmb {\alpha}_1,\pmb {\beta}_2 = \pmb {\alpha}_2 - l_1\pmb {\beta}_1,\pmb {\beta}_3 = \pmb {\alpha}_3 - k_1\pmb {\beta}_1 - k_2\pmb {\beta}_2$ ，且 $\pmb {\beta}_1,\pmb {\beta}_2,\pmb {\beta}_3$ 线性无关，则 $l_{1} = \frac{(\pmb{\alpha}_{2},\pmb{\beta}_{1})}{(\pmb{\beta}_{1},\pmb{\beta}_{1})},k_{1} = \frac{(\pmb{\alpha}_{3},\pmb{\beta}_{1})}{(\pmb{\beta}_{1},\pmb{\beta}_{1})},k_{2} = \frac{(\pmb{\alpha}_{3},\pmb{\beta}_{2})}{(\pmb{\beta}_{2},\pmb{\beta}_{2})}.$', 'E:\数学自用\数据资料\真题\按年份整理\2021\解析\2021年解析.md', 'ok', 'year_question_no', 0.119, '2021:6', 21, 0.313);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2021_main_q07', 'math1', 2021, '真题', 'main', 7, '7）设 $A, B$ 为 $n$ 阶实矩阵，下列结论不成立的是（ ）.

(A) $r\begin{pmatrix} \mathbf{A} & \mathbf{O}\\ \mathbf{O} & \mathbf{A}^{\mathrm{T}}\mathbf{A} \end{pmatrix} = 2r(\mathbf{A})$

(B) $r\begin{pmatrix} \mathbf{A} & \mathbf{AB}\\ \mathbf{O} & \mathbf{A}^{\mathrm{T}} \end{pmatrix} = 2r(\mathbf{A})$

(C) $r\begin{pmatrix} \mathbf{A} & \mathbf{B}\mathbf{A}\\ \mathbf{O} & \mathbf{A}\mathbf{A}^{\mathrm{T}} \end{pmatrix} = 2r(\mathbf{A})$

(D) $r\begin{pmatrix} \mathbf{A} & \mathbf{O}\\ \mathbf{B}\mathbf{A} & \mathbf{A}^{\mathrm{T}} \end{pmatrix} = 2r(\mathbf{A})$', 'E:\数学自用\数据资料\真题\按年份整理\2021\按题拆分\真题\第07题\题目.md', '2021\按题拆分\真题\第07题\题目.md', 0, 'ok', '2021 真题 第7题 7）设 $a, b$ 为 $n$ 阶实矩阵，下列结论不成立的是（ ）.

(a) $r\begin{pmatrix} \mathbf{a} & \mathbf{o}\\ \mathbf{o} & \mathbf{a}^{\mathrm{t}}\mathbf{a} \end{pmatrix} = 2r(\mathbf{a})$

(b) $r\begin{pmatrix} \mathbf{a} & \mathbf{ab}\\ \mathbf{o} & \mathbf{a}^{\mathrm{t}} \end{pmatrix} = 2r(\mathbf{a})$

(c) $r\begin{pmatrix} \mathbf{a} & \mathbf{b}\mathbf{a}\\ \mathbf{o} & \mathbf{a}\mathbf{a}^{\mathrm{t}} \end{pmatrix} = 2r(\mathbf{a})$

(d) $r\begin{pmatrix} \mathbf{a} & \mathbf{o}\\ \mathbf{b}\mathbf{a} & \mathbf{a}^{\mathrm{t}} \end{pmatrix} = 2r(\mathbf{a})$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2021_main_q07', 'tag_线性代数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2021_main_q07', 'math1_2021_main_q07', 2021, 7, 7, 6, '（7）【答案】 (C).

【解】 $r\begin{pmatrix} \mathbf{A} & \mathbf{O}\\ \mathbf{O} & \mathbf{A}^{\mathrm{T}}\mathbf{A} \end{pmatrix} = r(\mathbf{A}) + r(\mathbf{A}^{\mathrm{T}}\mathbf{A}) = 2r(\mathbf{A});$

由 $\left( \begin{array}{ll}A & AB\\ O & A^{\mathrm{T}} \end{array} \right)\xrightarrow{\text{列}}\left( \begin{array}{ll}A & O\\ O & A^{\mathrm{T}} \end{array} \right)$ 得 $r\left( \begin{array}{ll}A & AB\\ O & A^{\mathrm{T}} \end{array} \right) = 2r(A)$

由 $r\left(\begin{array}{cc}\mathbf{A}&\mathbf{O}\\ \mathbf{B}\mathbf{A}&\mathbf{A}^{\mathrm{T}}\end{array}\right)\xrightarrow{\text{行}}r\left(\begin{array}{cc}\mathbf{A}&\mathbf{O}\\ \mathbf{O}&\mathbf{A}^{\mathrm{T}}\end{array}\right)$ 得 $r\left(\begin{array}{cc}\mathbf{A}&\mathbf{O}\\ \mathbf{B}\mathbf{A}&\mathbf{A}^{\mathrm{T}}\end{array}\right)=2r(\mathbf{A})$ ，应选(C).', 'E:\数学自用\数据资料\真题\按年份整理\2021\解析\2021年解析.md', 'ok', 'year_question_no', 0.361, '2021:7', 7, 0.361);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2021_main_q08', 'math1', 2021, '真题', 'main', 8, '8）设 $A,B$ 为随机事件，且 $0 <   P(B) <   1$ ，下列命题中为假命题的是（ ）.

(A) 若 $P(A \mid B) = P(A)$ ，则 $P(A \mid \overline{B}) = P(A)$   
(B) 若 $P(A \mid B) > P(A)$ , 则 $P(\overline{A} \mid \overline{B}) > P(\overline{A})$   
(C) 若 $P(A \mid B) > P(A \mid \overline{B})$ ，则 $P(A \mid B) > P(A)$   
(D) 若 $P(A \mid A \cup B) > P(\overline{A} \mid A \cup B)$ , 则 $P(A) > P(B)$ .', 'E:\数学自用\数据资料\真题\按年份整理\2021\按题拆分\真题\第08题\题目.md', '2021\按题拆分\真题\第08题\题目.md', 0, 'ok', '2021 真题 第8题 8）设 $a,b$ 为随机事件，且 $0 <   p(b) <   1$ ，下列命题中为假命题的是（ ）.

(a) 若 $p(a \mid b) = p(a)$ ，则 $p(a \mid \overline{b}) = p(a)$   
(b) 若 $p(a \mid b) > p(a)$ , 则 $p(\overline{a} \mid \overline{b}) > p(\overline{a})$   
(c) 若 $p(a \mid b) > p(a \mid \overline{b})$ ，则 $p(a \mid b) > p(a)$   
(d) 若 $p(a \mid a \cup b) > p(\overline{a} \mid a \cup b)$ , 则 $p(a) > p(b)$ .');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2021_main_q08', 'math1_2021_main_q08', 2021, 8, 8, 7, '（8）【答案】 (D).

【解】由 $P(A\mid B) = P(A)$ 得 $P(AB) = P(A)P(B)$ ，即事件 $A,B$ 独立，

于是 $P(A|\overline{B}) = \frac{P(A\overline{B})}{P(\overline{B})} = \frac{P(A)P(\overline{B})}{P(\overline{B})} = P(A)$

由 $P(A\mid B) > P(A)$ 得 $P(AB) > P(A)P(B)$

从而 $P(\overline{A}|\overline{B}) = \frac{P(\overline{A}\overline{B})}{P(\overline{B})} = \frac{1 - P(A) - P(B) + P(AB)}{1 - P(B)}$

$$
> \frac {1 - P (A) - P (B) + P (A) P (B)}{1 - P (B)} = 1 - P (A) = P (\overline {{A}});
$$

由 $P(A|B) > P(A|\overline{B})$ 得 $\frac{P(AB)}{P(B)} >\frac{P(A) - P(AB)}{1 - P(B)}$ 整理得 $P(AB) > P(A)P(B)$ 则 $P(A|B) = \frac{P(AB)}{P(B)} >\frac{P(A)P(B)}{P(B)} = P(A)$ ，应选(D).', 'E:\数学自用\数据资料\真题\按年份整理\2021\解析\2021年解析.md', 'ok', 'year_question_no', 0.17, '2021:8', 8, 0.17);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2021_main_q09', 'math1', 2021, '真题', 'main', 9, '9）设 $(X_{1},Y_{1}),(X_{2},Y_{2}),\dots ,(X_{n},Y_{n})$ 为来自总体 $N(\mu_1,\mu_2;\sigma_1^2,\sigma_2^2;\rho)$ 的简单随机样本，

令 $\theta = \mu_1 - \mu_2, \overline{X} = \frac{1}{n}\sum_{i=1}^{n} X_i, \overline{Y} = \frac{1}{n}\sum_{i=1}^{n} Y_i, \hat{\theta} = \overline{X} - \overline{Y}$ , 则（ ）.

(A) $\hat{\theta}$ 是 $\theta$ 的无偏估计， $D(\hat{\theta}) = \frac{\sigma_1^2 + \sigma_2^2}{n}$   
(B) $\hat{\theta}$ 不是 $\theta$ 的无偏估计， $D(\hat{\theta}) = \frac{\sigma_1^2 + \sigma_2^2}{n}$   
(C) $\hat{\theta}$ 是 $\theta$ 的无偏估计， $D(\hat{\theta}) = \frac{\sigma_1^2 + \sigma_2^2 - 2\rho\sigma_1\sigma_2}{n}$   
(D) $\hat{\theta}$ 不是 $\theta$ 的无偏估计， $D(\hat{\theta}) = \frac{\sigma_1^2 + \sigma_2^2 - 2\rho\sigma_1\sigma_2}{n}$', 'E:\数学自用\数据资料\真题\按年份整理\2021\按题拆分\真题\第09题\题目.md', '2021\按题拆分\真题\第09题\题目.md', 0, 'ok', '2021 真题 第9题 9）设 $(x_{1},y_{1}),(x_{2},y_{2}),\dots ,(x_{n},y_{n})$ 为来自总体 $n(\mu_1,\mu_2;\sigma_1^2,\sigma_2^2;\rho)$ 的简单随机样本，

令 $\theta = \mu_1 - \mu_2, \overline{x} = \frac{1}{n}\sum_{i=1}^{n} x_i, \overline{y} = \frac{1}{n}\sum_{i=1}^{n} y_i, \hat{\theta} = \overline{x} - \overline{y}$ , 则（ ）.

(a) $\hat{\theta}$ 是 $\theta$ 的无偏估计， $d(\hat{\theta}) = \frac{\sigma_1^2 + \sigma_2^2}{n}$   
(b) $\hat{\theta}$ 不是 $\theta$ 的无偏估计， $d(\hat{\theta}) = \frac{\sigma_1^2 + \sigma_2^2}{n}$   
(c) $\hat{\theta}$ 是 $\theta$ 的无偏估计， $d(\hat{\theta}) = \frac{\sigma_1^2 + \sigma_2^2 - 2\rho\sigma_1\sigma_2}{n}$   
(d) $\hat{\theta}$ 不是 $\theta$ 的无偏估计， $d(\hat{\theta}) = \frac{\sigma_1^2 + \sigma_2^2 - 2\rho\sigma_1\sigma_2}{n}$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2021_main_q09', 'tag_级数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2021_main_q09', 'math1_2021_main_q09', 2021, 9, 9, 8, '（9）【答案】 (C).

【解】 $\overline{X} \sim N\left(\mu_1, \frac{\sigma_1^2}{n}\right), \overline{Y} \sim N\left(\mu_2, \frac{\sigma_2^2}{n}\right)$

则 $E(\hat{\theta}) = E(\overline{X}) - E(\overline{Y}) = \mu_1 - \mu_2 = \theta$

$$
\begin{array}{l} D (\hat {\theta}) = D (\bar {X} - \bar {Y}) = D (\bar {X}) + D (\bar {Y}) - 2 \operatorname {C o v} (\bar {X}, \bar {Y}) \\ = \frac {\sigma_ {1} ^ {2}}{n} + \frac {\sigma_ {2} ^ {2}}{n} - \frac {2}{n} \left[ \operatorname {C o v} \left(X _ {1}, \bar {Y}\right) + \operatorname {C o v} \left(X _ {2}, \bar {Y}\right) + \dots + \operatorname {C o v} \left(X _ {n}, \bar {Y}\right) \right] \\ = \frac {\sigma_ {1} ^ {2}}{n} + \frac {\sigma_ {2} ^ {2}}{n} - \frac {2}{n ^ {2}} \left[ \operatorname {C o v} \left(X _ {1}, Y _ {1}\right) + \operatorname {C o v} \left(X _ {2}, Y _ {2}\right) + \dots + \operatorname {C o v} \left(X _ {n}, Y _ {n}\right) \right] \\ = \frac {\sigma_ {1} ^ {2}}{n} + \frac {\sigma_ {2} ^ {2}}{n} - \frac {2}{n ^ {2}} \cdot n \rho \sigma_ {1} \sigma_ {2} = \frac {\sigma_ {1} ^ {2} + \sigma_ {2} ^ {2} - 2 \rho \sigma_ {1} \sigma_ {2}}{n}, \text {应 选 (C)}. \\ \end{array}
$$', 'E:\数学自用\数据资料\真题\按年份整理\2021\解析\2021年解析.md', 'ok', 'year_question_no', 0.205, '2021:9', 9, 0.205);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2021_main_q10', 'math1', 2021, '真题', 'main', 10, '10）设 $X_{1}, X_{2}, \dots, X_{16}$ 是来自总体 $N(\mu, 4)$ 的简单随机样本，考虑假设检验问题： $H_{0}:\mu \leqslant 10$ ， $H_{1}:\mu > 10, \Phi(x)$ 表示标准正态分布函数，若该检验问题的拒绝域为 $W = \{\overline{X} \geqslant 11\}$ ，其中 $\overline{X} = \frac{1}{16}\sum_{i=1}^{16} X_{i}$ ，则 $\mu = 11.5$ 时，该检验犯第二类错误的概率为（ ）.

(A) $1 - \Phi (0.5)$

(B) $1 - \Phi (1)$

(C) $1 - \Phi (1.5)$

(D) $1 - \Phi (2)$

二、填空题（11～16小题，每小题5分，共30分.请将答案写在题中的横线上.）', 'E:\数学自用\数据资料\真题\按年份整理\2021\按题拆分\真题\第10题\题目.md', '2021\按题拆分\真题\第10题\题目.md', 0, 'ok', '2021 真题 第10题 10）设 $x_{1}, x_{2}, \dots, x_{16}$ 是来自总体 $n(\mu, 4)$ 的简单随机样本，考虑假设检验问题： $h_{0}:\mu \leqslant 10$ ， $h_{1}:\mu > 10, \phi(x)$ 表示标准正态分布函数，若该检验问题的拒绝域为 $w = \{\overline{x} \geqslant 11\}$ ，其中 $\overline{x} = \frac{1}{16}\sum_{i=1}^{16} x_{i}$ ，则 $\mu = 11.5$ 时，该检验犯第二类错误的概率为（ ）.

(a) $1 - \phi (0.5)$

(b) $1 - \phi (1)$

(c) $1 - \phi (1.5)$

(d) $1 - \phi (2)$

二、填空题（11～16小题，每小题5分，共30分.请将答案写在题中的横线上.）');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2021_main_q10', 'tag_级数');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2021_main_q10', 'tag_概率');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2021_main_q10', 'math1_2021_main_q10', 2021, 10, 10, 9, '（10）【答案】 (B).

【解】由题 $\overline{X}\sim N\left(11.5,\frac{1}{4}\right)$ ，或 $\frac{\overline{X} - 11.5}{\frac{1}{2}}\sim N(0,1),$

犯第二类错误的概率为

$$
P \{\overline {{X}} <   1 1 \} = P \left\{\frac {\overline {{X}} - 1 1 . 5}{\frac {1}{2}} <   - 1 \right\} = \Phi (- 1) = 1 - \Phi (1),
$$

应选（B）.

# 二、填空题', 'E:\数学自用\数据资料\真题\按年份整理\2021\解析\2021年解析.md', 'ok', 'year_question_no', 0.098, '2021:10', 10, 0.098);
