INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2021_main_q22', 'math1_2021_main_q22', 2021, 22, 22, 21, '（22）【解】（I） $X$ 的密度函数为

$$
f _ {X} (x) = \left\{ \begin{array}{l l} 1, & 0 <   x <   1, \\ 0, & \text {其 他}. \end{array} \right.
$$

（Ⅱ）由 $Y = 2 - X$ 得 $Z = \frac{2 - X}{X}$

$$
F _ {Z} (z) = P \{Z \leqslant z \} = P \left\{\frac {2}{X} - 1 \leqslant z \right\},
$$

当 $z < 1$ 时， $F_{Z}(z) = 0$

当 $z \geqslant 1$ 时， $F_{Z}(z) = P\left\{X \geqslant \frac{2}{z + 1}\right\} = \int_{\frac{2}{z + 1}}^{1} 1 \, \mathrm{d}x = 1 - \frac{2}{z + 1} = \frac{z - 1}{z + 1}$ ，

即 $F_{Z}(z) = \left\{ \begin{array}{ll}0, & z < 1,\\ \frac{z - 1}{z + 1}, & z\geqslant 1, \end{array} \right.$

故 $Z$ 的密度函数为

$$
f _ {Z} (z) = \left\{ \begin{array}{l l} 0, & z \leqslant 1, \\ \frac {2}{(z + 1) ^ {2}}, & z > 1. \end{array} \right.
$$

$(\text{III}) E\left(\frac{X}{Y}\right) = E\left(\frac{X}{2 - X}\right) = \int_{0}^{1} \frac{x}{2 - x} \mathrm{d}x = 2 \ln 2 - 1.$', 'E:\数学自用\数据资料\真题\按年份整理\2021\解析\2021年解析.md', 'ok', 'year_question_no', 0.016, '2021:22', 10, 0.016);
