INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2023_main_q04', 'tag_级数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2023_main_q04', 'math1_2023_main_q04', 2023, 4, 4, 4, '(4) 已知 $a_{n} < b_{n}(n = 1,2,\dots)$ ，若级数 $\sum_{n=1}^{\infty} a_{n}$ 与 $\sum_{n=1}^{\infty} b_{n}$ 均收敛，则“ $\sum_{n=1}^{\infty} a_{n}$ 绝对收敛”是“ $\sum_{n=1}^{\infty} b_{n}$ 绝对收敛的”（）

(A) 充分必要条件

(B) 充分不必要条件

(C) 必要不充分条件

(D) 既不充分也不必要条件

【答案】(A)

【解析】由条件知 $\sum_{n=1}^{\infty}(b_n - a_n)$ 为收敛的正项级数，进而绝对收敛；

设 $\sum_{n=1}^{\infty} a_n$ 绝对收敛，则由 $|b_n| = |b_n - a_n + a_n| \leq |b_n - a_n| + |a_n|$ 与比较判别法，得 $\sum_{n=1}^{\infty} b_n$ 绝对收敛；

设 $\sum_{n=1}^{\infty} b_n$ 绝对收敛，则由 $|a_n| = |a_n - b_n + b_n| \leq |b_n - a_n| + |b_n|$ 与比较判别法，得 $\sum_{n=1}^{\infty} a_n$ 绝对收敛.', 'E:\数学自用\数据资料\真题\按年份整理\2023\解析\2023年解析.md', 'ok', 'year_question_no', 1, '2023:4', 4, 1);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2023_main_q05', 'math1', 2023, '真题', 'main', 5, '5. 已知 $n$ 阶矩阵 $A , B , C$ 满足 $A B C = O , E$ $n$ 阶单位矩阵. 记矩阵 $\left[ \begin{array} { c c } { { O } } & { { A } } \\ { { B C } } & { { E } } \end{array} \right] , \left[ \begin{array} { c c } { { A B } } & { { C } } \\ { { O } } & { { E } } \end{array} \right] .$ $\left[ \begin{array} { c c } { E } & { A B } \\ { A B } & { O } \end{array} \right]$ 的秩分别为 $r _ { 1 } , r _ { 2 } , r _ { 3 }$ , 则( )

A. $r _ { 1 } \le r _ { 2 } \le r _ { 3 }$

B. $r _ { 1 } \leq r _ { 3 } \leq r _ { 2 }$

C. r3 ≤ r2 ≤ r1

$\mathsf { D } . \ r _ { 2 } \leq r _ { 1 } \leq r _ { 3 }$', 'E:\数学自用\数据资料\真题\按年份整理\2023\按题拆分\真题\第05题\题目.md', '2023\按题拆分\真题\第05题\题目.md', 0, 'ok', '2023 真题 第5题 5. 已知 $n$ 阶矩阵 $a , b , c$ 满足 $a b c = o , e$ $n$ 阶单位矩阵. 记矩阵 $\left[ \begin{array} { c c } { { o } } & { { a } } \\ { { b c } } & { { e } } \end{array} \right] , \left[ \begin{array} { c c } { { a b } } & { { c } } \\ { { o } } & { { e } } \end{array} \right] .$ $\left[ \begin{array} { c c } { e } & { a b } \\ { a b } & { o } \end{array} \right]$ 的秩分别为 $r _ { 1 } , r _ { 2 } , r _ { 3 }$ , 则( )

a. $r _ { 1 } \le r _ { 2 } \le r _ { 3 }$

b. $r _ { 1 } \leq r _ { 3 } \leq r _ { 2 }$

c. r3 ≤ r2 ≤ r1

$\mathsf { d } . \ r _ { 2 } \leq r _ { 1 } \leq r _ { 3 }$');
