INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2023_main_q05', 'math1_2023_main_q05', 2023, 5, 5, 5, '(5) 已知 $n$ 阶矩阵 $A, B, C$ 满足 $ABC = 0$ , $E$ 为 $n$ 阶单位矩阵, 记矩阵 $\left( \begin{array}{cc}0 & A \\ BC & E\end{array} \right)$ , $\left( \begin{array}{cc}AB & C \\ 0 & E\end{array} \right)$ , $\left( \begin{array}{cc}E & AB \\ AB & 0\end{array} \right)$ 的秩分别为 $\gamma_1, \gamma_2, \gamma_3$ , 则( )

(A) $\gamma_{1} \leq \gamma_{2} \leq \gamma_{3}$

(B) $\gamma_{1} \leq \gamma_{3} \leq \gamma_{2}$

(C) $\gamma_{3} \leq \gamma_{1} \leq \gamma_{2}$

(D) $\gamma_{2} \leq \gamma_{1} \leq \gamma_{3}$

【答案】(B)

【解析】因初等变换不改变矩阵的秩，

$$
\begin{array}{l} r _ {1} = r \left[ \begin{array}{c c} 0 & A \\ B C & E \end{array} \right] = r \left[ \begin{array}{c c} - A B C & 0 \\ B C & E \end{array} \right] = r \left[ \begin{array}{c c} 0 & 0 \\ B C & E \end{array} \right] = n, \\ r _ {2} = r \left[ \begin{array}{c c} A B & C \\ 0 & E \end{array} \right] = r \left[ \begin{array}{c c} A B & 0 \\ 0 & E \end{array} \right] = r (A B) + n, \\ r _ {3} = r \left[ \begin{array}{c c} E & A B \\ A B & 0 \end{array} \right] = r \left[ \begin{array}{c c} E & 0 \\ A B & - A B A B \end{array} \right] = r \left[ \begin{array}{c c} E & 0 \\ 0 & - A B A B \end{array} \right] = r (A B A B) + n, \\ \end{array}
$$

故选(B).', 'E:\数学自用\数据资料\真题\按年份整理\2023\解析\2023年解析.md', 'ok', 'year_question_no', 0.6, '2023:5', 5, 0.6);
