INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2023_main_q08', 'math1_2023_main_q08', 2023, 8, 8, 10, '(8) 设随机变量 $X$ 服从参数为 1 的泊松分布, 则 $E(|X - EX|) = (\quad)$

(A) $\frac{1}{e}$

(B) $\frac{1}{2}$

(C) $\frac{2}{e}$

(D) 1

【答案】(C)

【解析】由题可知 $E(X) = 1$ ，所以 $\mid X - EX\mid = \left\{ \begin{array}{ll}1, & X = 0\\ X - 1, & X = 1,2,\dots \end{array} \right.$

故 $E(|X - EX|) = 1\cdot P\{X = 0\} +\sum_{k = 1}^{\infty}(k - 1)P\{X = k\}$

$$
\begin{array}{l} = \frac {1}{e} + \sum_ {k = 0} ^ {\infty} (k - 1) P \{X = k \} - (0 - 1) P \{X = 0 \} \\ = \frac {1}{e} + E (X - 1) - (0 - 1) \frac {1}{e} = \frac {2}{e}, \\ \end{array}
$$

故选(C).', 'E:\数学自用\数据资料\真题\按年份整理\2023\解析\2023年解析.md', 'ok', 'year_question_no', 0.733, '2023:8', 8, 0.733);
