INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2023_main_q09', 'tag_级数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2023_main_q09', 'math1_2023_main_q09', 2023, 9, 9, 11, '(9) 设 $X_{1}, X_{2}, \dots, X_{n}$ 为来自总体 $N(\mu_{1}, \sigma^{2})$ 的简单随机样本， $Y_{1}, Y_{2}, \dots, Y_{m}$ 为来自

总体 $N(\mu_2, 2\sigma^2)$ 的简单随机样本，且两样本相互独立，记 $\overline{X} = \frac{1}{n}\sum_{i=1}^{n} X_i$ ， $\overline{Y} = \frac{1}{m}\sum_{i=1}^{m} Y_i$ ， $S_1^2 = \frac{1}{n-1}\sum_{i=1}^{n} (X_i - \overline{X})^2$ ， $S_2^2 = \frac{1}{m-1}\sum_{i=1}^{m} (Y_i - \overline{Y})^2$ ，则（

(A) $\frac{S_1^2}{S_2^2} \sim F(n, m)$

(B) $\frac{S_1^2}{S_2^2} \sim F(n - 1, m - 1)$

$\left(\mathbb{C}\right)\frac{2S_1^2}{S_2^2}\sim F(n,m)$

$\frac{2S_1^2}{S_2^2}\sim F(n - 1,m - 1)$

【答案】(D)

【解析】 $X_{1}, X_{2}, \ldots, X_{n}$ 的样本方差 $S_{1}^{2} = \frac{1}{n - 1} \sum_{i=1}^{n} \left(X_{i} - \overline{X}\right)^{2}$ ,

$Y_{1}, Y_{2}, \ldots, Y_{n}$ 的样本方差 $S_{2}^{2} = \frac{1}{m - 1} \sum_{i = 1}^{m} \left(Y_{i} - \overline{Y}\right)^{2}$ ，则 $\frac{(n - 1) S_{1}^{2}}{\sigma^{2}} \sim \chi^{2}(n - 1)$ ，

$\frac{(m - 1)S_2^2}{2\sigma^2}\sim \chi^2 (m - 1)$ ，两个样本相互独立，

所以 $\frac{\frac{(n - 1)S_1^2}{\sigma^2} / (n - 1)}{\frac{(m - 1)S_2^2}{2\sigma^2} / (m - 1)} = \frac{S_1^2 / \sigma^2}{S_2^2 / 2\sigma^2} = \frac{2S_1^2}{S_2^2}\sim F(n - 1,m - 1),$

故选(D).', 'E:\数学自用\数据资料\真题\按年份整理\2023\解析\2023年解析.md', 'ok', 'year_question_no', 0.889, '2023:9', 9, 0.889);
