INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2023_main_q10', 'math1_2023_main_q10', 2023, 10, 10, 12, '(10) 设 $X_{1}, X_{2}$ 为来自总体 $N(\mu, \sigma^{2})$ 的简单随机样本，其中 $\sigma (\sigma > 0)$ 是未知参数。若 $\hat{\sigma} = a|X_1 - X_2|$ 为 $\sigma$ 的无偏估计，则 $a = (\quad)$

(A) $\frac{\sqrt{\pi}}{2}$

(B) $\frac{\sqrt{2\pi}}{2}$

(C) $\sqrt{\pi}$

(D) $\sqrt{2\pi}$

【答案】(A)

【解析】由题可知 $X_{1} - X_{2}\sim N(0,2\sigma^{2})$

令 $Y = X_{1} - X_{2}$ ，则 $Y$ 的概率密度为 $f(y) = \frac{1}{\sqrt{2\pi}\sqrt{2}\sigma} e^{-\frac{y^2}{2\cdot 2\sigma^2}}.$

![](images/1622cd80072508365fb526152d02423b099297ea655a11ee58f938ed5c76b917.jpg)

$$
\begin{array}{l} E (| Y |) = \int_ {- \infty} ^ {+ \infty} | y | \frac {1}{\sqrt {2 \pi} \sqrt {2} \sigma} e ^ {- \frac {y ^ {2}}{2 \cdot 2 \sigma^ {2}}} d y = \frac {2}{\sqrt {2 \pi} \sqrt {2} \sigma} \int_ {0} ^ {+ \infty} y e ^ {- \frac {y ^ {2}}{4 \sigma^ {2}}} d y = \frac {2 \sigma}{\sqrt {\pi}}, \\ E (a \mid X _ {1} - X _ {2} |) = a E (| Y |) = a \frac {2 \sigma}{\sqrt {\pi}}. \\ \end{array}
$$

由 $\hat{\sigma} = a|X_1 - X_2|$ 为 $\sigma$ 的无偏估计，有 $E(\hat{\sigma}) = \sigma$ ，得 $a = \frac{\sqrt{\pi}}{2}$ 故选(A).

# 二、填空题: $11 \sim 16$ 小题, 每小题 5 分, 共 30 分.', 'E:\数学自用\数据资料\真题\按年份整理\2023\解析\2023年解析.md', 'ok', 'year_question_no', 0.726, '2023:10', 10, 0.726);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2023_main_q11', 'math1', 2023, '真题', 'main', 11, '11. 当 $x \to 0$ 时, 函数 $f ( x ) = a x + b x ^ { 2 } + \ln ( 1 + x )$ 与 $g ( x ) = \mathrm { e } ^ { x ^ { 2 } } - \cos x$ 是等价无穷小, 则 $a b =$', 'E:\数学自用\数据资料\真题\按年份整理\2023\按题拆分\真题\第11题\题目.md', '2023\按题拆分\真题\第11题\题目.md', 0, 'ok', '2023 真题 第11题 11. 当 $x \to 0$ 时, 函数 $f ( x ) = a x + b x ^ { 2 } + \ln ( 1 + x )$ 与 $g ( x ) = \mathrm { e } ^ { x ^ { 2 } } - \cos x$ 是等价无穷小, 则 $a b =$');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2023_main_q11', 'math1_2023_main_q11', 2023, 11, 11, 13, '(11) 当 $x \to 0$ 时，函数 $f(x) = ax + bx^2 + \ln (1 + x)$ 与 $g(x) = e^{x^2} - \cos x$ 是等价无穷小，则 $ab = \_$

【答案】-2

【解析】 $\lim_{x\to 0}\frac{f(x)}{g(x)} = \lim_{x\to 0}\frac{ax + bx^2 + \ln(1 + x)}{e^{x^2} - \cos x} = \lim_{x\to 0}\frac{ax + bx^2 + x - \frac{1}{2}x^2 + o(x^2)}{1 + x^2 + o(x^2) - \left[1 - \frac{1}{2}x^2 + o(x^2)\right]} = 1,$

可得 $a + 1 = 0$ ， $b - \frac{1}{2} = \frac{3}{2}$ 即 $a = -1,b = 2$ 故 $ab = -2$', 'E:\数学自用\数据资料\真题\按年份整理\2023\解析\2023年解析.md', 'ok', 'year_question_no', 1, '2023:11', 11, 1);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2023_main_q12', 'math1', 2023, '真题', 'main', 12, '12. 曲面 $z = x + 2 y + \ln { \left( 1 + x ^ { 2 } + y ^ { 2 } \right) }$ 在点 $( 0 , 0 , 0 )$ 处的切平面方程为', 'E:\数学自用\数据资料\真题\按年份整理\2023\按题拆分\真题\第12题\题目.md', '2023\按题拆分\真题\第12题\题目.md', 0, 'ok', '2023 真题 第12题 12. 曲面 $z = x + 2 y + \ln { \left( 1 + x ^ { 2 } + y ^ { 2 } \right) }$ 在点 $( 0 , 0 , 0 )$ 处的切平面方程为');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2023_main_q12', 'math1_2023_main_q12', 2023, 12, 12, 14, '(12) 曲面 $z = x + 2y + \ln (1 + x^2 + y^2)$ 在点 $(0,0,0)$ 处的切平面方程为

【答案】 $x + 2y - z = 0$

【解析】 $F(x,y,z) = x + 2y + \ln (1 + x^2 +y^2) - z,$

$$
\mathbf {n} = \left(F _ {x} ^ {\prime}, F _ {y} ^ {\prime}, F _ {z} ^ {\prime}\right) = \left(1 + \frac {2 x}{1 + x ^ {2} + y ^ {2}}, 2 + \frac {2 y}{1 + x ^ {2} + y ^ {2}}, - 1\right),
$$

即在点 $(0,0,0)$ 处的法向量为 $(1,2,-1)$ ，即切平面方程为 $x + 2y - z = 0$', 'E:\数学自用\数据资料\真题\按年份整理\2023\解析\2023年解析.md', 'ok', 'year_question_no', 1, '2023:12', 12, 1);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2023_main_q13', 'math1', 2023, '真题', 'main', 13, '13. 设 $f ( x )$ 是周期为 2 的周期函数, 且 $f ( x ) \ = \ 1 - x , x \ \in \ [ 0 , 1 ]$ . 若 $f ( x ) = { \frac { a _ { 0 } } { 2 } } + \sum _ { n = 1 } ^ { \infty } a _ { n } \cos n \pi x$ , 则$\sum _ { n = 1 } ^ { \infty } a _ { 2 n } = \qquad \quad .$', 'E:\数学自用\数据资料\真题\按年份整理\2023\按题拆分\真题\第13题\题目.md', '2023\按题拆分\真题\第13题\题目.md', 0, 'ok', '2023 真题 第13题 13. 设 $f ( x )$ 是周期为 2 的周期函数, 且 $f ( x ) \ = \ 1 - x , x \ \in \ [ 0 , 1 ]$ . 若 $f ( x ) = { \frac { a _ { 0 } } { 2 } } + \sum _ { n = 1 } ^ { \infty } a _ { n } \cos n \pi x$ , 则$\sum _ { n = 1 } ^ { \infty } a _ { 2 n } = \qquad \quad .$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2023_main_q13', 'tag_级数');
INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2023_main_q13', 'math1_2023_main_q13', 2023, 13, 13, 15, '(13) 设 $f(x)$ 为周期为 2 的周期函数，且 $f(x) = 1 - x, x \in [0,1]$ ，若

$$
f (x) = \frac {a _ {0}}{2} + \sum_ {n = 1} ^ {\infty} a _ {n} \cos n \pi x , \text {则} \sum_ {n = 1} ^ {\infty} a _ {2 n} = \underline {{\quad}}.
$$

【答案】0

【解析】由 $f(x)$ 展开为余弦级数知， $f(x)$ 为偶函数.由傅里叶系数计算公式有

$$
\begin{array}{l} a _ {n} = 2 \int_ {0} ^ {1} (1 - x) \cos n \pi x d x \\ = 2 \left(\int_ {0} ^ {1} \cos n \pi x d x - \int_ {0} ^ {1} x \cos n \pi x d x\right) \\ = 2 \left(\frac {1}{n \pi} \sin n \pi x \Bigg | _ {0} ^ {1} - \frac {1}{n \pi} \int_ {0} ^ {1} x d \sin n \pi x\right) \\ = - \frac {2}{n \pi} \int_ {0} ^ {1} x d \sin n \pi x \\ = \frac {- 2}{n \pi} \left(x \sin n \pi x \big | _ {0} ^ {1} - \int_ {0} ^ {1} \sin n \pi x d x\right) \\ = \frac {2}{n \pi} \int_ {0} ^ {1} \sin n \pi x d x \\ = \frac {- 2}{n ^ {2} \pi^ {2}} \cos n \pi x | _ {0} ^ {1} \\ = \frac {- 2}{n ^ {2} \pi^ {2}} (\cos n \pi - 1). \\ \end{array}
$$

故 $a_{2n} = \frac{-1}{2n^2\pi^2}\left(\cos 2n\pi -1\right) = \frac{-1}{2n^2\pi^2}\left(1 - 1\right) = 0.$', 'E:\数学自用\数据资料\真题\按年份整理\2023\解析\2023年解析.md', 'ok', 'year_question_no', 0.921, '2023:13', 13, 0.921);
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2023_main_q14', 'math1', 2023, '真题', 'main', 14, '14. 设连续函数 $f ( x )$ 满足: $f ( x + 2 ) - f ( x ) = x , \int _ { 0 } ^ { 2 } f ( x ) \mathrm { d } x = 0$ $\int _ { 1 } ^ { 3 } f ( x ) \mathrm { d } x = _ { - }$', 'E:\数学自用\数据资料\真题\按年份整理\2023\按题拆分\真题\第14题\题目.md', '2023\按题拆分\真题\第14题\题目.md', 0, 'ok', '2023 真题 第14题 14. 设连续函数 $f ( x )$ 满足: $f ( x + 2 ) - f ( x ) = x , \int _ { 0 } ^ { 2 } f ( x ) \mathrm { d } x = 0$ $\int _ { 1 } ^ { 3 } f ( x ) \mathrm { d } x = _ { - }$');
