INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2023_main_q14', 'math1_2023_main_q14', 2023, 14, 14, 16, '(14) 设连续函数 $f(x)$ 满足 $f(x + 2) - f(x) = x, \int_0^2 f(x) dx = 0$ ，则 $\int_1^3 f(x) dx =$

【答案】 $\frac{1}{2}$

【解析】 $\int_{1}^{3}f(x)dx = \int_{1}^{2}f(x)dx + \int_{2}^{3}f(x)dx$

$$
\begin{array}{l} = \int_ {1} ^ {2} f (x) d x + \int_ {0} ^ {1} f (t + 2) d t (\text {令} x = t + 2) \\ = \int_ {1} ^ {2} f (x) d x + \int_ {0} ^ {1} f (x + 2) d x \\ = \int_ {1} ^ {2} f (x) d x + \int_ {0} ^ {1} [ f (x) + x ] d x \\ = \int_ {1} ^ {2} f (x) d x + \int_ {0} ^ {1} f (x) d x + \int_ {0} ^ {1} x d x \\ = \int_ {0} ^ {2} f (x) d x + \int_ {0} ^ {1} x d x \\ = \int_ {0} ^ {1} x d x \\ \end{array}
$$

$$
= \frac {1}{2}.
$$', 'E:\数学自用\数据资料\真题\按年份整理\2023\解析\2023年解析.md', 'ok', 'year_question_no', 0.96, '2023:14', 14, 0.96);
