INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2023_main_q15', 'math1_2023_main_q15', 2023, 15, 15, 17, '(15) 已知向量 $\alpha_{1} = \begin{pmatrix} 1 \\ 0 \\ 1 \\ 1 \end{pmatrix}, \alpha_{2} = \begin{pmatrix} -1 \\ -1 \\ 0 \\ 1 \end{pmatrix}, \alpha_{3} = \begin{pmatrix} 0 \\ 1 \\ -1 \\ 1 \end{pmatrix}, \beta = \begin{pmatrix} 1 \\ 1 \\ 1 \\ -1 \end{pmatrix}, \gamma = k_{1}\alpha_{1} + k_{2}\alpha_{2} + k_{3}\alpha_{3}$ ,

若 $\gamma^T\alpha_i = \beta^T\alpha_i(i = 1,2,3)$ ，则 $k_{1}^{2} + k_{2}^{2} + k_{3}^{2} =$

【答案】 $\frac{11}{9}$

【解析】

$$
\gamma^ {T} \alpha_ {1} = \beta^ {T} \alpha_ {1} = 1 \Rightarrow k _ {1} \alpha_ {1} ^ {T} \alpha_ {1} + k _ {2} \alpha_ {2} ^ {T} \alpha_ {1} + k _ {3} \alpha_ {3} ^ {T} \alpha_ {1} = 1 \Rightarrow k _ {1} \cdot 3 + k _ {2} \cdot 0 + k _ {3} \cdot 0 = 1 \Rightarrow k _ {1} = \frac {1}{3}.
$$

同理 $k_{2} = -1,k_{3} = -\frac{1}{3}$

所以， $k_{1}^{2} + k_{2}^{2} + k_{3}^{2} = \frac{11}{9}$', 'E:\数学自用\数据资料\真题\按年份整理\2023\解析\2023年解析.md', 'ok', 'year_question_no', 1, '2023:15', 15, 1);
