INSERT OR REPLACE INTO solutions(solution_id, question_id, year, question_no, chunk_no, source_chunk_index, content_md, source_path, quality_status, map_method, match_score, direct_key, best_chunk_no, best_score) VALUES ('sol_math1_2023_main_q16', 'math1_2023_main_q16', 2023, 16, 16, 18, '(16) 设随机变量 $X$ 与 $Y$ 相互独立，且 $X \sim B\left(1, \frac{1}{3}\right), Y \sim B\left(2, \frac{1}{2}\right)$ 则 $P\{X = Y\} =$

【答案】 $\frac{1}{3}$

【解析】因为 $X \sim B\left(1, \frac{1}{3}\right)$ ，所以 $X = 0, 1$

$$
Y \sim B \left(2, \frac {1}{2}\right), \text {所 以} Y = 0, 1, 2.
$$

又因为 $X$ 与 $Y$ 相互独立，所以

$$
\begin{array}{l} P \{X = Y \} = P \{X = 0, Y = 0 \} + P \{X = 1, Y = 1 \} \\ = P \{X = 0 \} P \{Y = 0 \} + P \{X = 1 \} P \{Y = 1 \} \\ = \frac {2}{3} C _ {2} ^ {0} \left(\frac {1}{2}\right) ^ {2} + \frac {1}{3} C _ {2} ^ {1} \left(\frac {1}{2}\right) ^ {2} = \frac {1}{3}. \\ \end{array}
$$

