INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2025_main_q01', 'math1', 2025, '真题', 'main', 1, '1．已知函数 $f { \big ( } x { \big ) } = \int _ { 0 } ^ { x } \mathbf e ^ { t ^ { 2 } } \sin t \mathrm d t$ ， $g \left( x \right) = \int _ { 0 } ^ { x } \mathrm { e } ^ { t ^ { 2 } } \mathrm { d } t \bullet \sin ^ { 2 } x$ ，则

A． $x = 0$ 是 $f ( x )$ 的极值点，也是 $g \left( x \right)$ 的极值点  
B． $x = 0$ 是 $f ( x )$ 的极值点， $\left( 0 , 0 \right)$ 是曲线 $y = g \left( x \right)$ 的拐点  
C． $x = 0$ 是 $f ( x )$ 的极值点， $\left( 0 , 0 \right)$ 是曲线 $y = f ( x )$ 的拐点．  
D． $\left( 0 , 0 \right)$ 是曲线 $y = f ( x )$ 的拐点， $\left( 0 , 0 \right)$ 也是曲线 $y = g \left( x \right)$ 的拐点

【答案】B

【解析】

$$
f ^ {\prime} (x) = e ^ {x ^ {2}} \sin x, f ^ {\prime \prime} (x) = 2 x e ^ {x ^ {2}} \sin x + e ^ {x ^ {2}} \cos x
$$

$$
f ^ {\prime} (0) = 0, f ^ {\prime \prime} (0) = 1 > 0.
$$

$x = 0$ 是 $f ( x )$ 的极值点.

$$
g ^ {\prime} (x) = e ^ {x ^ {2}} \sin^ {2} x + \sin 2 x \int_ {0} ^ {x} e ^ {t ^ {2}} d t,
$$

$$
g ^ {\prime \prime} (x) = e ^ {x ^ {2}} \sin 2 x + 2 x e ^ {x ^ {2}} \sin^ {2} x + \sin 2 x e ^ {x ^ {2}} + 2 \cos 2 x \int_ {0} ^ {x} e ^ {t ^ {2}} d t
$$

$$
g ^ {\prime} (0) = 0, \quad g ^ {\prime \prime} (0) = 0, \quad g ^ {\prime \prime \prime} (0) > 0.
$$

$( 0 , 0 )$ 是 $y = g ( x )$ 的拐点.', 'E:\数学自用\数据资料\真题\按年份整理\2025\按题拆分\真题\第01题\题目.md', '2025\按题拆分\真题\第01题\题目.md', 0, 'ok', '2025 真题 第1题 1．已知函数 $f { \big ( } x { \big ) } = \int _ { 0 } ^ { x } \mathbf e ^ { t ^ { 2 } } \sin t \mathrm d t$ ， $g \left( x \right) = \int _ { 0 } ^ { x } \mathrm { e } ^ { t ^ { 2 } } \mathrm { d } t \bullet \sin ^ { 2 } x$ ，则

a． $x = 0$ 是 $f ( x )$ 的极值点，也是 $g \left( x \right)$ 的极值点  
b． $x = 0$ 是 $f ( x )$ 的极值点， $\left( 0 , 0 \right)$ 是曲线 $y = g \left( x \right)$ 的拐点  
c． $x = 0$ 是 $f ( x )$ 的极值点， $\left( 0 , 0 \right)$ 是曲线 $y = f ( x )$ 的拐点．  
d． $\left( 0 , 0 \right)$ 是曲线 $y = f ( x )$ 的拐点， $\left( 0 , 0 \right)$ 也是曲线 $y = g \left( x \right)$ 的拐点

【答案】b

【解析】

$$
f ^ {\prime} (x) = e ^ {x ^ {2}} \sin x, f ^ {\prime \prime} (x) = 2 x e ^ {x ^ {2}} \sin x + e ^ {x ^ {2}} \cos x
$$

$$
f ^ {\prime} (0) = 0, f ^ {\prime \prime} (0) = 1 > 0.
$$

$x = 0$ 是 $f ( x )$ 的极值点.

$$
g ^ {\prime} (x) = e ^ {x ^ {2}} \sin^ {2} x + \sin 2 x \int_ {0} ^ {x} e ^ {t ^ {2}} d t,
$$

$$
g ^ {\prime \prime} (x) = e ^ {x ^ {2}} \sin 2 x + 2 x e ^ {x ^ {2}} \sin^ {2} x + \sin 2 x e ^ {x ^ {2}} + 2 \cos 2 x \int_ {0} ^ {x} e ^ {t ^ {2}} d t
$$

$$
g ^ {\prime} (0) = 0, \quad g ^ {\prime \prime} (0) = 0, \quad g ^ {\prime \prime \prime} (0) > 0.
$$

$( 0 , 0 )$ 是 $y = g ( x )$ 的拐点.');
