INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2025_main_q02', 'math1', 2025, '真题', 'main', 2, '2．已知级数： $\textcircled { 1 } \sum _ { n = 1 } ^ { \infty } \sin \frac { n ^ { 3 } \pi } { n ^ { 2 } + 1 }$ ； $\textcircled { 2 } \sum _ { n = 1 } ^ { \infty } ( - 1 ) ^ { n } \left( \frac { 1 } { \sqrt [ 3 ] { n ^ { 2 } } } - \tan \frac { 1 } { \sqrt [ 3 ] { n ^ { 2 } } } \right) ;$ $\frac { 1 } { \sqrt [ 3 ] { n ^ { 2 } } }$ ，则 ，

A． $\textcircled{1}$ 与 $\textcircled{2}$ 均条件收敛

B． $\textcircled{1}$ 条件收敛， $\textcircled{2}$ 绝对收敛

C． $\textcircled{1}$ 绝对收敛， $\textcircled{2}$ 条件收敛

