INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2025_main_q05', 'math1', 2025, '真题', 'main', 5, '5．二次型 $f { \left( x _ { _ { 1 } } , x _ { _ { 2 } } , x _ { _ { 3 } } \right) } = x _ { _ { 1 } } ^ { 2 } + 2 x _ { _ { 1 } } x _ { _ { 2 } } + 2 x _ { _ { 1 } } x _ { _ { 3 } }$ 的正 惯性 指数

A．0．

B．1

C．2

D．3．

【答案】B

【解析】

$$
A = \left( \begin{array}{c c c} 1 & 1 & 1 \\ 1 & 0 & 0 \\ 1 & 0 & 0 \end{array} \right)
$$

$$
\left(\lambda E - A\right) = \left(\begin{array}{c c c}\lambda - 1&- 1&- 1\\- 1&\lambda&0\\- 1&0&\lambda\end{array}\right)\rightarrow \left(\begin{array}{c c c}\lambda - 1&- 1&- 1\\0&\lambda&- \lambda\\- 1&0&\lambda\end{array}\right)\rightarrow \lambda \left(\begin{array}{c c c}\lambda - 1&- 1&- 1\\0&1&- 1\\- 1&0&\lambda\end{array}\right)
$$

$$
\begin{array}{l} = \lambda [ \lambda (\lambda - 1) - 1 - 1 ] \\ = \lambda (\lambda^ {2} - \lambda - 2) \\ = \lambda (\lambda - 2) (\lambda + 1) \\ \end{array}
$$

解得

$$
\lambda_ {1} = 0, \lambda_ {2} = 2, \lambda_ {3} = - 1
$$

故正惯性指数为 1，选 B.', 'E:\数学自用\数据资料\真题\按年份整理\2025\按题拆分\真题\第05题\题目.md', '2025\按题拆分\真题\第05题\题目.md', 0, 'ok', '2025 真题 第5题 5．二次型 $f { \left( x _ { _ { 1 } } , x _ { _ { 2 } } , x _ { _ { 3 } } \right) } = x _ { _ { 1 } } ^ { 2 } + 2 x _ { _ { 1 } } x _ { _ { 2 } } + 2 x _ { _ { 1 } } x _ { _ { 3 } }$ 的正 惯性 指数

a．0．

b．1

c．2

d．3．

【答案】b

【解析】

$$
a = \left( \begin{array}{c c c} 1 & 1 & 1 \\ 1 & 0 & 0 \\ 1 & 0 & 0 \end{array} \right)
$$

$$
\left(\lambda e - a\right) = \left(\begin{array}{c c c}\lambda - 1&- 1&- 1\\- 1&\lambda&0\\- 1&0&\lambda\end{array}\right)\rightarrow \left(\begin{array}{c c c}\lambda - 1&- 1&- 1\\0&\lambda&- \lambda\\- 1&0&\lambda\end{array}\right)\rightarrow \lambda \left(\begin{array}{c c c}\lambda - 1&- 1&- 1\\0&1&- 1\\- 1&0&\lambda\end{array}\right)
$$

$$
\begin{array}{l} = \lambda [ \lambda (\lambda - 1) - 1 - 1 ] \\ = \lambda (\lambda^ {2} - \lambda - 2) \\ = \lambda (\lambda - 2) (\lambda + 1) \\ \end{array}
$$

解得

$$
\lambda_ {1} = 0, \lambda_ {2} = 2, \lambda_ {3} = - 1
$$

故正惯性指数为 1，选 b.');
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2025_main_q06', 'math1', 2025, '真题', 'main', 6, '6．设 $\pmb { \alpha } _ { 1 } , \pmb { \alpha } _ { 2 } , \pmb { \alpha } _ { 3 } , \pmb { \alpha } _ { 4 }$ 是 $n$ 维列向量， ${ \pmb { \alpha } } _ { 1 } , { \pmb { \alpha } } _ { 2 }$ 线性无关， ${ \pmb { \alpha } } _ { 1 } , { \pmb { \alpha } } _ { 2 } , { \pmb { \alpha } } _ { 3 }$ 线性相关，且 $\pmb { \alpha } _ { 1 } + \pmb { \alpha } _ { 2 } + \pmb { \alpha } _ { 4 } = \pmb { 0 }$ .在空间直角坐标系 $O - x y z$ 中，关于 $x , y , z$ 的方程组 $x { \pmb { \alpha } } _ { 1 } + y { \pmb { \alpha } } _ { 2 } + z { \pmb { \alpha } } _ { 3 } = { \pmb { \alpha } } _ { 4 }$ 的几何图形是

A．过原点的一个平面

B．过原点的一条直线

C．不过原点的一个平面

D．不过原点的一条直线

【答案】D

【解析】记 $A = \left( \alpha _ { 1 } , \alpha _ { 2 } , \alpha _ { 3 } \right)$ ，由 $\alpha _ { 1 } , \alpha _ { 2 }$ 线性无关， $\mathcal { \alpha } _ { 1 } , \mathcal { \alpha } _ { 2 } , \mathcal { \alpha } _ { 3 }$ 线性相关，可得 $r \left( A \right) = 2$ 。记$\overline { { A } } = \left( A \left| \alpha _ { 4 } \right. \right) = \left( \alpha _ { 1 } , \alpha _ { 2 } , \alpha _ { 3 } , \alpha _ { 4 } \right)$ ，再由 $\alpha _ { 1 } + \alpha _ { 2 } + \alpha _ { 4 } = 0$ ，则 $r \left( { \overline { { A } } } \right) = 2$ 。于是 $A x = \alpha _ { 4 }$ 有无穷多解。则 $x \alpha _ { 1 } + y \alpha _ { 2 } + z \alpha _ { 3 } = \alpha _ { 4 }$ 等价于 $\left( \alpha _ { 1 } , \alpha _ { 2 } , \alpha _ { 3 } \right) \cdot \left( x , y , z \right) ^ { \mathrm { T } } = \alpha _ { 4 }$ ，即 $A \cdot \left( x , y , z \right) ^ { \mathrm { T } } = \alpha _ { 4 }$ 。若过原点，则 $\alpha _ { 4 } = 0$ 与 $\alpha _ { 1 } , \alpha _ { 2 }$ 线性无关矛盾，故不过原点。

$x \alpha _ { 1 } + y \alpha _ { 2 } + z \alpha _ { 3 } = \alpha _ { 4 } \Leftrightarrow \left\{ \begin{array} { c } { { a _ { 1 1 } x + a _ { 1 2 } y + a _ { 1 3 } z = a _ { 1 4 } } } \\ { { a _ { 2 1 } x + a _ { 2 2 } y + a _ { 2 3 } z = a _ { 2 4 } } } \\ { { \ldots } } \\ { { a _ { n 1 } x + a _ { n 2 } y + a _ { n 3 } z = a _ { n 4 } } } \end{array} \right.$ 21 22 23 24 a x a y a z a    + + =     ，由上述分析可知 r ( A) = r ( A ) = 2 ，故 $r \left( A \right) = r \left( { \overline { { A } } } \right) = 2$ 两平面交于一条直线，且不过原点。故选 $\mathrm { D }$ 。', 'E:\数学自用\数据资料\真题\按年份整理\2025\按题拆分\真题\第06题\题目.md', '2025\按题拆分\真题\第06题\题目.md', 0, 'manual_check', '2025 真题 第6题 6．设 $\pmb { \alpha } _ { 1 } , \pmb { \alpha } _ { 2 } , \pmb { \alpha } _ { 3 } , \pmb { \alpha } _ { 4 }$ 是 $n$ 维列向量， ${ \pmb { \alpha } } _ { 1 } , { \pmb { \alpha } } _ { 2 }$ 线性无关， ${ \pmb { \alpha } } _ { 1 } , { \pmb { \alpha } } _ { 2 } , { \pmb { \alpha } } _ { 3 }$ 线性相关，且 $\pmb { \alpha } _ { 1 } + \pmb { \alpha } _ { 2 } + \pmb { \alpha } _ { 4 } = \pmb { 0 }$ .在空间直角坐标系 $o - x y z$ 中，关于 $x , y , z$ 的方程组 $x { \pmb { \alpha } } _ { 1 } + y { \pmb { \alpha } } _ { 2 } + z { \pmb { \alpha } } _ { 3 } = { \pmb { \alpha } } _ { 4 }$ 的几何图形是

a．过原点的一个平面

b．过原点的一条直线

c．不过原点的一个平面

d．不过原点的一条直线

【答案】d

【解析】记 $a = \left( \alpha _ { 1 } , \alpha _ { 2 } , \alpha _ { 3 } \right)$ ，由 $\alpha _ { 1 } , \alpha _ { 2 }$ 线性无关， $\mathcal { \alpha } _ { 1 } , \mathcal { \alpha } _ { 2 } , \mathcal { \alpha } _ { 3 }$ 线性相关，可得 $r \left( a \right) = 2$ 。记$\overline { { a } } = \left( a \left| \alpha _ { 4 } \right. \right) = \left( \alpha _ { 1 } , \alpha _ { 2 } , \alpha _ { 3 } , \alpha _ { 4 } \right)$ ，再由 $\alpha _ { 1 } + \alpha _ { 2 } + \alpha _ { 4 } = 0$ ，则 $r \left( { \overline { { a } } } \right) = 2$ 。于是 $a x = \alpha _ { 4 }$ 有无穷多解。则 $x \alpha _ { 1 } + y \alpha _ { 2 } + z \alpha _ { 3 } = \alpha _ { 4 }$ 等价于 $\left( \alpha _ { 1 } , \alpha _ { 2 } , \alpha _ { 3 } \right) \cdot \left( x , y , z \right) ^ { \mathrm { t } } = \alpha _ { 4 }$ ，即 $a \cdot \left( x , y , z \right) ^ { \mathrm { t } } = \alpha _ { 4 }$ 。若过原点，则 $\alpha _ { 4 } = 0$ 与 $\alpha _ { 1 } , \alpha _ { 2 }$ 线性无关矛盾，故不过原点。

$x \alpha _ { 1 } + y \alpha _ { 2 } + z \alpha _ { 3 } = \alpha _ { 4 } \leftrightarrow \left\{ \begin{array} { c } { { a _ { 1 1 } x + a _ { 1 2 } y + a _ { 1 3 } z = a _ { 1 4 } } } \\ { { a _ { 2 1 } x + a _ { 2 2 } y + a _ { 2 3 } z = a _ { 2 4 } } } \\ { { \ldots } } \\ { { a _ { n 1 } x + a _ { n 2 } y + a _ { n 3 } z = a _ { n 4 } } } \end{array} \right.$ 21 22 23 24 a x a y a z a    + + =     ，由上述分析可知 r ( a) = r ( a ) = 2 ，故 $r \left( a \right) = r \left( { \overline { { a } } } \right) = 2$ 两平面交于一条直线，且不过原点。故选 $\mathrm { d }$ 。');
