INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2025_main_q07', 'math1', 2025, '真题', 'main', 7, '7．设 $n$ 阶矩阵 $A , B , C$ 满足 $r \left( A \right) + r \left( B \right) + r \left( C \right) = r \left( A B C \right) + 2 n$ ，给出下列四个结论：

$$
\begin{array}{l} ① r (A B C) + n = r (A B) + r (C); \\ ② r (A B) + n = r (A) + r (B); \\ ③ r (\boldsymbol {A}) = r (\boldsymbol {B}) = r (\boldsymbol {C}) = n; \\ \end{array}
$$

$$
④ r (A B) = r (B C) = n.
$$

其中正确结论的序号是

A． $\textcircled{1} \textcircled{2}$

B． $\textcircled{1} \textcircled{3}$

C． $\textcircled{2} \textcircled{4}$

D． $\textcircled{3} \textcircled{4}$

【答案】A

【解析】 1 0 ,0 0( )=  A $\scriptstyle A = { \left( { \begin{array} { l l } { 1 } & { 0 } \\ { 0 } & { 0 } \end{array} } \right) } , B = { \left( { \begin{array} { l l } { 0 } & { 0 } \\ { 0 } & { 1 } \end{array} } \right) } , C = E$ ，满足 $r ( A ) + r ( B ) + r ( C ) = r ( A B C ) + 2 n$ ，则$r ( A ) = 1 , r ( B ) = 1 , r ( C ) = 2$ ，排除结论 $\textcircled{3} \textcircled{4}$ ，故选 A.', 'E:\数学自用\数据资料\真题\按年份整理\2025\按题拆分\真题\第07题\题目.md', '2025\按题拆分\真题\第07题\题目.md', 0, 'manual_check', '2025 真题 第7题 7．设 $n$ 阶矩阵 $a , b , c$ 满足 $r \left( a \right) + r \left( b \right) + r \left( c \right) = r \left( a b c \right) + 2 n$ ，给出下列四个结论：

$$
\begin{array}{l} ① r (a b c) + n = r (a b) + r (c); \\ ② r (a b) + n = r (a) + r (b); \\ ③ r (\boldsymbol {a}) = r (\boldsymbol {b}) = r (\boldsymbol {c}) = n; \\ \end{array}
$$

$$
④ r (a b) = r (b c) = n.
$$

其中正确结论的序号是

a． $\textcircled{1} \textcircled{2}$

b． $\textcircled{1} \textcircled{3}$

c． $\textcircled{2} \textcircled{4}$

d． $\textcircled{3} \textcircled{4}$

【答案】a

【解析】 1 0 ,0 0( )=  a $\scriptstyle a = { \left( { \begin{array} { l l } { 1 } & { 0 } \\ { 0 } & { 0 } \end{array} } \right) } , b = { \left( { \begin{array} { l l } { 0 } & { 0 } \\ { 0 } & { 1 } \end{array} } \right) } , c = e$ ，满足 $r ( a ) + r ( b ) + r ( c ) = r ( a b c ) + 2 n$ ，则$r ( a ) = 1 , r ( b ) = 1 , r ( c ) = 2$ ，排除结论 $\textcircled{3} \textcircled{4}$ ，故选 a.');
