INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2025_main_q08', 'math1', 2025, '真题', 'main', 8, '8．设二维随机变量 $(X,Y)$ 服从正态分布 $N(0,0;1,1;\rho)$，其中 $\rho\in(-1,1)$。若 $a,b$ 为满足 $a^2+b^2=1$ 的任意实数，则 $D(aX+bY)$ 的最大值为

A．1

B．2

C．$1+|\rho|$

D．$1+\rho^2$

【答案】C

【解析】由于 $D(X)=D(Y)=1,\operatorname{Cov}(X,Y)=\rho$，

$$
D(aX+bY)=a^2+b^2+2ab\rho=1+2ab\rho.
$$

在 $a^2+b^2=1$ 下，$|2ab|\leq 1$，故最大值为 $1+|\rho|$。', 'E:\数学自用\数据资料\真题\按年份整理\2025\按题拆分\真题\第08题\题目.md', '2025\按题拆分\真题\第08题\题目.md', 0, 'manual_check', '2025 真题 第8题 8．设二维随机变量 $(x,y)$ 服从正态分布 $n(0,0;1,1;\rho)$，其中 $\rho\in(-1,1)$。若 $a,b$ 为满足 $a^2+b^2=1$ 的任意实数，则 $d(ax+by)$ 的最大值为

a．1

b．2

c．$1+|\rho|$

d．$1+\rho^2$

【答案】c

【解析】由于 $d(x)=d(y)=1,\operatorname{cov}(x,y)=\rho$，

$$
d(ax+by)=a^2+b^2+2ab\rho=1+2ab\rho.
$$

在 $a^2+b^2=1$ 下，$|2ab|\leq 1$，故最大值为 $1+|\rho|$。');
