INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2025_main_q09', 'math1', 2025, '真题', 'main', 9, '9．设 $X _ { 1 } , X _ { 2 } , \cdots , X _ { 2 0 }$ 是来自总体 $B { \left( 1 , 0 . 1 \right) }$ 的简单随机样本.令 $T = \sum _ { i = 1 } ^ { 2 0 } X _ { i }$ ，利用泊松分布近似表示二项分布的方法可得 $P \{ T \leq 1 \} \approx$

A． $\frac { 1 } { \mathrm { e } ^ { 2 } }$

B． 2 e

3 C． 2

4 D． 2e

【答案】C

【解析】由题意可知 $T \sim B ( 2 0 , 0 . 1 ) . n p = 2 0 \times 0 . 1 = 2$

$$
P \{T \leqslant 1 \} = P \{T = 0 \} + P \{T = 1 \} = \frac {2 ^ {0}}{0 !} e ^ {- 2} + \frac {2 ^ {1}}{1 !} e ^ {- 2} = e ^ {- 2} + 2 e ^ {- 2} = \frac {3}{e ^ {2}}
$$', 'E:\数学自用\数据资料\真题\按年份整理\2025\按题拆分\真题\第09题\题目.md', '2025\按题拆分\真题\第09题\题目.md', 0, 'ok', '2025 真题 第9题 9．设 $x _ { 1 } , x _ { 2 } , \cdots , x _ { 2 0 }$ 是来自总体 $b { \left( 1 , 0 . 1 \right) }$ 的简单随机样本.令 $t = \sum _ { i = 1 } ^ { 2 0 } x _ { i }$ ，利用泊松分布近似表示二项分布的方法可得 $p \{ t \leq 1 \} \approx$

a． $\frac { 1 } { \mathrm { e } ^ { 2 } }$

b． 2 e

3 c． 2

4 d． 2e

【答案】c

【解析】由题意可知 $t \sim b ( 2 0 , 0 . 1 ) . n p = 2 0 \times 0 . 1 = 2$

$$
p \{t \leqslant 1 \} = p \{t = 0 \} + p \{t = 1 \} = \frac {2 ^ {0}}{0 !} e ^ {- 2} + \frac {2 ^ {1}}{1 !} e ^ {- 2} = e ^ {- 2} + 2 e ^ {- 2} = \frac {3}{e ^ {2}}
$$');
