INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2025_main_q10', 'math1', 2025, '真题', 'main', 10, '10．设 $X_1,X_2,\cdots,X_n$ 为来自正态总体 $N(\mu,2)$ 的简单随机样本。记 $\overline X=\frac1n\sum_{i=1}^n X_i$，$Z_\alpha$ 表示标准正态分布的上侧 $\alpha$ 分位数。假设检验问题 $H_0:\mu\leq 1, H_1:\mu>1$ 的显著性水平为 $\alpha$ 的检验的拒绝域为

$$
\left\{(X_1,X_2,\cdots,X_n)\mid \overline X>1+\sqrt{\frac{2}{n}}Z_\alpha\right\}.
$$

【答案】D

【解析】当 $\mu=1$ 时，$\frac{\overline X-1}{\sqrt{2/n}}\sim N(0,1)$。右侧检验在显著性水平 $\alpha$ 下的拒绝域为

$$
\frac{\overline X-1}{\sqrt{2/n}}>Z_\alpha,
$$

即 $\overline X>1+\sqrt{\frac{2}{n}}Z_\alpha$。', 'E:\数学自用\数据资料\真题\按年份整理\2025\按题拆分\真题\第10题\题目.md', '2025\按题拆分\真题\第10题\题目.md', 0, 'manual_check', '2025 真题 第10题 10．设 $x_1,x_2,\cdots,x_n$ 为来自正态总体 $n(\mu,2)$ 的简单随机样本。记 $\overline x=\frac1n\sum_{i=1}^n x_i$，$z_\alpha$ 表示标准正态分布的上侧 $\alpha$ 分位数。假设检验问题 $h_0:\mu\leq 1, h_1:\mu>1$ 的显著性水平为 $\alpha$ 的检验的拒绝域为

$$
\left\{(x_1,x_2,\cdots,x_n)\mid \overline x>1+\sqrt{\frac{2}{n}}z_\alpha\right\}.
$$

【答案】d

【解析】当 $\mu=1$ 时，$\frac{\overline x-1}{\sqrt{2/n}}\sim n(0,1)$。右侧检验在显著性水平 $\alpha$ 下的拒绝域为

$$
\frac{\overline x-1}{\sqrt{2/n}}>z_\alpha,
$$

即 $\overline x>1+\sqrt{\frac{2}{n}}z_\alpha$。');
