INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2025_main_q11', 'math1', 2025, '真题', 'main', 11, '11． $\operatorname* { l i m } _ { x \to 0 ^ { + } } { \frac { x ^ { x } - 1 } { \ln x \cdot \ln ( 1 - x ) } } = \qquad \cdot$

【答案】-1

【解析】

$$
\lim  _ {x \rightarrow 0 ^ {+}} \frac {e ^ {x \ln x} - 1}{- x \ln x} = \lim  _ {x \rightarrow 0 ^ {+}} \frac {x \ln x}{- x \ln x} = - 1
$$', 'E:\数学自用\数据资料\真题\按年份整理\2025\按题拆分\真题\第11题\题目.md', '2025\按题拆分\真题\第11题\题目.md', 0, 'manual_check', '2025 真题 第11题 11． $\operatorname* { l i m } _ { x \to 0 ^ { + } } { \frac { x ^ { x } - 1 } { \ln x \cdot \ln ( 1 - x ) } } = \qquad \cdot$

【答案】-1

【解析】

$$
\lim  _ {x \rightarrow 0 ^ {+}} \frac {e ^ {x \ln x} - 1}{- x \ln x} = \lim  _ {x \rightarrow 0 ^ {+}} \frac {x \ln x}{- x \ln x} = - 1
$$');
