INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2025_main_q12', 'math1', 2025, '真题', 'main', 12, '12.已知函数 $f ( x ) = \left\{ { \begin{array} { l l } { 0 , } & { 0 \leq x < { \frac { 1 } { 2 } } , } \\ { } & { } \\ { x ^ { 2 } , } & { { \frac { 1 } { 2 } } \leq x \leq 1 } \end{array} } \right.$ , 的傅里叶级数为 $\sum _ { n = 1 } ^ { \infty } b _ { n }$ sin π ,n x S (x) 为 $\sum _ { n = 1 } ^ { \infty } b _ { n }$ sin πn x的和函数，则 $S \left( - { \frac { 7 } { 2 } } \right) = - \qquad $

【答案】 $\frac { 1 } { 8 }$

【解析】

$$
s \left(- \frac {7}{2}\right) = s \left(- \frac {7}{2} + 4\right) = s \left(\frac {1}{2}\right) = \frac {1}{8}.
$$', 'E:\数学自用\数据资料\真题\按年份整理\2025\按题拆分\真题\第12题\题目.md', '2025\按题拆分\真题\第12题\题目.md', 0, 'ok', '2025 真题 第12题 12.已知函数 $f ( x ) = \left\{ { \begin{array} { l l } { 0 , } & { 0 \leq x < { \frac { 1 } { 2 } } , } \\ { } & { } \\ { x ^ { 2 } , } & { { \frac { 1 } { 2 } } \leq x \leq 1 } \end{array} } \right.$ , 的傅里叶级数为 $\sum _ { n = 1 } ^ { \infty } b _ { n }$ sin π ,n x s (x) 为 $\sum _ { n = 1 } ^ { \infty } b _ { n }$ sin πn x的和函数，则 $s \left( - { \frac { 7 } { 2 } } \right) = - \qquad $

【答案】 $\frac { 1 } { 8 }$

【解析】

$$
s \left(- \frac {7}{2}\right) = s \left(- \frac {7}{2} + 4\right) = s \left(\frac {1}{2}\right) = \frac {1}{8}.
$$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2025_main_q12', 'tag_级数');
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2025_main_q13', 'math1', 2025, '真题', 'main', 13, '13. 已知函数 $u(x,y,z)=xy^2z^3$，向量 $\pmb n=(2,2,-1)$，则 $\left.\frac{\partial u}{\partial \pmb n}\right|_{(1,1,1)} =$ ______.

【答案】1

【解析】有

$$
\nabla u=(y^2z^3,2xyz^3,3xy^2z^2),
$$

故

$$
\nabla u(1,1,1)=(1,2,3).
$$

向量 $\pmb n=(2,2,-1)$ 的单位向量为

$$
\pmb n_0=\left(\frac23,\frac23,-\frac13\right).
$$

因此

$$
\left.\frac{\partial u}{\partial \pmb n}\right|_{(1,1,1)}
=\nabla u(1,1,1)\cdot\pmb n_0
=\frac23+\frac43-1=1.
$$', 'E:\数学自用\数据资料\真题\按年份整理\2025\按题拆分\真题\第13题\题目.md', '2025\按题拆分\真题\第13题\题目.md', 0, 'manual_check', '2025 真题 第13题 13. 已知函数 $u(x,y,z)=xy^2z^3$，向量 $\pmb n=(2,2,-1)$，则 $\left.\frac{\partial u}{\partial \pmb n}\right|_{(1,1,1)} =$ ______.

【答案】1

【解析】有

$$
\nabla u=(y^2z^3,2xyz^3,3xy^2z^2),
$$

故

$$
\nabla u(1,1,1)=(1,2,3).
$$

向量 $\pmb n=(2,2,-1)$ 的单位向量为

$$
\pmb n_0=\left(\frac23,\frac23,-\frac13\right).
$$

因此

$$
\left.\frac{\partial u}{\partial \pmb n}\right|_{(1,1,1)}
=\nabla u(1,1,1)\cdot\pmb n_0
=\frac23+\frac43-1=1.
$$');
INSERT OR IGNORE INTO question_tags(question_id, tag_id) VALUES ('math1_2025_main_q13', 'tag_线性代数');
INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2025_main_q14', 'math1', 2025, '真题', 'main', 14, '14. 已知有向曲线 $L$ 是沿抛物线 $y = 1 - x ^ { 2 }$ 从点 $( 1 , 0 )$ 到点 $( - 1 , 0 )$ 的一段，则曲线积分

$$
\int_ {L} (y + \cos x) d x + (2 x + \cos y) d y = \underline {{}}.
$$

【答案】 $\frac { 4 } { 3 } - 2 \sin 1$

【解析】由题易知可作曲线如右图所示.

记 $L _ { 0 }$ 是从 $x = - 1$ 到 $x = 1$ 的直线,

并记曲线积 $I = \int _ { L } ( y + \cos x ) d x + ( 2 x + \cos y ) d y$

则在 $L _ { 0 }$ 与 $L$ 所围的封闭区域可用格林公式

即 $I _ { 1 } = \oint _ { L _ { 0 } + L } ( y + \cos x ) d x + ( 2 x + \cos y ) d y$

$$
= \iint_ {D} 2 - 1 d \sigma = \int_ {- 1} ^ {1} d x \int_ {0} ^ {1 - x ^ {2}} d y = \int_ {- 1} ^ {1} (1 - x ^ {2}) d x = \frac {4}{3}
$$

又 $I _ { 2 } = \int _ { L _ { 0 } } ^ { 1 } ( y + \cos x ) d x + ( 2 x + \cos y ) d y = \int _ { - 1 } ^ { 1 } \cos x d x = 2 \sin 1$ ,故 $I = \frac { 4 } { 3 } - 2 \sin 1$', 'E:\数学自用\数据资料\真题\按年份整理\2025\按题拆分\真题\第14题\题目.md', '2025\按题拆分\真题\第14题\题目.md', 0, 'ok', '2025 真题 第14题 14. 已知有向曲线 $l$ 是沿抛物线 $y = 1 - x ^ { 2 }$ 从点 $( 1 , 0 )$ 到点 $( - 1 , 0 )$ 的一段，则曲线积分

$$
\int_ {l} (y + \cos x) d x + (2 x + \cos y) d y = \underline {{}}.
$$

【答案】 $\frac { 4 } { 3 } - 2 \sin 1$

【解析】由题易知可作曲线如右图所示.

记 $l _ { 0 }$ 是从 $x = - 1$ 到 $x = 1$ 的直线,

并记曲线积 $i = \int _ { l } ( y + \cos x ) d x + ( 2 x + \cos y ) d y$

则在 $l _ { 0 }$ 与 $l$ 所围的封闭区域可用格林公式

即 $i _ { 1 } = \oint _ { l _ { 0 } + l } ( y + \cos x ) d x + ( 2 x + \cos y ) d y$

$$
= \iint_ {d} 2 - 1 d \sigma = \int_ {- 1} ^ {1} d x \int_ {0} ^ {1 - x ^ {2}} d y = \int_ {- 1} ^ {1} (1 - x ^ {2}) d x = \frac {4}{3}
$$

又 $i _ { 2 } = \int _ { l _ { 0 } } ^ { 1 } ( y + \cos x ) d x + ( 2 x + \cos y ) d y = \int _ { - 1 } ^ { 1 } \cos x d x = 2 \sin 1$ ,故 $i = \frac { 4 } { 3 } - 2 \sin 1$');
