INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2025_main_q15', 'math1', 2025, '真题', 'main', 15, '15. 设矩阵 $A = { \left( \begin{array} { l l l } { 4 } & { 2 } & { - 3 } \\ { a } & { 3 } & { - 4 } \\ { b } & { 5 } & { - 7 } \end{array} \right) } ,$ 若方程组 $A ^ { 2 } x = \mathbf { 0 }$ 与 $\pmb { A } \pmb { x } = \pmb { 0 }$ 不同 解， 则 $a - b =$

【答案】-4

【解析】由题知， $\begin{array} { r } { A = \left( \begin{array} { c c c } { 4 } & { 2 } & { - 3 } \\ { a } & { 3 } & { - 4 } \\ { b } & { 5 } & { - 7 } \end{array} \right) , } \end{array}$ ，若 $A ^ { 2 } x = 0$ 与 $A x = 0$ 同解 ，则 三秩 相同 ，即

$r \left( A \right) = r \left( A ^ { 2 } \right) = r \left( \begin{array} { c } { { A } } \\ { { A ^ { 2 } } } \end{array} \right)$ 。如果 $A$ 可逆，三秩显然相同，则 $A ^ { 2 } x = 0$ 与 $A x = 0$ 同解，于是要想 $A ^ { 2 } x = 0$ 与 $A x = 0$ 不同解，即 $A$ 不可逆，于是 $\left| { \cal A } \right| = 0$ 。根据行列式的倍加性质易得

![](images/ec1f33b0c14c291197576c603a4fcdc0f2e5a3a4f9932bebe1801c67273482c9.jpg)

$$
\left| A \right| = \left| \left( \begin{array}{l l l} {4} & {2} & {- 3} \\ {a} & {3} & {- 4} \\ {b} & {5} & {- 7} \end{array} \right) \right| = \left| \left( \begin{array}{l l l} {4} & {2} & {- 1} \\ {a} & {3} & {- 1} \\ {b} & {5} & {- 2} \end{array} \right) \right| = \left| \left( \begin{array}{l l l} {4} & {0} & {- 1} \\ {a} & {1} & {- 1} \\ {b} & {1} & {- 2} \end{array} \right) \right| = 4 \left(- 2 + 1\right) - \left(a - b\right), \text {令} \left| A \right| = 0,
$$

有 $a - b = - 4$ 。', 'E:\数学自用\数据资料\真题\按年份整理\2025\按题拆分\真题\第15题\题目.md', '2025\按题拆分\真题\第15题\题目.md', 1, 'manual_check', '2025 真题 第15题 15. 设矩阵 $a = { \left( \begin{array} { l l l } { 4 } & { 2 } & { - 3 } \\ { a } & { 3 } & { - 4 } \\ { b } & { 5 } & { - 7 } \end{array} \right) } ,$ 若方程组 $a ^ { 2 } x = \mathbf { 0 }$ 与 $\pmb { a } \pmb { x } = \pmb { 0 }$ 不同 解， 则 $a - b =$

【答案】-4

【解析】由题知， $\begin{array} { r } { a = \left( \begin{array} { c c c } { 4 } & { 2 } & { - 3 } \\ { a } & { 3 } & { - 4 } \\ { b } & { 5 } & { - 7 } \end{array} \right) , } \end{array}$ ，若 $a ^ { 2 } x = 0$ 与 $a x = 0$ 同解 ，则 三秩 相同 ，即

$r \left( a \right) = r \left( a ^ { 2 } \right) = r \left( \begin{array} { c } { { a } } \\ { { a ^ { 2 } } } \end{array} \right)$ 。如果 $a$ 可逆，三秩显然相同，则 $a ^ { 2 } x = 0$ 与 $a x = 0$ 同解，于是要想 $a ^ { 2 } x = 0$ 与 $a x = 0$ 不同解，即 $a$ 不可逆，于是 $\left| { \cal a } \right| = 0$ 。根据行列式的倍加性质易得

![](images/ec1f33b0c14c291197576c603a4fcdc0f2e5a3a4f9932bebe1801c67273482c9.jpg)

$$
