INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2025_main_q16', 'math1', 2025, '真题', 'main', 16, '16. 设 $A , B$ 为两个随机事件，且 $A$ 与 $B$ 相互独立，已知 $P ( A ) = 2 P ( B ) , P ( A \cup B ) = { \frac { 5 } { 8 } } .$ , 则在事件 $A , B$ 至少有一个发生的条件下， $A , B$ 中恰有一个发生的概率为

【答案】 $\frac { 4 } { 5 }$

【解析】 $P ( A { \bar { B } } ) + P ( { \overline { { A } } } B ) = P ( A ) - P ( A B ) + P ( B ) - P ( A B )$

$$
= P (A) + P (B) - 2 P (A) P (B)
$$

$$
P (A \cup B) = P (A) + P (B) - P (A B) = \frac {5}{8}, \Rightarrow 3 P (B) - 2 P ^ {2} (B) = \frac {5}{8}
$$

$$
2 4 P (B) - 1 6 P ^ {2} (B) = 5, 1 6 P ^ {2} (B) - 2 4 P (B) + 5 = 0
$$

$$
\Rightarrow (4 P (B) - 1) (4 P (B) - 5) = 0
$$

$$
P (B) = \frac {1}{4}, P (A) = \frac {1}{2}
$$

$$
\begin{array}{l} P (A \bar {B}) + P (\bar {A} B) = P (A) - P (A B) + P (B) - P (A B) = P (A) + P (B) - 2 P (A) P (B) \\ = \frac {1}{2} + \frac {1}{4} - 2 \times \frac {1}{4} \times \frac {1}{2} = \frac {1}{2} \\ \end{array}
$$

$$
P = \frac {\frac {1}{2}}{\frac {5}{8}} = \frac {1}{2} \times \frac {8}{5} = \frac {4}{5}
$$

# 三、解答题： $1 7 { \sim } 2 2$ 小题，共 70分．解答应写出文字说明、证明过程或演算步骤', 'E:\数学自用\数据资料\真题\按年份整理\2025\按题拆分\真题\第16题\题目.md', '2025\按题拆分\真题\第16题\题目.md', 0, 'ok', '2025 真题 第16题 16. 设 $a , b$ 为两个随机事件，且 $a$ 与 $b$ 相互独立，已知 $p ( a ) = 2 p ( b ) , p ( a \cup b ) = { \frac { 5 } { 8 } } .$ , 则在事件 $a , b$ 至少有一个发生的条件下， $a , b$ 中恰有一个发生的概率为

【答案】 $\frac { 4 } { 5 }$

【解析】 $p ( a { \bar { b } } ) + p ( { \overline { { a } } } b ) = p ( a ) - p ( a b ) + p ( b ) - p ( a b )$

$$
= p (a) + p (b) - 2 p (a) p (b)
$$

$$
p (a \cup b) = p (a) + p (b) - p (a b) = \frac {5}{8}, \rightarrow 3 p (b) - 2 p ^ {2} (b) = \frac {5}{8}
$$

$$
2 4 p (b) - 1 6 p ^ {2} (b) = 5, 1 6 p ^ {2} (b) - 2 4 p (b) + 5 = 0
$$

$$
\rightarrow (4 p (b) - 1) (4 p (b) - 5) = 0
$$

$$
p (b) = \frac {1}{4}, p (a) = \frac {1}{2}
$$

$$
\begin{array}{l} p (a \bar {b}) + p (\bar {a} b) = p (a) - p (a b) + p (b) - p (a b) = p (a) + p (b) - 2 p (a) p (b) \\ = \frac {1}{2} + \frac {1}{4} - 2 \times \frac {1}{4} \times \frac {1}{2} = \frac {1}{2} \\ \end{array}
$$

$$
p = \frac {\frac {1}{2}}{\frac {5}{8}} = \frac {1}{2} \times \frac {8}{5} = \frac {4}{5}
$$

