INSERT OR REPLACE INTO questions(question_id, subject_id, year, paper, paper_slug, question_no, content_md, source_path, relative_source_path, has_assets, quality_status, search_text) VALUES ('math1_2025_main_q21', 'math1', 2025, '真题', 'main', 21, '21.（本题满分 10分）

设矩阵 $A = { \left( \begin{array} { l l l } { 0 } & { - 1 } & { 2 } \\ { - 1 } & { 0 } & { 2 } \\ { - 1 } & { - 1 } & { a } \end{array} \right) } ,$ 已知 1是 $A$ 的特征多项式的重根.

(1)求 a 的值；  
（2）求所有满足 $A \alpha = \alpha + \beta , A ^ { 2 } \alpha = \alpha + 2 \beta$ 的非零列向量 $\alpha$ ， $\beta$

解：（1） $f ( \lambda ) = \mid A - \lambda E \mid = ( 1 - \lambda ) [ ( \lambda - a ) ( \lambda + 1 ) + 4 ]$

可得 $( 1 - a ) ( 1 + 1 ) + 4 = 0 , a = 3$ $a = 3$

（2）由（1）可知 $A = \left( \begin{array} { r r r } { { 0 } } & { { - 1 } } & { { 2 } } \\ { { - 1 } } & { { 0 } } & { { 2 } } \\ { { - 1 } } & { { - 1 } } & { { 3 } } \end{array} \right) , | A - \lambda E | = 0$ ,得 $\pmb { A }$ 中 $\lambda _ { 1 } = \lambda _ { 2 } = \lambda _ { 3 } = 1$ ，

$$
A \alpha = \alpha + \beta . A ^ {2} \alpha = \alpha + 2 \beta \Rightarrow (A - E) \alpha = \beta , \left(A ^ {2} - E\right) \alpha = 2 \beta = 2 (A - E) \alpha
$$

$\left( A - E \right) ^ { 2 } { \pmb { a } } = { \pmb { 0 } }$ ,其中 $( \pmb { A } - \pmb { E } ) ^ { 2 } \mp \pmb { \operatorname { \_ } }$ ,故 $\pmb { \alpha }$ 为任意的非零向量， ${ \pmb { a } } = \left( a _ { 1 } , a _ { 2 } , a _ { 3 } \right) ^ { \operatorname { T } } , a _ { 1 } a _ { 2 } a _ { 3 } \neq 0$

$$
\Rightarrow \boldsymbol {\beta} = (\boldsymbol {A} - \boldsymbol {E}) \boldsymbol {\alpha} = \left( \begin{array}{l l l} - 1 & - 1 & 2 \\ - 1 & - 1 & 2 \\ - 1 & - 1 & 2 \end{array} \right) \left( \begin{array}{l} a _ {1} \\ a _ {2} \\ a _ {3} \end{array} \right) = \left( \begin{array}{l} 2 a _ {3} - a _ {1} - a _ {2} \\ 2 a _ {3} - a _ {1} - a _ {2} \\ 2 a _ {3} - a _ {1} - a _ {2} \end{array} \right)
$$

其中 $a _ { 1 } + a _ { 2 } \neq 2 a _ { 3 }$

则综上 $\mathbf { \Delta } \cdot \mathbf { a } = { \left( \begin{array} { l } { a _ { 1 } } \\ { a _ { 2 } } \\ { a _ { 3 } } \end{array} \right) } , \mathbf { \beta } \mathbf { \int } \mathbf { = } { \left( \begin{array} { l } { 2 a _ { 3 } - a _ { 1 } - a _ { 2 } } \\ { 2 a _ { 3 } - a _ { 1 } - a _ { 2 } } \\ { 2 a _ { 3 } - a _ { 1 } - a _ { 2 } } \end{array} \right) } , \left( a _ { 1 } a _ { 2 } a _ { 3 } \neq 0 , a _ { 1 } + a _ { 2 } \neq 2 a _ { 3 } \right)$', 'E:\数学自用\数据资料\真题\按年份整理\2025\按题拆分\真题\第21题\题目.md', '2025\按题拆分\真题\第21题\题目.md', 0, 'ok', '2025 真题 第21题 21.（本题满分 10分）

设矩阵 $a = { \left( \begin{array} { l l l } { 0 } & { - 1 } & { 2 } \\ { - 1 } & { 0 } & { 2 } \\ { - 1 } & { - 1 } & { a } \end{array} \right) } ,$ 已知 1是 $a$ 的特征多项式的重根.

(1)求 a 的值；  
（2）求所有满足 $a \alpha = \alpha + \beta , a ^ { 2 } \alpha = \alpha + 2 \beta$ 的非零列向量 $\alpha$ ， $\beta$

解：（1） $f ( \lambda ) = \mid a - \lambda e \mid = ( 1 - \lambda ) [ ( \lambda - a ) ( \lambda + 1 ) + 4 ]$

可得 $( 1 - a ) ( 1 + 1 ) + 4 = 0 , a = 3$ $a = 3$

（2）由（1）可知 $a = \left( \begin{array} { r r r } { { 0 } } & { { - 1 } } & { { 2 } } \\ { { - 1 } } & { { 0 } } & { { 2 } } \\ { { - 1 } } & { { - 1 } } & { { 3 } } \end{array} \right) , | a - \lambda e | = 0$ ,得 $\pmb { a }$ 中 $\lambda _ { 1 } = \lambda _ { 2 } = \lambda _ { 3 } = 1$ ，

$$
a \alpha = \alpha + \beta . a ^ {2} \alpha = \alpha + 2 \beta \rightarrow (a - e) \alpha = \beta , \left(a ^ {2} - e\right) \alpha = 2 \beta = 2 (a - e) \alpha
$$

$\left( a - e \right) ^ { 2 } { \pmb { a } } = { \pmb { 0 } }$ ,其中 $( \pmb { a } - \pmb { e } ) ^ { 2 } \mp \pmb { \operatorname { \_ } }$ ,故 $\pmb { \alpha }$ 为任意的非零向量， ${ \pmb { a } } = \left( a _ { 1 } , a _ { 2 } , a _ { 3 } \right) ^ { \operatorname { t } } , a _ { 1 } a _ { 2 } a _ { 3 } \neq 0$

$$
\rightarrow \boldsymbol {\beta} = (\boldsymbol {a} - \boldsymbol {e}) \boldsymbol {\alpha} = \left( \begin{array}{l l l} - 1 & - 1 & 2 \\ - 1 & - 1 & 2 \\ - 1 & - 1 & 2 \end{array} \right) \left( \begin{array}{l} a _ {1} \\ a _ {2} \\ a _ {3} \end{array} \right) = \left( \begin{array}{l} 2 a _ {3} - a _ {1} - a _ {2} \\ 2 a _ {3} - a _ {1} - a _ {2} \\ 2 a _ {3} - a _ {1} - a _ {2} \end{array} \right)
$$

其中 $a _ { 1 } + a _ { 2 } \neq 2 a _ { 3 }$

则综上 $\mathbf { \delta } \cdot \mathbf { a } = { \left( \begin{array} { l } { a _ { 1 } } \\ { a _ { 2 } } \\ { a _ { 3 } } \end{array} \right) } , \mathbf { \beta } \mathbf { \int } \mathbf { = } { \left( \begin{array} { l } { 2 a _ { 3 } - a _ { 1 } - a _ { 2 } } \\ { 2 a _ { 3 } - a _ { 1 } - a _ { 2 } } \\ { 2 a _ { 3 } - a _ { 1 } - a _ { 2 } } \end{array} \right) } , \left( a _ { 1 } a _ { 2 } a _ { 3 } \neq 0 , a _ { 1 } + a _ { 2 } \neq 2 a _ { 3 } \right)$');
